INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400001,6,'逻辑判断','中国古诗中曾有“借酒消愁愁更愁”的句子。日本专家则通过动物实验验证了这句 话的科学性，即饮酒会让人对不愉快的记忆更深刻。实验人员把大白鼠挪到与平常 的饲养环境不同的箱子里，并给它们以电击。接着，把实验鼠关回往常的饲养箱， 第二天再把它们挪到曾经给它们带来恐怖的箱子。依靠大白鼠在箱子中呆立不动的 时间长短，来测算大白鼠恐怖记忆的程度。这时，研究人员把大白鼠分成两组，只 让其中的一组饮用酒精，然后把它们再次关入“恐怖箱”,观察大白鼠呆立不动的 时间，以验证酒精对于实验鼠的影响。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"与未饮用酒精的实验鼠相对照，“醉酒”的实验鼠呆立不动的时间会变得更长"},{"label":"B","content":"在未分组之前，如果不再次给大白鼠以电击，大白鼠在“恐怖箱”中呆立不动的 时间和之前一样"},{"label":"C","content":"与未饮用酒精的实验鼠相对照，“醉酒”实验鼠呆立不动的时间较短"},{"label":"D","content":"在未分组之前，如果继续给大白鼠以电击，大白鼠在“恐怖箱”中呆立不动的时 间越来越短"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":1,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400002,6,'逻辑判断','研究显示，世界上较长的246条河流中，目前仅有三分之一还能保持全程自由流动， 越来越多的水坝和水库正在减少健康河流为全人类提供的多种利益。 以下各项如果为真，最能支持上述结论的是：','[{"label":"A","content":"这是科学家有史以来第一次对地球上河流自由流动的状况进行评估"},{"label":"B","content":"目前全世界已建成的大型水坝有近6万座，正在规划或建造的大坝则超过3700座"},{"label":"C","content":"许多国家致力于发展低碳经济，迫切需要开发可再生能源，水电成为重要选择"},{"label":"D","content":"自由流动的河流不仅支持淡水鱼的繁衍，还能提供大量沉积物维系生物多样性"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":2,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400003,6,'逻辑判断','四川省气象局气候中心最近完成的一项研究认为：未来10至30年，“干暖”将成 为目前大熊猫栖息地气候变化的总体趋势，这些地区将越来越不适合大熊猫的生存 繁衍，而西北方向的邛崃山系则会因为气温升高、降水明显增加，变得更适宜大熊 猫生存。大熊猫栖息地气候适宜区、次适宜区将由东南向西北转移，因此大熊猫未 来将会向西北迁徙。 以下哪项如果为真，最能支持上述观点：','[{"label":"A","content":"大熊猫喜欢湿润的气候"},{"label":"B","content":"“干暖”气候不利于竹子生长"},{"label":"C","content":"西北地区的气候正变得越来越湿润"},{"label":"D","content":"大熊猫具备迁徙的能力 逻 辑 判 断"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":3,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400004,6,'逻辑判断','甲、乙、丙、丁、戊是同班同学，在某次寒假聚会上，每人就寒假作业的完成情况 分别说一句话： 甲：“我和乙、丁、戊中，只有一人没完成作业。” 乙：“我和甲、丙、丁中，有三人没完成作业。” 丙：“除丁外，我们四人都完成了作业。” 丁：“甲和乙没完成作业。” 戊：“甲和丙没完成作业。” 若完成作业的人说真话，没完成作业的人说假话，且每人都知道其他四人的作业完 成情况，则没完成作业的是：','[{"label":"A","content":"甲、乙、丙"},{"label":"B","content":"甲、丙、丁"},{"label":"C","content":"甲、乙、丁"},{"label":"D","content":"丙、丁、戊"}]','B','。 四海公煮 逻 辑 判 断60 0','逻辑判断600题','进阶','published','{"globalNumber":4,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400005,6,'逻辑判断','挪威研究人员分析了该国过去几十年里230万份出生记录，以及相应孕妇的健康数据， 结果发现，如果母亲怀孕期间出现妊娠剧吐症状，女儿后来怀孕时也出现该症状的 可能性是其他人的3倍。研究还表明，孕妇妊娠剧吐与腹中胎儿是否含有来自丈夫 一方的相关基因没有关系，导致这一症状的基因只可能来自母亲。因此研究人员认为， 妊娠剧吐与父亲的基因无关，而是由母亲遗传给女儿。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"女儿和母亲生活的自然和家庭环境(气候、饮食习惯等)比较类似"},{"label":"B","content":"一项亚洲研究表明，母亲有妊娠剧吐，女儿出现的可能性是其他人的1.5倍"},{"label":"C","content":"研究表明，外婆怀孕时有妊娠剧吐，外孙女出现的可能性是其他人的3倍"},{"label":"D","content":"在过去十年中，挪威妇女吸烟的比例逐年上升，而吸烟与妊娠剧吐有关"}]','A','。 ⑥花生批注： 题干论据为对比实验， 根据“母亲怀孕期间 是否出现妊娠剧吐症 状”分组，得出“母 亲怀孕时剧吐，女儿 也出现剧吐的可能性 为其他人3倍”的结果。 结论：妊娠剧吐的基 因由母亲遗传给女儿。 ⑦花生批注： 例如：居住条件较差、 母亲的丈夫(女儿的 父亲)做饭难吃等。 ⑧花生批注： 对比实验归因题，正 确选项要回归实验， 和实验分组一致，脱 离实验的“他因”往 往是强干扰项； 若此选项改为：母亲 剧吐组的女儿，吸烟 比例也更高，就是另 有他因质疑。 5 5 ⑨花生批注： 论据：60%认为收入水 平高于平均，10%认为 在平均水平附近，10% 认为与平均水平差异 大； 结论：本市居民收入 的平均水平要高于全 国城市居民收入的平 均水平。 6 6','逻辑判断600题','进阶','published','{"globalNumber":5,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400006,6,'逻辑判断','为了解本市居民的收入状况，某大学5位同学走出校园，分别就个人年收入问题深 入城市各地，对本市居民进行随机采访。采访结果表明，有60%的受访者表示自己 的收入高于全国城市居民收入的平均水平，有10%的人认为自己正处于收入平均线 附近，还有10%的人认为自己的收入与全国平均水平相比还有不少差距，剩余20% 的人不愿意回答此问题。根据这一采访结果，这5位同学推断，本市居民收入的平 均水平要高于全国城市居民收入的平均水平。 以下哪项如果为真，最能质疑上述5位同学的推断：','[{"label":"A","content":"5 位同学的采访地分别位于城市的东南西北中"},{"label":"B","content":"采访中受访者一般都会对自己的收入有所夸大"},{"label":"C","content":"5 位同学随机采访的场所都是本市的高档商场"},{"label":"D","content":"有些受访者对自己的个人年收入可能并不清楚 四海公考 逻辑判断6 00"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":6,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400007,6,'逻辑判断','我国生产婴幼儿配方奶粉的企业有130多家，而美国只有4家企业，但是美国吃配 方奶粉的婴幼儿数量则远高于我国。“设想一下，如果只有4家企业生产配方奶粉。 企业会倍加珍惜自己的品牌价值，不断加强食品安全意识，任何可能的食品安全风 险都是企业自身无法容忍的，发生三聚氰胺这样的问题是不可想象的。” 以下哪项如果为真，最能削弱上述观点：','[{"label":"A","content":"我国生产婴幼儿配方奶粉的企业太多，品牌价值对于企业并不重要，所以这些企 业敢在奶粉中添加三聚氰胺"},{"label":"B","content":"某国的婴幼儿配方奶粉生产商有90多家，它们之中大多数企业生产出的奶粉均 未查出过三聚氰胺"},{"label":"C","content":"某公司是我国生产奶制品的著名企业，其品牌价值很高。但是在其生产的奶制品 中查出了三聚氰胺"},{"label":"D","content":"某企业是美国婴幼儿配方奶粉的著名生产商。在他们生产的某品牌配方奶粉中查 出了三聚氰胺"}]','D','【题型分类】 一般质疑类——严谨逻辑关系 【实战解析】题干结论为严谨逻辑关系，可翻译为：只有4家企业 →不会发生三聚氰胺问题。优先在选项中寻找“A 且非B” 选项： D 选项，可翻译为：美国只有4家奶粉生产商且发生三聚氰胺问题， 与题干命题矛盾，当 选①。 ⑩花生批注： 严谨逻辑关系题目， 直接在选项中寻找“A 且非B” 选项即可，避 免其他选项干扰。 ⑪花生批注： 其他选项： A选项，可翻译为： 非A 且非B; B 选项，可翻译为： 非A 且B; C 选项，可翻译为： 非A 且非B。','逻辑判断600题','进阶','published','{"globalNumber":7,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400008,6,'逻辑判断','大家往往认为，穿着深色面料的衣服，由于衣服大量吸收外界的热量，人们就会感 到十分闷热。而当穿着浅色的衣服时衣服能反射热量，人从而觉得凉爽。所以夏天 穿浅色的衣服比穿深色的衣服更凉快。 以下说法如果为真，不能质疑上述结论的是：','[{"label":"A","content":"黑色衣服虽然会吸收更多的热量，但同时也会吸收人体的热量"},{"label":"B","content":"在炎热的天气中，只要衣服宽松，无论穿的是黑色还是白色衣服，人的感觉都不 会有太大差别"},{"label":"C","content":"在炎热干旱的阿拉伯地区，受历史、文化、地理等多种因素的影响，很多人都会 选择穿黑色的长袍"},{"label":"D","content":"穿着白色长袍和黑色长袍站在烈日下暴晒30分钟，然后测量两种长袍的温度， 结果发现差异几乎为零"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":8,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400009,6,'逻辑判断','某地发布了公共场所禁烟条例之后，决定将整个地铁站都划定为禁烟区，但是仍然 有不少人在地铁站的厕所中偷偷吸烟，违反了规定。所以有人建议应当把地铁站的 厕所划定为专门的吸烟区，这样可以使烟民有一个抽烟的且不违反规定的地方。 以下哪项如果为真，最能削弱上述建议的可行性：','[{"label":"A","content":"即使划定新的吸烟区，烟民中仍旧有些人会逐渐到厕所以外的禁烟区吸烟"},{"label":"B","content":"划定新的吸烟区会把厕所的卫生和环境搞差，对非烟民的人是不公平的"},{"label":"C","content":"在厕所吸烟的人多了，其他禁烟区发现违规的人就少了"},{"label":"D","content":"地铁厕所作为吸烟区仍然不能解决地铁站发生火灾危险的问题 逻辑判断"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":9,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400010,6,'逻辑判断','某餐厅包厢在举办同学聚会。该包厢中，一个是广东人，两个是南方人，一个是河北人。 2人只做服装生意，3人只做机电生意。 假设以上陈述涉及了包厢中的所有人，则下列说法正确的是：','[{"label":"A","content":"该包厢中最少可能是3人，最多可能是8人"},{"label":"B","content":"该包厢中最少可能是5人，最多可能是8人"},{"label":"C","content":"该包厢中最少可能是5人，最多可能是9人"},{"label":"D","content":"该包厢中最少可能是3人，最多可能是9人"}]','B','。 ⑮花生批注： 此题为模型题，题目 中必然存在包含关系， 寻找即可。 ⑯花生批注： “生意组”和“地域组” 不相交时人最多。 地域组 3人生意组 5人 地域组 3人 ⑪花生批注： “生意组”包含“地 域组”时人最少。','逻辑判断600题','进阶','published','{"globalNumber":10,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400011,6,'逻辑判断','研究发现，细胞端粒遗传介质减少是导致阿尔兹海默症的原因，而且这种变化还会 隔代遗传。但是有反对者认为，脑部神经突起数目的减少使得大脑中神经元传递效 率变低，这是引发阿尔兹海默症的原因。 以下哪项如果为真，最能削弱反对者观点：','[{"label":"A","content":"细胞端粒遗传介质的减少是人们患上许多疾病的原因"},{"label":"B","content":"大脑中神经元传递效率变低会导致细胞端粒遗传介质减少"},{"label":"C","content":"细菌感染也会引起大脑变异引发阿尔茨海默症"},{"label":"D","content":"细胞端粒遗传介质减少会引起脑部神经突起数目降低"}]','D','【题型分类】归因类——直接根本原因 【实战解析】题干为直接根本原因题型，直接考虑“原观点导致反对 者(即细胞端粒遗传介质减少导致脑部神经突起数目减少)”这一形 式的答案，直接定位D 选项； 其他选项⑨ A 选项，细胞端粒遗传介质的减少是人们患上许多疾病的原因，但不 代表其就是阿尔兹海默症的原因，无法质疑； B 选项，大脑中神经元传递效率变低(反对者)导致细胞端粒遗传介 质减少(原观点)导致阿尔兹海默症，反对者的观点成了根本原因， 支持了反对者的观点； C 选项，细菌感染和神经突起数目减少使神经元传递效率变低(反对 者)都可能是引发阿尔兹海默症的原因，质疑力度不如D 选项。','逻辑判断600题','进阶','published','{"globalNumber":11,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400012,6,'逻辑判断','一个旅行者要去火车站，早上从旅馆出发，到达一个十字路口。十字路口分别通向 东南西北四个方向，四个方向上分别有饭店、旅馆、书店和火车站。书店在饭店的 东北方，饭店在火车站的西北方。该旅行者要去火车站，应当往哪个方向走：','[{"label":"A","content":"东"},{"label":"B","content":"南"},{"label":"C","content":"西"},{"label":"D","content":"北"}]','B','。 四海公考 逻辑判断60 0','逻辑判断600题','进阶','published','{"globalNumber":12,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400013,6,'逻辑判断','研究人员对平均年龄为66岁的648名痴呆症患者进行研究。发现掌握两种语言的患 者罹患痴呆的时间比只掌握一种语言的患者晚大约四年半，研究人员因此认为掌握 两种语言可以延缓痴呆的发生。 以下哪项如果为真，最能质疑上述结论：','[{"label":"A","content":"很多人患上痴呆之后大脑的言语功能均出现显著下降"},{"label":"B","content":"大脑认知功能好的人才会说双语，认知功能好可延缓痴呆"},{"label":"C","content":"相当多的人只掌握一种语言，但一生都未出现痴呆的症状"},{"label":"D","content":"掌握三种或以上语言的人，痴呆发生时间比掌握两种语言的稍晚"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":13,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400014,6,'逻辑判断','某大型餐饮服务企业在全公司范围内发起了“最受欢迎员工”的评选活动，获得“最 受欢迎员工”称号的人会获得公司的奖励，最终市场部的小兰以三分之二以上的票 数获得了这一称号，因此小兰是全公司最受欢迎的员工。 逻辑判断四海公煮 逻辑判断 下列选项最能削弱上述结论的是：','[{"label":"A","content":"公司的高层干部都没有参与这次活动，也没有投票"},{"label":"B","content":"小兰的有力竞争者小花由于上个月离职了，并没有参与评选"},{"label":"C","content":"评选后发现小兰的票数存在造假，实际上的票数只能排在第二"},{"label":"D","content":"参与投票的员工里有些是随便选的，并不认识小兰"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":14,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400015,6,'逻辑判断','某机场停车场T1区目前的收费标准是每小时5元，T2 区的收费标准是每12小时20 元。为了提高停车费收入，该停车场计划改变T1 区收费模式，改为2小时之内收费 10元，而后每小时收费5元。 下面哪项如果为真，该计划能提高机场停车费收入：','[{"label":"A","content":"长时间将车停在机场的旅客一般将车停在T2区"},{"label":"B","content":"过去5年间，T1 区的运行成本一直高于停车费收入"},{"label":"C","content":"在 T1 区内一次停车超过1小时的车辆占比不超过10%"},{"label":"D","content":"T1区扩建后面积提高了1倍，再也不会出现停车位紧张的情况"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":15,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400016,6,'逻辑判断','作为AI 领域目前最成熟的技术，人脸识别正在深入教育行业，在刷脸签到、学员身 份查询、校园安防、课堂教学效果检测等诸多场景中逐渐得到应用。有些人脸识别 技术甚至可以记录学生上课的行为、表情、专注度等多维度课堂数据，将对人脸的 识别上升到“对人的深刻理解”,为课堂教学评估提供强有力辅助资料。当下，人 脸识别技术正在飞速发展，但有专家预测，学校会谨慎甚至限制使用人脸识别技术， 这项技术不会有较大的校园市场。 以下哪项如果为真，最能支持上述专家的预测：','[{"label":"A","content":"学生、老师和家长都高度重视课堂教学效果"},{"label":"B","content":"人脸识别技术的应用涉及侵犯学生的隐私权"},{"label":"C","content":"人脸识别只用于监控而非实质改善教学效果"},{"label":"D","content":"人脸信息的收集与存储目前仍存在安全隐患"}]','B','。 25花生批注： 前文可看作背景，题 干只有结论：人脸识 别技术在校园不会有 较大市场。','逻辑判断600题','进阶','published','{"globalNumber":16,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400017,6,'逻辑判断','某知名跨国公司的总部员工中，所 有懂英语的员工都不精通印尼语；有些懂英语的 员工不精通西班牙语；有些懂韩语的员工精通印尼语；所有懂韩语的员工都精通西 班牙语；有些懂韩语的员工精通英语。 由此推论不正确的选项是：','[{"label":"A","content":"有些懂韩语的员工不精通印尼语"},{"label":"B","content":"有些懂印尼语的员工不精通西班牙语"},{"label":"C","content":"有些懂韩语的员工不精通英语"},{"label":"D","content":"有些懂英语的员工不精通韩语 逻辑判断"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":17,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400018,6,'逻辑判断','如果“只有小王是大学生，小王才懂英语”为假，则下列哪句为真：','[{"label":"A","content":"小王不是大学生，但小王懂英语"},{"label":"B","content":"小王是大学生，并且小王不懂英语"},{"label":"C","content":"小王不是大学生，并且小王不懂英语"},{"label":"D","content":"如果小王不是大学生，那么小王不懂英语"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":18,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400019,6,'逻辑判断','某机构决定从五位业务员中选派一人到国外学习，这五位骨干分别是赵、钱、孙、李、 周，在决定选派人选之前有如下对话： 赵说：或者是我去，或者是孙去； 钱说：周不去； 孙说：如果不是李去，那么就是钱去； 李说：既不是我去，也不是钱去； 周说：既不是孙去，也不是赵去。 最终确定人选后发现以上对话中只有两个人说对了，那么被选中的是：','[{"label":"A","content":"赵"},{"label":"B","content":"钱"},{"label":"C","content":"李"},{"label":"D","content":"周"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":19,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400020,6,'逻辑判断','只有在湿度高且光线昏暗的山林里才会有野生灵芝生长。紫金山林区没有野生灵芝 生长。 若以上判断为真，可推出以下哪项结论： I. 紫金山林区湿度不高并且光线不昏暗。 Ⅱ.如果紫金山林区光线昏暗，则肯定湿度不高。 Ⅲ.如果紫金山林区湿度高，则肯定光线不昏暗。','[{"label":"A","content":"仅 I"},{"label":"B","content":"仅Ⅱ"},{"label":"C","content":"仅Ⅱ和Ⅲ"},{"label":"D","content":"I 、Ⅱ 和Ⅲ都推不出 四海公煮 逻辑判断600o 四海公煮 练习题02"}]','D','。 练习题0 2 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":20,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400021,6,'逻辑判断','有人提出过，为什么不能给民航客机上的每个座位配备一个小型降落伞，发生意外 时每个人都能有求生的机会。实际上，这种做法的可行性很低。 以下各项如果为真，最不能支持上述观点的是：','[{"label":"A","content":"求生的本能会让机组人员放弃排除事故，而选择弃机跳伞"},{"label":"B","content":"民航飞行环境中的高度、温度、气压条件不符合跳伞要求"},{"label":"C","content":"飞机从发现故障到出事的时间一般很短，没有足够时间组织乘客跳伞"},{"label":"D","content":"飞机载客数量会因为配备了降落伞而减少，航空公司不愿因此降低收益"}]','D','。 ①花生批注： 题干的观点：为民航 客机每个座位配备降 落伞以增加意外时求 生机会，但这一做法 可行性低。 ②花生批注： 若此方法可提高乘客 生存概率，即使航空 公司因利益受损而不 愿意，民航总局也会 要求执行； “做法可行性低”, 应从做法本身是否有 作用角度进行支持。 17 17','逻辑判断600题','进阶','published','{"globalNumber":21,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400022,6,'逻辑判断','据某知名房产中介机构统计，2010年9月份第二周全国十大城市的商品房成交量总 体呈上涨趋势，并且与8月份第二周相比上涨幅度更明显。如果没有其他因素抑制， 按照这种趋势发展，9月份或将创新政以来成交量最高水平，虽然现在还不能明确 楼市完全回暖，但未来楼价调控的压力还是很大的。 下列最有可能是上述论证前提假设的是：','[{"label":"A","content":"炒房者将大量资金投入楼市"},{"label":"B","content":"国家对楼价的调控手段不足"},{"label":"C","content":"消费者对房子的购买热情没有减退"},{"label":"D","content":"楼市成交量的增长会带动楼价的上涨"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":22,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400023,6,'逻辑判断','暑期来临，甲、乙、丙、丁4位大学生决定赴西部某地的青山村、绿水村、红石村、 黄叶村进行调查研究，在这4个村落中，每人均选择了两个，而每个村落又恰有两 人选择，且每人所选择调研的村落并不完全相同。已知： (1)如果甲选青山村，则丙也选青山村； (2)如果乙选绿水村，则丁也选绿水村； (3)如果丁选绿水村，则丙选黄叶村； (4)甲不选绿水村，且丁不选青山。 村根据上述信息，可以得出下面哪项：','[{"label":"A","content":"甲选红石村"},{"label":"B","content":"乙选青山村"},{"label":"C","content":"丙选绿水村"},{"label":"D","content":"丁选黄叶村"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":23,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400024,6,'逻辑判断','S 市规定，适龄儿童须接种麻疹疫苗，适龄儿童必须接受义务教育，下图表示： 人数M120101990年 份2000 人数 M 12010 1990 年 份 2000 1990年到2010年间S 市儿童数量的一些统计，其中M表示接受义务教育的儿童总 数 ，N表示新生儿总数，P 表示接种麻疹疫苗的儿童总数，下面哪一项最能解释2000年 到2010年间S 市接受义务教育的儿童总数与接种麻疹疫苗的儿童总数下降程度的不同：','[{"label":"A","content":"2000 年至2010年间，有部分在S 市接种麻疹疫苗的儿童没有在S 市入学"},{"label":"B","content":"2000 年至2010年间，约有20%的父母没有按照S 市的规定让他们的孩子接种麻 疹疫苗"},{"label":"C","content":"2000 年至2010年间，每年都有不在S 市出生但已接种了麻疹疫苗的儿童在S 市 入学"},{"label":"D","content":"2000 年至2010年间，S 市新生儿总数下降，因此入学儿童总数和接种麻疹疫苗 的儿童总数也随之下降"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":24,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400025,6,'逻辑判断','近来网上出现了一则有关“公务员绿色出行”的报道，即A市教育局通过添置公务 自行车，使得较近距离的公务活动不再派汽车，从而大幅降低了公务汽车使用率。B 市环保局负责人看了这则报道，认为引进公务自行车能缩减财政开支，于是决定也 采取这种做法。 以下哪项如果为真，不能构成上述决定的前提条件：','[{"label":"A","content":"自行车出行的方式结合B城市的地理环境以及道路交通状况是可行又可取的"},{"label":"B","content":"B 市环保局的办公人员规模和已有公车数量与A市教育局相近"},{"label":"C","content":"较近距离的公务活动用自行车取代汽车不会影响办公效率"},{"label":"D","content":"B市环保局原来的公务活动主要采取汽车出行的方式"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":25,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400026,6,'逻辑判断','王涛的好朋友都喜欢歌手周某的歌。王涛在某咨询公司工作的同学都不喜欢歌手周 某的歌。丽莎既是王涛的同学，也是他的好朋友，米蓝是王涛的同学但不在该咨询 公司工作，贺宇是王涛的同学但不喜欢歌手周某的歌。 根据以上陈述，一定可以得出以下哪项： 四海公煮 600o','[{"label":"A","content":"米蓝喜欢歌手周某的歌"},{"label":"B","content":"王涛不在该咨询公司工作"},{"label":"C","content":"贺宇在该咨询公司工作"},{"label":"D","content":"丽莎不在该咨询公司工作"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":26,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400027,6,'逻辑判断','美国斯坦福大学的研究人员对130名同时患有血脂异常、高血压(并未服用降压药) 的患者进行了长达12年的试验。在试验中，研究人员将这130名研究对象随机分成 人数相等的两组，并让其中的一组研究对象服用松树皮提取物(每天服用的剂量为 200毫克),另一组研究对象服用安慰剂。在这12年中，研究人员每6周测量1次 研究对象的血压、血糖、胆固醇及C 反应蛋白的水平。试验结果显示，服用松树皮 提取物人员的上述各项指标与服用安慰剂人员的上述各项指标并无明显的差别。由 此可知，松树皮提取物无降血压、降血糖、降血脂以及预防心血管疾病等功效。 以下各项如果为真，最能反驳上述结论的是：','[{"label":"A","content":"两组试验患者仅人数相等，其血压和血脂等的原始指标差异较大"},{"label":"B","content":"对照组服用安慰剂，对高血压和高血脂患者有心理暗示作用"},{"label":"C","content":"12 年的实验时间太长，这有可能使一些重要的实验数据失真"},{"label":"D","content":"参加实验的患者人数仅130人，样本太小，代表性不够"}]','A','。 ⑩花生批注： 举例帮助理解： 假设四海学员平均分 是70分，五湖学员平 均分也是70分。不能 就此得出两个学校的 教学效果是一样的。 因为基础可能不一样， 若四海学员的基础是 40分，五湖学员的基 础是65分，那么两个 学校的教学效果显然 是不一样的。 ⑪花生批注： 对比实验归因题常见 错误选项：有些类选 项、实验瑕疵、未分 组或分组错误、未谈 及原因选项。','逻辑判断600题','进阶','published','{"globalNumber":27,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400028,6,'逻辑判断','研究人员研究了13只克隆绵羊，其中4只是世界上第一只体细胞克隆羊“多莉”的 复制品。研究者检测了这些克隆羊的肌肉骨骼、新陈代谢和血压情况。结果发现， 与对照组羊对比，这些克隆羊仅患轻度骨关节炎，只有一只为中度。它们没有新陈 代谢疾病的症状，血压也正常，相对健康。因此，研究人员指出，克隆动物的衰老 过程正常。 以下哪项如果为真，最能削弱上述论证：','[{"label":"A","content":"研究中对照组羊的年龄比实验组羊的年龄小"},{"label":"B","content":"世界上第一只克隆羊“多莉”仅仅存活了6年"},{"label":"C","content":"目前的体细胞克隆技术还远远没达到完善地步"},{"label":"D","content":"研究人员没有检测与衰老相关的主要分子标记"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":28,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400029,6,'逻辑判断','自由基是人类机体在消耗氧气时产生的一种有时会有害的自由分子，很多人相信自 由基是机体衰老背后的罪魁祸首。因为有研究人员发现，人类在衰老的过程中自由 基的数量在不断上升。 以下除哪项外，均能削弱上述结论：','[{"label":"A","content":"关于人类衰老的具体过程还存在着很多的争议"},{"label":"B","content":"自由基在对抗机体衰老的过程中数量会上升"},{"label":"C","content":"通过人工提升自由基的数量可延长机体的寿命"},{"label":"D","content":"染色体结构失去稳定性是导致人类衰老的原因"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":29,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400030,6,'逻辑判断','截至2011年底某市常住人口1100万人，其中本地人口800万人，外来人口300万人。 常住人口的男、女比例为1.03:1。该市高校众多，教育水平远高于全国平均水平。 常住人口中具有大学本科及以上学历的超过20%。 根据以上陈述，一定可以推出的是：','[{"label":"A","content":"本地本科及以上人口超过外来本科及以上人口"},{"label":"B","content":"本地女性人口超过外来女性人口"},{"label":"C","content":"本地男性人口超过外来女性人口"},{"label":"D","content":"本地男性人口超过外来男性人口"}]','C','【题型分类】分析类——日常分析 【实战解析】由题干条件可知：本地人>外来人，男性>女性， 则 本 地男性一定大于外来女性⑤,C 选 项 当 选⑨; 推理过程如下： ①本地人>外来人，拆解成②本地男+本地女>外来男+外来女； ③男性>女性，拆解成④本地男+外来男>本地女+外来女； ②+④可得：本地男+本地女+本地男+外来男>外来男+外来女 +本地女+外来女 化简得：本地男>外来女。 ⑯花生批注： 此类题目可记住模型， 大大>小小； 以本题为例：本地和 男性较多，外来和女 性较少，则本地男一 定大于外来女。 ⑪花生批注： 本题也可采用赋值法 由题干内容可计算得 出： 男性：558万；女性： 442万。 设本地男性为a, 则本 地女性为800-ao 外来女性=女性442- 本地女性(800- a) =a-358 由此可知本地男性a > 外来女性a- 358。','逻辑判断600题','进阶','published','{"globalNumber":30,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400031,6,'逻辑判断','一般来说，动物的蛋会通过土壤中微生物和堆肥分解有机物时产生的热量来孵化， 但这些微生物(包含细菌)也会穿透蛋壳、感染胚胎，自然情况下这一比例高于 20%。然而，在澳洲有一种名为丛家雉的鸟类，其蛋发生感染的几率仅为9%,研究 者发现其蛋壳中含有溶酶酵素，研究者据此认为这种物质很可能就是抵御细菌侵扰 的关键因素。 以下哪项如果为真，没有削弱上述结论：','[{"label":"A","content":"丛冢雉的蛋壳中所含的溶酶酵素量，与其他动物相比，含量大抵相当"},{"label":"B","content":"丛家雉的蛋壳被一层纳米级的碳酸钙层包裹，拥有了更强的防水性和抗细菌入侵 能力"},{"label":"C","content":"丛冢雉蛋散发一种特殊气味，会使附着在其蛋壳上的细菌数减少"},{"label":"D","content":"与其他动物的蛋壳相比，丛家雉的蛋壳要薄三分之一，更易受到微生物的入侵"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":31,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400032,6,'逻辑判断','新冠疫情给经济社会生活造成了严重影响，也使得无接触经济浮现在人们眼前，直 播带货、远程会议等新事物迅速涌进日常生活。经济活动的参与者在空间隔离的条 件下，通过网络等平台间接接触，实现人与物之间、人与人之间经济交往。这种方 式得到了消费者的高度认可。有专家就此断言，无接触经济会因新冠疫情而在未来 得到快速发展。 以下哪项如果为真，最能支持上述专家的断言：','[{"label":"A","content":"目前线上支付的安全性，及线上交易的企业与个人信用度均略有不足"},{"label":"B","content":"相对于无接触经济，“面对面”经济交往活动仍具有较低的交易成本"},{"label":"C","content":"如果新冠病毒传播具有长期性和反复性，人们仍会坚持“云端生活”"},{"label":"D","content":"人们注重生命健康，“无接触”消费习惯一经养成就会形成路径依赖"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":32,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400033,6,'逻辑判断','全球范围内的森林是一个巨大的碳汇，它们通过光合作用和林木生产所吸收的碳多 于其通过呼吸和腐烂所释放的碳。与此同时，在森林环境中，树木生长相对较快， 蒸发掉大量会形成云的水分，从而使气候冷却。这就意味着森林具有降温作用，还 吸收了更多的导致全球变暖的二氧化碳，所以说森林是显而易见的气候“冷却器”。 以下哪项如果为真，没有质疑上述观点：','[{"label":"A","content":"近十几年，一些地区不断增加林木植被，扩大森林覆盖率，但当地气候变暖并未 改善"},{"label":"B","content":"高纬度的北方森林会产生萜烯，萜烯形成气溶胶后会阻挡阳光、形成云粒"},{"label":"C","content":"在山区或干燥地区，森林会降低地球的表面反射率，让地球反射回太空的入射光 减少"},{"label":"D","content":"树木释放的有机化合物中，包含 一种名为异戊二烯的化合物，它能够与空气中的 氮氧化物发生反应，形成强大的升温作用"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":33,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400034,6,'逻辑判断','随着生活节奏的加快，很多人都会用时间管理软件来规划自己的时间，以 提升工作 效率。这一做法是可行的。因为大脑的“提醒功能”不够准确，很少能在正确的时 间做出正确的提醒，而外部提醒可以让人更好地掌握时间。 以下选项中最能削弱上述论断的是：','[{"label":"A","content":"时间管理软件会让人压力增大，影响工作效率"},{"label":"B","content":"时间管理软件质量参差不齐，人们难以辨别优劣"},{"label":"C","content":"时间管理软件会使人们的生活节奏进一步加快"},{"label":"D","content":"时间管理软件难以适用所有工作、生活事项"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":34,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400035,6,'逻辑判断','科学家去非洲考察，发现非洲沙漠的眼镜蛇数量锐减，但几乎同时胡狼的数量却明 显增加。有人认为是胡狼导致了眼镜蛇的减少。但这种说法难以成立，因为胡狼很 少以眼镜蛇为食。 以下哪项如果为真，最能削弱上述论证：','[{"label":"A","content":"眼镜蛇只吃沙鼠，而沙鼠也是胡狼的主要食物"},{"label":"B","content":"干旱缺水对眼镜蛇造成的影响比对胡狼造成的影响更加严重"},{"label":"C","content":"在胡狼的数量增加以前，非洲沙漠的眼镜蛇数量就已经减少了"},{"label":"D","content":"尽管眼镜蛇数量锐减，胡狼数量增加，但非洲沙漠里胡狼的数量仍少于眼镜蛇 逻辑判断600"}]','A','。 花生批注： 有人认为：胡狼导致 眼镜蛇减少； 有人反对：因为胡狼 很少吃眼镜蛇，所以 胡狼不是眼镜蛇减少 的原因。 3花生批注： 若理解为是“干旱缺 水导致眼镜蛇减少”, 就支持了“胡狼不是 眼镜蛇减少原因”。 ④花生批注： 异因同果的“三图质 疑”,质疑的是“胡 狼导致眼镜蛇数量减 少”,即支持了“胡 狼不是眼镜蛇减少的 原因 ”; 本题是对“否定此因” 的质疑，即要支持这 个原因，C 选项是“三 圈质疑”,正相反。 29 25花生批注： “C 型→识别颜色”, 1号识别对了颜色，但 不能据此判断它是C 型(终点无法向前推)。 6花生批注： “S 型→识别形状”, 2号识别对了形状，但 不能据此判断它是S 型(终点无法向前推)。 30 30','逻辑判断600题','进阶','published','{"globalNumber":35,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400036,6,'逻辑判断','某实验室一共有3种类型的机器人，C 型能识别颜色、S 型能识别形状、X型既不能 识别颜色也不能识别形状。3类机器人都能根据简单命令拿起实验品。实验室对1 号机器人和2号机器人进行实验，当命令它们拿起红球时，1号拿起的是红方块，2 号拿起的是蓝球。 根据上述实验，以下哪项断定一定为真：','[{"label":"A","content":"1 号和2号都是X型"},{"label":"B","content":"1 号和2号都不是X型"},{"label":"C","content":"1 号是C 型且2号是S 型"},{"label":"D","content":"1 号不是S 型且2号不是C型"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":36,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400037,6,'逻辑判断','某单位组织职工进行体检，职工可自愿报名参加。老王碰到新来的小李，聊起此事， 老王提醒小李说：“单位组织体检呢，赶紧报名去吧。”小李说：“我身体健康着呢， 不用报了。” 以下除哪项外，都可以作为小李的回答所包含的假设：','[{"label":"A","content":"如果身体不健康，则要报名参加体检"},{"label":"B","content":"只要我身体健康，我就不必参加体检"},{"label":"C","content":"凡是报名参加体检的，都是身体不健康的"},{"label":"D","content":"只有身体不健康的人，才报名参加体检"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":37,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400038,6,'逻辑判断','统计表明，某国的火车事故多发生在南部地区，因此在北部地区坐火车更安全。 以下哪项最能反驳上述论证：','[{"label":"A","content":"该国北部的火车车速较慢"},{"label":"B","content":"该国南部的火车线路比北部多得多"},{"label":"C","content":"该国南部的许多线路已经使用动车组 了"},{"label":"D","content":"该国北部大部分地区为山区，更适合汽车行驶"}]','B','【题型分类】一般质疑类——比例论证 【实战解析】论据结论见批注，观察选项： 典型的比例类论证⑨,题干只调查了火车事故多发生在南部(分子), 就得出北部地区火车更安全(即南部更危险)的结论，显然忽略了 火车运行的数量，去选项中寻找包含比例的“分母(火车运行数量)” 即可： B选项，指出南部火车多得多，即南部“分子(事故数量)”较北部“分 子”大，但“分母(运行数量)”较北部大的更多，南部事故发生率 反而更小，意味着南部火车更安全，当选。','逻辑判断600题','进阶','published','{"globalNumber":38,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400039,6,'逻辑判断','有两种农产品甲和乙，甲不能生长在干旱的气候里，乙不能生长在寒冷的气候里。 在某个国家的大部分地区，或者可以种植农产品甲，或者可以种植农产品乙。 如果以上陈述为真，则以下哪项一定为假：','[{"label":"A","content":"这个国家有一半地区的气候既干旱又寒冷"},{"label":"B","content":"这个国家大部分地区的气候是非常寒冷的"},{"label":"C","content":"这个国家根本不种植农产品甲"},{"label":"D","content":"这个国家只能种植农产品甲"}]','A','【题型分类】分析类—日常分析 【实战解析】由题干条件可知： ③花生批注：“非干旱或非寒冷” 的矛盾是“干旱且寒 冷”,一边超过一半， 另一边就要小于一半。甲不能生长在干旱的气候里，乙不能生长在寒冷的气候里，且“大部 分地区(即超过一半)”可种植甲或乙，那么此国家的一半以上地区 或者不是干旱气候或者不是寒冷气候，即干旱且寒冷地区一定小于一 半(见下图)②,由此可知A 选项一定为假； ③花生批注： “非干旱或非寒冷” 的矛盾是“干旱且寒 冷”,一边超过一半， 另一边就要小于一半。 干早 且寒冷干 旱 或非寒冷 干早 且寒冷 33花生批注：或者或者，一真则真； 只要满足“非干旱” 就符合要求，可以都 是寒冷的。其他选项： 33花生批注： 或者或者，一真则真； 只要满足“非干旱” 就符合要求，可以都 是寒冷的。 B 选项，如上图所示，左侧部分可以都是“非干旱且寒冷 ”,可能为真； C 选项，如上图所示，左侧部分可以都种植乙，“不种植甲”可能为真； D 选项，与C 选项同质，左侧部分可以都种植甲，可能为真。','逻辑判断600题','进阶','published','{"globalNumber":39,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400040,6,'逻辑判断','某企业计划组织员工参观文化馆、档案馆和博物馆，但由于时间有限，这三个场馆 不能都去。因此，有3名员工提出了以下建议： 甲：文化馆和档案馆之间距离很远，最多只去其中一个。 乙：档案馆和博物馆都有主题展览，两个都应该参观。 丙：去年已经组织参观过文化馆，今年就不去了。 结果发现，只有1名员工的建议被采纳，则下列判断必然正确的是：','[{"label":"A","content":"该企业一定去了档案馆"},{"label":"B","content":"该企业一定没去档案馆"},{"label":"C","content":"该企业一定去了博物馆"},{"label":"D","content":"该企业一定没去博物馆 13 练习题03"}]','B','。 ③④花生批注： “A、B 至多一个”可 翻译为“非A 或非B”。 ③5花生批注： A或B 为真，且A 为 假，根据“否一推一 ” 可得B 为真。 练习题03 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":40,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400041,6,'逻辑判断','格陵兰岛是地球上最大的岛屿，形成于38亿年前，大部分地区被冰雪覆盖。有大量 远古的岩石化石埋藏在格陵兰岛地下，它们的排列就像是一个整齐的堤坝，也被称 为蛇纹石。通过这些蛇纹石，人们可以断定格陵兰岛在远古时可能是一块海底大陆。 补充以下哪项作为前提可以得出上述结论：','[{"label":"A","content":"蛇纹石是两个大陆板块在运动中相互碰撞时挤压海底大陆而形成的一种岩石"},{"label":"B","content":"这些蛇纹石化石的年代和特征与伊苏亚地区发现的一致，而后者曾是一片海底大陆"},{"label":"C","content":"蛇纹石中碳的形状呈现出生物组织特有的管状和洋葱型结构，类似于早期的海洋 微生物"},{"label":"D","content":"由于大陆板块的运动才创造出了许多新的大陆，在板块运动发生之前，地球上绝 大部分地区是一片汪洋大海"}]','A','【题型分类】前提假设类——断点搭桥 【实战解析】论据结论可见批注。蛇纹石与海底大陆中间存在明显断 点，选项中只有A 选项将二者搭桥，可直接秒选，其逻辑关系如下： 格陵兰岛有蛇纹石，蛇纹石由海地大陆受挤压形成，所以可通过蛇纹 石断定格陵兰岛在远古时可能是海底大陆。 ②花生批注：断点搭桥题目正确答 案一定包含结论中新 内容。其他选项： ②花生批注： 断点搭桥题目正确答 案一定包含结论中新 内容。 B 选项，属于类比支持，有支持力度，但非前提假设类题目正确选项； C 选项、D 选项均未提及结论中新内容“海底大陆”② 34','逻辑判断600题','进阶','published','{"globalNumber":41,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400042,6,'逻辑判断','根据最新公布的统计结果，食物及皮肤过敏症是“小康病”。对相关数据细化分析后， 研究者惊讶地发现，家庭收入水平超过贫困线一倍的孩子，受过敏症困扰的风险最高， 而家庭收入在贫困线上的孩子患食物及皮肤过敏症的几率要显著低于收入高出贫困 线一倍的家庭的孩子。 下列选项如果为真，最能支持上述结论的是：','[{"label":"A","content":"家庭收入过低的家庭的孩子从饮食中摄入的营养偏单一，身体抵抗力较弱"},{"label":"B","content":"过敏性疾病是一类受遗传和环境因素影响的免疫性疾病，受父母体质影响较大"},{"label":"C","content":"小康家庭孩子的肥胖率明显高于贫困家庭，而肥胖导致的体能下降是过敏症的一 大诱因"},{"label":"D","content":"家庭收入较高的家庭更有能力承担日常消毒及清洁用品，使孩子有效隔离过敏源"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":42,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400043,6,'逻辑判断','一种生长在土豆根部的植物病菌有两组明显的遗传特征A和B, 研究人员有以下几 点假设：①特征A 和 B中至少有一个遗传性强；②特征A遗传性可能不强；③特征 A遗传性强；④特征B遗传性强。最后研究结论证明以上四点假设两个为真，两个 为假。 如果上述结论为真，则下列哪项为真：','[{"label":"A","content":"特征A遗传性强，特征B遗传性不强"},{"label":"B","content":"特征A遗传性不强，特征B遗传性强"},{"label":"C","content":"特征A遗传性强，特征B遗传性强"},{"label":"D","content":"特征A遗传性不强，特征B遗传性不强"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":43,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400044,6,'逻辑判断','一些学者指出，当前的大学教育在某些方面是失败的。有人对若干大公司调查发现， 很多新上岗人员进入公司后，连基本办公软件的操作、打印机的使用都不会。 以下哪项如果为真，最能支持上述论证：','[{"label":"A","content":"大公司的新上岗人员基本代表了当前大学毕业生的水平"},{"label":"B","content":"有的大学生在大学里面没有学过基本办公软件的操作、打印机的使用"},{"label":"C","content":"新上岗人员里很少有大学生"},{"label":"D","content":"基本办公软件的操作、打印机的使用对胜任工作很重要"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":44,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400045,6,'逻辑判断','为探索每周4天工作制的可行性，某集团进行了一次大规模的试验。结果表明，尽 管减少了工作天数，数千名员工仍然完成了原定的工作任务，且员工的工作压力水 平下降了7%,企业的办公成本如耗材、水电的消耗量也有所下降。有人因此认为， 4 天工作制不仅能降低企业的运营成本，还大大提高了企业员工的工作效率。 以下选项如果为真，最能质疑上述观点的是：','[{"label":"A","content":"实行4天工作制后，该集团一些分公司的营业收入有所降低"},{"label":"B","content":"实行4天工作制后，员工每天的工作时长从8小时变为10小时"},{"label":"C","content":"劳动法规制定的前提是保护劳动者权益，而非降低企业运营成本"},{"label":"D","content":"由于运营维护的需要，部分岗位的工作人员并不能实行4天工作制"}]','B','。 ⑨花生批注： 论据：减少工作天数 后，员工仍然完成了 原定的工作任务，并 且员工的工作压力和 企业的办公成本均有 所下降。 结论：4天工作制可以 降低企业的运营成本， 可以提高员工的工作 效率。 ⑩花生批注： 题干论据为对比实验， 根据“吃早餐与否的 男性”和“吃早餐与 否的女性”分组，实 验结果为无论男女， 不吃早餐体重增加的 都更多； 得到“如果不吃早餐， 无论男女，体重增加 的概率都会比较高” 的结论； 其中隐含了“不吃早 餐导致体重增加”的 归因过程。 ⑪花生批注： 若改成“在18岁以下 人群的调查中，未出 现上述实验结果”, 可以质疑。 ⑫花生批注： 对比实验归因题常见 错误选项：有些类选 项，实验瑕疵，未分 组或分组错误，未提 及原因。 ⑬花生批注： 题干只有结论：按照 几种类型评选最佳影 片可使电影工作者受 到更公平的对待、使 观众和电影爱好者更 有发言权。','逻辑判断600题','进阶','published','{"globalNumber":45,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400046,6,'逻辑判断','科学家对19岁以上的1524名男性和2008名女性共3532人进行了调查。结果显示， 不吃早餐的男性在1年内体重增加3公斤以上的比重是吃早餐的1.9倍之多；不吃 早餐的女性在1年内体重增加3公斤以上的比重是吃早餐的1.4倍之多。因此，他 们得出结论：如果不吃早餐，无论男女，体重增加的概率都会比较高。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"不吃早餐，男女体重不一定都会增加"},{"label":"B","content":"男女体重增加主要是早上睡懒觉造成的"},{"label":"C","content":"18 岁以下的人群不一定会出现研究中的结果"},{"label":"D","content":"相比男性，不吃早餐对女性体重增加的影响并不大"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":46,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400047,6,'逻辑判断','新一年的电影节的影片评比，准备打破过去的只有一部最佳影片的评比，而按照历史片、 爱情片等几种专门的类型分别评选最佳影片，这样可以使电影工作者的工作能够得到 更为公平的对待，也可以使观众和电影爱好者对电影的优劣有更好的发言权。 以下哪项假设最可能是上述评比制度改革隐含的前提：','[{"label":"A","content":"过去因为只有一部最佳影片，影响了电影工作者参加电影节评比积极性"},{"label":"B","content":"每一部影片都可以按照这几种专门的类型来进行分类"},{"label":"C","content":"划分影片类型，对于规范影片拍摄有重要的引导作用"},{"label":"D","content":"观众和电影爱好者在进行电影评论时喜欢进行类型的划分 15"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":47,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400048,6,'逻辑判断','健康专家在电视节目中劝说经常饮用纯净水的人群，与矿泉水相比，纯净水缺乏矿 物质，而其中有些矿物质是人体必需的。所以，人们应该改变习惯，多饮用矿泉水。 下列最能削弱健康专家观点的是：','[{"label":"A","content":"人体所需的不仅仅是矿物质"},{"label":"B","content":"人们可以从其他食物中摄取足够的矿物"},{"label":"C","content":"一些经常饮用矿泉水的人得了肾结石"},{"label":"D","content":"可以饮用纯净水和矿泉水以外的其他水"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":48,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400049,6,'逻辑判断','全球气候变暖给人类带来诸多影响的同时也影响着地球上的其他生物，降水的增加 可以改善植被，从而有利于鼠类的增长。研究表明，降水的增加使原本干旱的内蒙 古地区植物更加丰富，也增加了鼠类的食物，长爪沙鼠数量随之增加。 以下哪项如果为真，最能削弱上述论断：','[{"label":"A","content":"据统计，一些地区的植被覆盖率并没有增加"},{"label":"B","content":"据测算，全球沙漠化面积近年有所增加"},{"label":"C","content":"内蒙古地区植被的增加和近年的生态保护有很大关系"},{"label":"D","content":"植被的增加使各种动物包括鼠类的天敌都增加了"}]','C','。 40','逻辑判断600题','进阶','published','{"globalNumber":49,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400050,6,'逻辑判断','甲乙丙三人商量去钓鱼，甲说：如果乙去我就去；乙说：如果我不去，丙也不会去； 丙说：如果甲不去，那么我就去。那么可以推出的是：','[{"label":"A","content":"甲去钓鱼"},{"label":"B","content":"乙去钓鱼"},{"label":"C","content":"丙去钓鱼"},{"label":"D","content":"乙不去钓鱼"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":50,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400051,6,'逻辑判断','一项新研究中，研究者让大鼠们呼吸了某种空气，结果那些啮齿动物的体重增加， 科研人员推测，暴露在污染的空气中可能会增加患肥胖症的风险。 下列哪项最能质疑上述推论：','[{"label":"A","content":"长期呼吸污染空气对生物的健康有很大影响"},{"label":"B","content":"空气质量对啮齿动物的视力水平也存在影响"},{"label":"C","content":"在此次研究中受测的大鼠部分受到过核污染"},{"label":"D","content":"影响啮齿动物体重增加的因素与人完全不同"}]','D','【题型分类】归因类——一般归因 【实战解析】题干由“鼠”推“人”,存在类比推理， D 选项指出影 响啮齿动物(老鼠)体重增加的因素与人不同，针对此漏洞进行了攻击， 当选； 其他选项： A 选项、B 选项、C 选项，健康、视力、受过核污染均与肥胖无关， 无法质疑。 ⑲花生批注： 两难推理： A→B 与 非A→B, 可推得B; A→B 与A→ 非B, 可推得非A。 ②花生批注： 题干根据呼吸受污染 空气的大鼠体重增长， 得出暴露在污染空气 会增加肥胖症风险的 结论； 其中隐含了污染空气 导致大鼠体重增长的 归因过程。 ②花生批注： 论据：70%的参加者财 务管理基本知识水平 高，20%参加者有一定 水平； 结论：群众对于财务 管理基本知识掌握得 不错。 2 花生批注： 在“不能质疑”题目中， 可看作“可以质疑”。 42 42','逻辑判断600题','进阶','published','{"globalNumber":51,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400052,6,'逻辑判断','为了调查当下人们对财务管理基本知识的掌握程度，《财务与会计》杂志为读者开 展了一次财务管理知识有奖调查问卷活动。分析调查数据得知，70%的参加者对于 财务管理基本知识掌握的水平很高，20%左右的参加者也表现出了一定的水平。《财 务与会计》杂志因此得出结论，目前社会群众对于财务管理基本知识的掌握还是不 错的。 以下哪项，如果为真，最能削弱以上结论：','[{"label":"A","content":"财务管理基本知识的范围很广，仅凭一个调查问卷就得出结论未免过于草率"},{"label":"B","content":"掌握财务管理基本知识并不等同于能够灵活运用财务管理知识"},{"label":"C","content":"可能该杂志社工作人员的亲朋好友参与了此次调查问卷，并获得了奖品"},{"label":"D","content":"从定价、发行渠道等方面看，《财务与会计》的读者主要集中在高学历知识阶层"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":52,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400053,6,'逻辑判断','抹香鲸是体型最大的齿鲸。由于潜水能力极强，抹香鲸也是潜水最深、潜水时间最 长的哺乳动物。只有在有大量乌贼存活且不结冰的海域，才会有抹香鲸存活。阿拉 弗拉海域没有抹香鲸。 根据以上断定，可得出以下哪项结论： I. 阿拉弗拉海域或者没有大量乌贼存活，或者是结冰的海域 II. 只有在不结冰的海域里，乌贼才能存活 III. 阿拉弗拉海域没有齿鲸','[{"label":"A","content":"仅 I"},{"label":"B","content":"仅 II"},{"label":"C","content":"仅 III"},{"label":"D","content":"I, II 和 III 都得不出"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":53,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400054,6,'逻辑判断','近几年，购买轿车的人中买新车的人所占的比例下降了，一些销售商把这个现象归 因于新车价格的增长，他们认为，即使完全扣除掉物价增长的因素，现在一辆新车 的价格也比几年前高了很多。 以下哪项如果为真，最能反驳销售商的观点：','[{"label":"A","content":"一个人购买一辆新车到他下次买车会间隔几年时间"},{"label":"B","content":"一辆新车的价值往往下降的很快，但在一段时间后就不怎么下降了"},{"label":"C","content":"二手车销量的增加是由于现在市场上少数二手车经销商正低价抛售"},{"label":"D","content":"新车均价的改变是由于更多的人拒绝购买便宜的新车而选择购买二手车"}]','A','。 44','逻辑判断600题','进阶','published','{"globalNumber":54,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400055,6,'逻辑判断','随着社会发展，以及疾病谱、生态环境、生活方式等的不断变化，我国面临多重疾 病威胁并存、多种健康影响因素交织的复杂局面。这一局面将会严重影响人们的健康。 以下选项中最能削弱上述论断的是：','[{"label":"A","content":"近年来我国主要疾病发病率持续降低"},{"label":"B","content":"调查研究表明，这一局面难以在短时间内改变"},{"label":"C","content":"人们的健康会受到多方面因素的综合影响"},{"label":"D","content":"这一局面已经持续了很长时间 17 逻辑判断"}]','A','','逻辑判断600题','进阶','published','{"globalNumber":55,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400056,6,'逻辑判断','某班在统计学生政治面貌时，学生甲说到“班上有的同学是共青团员”,学生乙则 说道“我们班有的同学不是共青团员”,则下列判断错误的是：','[{"label":"A","content":"甲说的为真，乙说的也为真"},{"label":"B","content":"甲说的为真，乙说的为假"},{"label":"C","content":"甲说的为假，乙说的也为假"},{"label":"D","content":"甲说的为假，乙说的为真"}]','C','【题型分类】推出类——等价推出 【实战解析】将题干中包含逻辑关联词的一句翻译且简化为：不应付 →无法回答，直接定位C 选项： 45 ③2花生批注：“只有才”可翻译为 “后推前”和“不不”。C 选项， “只有才”可翻译为“不不”②,即“不应付→不能回答”, 与题干逻辑关系一致，当选； ③2花生批注： “只有才”可翻译为 “后推前”和“不不”。 其他选项： A 选项，可翻译为“提问具体明了→采访对象回答不困难”,“不困难” 无中生有； B 选项，可翻译为“无法回答→没有应付”,题干的逆命题，无法推出； D 选项，“泛泛的或言不由衷的回答”无中生有，无法推出。','逻辑判断600题','进阶','published','{"globalNumber":56,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400057,6,'逻辑判断','记者采访时的提问要具体、简洁明了，切忌空泛、笼统、不着边际。约翰 ·布雷迪在《采 访技巧》中剖析了记者采访时向访问对象提出诸如“您感觉如何?”等问题的弊端， 认为这些提问“实际上在信息获取上等于原地踏步，它使采访对象没法回答，除非 用含混不清或枯燥无味的话来应付。” 由此可以推出：','[{"label":"A","content":"记者采访时的提问如果具体、简洁明了，就不会给采访对象带来回答的困难"},{"label":"B","content":"采访对象如果没法回答提问，说明他没有用含混不清或枯燥无味的话来应付"},{"label":"C","content":"采访对象只有用含混不清或枯燥无味的话来应付，才能回答那些空泛、笼统的提问"},{"label":"D","content":"诸如“您感觉如何?”这样的问题，只能使采访对象抓不住问题的要点而作泛泛 的或言不由衷的回答"}]','D','','逻辑判断600题','进阶','published','{"globalNumber":57,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400058,6,'逻辑判断','某高速路段管理处决定招聘10名道路辅助管理人员，以解决正式管理人员不足的问 题，但这一建议招致某人士的反对，该人士认为，增加这10名道路辅助管理人员后， 将会有更多道路违规、违纪行为被发现，而后期处理这些问题需占用更多的正式管 理人员，这将导致本已紧张的正式管理人员更加不足。 以下哪项如果为真，最能削弱该人士观点：','[{"label":"A","content":"新招聘的道路辅助管理人员工作起来，未必能尽心尽职"},{"label":"B","content":"有许多道路违纪违法行为，当场就可以解决，不需要拖到后期处理"},{"label":"C","content":"道路辅助管理人员也可以对道路违规违纪行为进行后期处理"},{"label":"D","content":"增加道路辅助管理人员将有效减少该路段道路违规违纪行为发生 18"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":58,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400059,6,'逻辑判断','若在一墓穴中发掘出墓主的印章和墓志铭，就能确定该墓穴是墓主的真墓。在西高 穴大墓中，没有发掘出曹操的印章和墓志铭。故西高穴大墓不是真的曹操墓。 以下哪项的论证方式与题干最为类似：','[{"label":"A","content":"若在墓穴中发现刻有“魏武王”之类字样的随葬品，就能说明那个墓穴是曹操的。 在西高穴大墓中发现了刻有“魏武王常用格虎大戟”的石碑等随葬品。故该墓是 曹操墓"},{"label":"B","content":"十八岁的人还没有面对过社会上的问题，而任何没有面对过这些问题的人不能够 进行投票。所以，十八岁的人不能够进行投票"},{"label":"C","content":"只有持有深水合格证，才能进入深水池。高亮没有深水合格证，所以，他不能进 入深水池"},{"label":"D","content":"如果我有翅膀，我就能飞翔。我没有翅膀，所以，我不能飞翔"}]','D','。 ③④花生批注： “只有才”可翻译为 “不不”。 47','逻辑判断600题','进阶','published','{"globalNumber":59,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400060,6,'逻辑判断','在以下5×5矩阵中，每个小方格中可填入一个汉字，要求每行每列均含有金、木、 水、火、土5个汉字 ，不能重复也不能遗漏，根据已经给到的条件，矩阵中①所在 方格中应填入的汉字是： 木 ① 土 水 金 火 土','[{"label":"A","content":"金"},{"label":"B","content":"火"},{"label":"C","content":"水"},{"label":"D","content":"土 19 19 练习题04"}]','D','。 练习题04 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":60,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400061,6,'逻辑判断','有一段时间，电视机生产行业竞争激烈。由于电视机品牌众多，产品质量成为消费 者考虑的首要因素。某电视机生产厂家为了扩大市场份额，一方面加大研发力度， 进一步提高了电视机产品的质量另一方面在价格上作调整，适当降低了产品的价格。 然而，调整之后的头三个月，其电视机产品的市场份额不但没有提高反而有所下降。 以下哪项如果为真，最能解释上述现象：','[{"label":"A","content":"消费者通常会考虑不同产品的价格差异，而非同一产品在不同时期的价格差异"},{"label":"B","content":"一个家庭再次购买电视机产品时会首先考虑原来的品牌"},{"label":"C","content":"消费者通常是通过价格来衡量电视机产品质量的"},{"label":"D","content":"其他电视机生产厂家也调整了产品价格"}]','C','。 ①花 生批注： 题干中看似矛盾实则 合理的现象是：某电 视机厂家提高质量降 低价格，但市场份额 却不升反降。 49 49','逻辑判断600题','进阶','published','{"globalNumber":61,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400062,6,'逻辑判断','某小区一些住户乱停乱放车辆，常常造成交通堵塞。小区物管对一位乱停车辆的车 主说：“如果你不在规定的时间内将车开走，我们将对你实施罚款处罚。”该车主 回答：“我坚决不同意。” 按照车主的说法，他同意的是：','[{"label":"A","content":"在规定时间内不将车开走，也不接受处罚"},{"label":"B","content":"在规定时间内将车开走以免受处罚"},{"label":"C","content":"在规定时间内不将车开走，接受处罚"},{"label":"D","content":"延期将车开走，并免受处罚"}]','D','②。','逻辑判断600题','进阶','published','{"globalNumber":62,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400063,6,'逻辑判断','国外某公司从农户手中收购伪步行虫和蟋蟀等昆虫，把它们加工成粉末或油，再与 其它食材混合，制成让人吃不出昆虫味道的美味食品。2019年该公司销售这种食品 已实现百万美元盈利。联合国粮农组织肯定这家公司的做法，并指出食用昆虫，有 利于应对世界性粮食供应紧缺和营养不良的问题。 上述论证若要成立，必须增加的前提是：','[{"label":"A","content":"世界粮食供应紧张状况还将持续，开发昆虫等新食材，可有效应对食物需求增长"},{"label":"B","content":"昆虫富含蛋白质、脂肪、补足维生素和铁的营养成分，是量大低成本的补充食材"},{"label":"C","content":"国外某权威研究机构称，在本世纪，食用昆虫有利于人口增长和蛋白质消费增加"},{"label":"D","content":"亚洲、非洲一些缺粮且人口营养不良的地区在大力发展昆虫养殖加工业"}]','B','。 ④花生批注： 断点搭桥题目，要有 目的的寻找包含结论 新内容的选项，不要 被其他选项过度干扰。','逻辑判断600题','进阶','published','{"globalNumber":63,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400064,6,'逻辑判断','随着网络技术、数字技术的发展，人 们的阅读方式、阅读途径更加多元化，并且不 断深化与拓展，呈现出数字阅读的新态势。阅读本是一种极具个人风格的私事，但 在社交媒体环境中，数字阅读成为了一件能够与他人共享、交流的事情；数字阅读 的行为习惯，推广方式及平台等也都在发生变化。 以下各项如果为真，最能加强上述论证的是：','[{"label":"A","content":"有统计显示去年实体书店的销量下降了30%左右"},{"label":"B","content":"有数据显示去年电子书的购买率下降了10%左右"},{"label":"C","content":"社交媒体本身能为数字阅读找到更直接分享对象"},{"label":"D","content":"数字阅读的“智能”元素改变了传统阅读的本质"}]','C','。 ⑤花生批注： 前文可看作背景与分 析，结论是对上文总 结，全文就一个结论： 社交媒体环境中的数 字阅读变得能共享； 数字阅读行为习惯， 推广方式及平台等发 生变化。 逻辑判断','逻辑判断600题','进阶','published','{"globalNumber":64,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400065,6,'逻辑判断','某消费导向杂志在读者中做了一项调查，以预测明年的消费趋势。在被调查者中， 有57%的人在明年有奢侈品项目消费的计划。该杂志由此推测：明年消费者的消费 能力会很强。 以下哪项如果为真，最能削弱该杂志的推测：','[{"label":"A","content":"该刊物的读者要比一般消费者富有"},{"label":"B","content":"并非所有该刊物的读者都对调查作了回答"},{"label":"C","content":"大多没有奢侈品项目消费计划的人都打算存钱买房"},{"label":"D","content":"计划购买的奢侈品大多是进口的，并不能刺激国内市场"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":65,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400066,6,'逻辑判断','某国政府在半年内两次宣布降低购房按揭贷款的利率，因此很多潜在的购房者都处 于持币待购的状态，进一步观望利率能否再探新低，所以六月份新建房屋的销售量 大幅下降。但是，一个值得关注的现象是，在新建房屋销售量大幅下降的同时，新 建房屋销售的平均价格却在快速上涨。 以下哪项如果为真，能解释这一矛盾现象：','[{"label":"A","content":"新建高价房处于热销中，价格一路上涨，因为高价房的购买者基本不受利率波动 的影响"},{"label":"B","content":"受利率波动的影响，已购房者惜售手中的房屋，造成二手房的供应量不足"},{"label":"C","content":"过去三年中，由于住房供应短缺的问题越来越严重，使得新建房屋的销售量一直 在缓慢上涨"},{"label":"D","content":"受国际市场的影响，一年来该国建筑材料价格不断波动"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":66,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400067,6,'逻辑判断','近年来，化妆品消费市场上，国产化妆品的市场占有率显著提升，品牌效应日益凸显。 一项关于国产化妆品购买意愿的调查显示，74%的被调查者表示赞成购买国产化妆 品。但是当问及这些被调查者是否曾购买国产化妆品自用，却有70%的人表示“没有”。 如果以下各项为真，最能够解释上述看似矛盾的现象的是：','[{"label":"A","content":"70% 的被调查者表示，欧美化妆品的历史更久，品牌更大，更能够引领时尚"},{"label":"B","content":"大部分被调查者在购买自用化妆品时，主要考虑其功效及自身肤况，不太考虑产地"},{"label":"C","content":"购买国产化妆品的消费者中，70%的人将其作为礼物送人，只有30%的人选择自用"},{"label":"D","content":"大部分被调查者表示，会将每年的化妆品消费支出控制在1000元以内"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":67,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400068,6,'逻辑判断','辐射指的是由发射源(电磁波等)发出的电磁能量中一部分脱离场源向远处传播， 而后不再返回场源的现象，能量以电磁波或粒子的形式向外扩散。太阳辐射也是一 种常见辐射。长期受辐射影响，会使人产生不适，严重的可能造成人体器官和系统 的损伤，导致各种疾病的发生。因此，有专家声称：为保护身体健康，不能暴露在 太阳光下。 下列选项最不能质疑上述论证的是：','[{"label":"A","content":"太阳的紫外线在大气传播中不断衰减，真正照射到地球表面的辐射量只占总辐射 的4%"},{"label":"B","content":"有研究表明，常晒太阳对身体有很多益处"},{"label":"C","content":"晒太阳会导致皮肤晒伤，诱发皮肤癌变"},{"label":"D","content":"有科学论证，阳光中的紫外线可以刺激骨髓制造红血球，提高造血功能"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":68,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400069,6,'逻辑判断','在国家社科基金重大项目招标中，甲、乙、丙、丁、戊、己等六所高校参与了投标。 根据相关规则，最终只能有一所高校中标。关于究竟哪所高校是中标者，公布结果 前参与投票的三位评审专家谈了各自的看法： (1)中标的高校不是甲就是乙； (2)中标的高校不是丙； (3)戊和己两所高校均未中标。 对照后来公布的中标结果，发现上述三位专家中只有一人的看法是正确的。 根据以上信息，可以确定下列哪项中的三所高校均未中标：','[{"label":"A","content":"甲、戊、己"},{"label":"B","content":"丙、戊、己"},{"label":"C","content":"甲、乙、丁"},{"label":"D","content":"甲、丙、丁 22"}]','C','。 ⑨花生批注： 此题中，甲乙同质， 只是名称不同，所以 可能同时考虑。 同理，戊己同质，也 可同时考虑； 据此，观察选项，A 、 D 选项只包含甲，甲 乙同质，有甲必有乙， 两选项均可排除； 若选项合适，此方法 可秒杀。','逻辑判断600题','进阶','published','{"globalNumber":69,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400070,6,'逻辑判断','某市近年来，统计发现中小学生存在营养过剩，肥胖人群超标的问题，为了提高中 小学生身体素质，养成每日锻炼习惯，在2015年、2018年先后建成两个运动场馆， 通知中小学生可凭借学生证办理免费健身卡，2015年底全市共计办理健身卡3万余 张，2018年底共办理健身卡7万余张。2019年，该市又在西郊建成第三个体育馆， 于2020年落成开放，截至2020年底，全市共计办理健身卡11万余张，市政府认为 该项举措是有效的，因为在短短5年间，办理健身卡的学生人数增加了两倍多。 下列最能削弱上述结论的是：','[{"label":"A","content":"该市中小学生人数在增加，2015年底为20万人，2020年底为30万人"},{"label":"B","content":"体育馆需要不断购置健身休闲器材，维护成本较高，难以平衡财政支出"},{"label":"C","content":"很多办理第一个体育馆健身卡的学生又办理另外两个体育馆的健身卡"},{"label":"D","content":"有部分学生在办卡后，从未去过体育馆运动"}]','C','【题型分类】 一般质疑类——有论据有结论 【实战解析】论据和结论见批注。用办卡次数推出办卡人数的结论明 显存在错误(可能存在一个人多次办卡的情况),针对此漏洞进行攻 击即可； C 选项，指出很多办理第一个体育馆健身卡的学生又办理了另外两个 体育馆的健身卡，即健身卡增加两倍多，人数可能未变，政府举措不 一定有效。针对逻辑漏洞质疑，当选； 其他选项： A 选项，指出该市小学生人数增加，但未提及建设体育馆这一举措是 否有效，无法质疑； ⑪花生批注：若这一部分学生人数 极少，则完全不能质 疑此举作用。B 选项，体育馆成本和建设体育馆是否可改变中小学生身体素质话题 不一致，无法质疑； ⑪花生批注： 若这一部分学生人数 极少，则完全不能质 疑此举作用。 D 选项，指出部分学生①办卡后未去体育馆运动，但不确定此类人数 有多少，质疑力度很弱，不如C 选项。 56','逻辑判断600题','进阶','published','{"globalNumber":70,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400071,6,'逻辑判断','在一项实验中，研究者让大学生回忆他们在高中时期的成绩，告知他们研究者将会 从高中获取其真实成绩，所以撒谎没有任何意义。结果显示：参与者回忆起的成绩 有五分之一都和实际不符，而不同等级的成绩，被误记的概率也是不同的。分数越 高越不容易记错：得了A的时候总是能准确地被回忆起来，但得了F 的时候却难以 被想起。 根据以上信息，可以推出的是：','[{"label":"A","content":"人们记忆中的成绩可能比真实的成绩更优秀"},{"label":"B","content":"一般来说，人们最擅长的就是对细节的遗忘"},{"label":"C","content":"错误的记忆可以保护我们对公平正义的信念"},{"label":"D","content":"错误的记忆让我们自我感觉良好，利于健康"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":71,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400072,6,'逻辑判断','王某出游途中，在某河道旁洗车，污水流入河道产生污染。当地政府工作人员发现 后试图制止他的行为，但是他不仅不听劝，反问：“我就是洗个车而已，与工业污 染相比算得了啥，那些往江河湖海排污水、往大气中排污染气体的厂家，你们管得 了吗?制止住了吗?” 以下最能反驳王某观点的是：','[{"label":"A","content":"制止工业污染需要付出经济代价"},{"label":"B","content":"为了保护环境，任何污染行为都应该制止"},{"label":"C","content":"生活污染对环境的破坏不亚于工业污染"},{"label":"D","content":"当地政府已经多次查处违法企业的偷排行为"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":72,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400073,6,'逻辑判断','在上课时间与学习成绩的关联研究中，研究者跟踪调查了10所中学里就读的上万名 学生，结果发现：如果将早晨上课时间推迟半个小时，一个学期后，学生们的数学、 英语、科学成绩普遍提高了1/2个等级，如从B 提高到B+的位置。因此，研究者认 为推迟半个小时上早课，有助于保证学生更加充足的睡眠，从而提高成绩。 以下哪项如果为真，最能削弱上述观点：','[{"label":"A","content":"调查中少数学生有部分课程的成绩降低了1个等级"},{"label":"B","content":"即使推迟上课时间，成绩提高的学生依然早起预习"},{"label":"C","content":"推迟半个小时上早课，缩短了学生上课的整体时间"},{"label":"D","content":"改善学生的学习方法，会有效提高学生的学习成绩"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":73,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400074,6,'逻辑判断','研究者在2009至2018年间针对10万余名平均年龄为42岁的健康成年人展开研究。 研究内容包括他们的含糖饮料摄入量及他们在多年随访期内的患癌状况。结果显示， 每天饮用含糖饮料100毫升，总体患癌风险会增加18%,患乳腺癌的风险更是高出 22%。研究人员推测，饮料中含有较多的糖，而糖会对内脏脂肪、血糖水平等产生影 响，进而增加患癌风险。 以下哪项如果为真，最能质疑上述推断：','[{"label":"A","content":"某些高血糖患者食用无糖食品，其癌症发病率较低"},{"label":"B","content":"饮料中的添加剂等物质是患癌风险增加的主要因素"},{"label":"C","content":"经常喝纯果汁会增加人体的患癌风险"},{"label":"D","content":"内脏脂肪和血糖水平升高是患癌的主要因素之一"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":74,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400075,6,'逻辑判断','某大学教授认为，我国住房公积金制度自实行以来，只有一些有购房能力的缴存职 工享受到了低息购房贷款，而对于那些收入较低且无购房能力的工薪阶层并没有起 到住房保障作用。所以，住房公积金制度是一种“劫贫济富”的制度，国家应该取 消住房公积金制度。 以下哪项如果为真，将最能削弱该教授的观点：','[{"label":"A","content":"住房公积金制度是国家建立的一项强制性住房保障制度"},{"label":"B","content":"企业缴存部分的公积金对个人来说是一项额外收入"},{"label":"C","content":"民营企业的缴存职工因收入不高而没有购房能力"},{"label":"D","content":"外地务工人员一般不愿意在工作地买房 24"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":75,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400076,6,'逻辑判断','为什么青少年会更“热血”,更冲动，更容易冒险，有研究显示，这跟青少年大脑 前额叶皮层的功能有关。前额叶皮层具有负责调控注意力、作出计划、理性思考、 调控情绪的能力，这部分皮层一般要等到25岁左右才能发育完全。因此，25岁之 前谈理智是没有意义的。 以下各项如果为真，哪项最能质疑上述结论：','[{"label":"A","content":"青少年时期的大脑中多巴胺的分泌很旺盛，使得青少年更喜欢新鲜刺激的游戏"},{"label":"B","content":"婴幼儿时期大脑发育相对青少年时期更加幼稚和不成熟，但 也能逐渐学会控制大 小便"},{"label":"C","content":"大脑有“用进废退”的现象，青少年大脑前额叶皮层可通过不断训练而促进其成熟"},{"label":"D","content":"很多中年人也经常有冲动冒险、情绪失控的行为，前额叶皮层发育完全也并不意 味着就一定很理智"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":76,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400077,6,'逻辑判断','所有工作都是有报酬的，而任何有报酬的工作都是可以用金钱衡量的。因此，公益 劳动不是工作。 上述论证的成立，必须补充以下哪项前提：','[{"label":"A","content":"公益劳动不可以用金钱衡量"},{"label":"B","content":"有报酬的工作不是公益劳动"},{"label":"C","content":"公益劳动不是有报酬的工作"},{"label":"D","content":"一切有报酬的工作都是工作"}]','A','【题型分类】前提假设类——断点搭桥 【实战解析】题干分析见批注。论据中的“可以用金钱衡量”与结论 中的“公益劳动”之间有断点，需搭桥，观察选项： ②0花生批注： 举例便于理解： 6岁之前儿童控制大小 便系统才能完全发育 成熟，所以6岁之前 告诉儿童控制大小便 是无意义的； C 选项，告诉儿童控 制大小便可促进相关 系统成熟，可能更早 的学会控制大小便， 所以6岁前告诉儿童 控制大小便是有意义 的； D 选项，成年人也有 控制不住大小便的情 况，6岁之后不意味着 一定能控制大小便， 成年人是否完全控制 大小便和“6岁前教育 儿童控制大小便是否 有意义”完全无关。 ②花生批注： 论据：工作→有报酬 →可以用金钱衡量； 结论：公益劳动→非 工作。 花生批注： 题干将死亡风险增高 的原因归为脂肪含量 少。 3 花生批注： 例如：节食比运动更 能减肥，无法质疑“运 动能减肥”。 62 62 A 选项，可翻译为：公益劳动→不可以用金钱衡量，与论据联立，可 得出：公益劳动→非工作，属于断点搭桥，且利用了题干所有条件， 当选； 其他选项： B 选项、C 选项，互为逆否命题，均可翻译为：公益劳动→非有报酬， 也可得出：公益劳动→非工作，但未用到“可以用金钱衡量”这一条件， 并非原题干缺少的前提，排除； D 选项，未包含公益劳动，排除。','逻辑判断600题','进阶','published','{"globalNumber":77,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400078,6,'逻辑判断','研究人员基于生物库大样本队列，采用生物电阻抗测量脂肪含量，分析其与死亡风 险的关系，结果显示脂肪含量过少与死亡风险增高存在关联。研究人员认为，脂肪 含量过少的人，死亡风险会增高。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"在生活方式不健康的人群中，脂肪含量过多或过少均会增加死亡风险"},{"label":"B","content":"脂肪含量过多给人带来的死亡风险高于脂肪含量过少带来的死亡风险"},{"label":"C","content":"脂肪含量过少和死亡风险高都是由疾病带来的，疾病是二者的共同原因"},{"label":"D","content":"低脂肪的饮食可以改善血脂的代谢、降低胆固醇、降低低密度脂蛋白的水平"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":78,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400079,6,'逻辑判断','G镇 A小区内老王家出现了不少飞蛾，除非小区里业主家出现了飞蛾，否则小区不 能向居委会申请除蛾的药剂。G镇B小区可以向居委会申请除蛾的药剂。 如果上述断定为真，则下列哪项不能断定真假： I.A 小区有的业主家中没有发现飞蛾。 Ⅱ. A小区可以申请除蛾的药剂。 Ⅲ. B小区的业主家均出现了飞蛾。','[{"label":"A","content":"只有I"},{"label":"B","content":"只有Ⅱ"},{"label":"C","content":"只有 I 和Ⅲ"},{"label":"D","content":"I 、Ⅱ 和Ⅲ"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":79,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400080,6,'逻辑判断','近期女子乒乓球世界排名前7名(没有并列)在甲、乙、丙、丁、戊、己和庚(这 不是排名顺序)7人中产生。已知： (1)甲排名第4; (2)乙和丙的排名在甲之前； (3)丁的排名在乙之前； (4)排名第6的是一名外国选手； (5)在排名中，每一名外国选手的前一名都是中国选手； (6)戊是一名外国选手。 如果己和丙排名之间隔着两人，则可以得出下列哪项：','[{"label":"A","content":"己排名第7"},{"label":"B","content":"庚排名第5"},{"label":"C","content":"乙和庚排名之间隔着两人"},{"label":"D","content":"乙和庚排名之间隔着三人 26 练习题05"}]','D','【题型分类】分析类 日常分析 【实战解析】根据已知条件(1)(2)(3)可知，乙丙丁排名前三名， 戊己庚排名后三名； 根据(4)(5)(6)可知，戊只能在第六名； 根据已丙相隔两人，己只能在第五名，丙在第二名； 根据(3),可确定丁在第一名，乙在第三名； 由此，可以得出如下表格情况： 1 2 3 4 5 6 7 丁 丙 乙 甲 己 戊 庚 综上，只有D选项正确。 逻辑判断 练习题05 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":80,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400081,6,'逻辑判断','俗话说“每逢佳节胖三斤，仔细一看三公斤”。春节过后，人们摸着肚子上突然显 露的一圈肥肉细思极恐，迫不及待地开始了新一轮的疯狂节食和运动。不过，很多 人通过运动、节食减肥好一段时间了，但是仍然看不到效果。 以下哪项如果为真，最能解释上述现象：','[{"label":"A","content":"减肥欲速则不达，事实上，减肥速度最好是要控制在一个月减一到两公斤"},{"label":"B","content":"在减肥的过程中不宜天天称体重，一周一次就好，最好在起床空腹时称重"},{"label":"C","content":"太瘦的人身体内的蛋白量比较低，处于一种低水平健康状态，易受伤害"},{"label":"D","content":"人体对体重的下降很敏感，会通过刺激饥饿感来提醒自己多吃以维持体重"}]','D','。 ②花生批注： 论据：智商高更容易 在某个专业领域取得 成绩，情商高通常有 完满的婚姻家庭和良 好的人际关系； 结论：父母为了孩子 的幸福更应该注重情 商培养(即情商高比 智商高可以获得更多 的幸福)。 66 66','逻辑判断600题','进阶','published','{"globalNumber":81,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400082,6,'逻辑判断','小王、小张、小赵、小刘四人讨论比赛四强的甲、乙、丙、丁四个队伍哪个将获得冠军。 小王：“乙是冠军。” 小张：“冠军是丁或丙。” 小赵：“冠军是甲或丁。” 小刘：“甲和丙不是冠军。” 结果出来后，只有两个人的推断是正确的，冠军是：','[{"label":"A","content":"甲"},{"label":"B","content":"乙"},{"label":"C","content":"丙"},{"label":"D","content":"丁"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":82,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400083,6,'逻辑判断','有研究指出，智商高的人更容易在某个专业领域取得成绩，而情商高的人，通常有 较完满的婚姻和家庭，有良好的人际关系。专家指出，为了孩子的幸福，父母应该 更加注重对孩子情商的培养。 以下最能支持上述专家观点的是：','[{"label":"A","content":"相比于社会环境因素，遗传因素对智商的影响更大"},{"label":"B","content":"许多成功的专业人士的智商并不是很高，但情商很高"},{"label":"C","content":"一个人的情商水平，与其童年时期接受的教育培养关系密切"},{"label":"D","content":"良好的人际关系和家庭状况比专业成就更能让人获得幸福感 27"}]','D','【题型分类】支持类——断点搭桥 【实战解析】论据结论见批注， 结论中的“更幸福”为新内容③,正 确选项中一定包含，观察选项： A 选项、B 选项、C 选项均未提及“幸福”,无法通过断点搭桥支持， 先略过； D 选项，意味着“情商高”比“智商高”更容易获得幸福感，即培养 情商更能让孩子获得幸福感，断点搭桥，当选； 整个逻辑过程如下： “智商高容易有专业成就，情商高有良好人际关系和家庭状况”+“良 好人际关系和家庭状况比专业成就更容易让人获得幸福感”推出“要 想获得幸福感，父母更应培养孩子的情商”。','逻辑判断600题','进阶','published','{"globalNumber":83,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400084,6,'逻辑判断','研究人员对40名在校大学生进行了实验，他们让这些学生记忆斯瓦西里语对应的英 文单词，一共十组，每组十对词汇，每学习完一组，对参与者进行回想测验，测验中， 每错一次，他们将会看到两种图片的一种，一种是可以产生负面情绪的图片，例如 一把指向自己的枪；另一种是普通的图片，例如一把椅子或是一个空白影像。随后 对他们进行一分钟的附加实验，清除短暂记忆的效果。最后再对这一百对词汇的记 忆情况进行检测。测验结果显示，那些获得最好成绩的学生之前看的都是有负面影 响的图片。因此，研究人员认为，负面情绪有助于记忆力提高。 以下哪项如果为真，能够解释这一现象：','[{"label":"A","content":"看有负面影响的图片时，大脑仍在进行记忆信息的处理"},{"label":"B","content":"这40名被试大学生中，有的人曾经学过斯瓦西里语"},{"label":"C","content":"能引发负面情绪的图片更容易使人记忆深刻"},{"label":"D","content":"人们在情绪不稳定时，注意力很难集中"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":84,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400085,6,'逻辑判断','某科研机构研发了一项神经刺激技术，他们在试验中对一批滑雪选手实施了该刺激， 持续数周后发现，相比未接受刺激的选手，接受刺激选手的跳跃能力和协调性分别 提高了10%和15%。本国体育部门计划与该机构合作，在滑雪运动员的训练、比赛 中推广使用这一技术。 以下哪项为真，最能质疑该国体育部门的计划：','[{"label":"A","content":"未接受刺激的运动员通过正常训练也能提高跳跃能力和协调性"},{"label":"B","content":"这项合作会增加该国体育部门的经费支出"},{"label":"C","content":"该国是传统滑雪强国，滑雪成绩长期处于世界领先地位"},{"label":"D","content":"这项技术会降低运动员的专注力，而专注力是能力发挥的前提"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":85,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400086,6,'逻辑判断','某企业秉持人才为上的理念，一直致力于专业技术人才队伍建设，十年来，该企业 招聘的大部分机械工人来自甲职业技术学院，今年招聘的机械工人总数明显增加， 但从该学院招聘的机械工人数量却大幅减少，而且招进来的很多人没有经过职业技 术学院系统的学习。 以下哪项如果为真，最能解释该企业今年招聘情况的变化：','[{"label":"A","content":"该企业增设了技术培训部门，以培训新招聘的机械工人"},{"label":"B","content":"三年前，该企业的管理层进行了重大重组，决定推广AI 的应用"},{"label":"C","content":"从去年开始，权威的职业技术学院排行榜上，甲学院落后于乙学院"},{"label":"D","content":"很多没有上过职业技术学院的工人很有才华，只是没有机会上学"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":86,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400087,6,'逻辑判断','哲学家和历史学家桑塔耶纳曾经评论说，那些不了解历史的人必定重复前人的错误。 但这种说法并不正确，在一些情况下，心理学家们已经知道了过去的错误，但还是 会重复它们。 下列选项中与题干反驳方式最为相似的是：','[{"label":"A","content":"俗话说“活到老，学到老”。但众所周知，学习得多就知道得多，知道得多就忘 记得多，如果学得越多忘得越多，那学习有什么用呢"},{"label":"B","content":"前辈常教导说，“想要有光明的未来，就得好好读书”。但“三百六十行，行行 出状元”,不读书照样可以有光明的未来"},{"label":"C","content":"俗话说“不入虎穴焉得虎子”。但事实并非如此，等你真的进入虎穴，也可能发 现里面空空如也，因为老虎早已被关在笼子里了"},{"label":"D","content":"“ 常在河边走 ，哪能不湿鞋?”我们都应该吸取这个教训，既然要在河边走，就 要为自己准备一双不会被打湿的靴子"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":87,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400088,6,'逻辑判断','有五名员工小李、小王、小陈、小罗和小傅竞聘一个管理岗位；他们对竞聘结果进 行了猜测。 小李说：这次竞聘上的人不是我，就是小陈。 小王说：小傅这次竞聘不上。 小陈说：这次竞聘上的人如果不是小罗，就是小王。 小罗说：这次我和小王都竞聘不上。 小傅说：这次竞聘上的既不是小陈，也不是小李。 有两个人都猜对了，那么下列说法正确的是：','[{"label":"A","content":"这次竞聘上的人是小李"},{"label":"B","content":"这次竞聘上的人是小王"},{"label":"C","content":"这次竞聘上的人是小傅"},{"label":"D","content":"这次竞聘上的人是小陈"}]','C','【题型分类】分析类——真假分析 【实战解析】观察题干条件可知： 小李小傅矛盾，小陈小罗矛盾②, 则这四人中两真两假； 因为只有两人猜对，则小王说法为假，即小傅竞聘成功，C 选项正确。 ⑫花生批注： 小李：非小李→ 小陈； 小傅：非小李且非小陈； 小陈：非小罗→ 小王； 小罗：非小罗且非小王； A→B 与A 且非B矛盾。','逻辑判断600题','进阶','published','{"globalNumber":88,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400089,6,'逻辑判断','有实验表明，秋葵的提取物——秋葵素，对于治疗动物糖尿病有一定效果。有人据 此认为，秋葵切片泡水喝，有助于降低糖尿病人的血糖。 以下哪项如果为真，最能质疑上述论证：','[{"label":"A","content":"只有使用提取、浓缩后的大剂量秋葵素才能降低糖尿病人的血糖"},{"label":"B","content":"接受正规治疗才是糖尿病人控制血糖最为安全有效的途径"},{"label":"C","content":"秋葵素对Ⅱ型糖尿病患者有效，对 I 型糖尿病患者无效"},{"label":"D","content":"秋葵中所含有的膳食纤维和多种维生素并不比一般蔬菜高 29"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":89,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400090,6,'逻辑判断','有研究人员对A、B、AB、0血型各50名对象进行调查，发现各类血型人群中，容易 被蚊子叮咬的比例分别为：A型22%,B型28%,AB型8%,0型42%,于是研究人员 得出结论，容易被蚊子叮咬的各血型顺序为0型>B型 >A型 >AB型。 以下哪项如果为真，最能反驳上述论证：','[{"label":"A","content":"调查对象AB型的人，大多蚊虫防护意识较强"},{"label":"B","content":"调查对象中，A 型血中女性比例明显高于B型血"},{"label":"C","content":"调查对象中，0型血的人大多从事户外作业，工作环境中蚊子较多"},{"label":"D","content":"蚊子只依据二氧化碳、热量、挥发性化学物质这些因素来选择叮咬目标，研究发 现不同血型人群在上述因素中没有差异"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":90,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400091,6,'逻辑判断','小李对小张说：“你少吃一点咸菜，平时吃得太咸，将来会得高血压。”小张反驳道： “吃得咸不咸跟高血压没有关系，你看五十年代的人，天天都吃咸菜疙瘩，也没有 现在这么多人得高血压。” 以下哪项如果为真，不能帮助小李质疑小张的观点：','[{"label":"A","content":"过去医疗条件落后，民众健康意识淡薄，即使得了高血压也不知道"},{"label":"B","content":"吃太多盐会影响钙和锌的吸收，易患骨质疏松，还会加重肝肾代谢负担"},{"label":"C","content":"五十年代的人作息更规律，运动量更大，有助于排出体内的钠，降低血压"},{"label":"D","content":"吸烟、饮酒、高盐饮食、精神紧张都会导致高血压和心脑血管疾病风险增加"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":91,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400092,6,'逻辑判断','以下是一个4×4的图形，共有16个小方格，每个小方格中均可填入一个字，要求 图形的每行、每列均填入“兵”“不”“厌”“诈”4个字，不能重复，也不能遗漏。 根据以上信息，依次填入图形中①②③④处的4个字可为： ① ② ③ ④ 兵 厌 不 不','[{"label":"A","content":"厌，诈，兵 ，不"},{"label":"B","content":"厌，兵，不，诈"},{"label":"C","content":"兵，不，厌，诈"},{"label":"D","content":"不，诈，厌，兵"}]','B','【题型分类】分析类——日常分析 【实战解析】第二列第二行不能是“兵”,则第二列的“兵”只能在②, 观察选项，答案只能为B 选项。','逻辑判断600题','进阶','published','{"globalNumber":92,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400093,6,'逻辑判断','汽车的出现改变了现代生活的面貌改变了我们的生活所在地、购买习惯、工作方式等。 随着汽车越来越普遍，它们已经成为社会文化和生态不可分割的一部分，但是世界 卫生组织的数据显示，每年由车祸导致的死亡人数约有125万人。其中，半数死亡 的情况为车辆与路人、自行车、摩托车相撞所致。车祸已成为15-29岁人群致死事 件的罪魁祸首。那么自动驾驶车辆的出现将有改变这一现象的趋势。 下列各项如果为真，最能质疑上述结论的是：','[{"label":"A","content":"自动驾驶车辆撞人致死的事件已经发生"},{"label":"B","content":"自动驾驶车辆的控制系统有待进一步完善"},{"label":"C","content":"车祸的酿成与普罗大众的个人素质不无关系"},{"label":"D","content":"自动驾驶车辆的商业普及率还很低"}]','A','。 ⑱花生批注： 前文可看作背景介绍， 题干只有结论：自动 驾驶车辆的出现将改 变车祸伤人现象。','逻辑判断600题','进阶','published','{"globalNumber":93,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400094,6,'逻辑判断','研究人员发现，在过去的一个半世纪中，出现过几次地球转速放缓时期，这种时期 每次会持续5年左右，更为关键的是，地球转速放缓的同时伴随着强震增多。研究 人员据此得出结论：地球转速放缓导致强震多发。 以下哪项如果为真，最能质疑上述结论：','[{"label":"A","content":"在地球转速放缓时期，每年约发生25～30次强震，在其他时期，约为15次"},{"label":"B","content":"在地球转速放缓时期，发生火山喷发的次数与其他时期相比没有明显变化"},{"label":"C","content":"地球转速放缓，会使昼夜长短发生变化，昼夜长短变化导致全球强震多发"},{"label":"D","content":"地核的轻微变化，导致地球的转速放缓，也导致全球范围内的强震多发"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":94,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400095,6,'逻辑判断','某硕士班同学举办毕业20周年聚会，联络人王宁说班里有同学不能参加。班长说： “我看513宿舍的4名同学秋菊、阿春、秀秀和楠楠最多有两人能参加。”团支书说： “班长，我觉得你说的不对。” 如果团支书说得不对，则下列哪项必定为假：','[{"label":"A","content":"秋菊、阿春、秀秀和楠楠四人中有两人能参加"},{"label":"B","content":"秋菊、阿春、秀秀和楠楠四人都不能参加"},{"label":"C","content":"秋菊、阿春、秀秀和楠楠四人都能参加"},{"label":"D","content":"如果秋菊、阿春都参加，那么秀秀和楠楠也都能参加"}]','C','','逻辑判断600题','进阶','published','{"globalNumber":95,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400096,6,'逻辑判断','某工厂为了严格管理员工，提高员工工作效率，出台了一套新的员工管理制度。该 制度试行一年后，工厂总利润较去年上涨了30%。该工厂厂长认为，新的员工管理 制度能够有效管理员工的行为并提高员工的工作效率，应该继续实行下去。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"近五年来，该工厂每年的总利润上涨幅度均在30%以上"},{"label":"B","content":"很多员工抱怨新的员工管理制度过于严苛，不够人性化"},{"label":"C","content":"工厂生产效率提高了，员工的迟到率和早退率也有所上升"},{"label":"D","content":"工厂去年购置了一台新型生产机器，大幅提高了产出效率 31 31 逻辑判断"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":96,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400097,6,'逻辑判断','科学家研制出了一种新型的纳米涂层材料，这种材料能够促使任何液体从物体表面 反弹出去。例如油渍、酒精等表面张力很低的液体溅到用这种材料粉刷的墙壁上时， 会立刻被反弹，不会弄脏墙壁。因此，有商人预测，这种材料如果大量用于粉刷墙壁， 涂料的销量将大幅度下降。 以下哪项如果为真，不能质疑该商业人士的预测：','[{"label":"A","content":"消费者使用涂料往往还因为涂料具有其他的功效"},{"label":"B","content":"这种涂层材料将影响墙壁的美观"},{"label":"C","content":"该研究成果商业化还需要相当长的一段时间"},{"label":"D","content":"人们习惯于根据墙壁粉刷了多长时间来粉刷墙壁，不论墙壁是否已经被弄脏"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":97,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400098,6,'逻辑判断','在下列4×4的正方形矩阵中，每个小方格可填入一个汉字。要求每行每列以及粗线 框组成的4个小正方形中均含有甲、乙、丙、丁4个汉字。 根据上述条件，方格①中应填入的汉字是： 丁 乙 丙 ① 甲','[{"label":"A","content":"甲"},{"label":"B","content":"乙"},{"label":"C","content":"丙"},{"label":"D","content":"丁"}]','A','【题型分类】分析类——日常分析 【实战解析】如图所示： 78 逻辑判断 丁 乙 丙 ②甲 ① ③ 甲 ⑤ ④ 从最大信息入手，首先观察②号格，②不能是乙、丙、丁，②只能是甲； 此时观察右下角正方形，甲不能在③④⑤三个位置，甲只能在①,答 案为A 选项。','逻辑判断600题','进阶','published','{"globalNumber":98,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400099,6,'逻辑判断','某单位召开工作总结会议，7位员工从左到右依次坐在一排上。其中，小张、小唐、 小赵和小宋来自同一个部门；小林、小贾和小康来自另一个部门，同时还满足以下 条件： (1)所有座位朝向相同。 (2)小张所在部门所有员工的座位都不相邻。 (3)小赵在这排椅子的位置中紧挨着第四个员工的右边坐。 (4)小贾坐在小赵的右边。 (5)小张和小林相邻。 (6)小张和小赵中间间隔了不止一人。 根据以上表述，下列选项可能为真的是：','[{"label":"A","content":"小康坐在小张的左边"},{"label":"B","content":"小林坐在小张的左边"},{"label":"C","content":"小唐坐在小张的左边"},{"label":"D","content":"小宋坐在小赵的左边"}]','D','【题型分类】分析类——日常分析 【实战解析】根据(2)可知，(7)张、唐、赵、宋坐在1、3、5、7 号座位，(8)林、贾、康坐在2、4、6号座位； ①由(3)可知，赵坐在5号座位； ②由(4)可知，贾坐在6号座位； ③由(6)和(7)可知，张只能坐在1号座位； ④由(5)可知，林坐在2号座位； 逻辑判断 ⑤由(8)可知，康坐在5号座位； 1 2 3 4 5 6 7 张 ③ 林 ④ 康 ⑤ 赵 ① 贾 ② 如上图所示，A选项、B选项、C选项均为假，只有宋在3号座位时， D 选项可能为真。','逻辑判断600题','进阶','published','{"globalNumber":99,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400100,6,'逻辑判断','硒元素能够防治“克山病”,还具有抗氧化性、维持人体正常免疫功能等作用。研 究人员对ABCDEFGH几种食物的硒含量进行预测分析，如果食物A的硒含量高于食物 B并且食物C的硒含量高于食物D, 则认定食物E的硒含量最高；如果食物B的硒含 量高于食物A, 或者食物F的硒含量高于食物G, 则认定食物H的硒含量最高；如果 食物D的硒含量高于食物C则认定食物F 的硒含量最高。 最后发现食物H的硒含量最高，如果上述的分析都能够成立，则可以判断下列哪个 选项一定是真的：','[{"label":"A","content":"食物A的硒含量高于食物B"},{"label":"B","content":"食物 A的硒含量和食物G 一样高"},{"label":"C","content":"食物D的硒含量不比食物C高"},{"label":"D","content":"食物F 的硒含量高于食物C 练习题06"}]','C','【题型分类】推出类——正推逆推 最高；②B>即食物D 的硒【实战解析】题干可翻译为：①A>B 且C>D→E A 或 F>G→H 最高；③D>C→F 最高； 最高；②B> 即食物D 的硒 由 H 最高可知，F 非最高，可逆否③推出： D≤C, 含量不高于食物C, 答 案 为C 选项。 四海公考 练习题06 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":100,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400101,6,'逻辑判断','有甲、乙、丙、丁、戊五个人坐在一张圆桌上吃饭，其中有两个人是法律专业，有 两个人是文学专业，有一个是历史专业。已知两个法律专业的人和两个文学专业的 人都坐在相邻位置，甲与丁同一个专业，丙坐在乙和一个文学专业的人之间，戊和 乙不相邻，丙和甲不相邻，则下列推断正确的是：','[{"label":"A","content":"甲是文学专业"},{"label":"B","content":"乙是法律专业"},{"label":"C","content":"丙是文学专业"},{"label":"D","content":"戊是历史专业"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":101,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400102,6,'逻辑判断','很多家长认为，孩子不听话，“打屁屁”惩罚一下，至少能让孩子注意到自己的行为不当， 变得更听话一些。还有一些人坚持“不严加管教会惯坏孩子”的传统信念，认为“打 屁屁”是为孩子好。研究者对16万名儿童在过去5年里的经历进行研究，通过收集 “打屁屁”行为的原数据加以分析，发现：打屁股会在儿童成长过程中造成智商低、 攻击性行为高等多种负面影响。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"最新调查显示，智商相对较低的孩子大多数经常被家长打屁股"},{"label":"B","content":"本身不听话且更容易惹祸的孩子更有可能受到父母的严厉惩罚"},{"label":"C","content":"研究报告称全球大约80%的父母都有以打屁股管教孩子的经历"},{"label":"D","content":"被打屁股而困惑的孩子只懂得按家长要求去做而不会独立思考"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":102,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400103,6,'逻辑判断','在某高速公路的一段，直线相邻地排列着5个小镇。已知(1)栖霞镇既不和金井镇 相邻，也不和莲花镇相邻；(2)五溪镇既不和花石镇相邻，也不和莲花镇相邻；(3) 花石镇既不和金井镇相邻，也不和莲花镇相邻；(4)栖霞镇里没有木塔；(5)有 木塔的镇是排在第一和第四的小镇。 由此可见，排在第二的小镇是以下哪一个：','[{"label":"A","content":"栖霞镇"},{"label":"B","content":"莲花镇"},{"label":"C","content":"五溪镇"},{"label":"D","content":"花石镇"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":103,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400104,6,'逻辑判断','科学家重建地球地质历史上的大气成分面临的难题之一就是——缺少可用样品。近 年来，不少人开始关注琥珀，他们认为相比其他有机材料，琥珀在长久的地质年代内， 所保存的化学和同位素信息几乎不会改变，因此可以用于揭示不同年代的全球大气 成分。 以下哪项如果为真，最能质疑上述结论：','[{"label":"A","content":"由于琥珀内部常保留着生物的形体，故能反映当时生态环境与生物的关系"},{"label":"B","content":"琥珀主要诞生于约四千万至六千万年前的始新世纪，其他年份并没有形成琥珀"},{"label":"C","content":"琥珀是由松柏科植物的树脂经压力和热力作用形成，由于时间漫长，数量极少"},{"label":"D","content":"琥珀的硬度较低，如果因搬运、储存不当而造成损害，会影响同位素检测的准确性"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":104,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400105,6,'逻辑判断','甲乙丙丁四人涉嫌某案被传讯。 甲说：作案者是乙。 乙说：作案者是甲。 丙说：作案者不是我。 丁说：作案者在我们四人中。 如果四人中有且只有一个人说真话，则下列哪项断定⑤成立：','[{"label":"A","content":"作案者是甲"},{"label":"B","content":"作案者是乙"},{"label":"C","content":"作案者是丙"},{"label":"D","content":"题干中的条件不足以断定谁是作案者"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":105,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400106,6,'逻辑判断','宇宙加速膨胀是因为物质之间相互排斥，减速膨胀是因为物质之间相互吸引。因此， 要在此基础上解释宇宙的加速或减速膨胀，必须要有不同特性的物质在不同的时期 占主导地位，从而产生强大的排斥力或吸引力。粒子物理标准模型中的所有粒子都 产生吸引的引力，然而星系转动曲线的研究表明，在星系里面还有大量的、看不到 的物质，这些物质可以产生非常强大的吸引性引力。 以上论证如果为真，那么星系转动曲线研究结论隐含了下列哪一项前提：','[{"label":"A","content":"粒子物理标准模型中的所有粒子产生的吸引性引力不足"},{"label":"B","content":"粒子物理标准模型中的粒子不是唯一的，存在其它粒子"},{"label":"C","content":"星系转动曲线的研究说明这个时期的宇宙正在加速膨胀"},{"label":"D","content":"星系转动曲线的研究说明存在超大质量、看不到的黑洞"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":106,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400107,6,'逻辑判断','在某小学中，大多数高年级学生都喜欢打篮球，所有三好学生都参加了游泳班，所 有喜欢打篮球的学生都没参加游泳班。 根据上述描述，以下选项中必定为真的是： ①有的高年级学生没参加游泳班； ②有的高年级学生是三好学生； ③所有三好学生都不喜欢打篮球。','[{"label":"A","content":"①②③"},{"label":"B","content":"①②"},{"label":"C","content":"②③"},{"label":"D","content":"①③ 35"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":107,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400108,6,'逻辑判断','某三甲医院的医生中，专科医院毕业的医生人数大于非专科医院毕业的医生人数， 女医生的人数大于男医生的人数。 如果上述论述是真的，那么哪项关于该医院医生的断定也一定是真的： (1)非专科医院毕业的女医生人数大于专科医院毕业的男医生人数。 (2)专科医院毕业的男医生人数大于非专科医院毕业的男医生人数。 (3)专科医院毕业的女医生人数大于非专科医院毕业的男医生人数。','[{"label":"A","content":"(1) 和 ( 2 )"},{"label":"B","content":"只有(2)"},{"label":"C","content":"只有(3)"},{"label":"D","content":"(2) 和 ( 3 )"}]','C','； 四海公考 逻辑判断6 00 o 推理过程如下： ①专科医生>非专科医生，拆解成②专科男+专科女>非专科男+ 非专科女； ③女医生>男医生，拆解成④专科女+非专科女>专科男+非专科男； ②+④可得：专科男+专科女+专科女+非专科女>非专科男+非 专科女+专科男+非专科男； 化简(左右约掉专科男和非专科女)得：专科女>非专科男。','逻辑判断600题','进阶','published','{"globalNumber":108,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400109,6,'逻辑判断','长久以来，心理学家都支持“数学天赋论”:数学能力是人类自打娘胎里出来就有 的能力，就连动物也有这种能力。他们认为存在一种天生的数学内核，通过自我慢 慢发展，这种数学内核最后会“长”成我们所熟悉的一切数学能力。最近有反对者 提出了不同的看法：数学能力没有天赋，只能是文化的产物。 以下哪项如果为真，最能支持反对者的看法：','[{"label":"A","content":"10～12 个月的婴儿已经知道3个黑点和4个黑点是不一样的"},{"label":"B","content":"数学是大脑的产物，而大脑的生长模式早已由基因“预设”"},{"label":"C","content":"经过人为训练的大猩猩、海豚和大象等动物能处理数学问题"},{"label":"D","content":"绝大多数的原始部落的居民只能表示5以下甚至更少的数量"}]','D','。 87 逻辑判断','逻辑判断600题','进阶','published','{"globalNumber":109,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400110,6,'逻辑判断','多伦多大学研究员招募一批儿童接受智商测试，将他们分为4组，前3组分别学习 钢琴、声乐和话剧，每周上课一次；最后一组则没有上任何课外活动。9个月后， 他们接受第二次历时3小时的智商测试。结果显示，4组儿童的得分增加最少4.3分。 然而，接受声乐和学习钢琴的两组儿童，他们的得分平均比其余两组儿童高出2.7分。 因此研究员认为：学音乐可有效提高儿童在智商测试中的得分。 以下哪项如果为真，最能反驳上述结论：','[{"label":"A","content":"前两组受试者儿童都很喜欢学音乐"},{"label":"B","content":"前两组受试者儿童在中高智商选取，后两组在普通智商中选取"},{"label":"C","content":"后两组受试者在进行智商测试时较为紧张、焦虑"},{"label":"D","content":"智商测试的题目只有图形推理题，不能全面反映受试者的智商情况"}]','B','。 对比实验归因题的常 见错误选项：有些类 选项、实验瑕疵、分 组错误或未分组，未 谈论原因选项。','逻辑判断600题','进阶','published','{"globalNumber":110,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400111,6,'逻辑判断','某研究所进行了一次实验，让两批实验者分别进入睡眠实验室。第一批实验者睡得 很晚，但睡眠时间充足，第二批实验者睡得很早，但睡眠时间短暂。第三晚后，第 二批实验者情绪变得消极，友善度也大幅下降。研究者据此认为，睡眠时间短暂导 致实验者无法获得足够的短波睡眠，而短波睡眠是恢复精力的关键。但也有其他研 究者对该结论提出质疑。 四海公煮 下列哪项如果为真，最能反驳质疑者：','[{"label":"A","content":"第二批实验者长期以来情绪消极"},{"label":"B","content":"两批实验者原本的健康状况、心理素质存在差距"},{"label":"C","content":"第一批实验者积极情绪和友善度下降不够明显"},{"label":"D","content":"两批实验者在参与睡眠实验前，精力水平参差不齐"}]','C','【题型分类】归因类——对比实验 【实战解析】将题目对比实验过程画图如下： 第二批 第一批 睡得晚但睡眠足原因 结果睡得早但睡眠短 消极和友善下降 睡得晚但睡眠足 原因 结果 题干明显未提及第一批实验者的表现，可补充论据加以支持，C 选项 指出第一批实验者积极情绪和友善度下降不明显， 构成异因异果的四 圈支持①,即第二批实验者情绪消极和友善度下降是因为睡眠不足， 支持了结论，当选； 其他选项，均未将实验补充完整，而且均稍有他因质疑作用，无法支持。','逻辑判断600题','进阶','published','{"globalNumber":111,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400112,6,'逻辑判断','去年，海尔洗衣机的销量大幅增长，同期，其品牌的广告宣传力度也大幅增加，因 此有人认为，海尔洗衣机销量的增长，是由于广告的大力宣传作用。 以下哪项为真，最能削弱上述结论：','[{"label":"A","content":"购买海尔洗衣机的顾客，很少注意到它的广告宣传"},{"label":"B","content":"某洗衣机是海尔洗衣机的主要竞争对手，他的广告宣传力度更大"},{"label":"C","content":"注意到海尔洗衣机广告的顾客，很少有人购买"},{"label":"D","content":"近一年，人们对洗衣机的需求量有很大增加"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":112,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400113,6,'逻辑判断','在第二次世界大战期间，大约有37.5万美国平民丧生，40.8万美国武装部队的人 员在海外牺牲。根据这个数据可以得出，第二次世界大战期间，被派往海外的人员 并没有比留在美国的平民危险多少。 下列哪项如果为真，最能揭示上述论断的荒谬之处：','[{"label":"A","content":"除上述对比外，还应该对比在美国因为意外事故死亡的人数和在战争中死亡的人数"},{"label":"B","content":"不应该单纯比较死亡人数总量，而应该就各自群体每千人中死亡的人数进行比较"},{"label":"C","content":"除了统计美国武装部队在海外死亡的人数外，还要计算整个美国武装部队的人数"},{"label":"D","content":"应该把武装部队中因疾病导致的死亡人数与因战争受伤而导致的死亡人数区别开来"}]','B','【题型分类】一般质疑类——比例类论证 【实战解析】论据结论见批注。是否危险应该比较死亡率，题干只比 较了死亡人数，未考虑总人数， 直接在选项中寻找“带数字的分母(即 平民和海外人员的人数)”即可②,观察选项： B 选项，虽然未给出美国平民和海外人员的具体人数，但指明了比例 类论证常见的问题，是否安全应该比较各自群体每千人中死亡的人数， 而非死亡人数，直接针对漏洞攻击，当选。','逻辑判断600题','进阶','published','{"globalNumber":113,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400114,6,'逻辑判断','为什么有人乐于参加社交活动、结交朋友，有人却对此避之不及?有研究人员提出， 与其他人相比，CD38基因表达量较高、CD157基因序列存在特定变异的人更乐于社交， 所以这两种基因影响了人的社交能力。但是，有反对者提出，人的社交能力是由位 于人类4号染色体长臂1区的催产素决定的，不论男性还是女性的大脑都能合成这 种激素，它对人的社交能力有着重要影响。 以下哪项如果为真，最能削弱反对者的观点：','[{"label":"A","content":"CD38 和CD157基因控制着催产素的分泌"},{"label":"B","content":"催产素的分泌影响着人的共情能力、信任和慷慨程度等"},{"label":"C","content":"上述两种基因中哪一种对人的社交能力影响更大还不确定"},{"label":"D","content":"基因表达是否能影响行为，在很大程度取决于人们所处的社会环境 37"}]','A','。 2花生批注： 比例类题目要“以我 为主”,直接去选项 中寻找“带数字的分 母”即可。 ②3花生批注： 原 观 点 ：CD38和 CD157两种基因影响 了人的社交能力； 反对者：催产素决定 了社交能力。 ④花生批注： 此类题目可以直接在 选项中寻找“原观点 导致反对者”的选项， 不要被其他选项干扰。 91 91 逻辑判断600o','逻辑判断600题','进阶','published','{"globalNumber":114,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400115,6,'逻辑判断','2008年全球金融危机爆发至今，美、日、欧等发达经济体陷入了经济增长乏力的困境， 经济增速始终显著低于危机前的水平。长期停滞理论认为，这是由于均衡实际利率 持续下滑并已跌入负值区间，央行受零下限约束难以将现实中的实际利率压低至均 衡实际利率，所以相对较高的实际利率导致总需求(尤其是投资需求)持续受到抑制。 正因如此，即使美、日、欧推行零利率政策，产出缺口始终为负，经济难以实现复苏。 按照该理论，有人认为中国经济同样面临着投资需求不足的局面，中国经济也会陷 入长期停滞状态。 以下各项如果为真，除哪项外均能反驳上述结论：','[{"label":"A","content":"中国投资需求不足主要表现为民间投资需求的大幅下滑"},{"label":"B","content":"中国实际利率的可调整范围更大，因而更容易降至均衡实际利率"},{"label":"C","content":"即使该停滞理论是成立的，但中国目前的均衡实际利率仍大于零"},{"label":"D","content":"中国投资增速的大幅下降与该理论强调的投资需求不足性质截然不同"}]','A','。 92','逻辑判断600题','进阶','published','{"globalNumber":115,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400116,6,'逻辑判断','某组织评选国际名城，关于甲、乙、丙、丁4个城市能否入选，人们预测： ①甲、乙两城市至少有1个城市入选； ②若甲城市入选，则丙城市入选； ③若丁城市不入选，则丙城市亦不入选； ④乙、丁两城市至少有1个城市不入选。 结果，上述预测均得到证实。 根据上述信息，可以得出以下哪项：','[{"label":"A","content":"仅有1个城市入选，或者仅有1个城市不入选"},{"label":"B","content":"乙、丙2个城市均入选"},{"label":"C","content":"至少有2个城市入选"},{"label":"D","content":"至多有2个城市入选"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":116,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400117,6,'逻辑判断','花园有东西两个区，已知： (1)玫瑰都种植在东区； (2)西区是牡丹园，种植的是各色牡丹； (3)花园中的牡丹有许多名贵品种，但是没有黑色的； (4)珍稀品种都是玫瑰。 根据以上陈述，关于该花园中的花卉，下列哪项必然为假：','[{"label":"A","content":"西区牡丹中有珍稀品种"},{"label":"B","content":"玫瑰没有名贵品种"},{"label":"C","content":"东区有许多名贵品种"},{"label":"D","content":"玫瑰有许多珍稀品种 38"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":117,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400118,6,'逻辑判断','紫外线穿透能力强，可达真皮层，将皮肤晒黑，对皮肤伤害性很大，即便在非夏季期间， 紫外线虽然强度较弱，也仍然存在，但长时间累积也容易让皮肤受伤，产生黑色素 沉淀、肌肤老化松弛等问题。所以爱美的女性必须每天都涂防晒霜。 如果以下各项为真，最能削弱上述结论的是：','[{"label":"A","content":"室内距窗户半米处紫外线辐射量约是室外的40%,距离窗户1.5米处就衰减到室 外的15%,因此如果足不出户就不用涂防晒霜"},{"label":"B","content":"防晒霜一般要求涂抹均匀和及时补涂，如果使用不当，即便是标称高倍数防晒的 产品，也不一定能发挥出多大的防护功效"},{"label":"C","content":"紫外线在每年的4～9月强度最高，而冬天最弱"},{"label":"D","content":"大部分的阳伞都有一定的防晒保护作用，一把普通的阳伞可以遮挡77%的紫外线， 而一把黑色的阳伞可以遮挡99%的紫外线"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":118,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400119,6,'逻辑判断','一家人准备一起去北欧旅游，各自表达如下愿望： 父亲：若去挪威，则不去丹麦和冰岛； 母亲：若不去冰岛，则去挪威和丹麦； 儿子：若不去挪威，则去瑞典和芬兰。 最终的方案满足了上述每个人的愿望。根据以上陈述，可以得出下列哪项：','[{"label":"A","content":"去瑞典、芬兰和丹麦"},{"label":"B","content":"去瑞典、芬兰和冰岛"},{"label":"C","content":"去瑞典、丹麦和冰岛"},{"label":"D","content":"去芬兰、丹麦和冰岛"}]','B','。 ③花生批注： 阳伞虽能遮挡直射阳 光，但事实上，阳光 还可能通过反射照到 人体(镜面反射、漫 反射等),该情况在 原文中有所提及： A 选项明确说明“足 不出户就不用涂防晒 霜”,考试时优先选择。 31花生批注： 命题①: 挪威→非丹麦且非冰岛； 命题②: 非冰岛→挪威且丹麦； 命题③: 非挪威→瑞典且芬兰。 ③花生批注： 挪威→非丹麦； 挪威→丹麦； 根据两难推理，可知 “非挪威”成立。 两难推理： A→B 与 非A→B, 可推得B; A→B 与 A→ 非B, 可推得非A。 33花生批注： 此题可推出去瑞典、 芬兰、冰岛，可推出 不去挪威，但无法推 出是否去丹麦。 95 ③花生批注： 甲或乙之一，可翻译 为“要么甲要么乙”; 要么要么,一真一假 为真，两真两假为假。 35花生批注： 第二种思路： 若甲乙一人正科一人 副科，则丁正科，丙 副科，与(3)矛盾， 即甲乙必然都是正科 或都是副科，观察选 项，只有A可能成立。 36花生批注： 命题A→B 的真假判 断： 只在A 且非B 时为假； 前件为假(即非A成立， 不能满足A且非B), 命题为真； 后件为真(即B成立， 不能满足A且非B), 命题为真。 ③花生批注： “A→B” 与“A 且非 B ”矛盾。','逻辑判断600题','进阶','published','{"globalNumber":119,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400120,6,'逻辑判断','在干部选拔中，甲、乙、丙、丁4人脱颖而出。进一步考察，4人中2人拟任正科级， 2人拟任副科级。已知： (1)若甲或乙之一任正科级，则丁任正科级； (2)若甲或乙之一任副科级，则丙任副科级； (3)如果丁任正科级，则丙也任正科级。 根据以上信息，则下列哪项可能为真：','[{"label":"A","content":"甲乙均任正科级"},{"label":"B","content":"乙丙均任正科级"},{"label":"C","content":"甲丙均任正科级"},{"label":"D","content":"乙丁均任正科级 39 练习题07"}]','A','。 练习题07 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":120,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400121,6,'逻辑判断','为什么减肥老反弹?科学家先用高脂饮食喂养小鼠。小鼠们变的过度肥胖之后，对 其中的一部分进行正常饮食，它们随之恢复到最初体型。经多次循环上述喂养方式。 研究者发现，每次当高脂——正常饮食的小鼠恢复到最初体重时，它们的耗氧量、 能量消耗和其他肥胖指标均恢复到了正常值，但它们的每个饮食循环里净增长的体 重多于一直保持高脂饮食的小鼠。是什么导致了多余的增重?科学家发现，高脂和 低脂饮食的循环会改变小鼠肠道菌群的平衡，破坏了有益的黄酮类化合物，导致小 鼠体重更容易增加。 以下哪项如果为真，不能支持上述结论：','[{"label":"A","content":"研究发现，过度肥胖小鼠的菌群利用的黄酮类化合物更少"},{"label":"B","content":"人类和小鼠肠道的微生物群落，在减肥中存在类似的模式"},{"label":"C","content":"当采用了黄酮类化合物膳食补充剂后，就能够抑制体重的过分反弹"},{"label":"D","content":"当小鼠回归正常饮食并减轻体重后，体内被打破的菌群不会自行恢复"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":121,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400122,6,'逻辑判断','老赵、老杨、老胡三人中有一个是农夫、一个是樵夫、一个是大夫，他们由东向西 相邻而居在一条通往山脚的路边。 老赵说：老杨生病时还是我去给他找的大夫。 樵夫说：我每次从山上砍完柴回家，都要经过老杨家。 大夫说：我家隔壁只有老赵一家。 根据以上信息，住在离山脚最近的一家是：','[{"label":"A","content":"老赵"},{"label":"B","content":"老杨"},{"label":"C","content":"老胡"},{"label":"D","content":"不能确定"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":122,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400123,6,'逻辑判断','脊髓性肌萎缩症是一种罕见的致死性遗传病，大多数患儿活不到20个月。近日，有 研究人员使用一种新的基因疗法，研发了一种生物技术药物Spinraza, 通过在患者 脊髓周边注射给药，Spinraza 使73名受试患者中的近一半患者不同程度的恢复了 运动机能。研究人员据此得出结论：这种新的基因疗法将为脊髓性肌萎缩症的治疗 带来突破性进展。 以下哪项如果为真，最能支持上述论证：','[{"label":"A","content":"该项研究的具体程序设计较为科学合理"},{"label":"B","content":"这种基因疗法也可用于其他疾病的治疗"},{"label":"C","content":"美国药监局已经批准了这一新药的上市"},{"label":"D","content":"对照组的所有患者都没有恢复运动机能"}]','D','【题型分类】归因类——补充对比实验 【实战解析】题干论据只给出了使用新药的情况，缺少对照组，可通 过补充对照组构成对比实验，D 选项符合，补充后对比实验如下图所 示： 使用新基因疗法的受试患者 近一半不同程度恢复了运动机能 其他选项： 未使用新基因疗法的受试患者 所有患者都没有恢复运动机能 A 选项，说明此研究较为可信，但没有补充题干漏洞，支持力度很弱； B 选项、C 选项没有讨论新疗法是否能为脊髓性肌萎缩症的治疗带来 突破性进展，无法支持。 ④花生批注： 论据：使用生物技术 药物的受试患者近一 半不同程度的恢复了 运动机能； 结论：这种新的基因 疗法将为脊髓性肌萎 缩症的治疗带来突破 性进展。 ⑤花生批注： 论据：新材料能解决 机械超材料无法更改 或调整的问题； 结论：机器人、智能 可穿戴装备等领域会 旧貌换新颜。','逻辑判断600题','进阶','published','{"globalNumber":123,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400124,6,'逻辑判断','目前，广泛应用的机械超材料有着负热膨胀、低重量时的高强度和高刚度等卓越特性。 但这种机械超材料一旦构建完成，其属性将无法更改或调整。近日，有研究人员开 发出一种新型材料攻克了这一难题。可以肯定，在不久的将来，机器人、智能可穿 戴装备等领域一定会旧貌换新颜。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"目前，已有科研团队与该成果的研究团队探讨这种新型材料的具体应用前景"},{"label":"B","content":"从一种新材料的合成到该材料的具体实际应用，要克服多种难以预料的困难"},{"label":"C","content":"这种新材料对磁场响应的稳定性及对磁场强度的要求还在反复地检验和测试"},{"label":"D","content":"历史证明，每一次新技术和新材料的突破都会迅速引起相关应用领域的剧变"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":124,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400125,6,'逻辑判断','通常情况下，伤害行为的受害者会通过法律渠道表达利益诉求，但是，如果制度不 公或失效，就会引发更多的社会伤害行为：不但强势者可能会进一步伤害弱势者， 而且他们也可能会受到弱势者的伤害；弱势者也可能对其他弱势者造成伤害，造成“弱 者对弱者的欺凌”。这样一来，整个社会就会弥漫着一股戾气，给日常生活带来严 重的不安与不快。 由此可以推出：','[{"label":"A","content":"只有制度不公或失效，强势者才会伤害弱势者"},{"label":"B","content":"如果制度不公或失效，弱势者就会伤害强势者"},{"label":"C","content":"只有制度公正且有效，才能防止引发更多的社会伤害行为"},{"label":"D","content":"如果制度公正且有效，就能给日常生活带来安宁与快乐"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":125,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400126,6,'逻辑判断','A 市近年来人才外流数量不断增加，然而自从许多外地大学迁移到A市以后，该市 大学生就业率出现了严重下降。据此，有专家认为许多大学迁移到A市导致其就业 率降低。 据此，下面哪个选项为真，最能加强上述结论：','[{"label":"A","content":"A市在近3年内企业数量增加了3倍"},{"label":"B","content":"A市周围城市人才外流数量依然不断增加"},{"label":"C","content":"A 市在许多外地大学迁移之前就业率并不高"},{"label":"D","content":"A 市政府已经实施鼓励大学生自主创业的政策 41 41"}]','A','项。','逻辑判断600题','进阶','published','{"globalNumber":126,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400127,6,'逻辑判断','近年来减肥人士所追捧的低碳饮食，指的是在饮食中严格限制碳水化合物的摄入量， 增加蛋白质和脂肪的摄入量。一些研究指出，通过降低饮食中的碳水化合物不但可 以达到减重的目的，还能在一定程度上降低血液胆固醇水平，令心脏病风险有所降低。 所以不少支持者认为，长期低碳饮食对身材和健康都有益。 以下哪项如果为真，不能削弱上述结论：','[{"label":"A","content":"研究发现只有1%的人能够长期坚持低碳饮食，平均坚持19个月"},{"label":"B","content":"低碳饮食者会更多进食蛋白质、脂肪，不适合冠心病、痛风等患者"},{"label":"C","content":"碳水化合物是营养膳食的基础，长期低碳饮食会影响大脑功能，导致精神萎靡"},{"label":"D","content":"少吃才是减肥的硬道理，通过改变碳水化合物、蛋白质和脂肪的比例并不能起到 效果"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":127,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400128,6,'逻辑判断','根据统计，电瓶车引发的交通事故占全部交通事故的比例超过40%,引起了国家相 关部门的重点关注。电瓶车事故的发生主要由电瓶车速度快、电瓶车主不遵守交通 规则等引起。国家为加强对电瓶车的管理，规定新生产、销售的电瓶车车速不得超 过25KM/h,质量不能超过55KG。专家认为，这样能够大幅减少电瓶车引发的交通事故。 以下哪项为真，最能质疑上述专家的结论：','[{"label":"A","content":"电瓶车引发的交通事故主要是由电瓶车本身的车速过快引起的"},{"label":"B","content":"电瓶车引发的交通事故中，车速快虽然是其中一个原因，但最主要的是电瓶车主 不遵守交通规则"},{"label":"C","content":"很多城市电瓶车道比较窄，电瓶车经常碰撞在一起"},{"label":"D","content":"以前发生的交通事故中，机动车引起的交通事故比例更高"}]','B','【题型分类】 一般质疑类——有论据有结论 【实战解析】论据和结论见批注。通过题干可知，引起交通事故的原 因主要有两方面：速度快和不遵守交通规则，国家为加强管理限制了 电瓶车车速，但未解决另一问题，针对此漏洞进行攻击即可； B 选项，指出最主要的电瓶车引发交通事故的原因是电瓶车车主不遵 守交通规则，那么即使对车速和质量进行限制，也无法实现大幅减少 电瓶车引发的交通事故，可以质疑，当选； ⑩花生批注：假设车道较窄导致的 事故只占整体的1%, 车速较快导致的事故 占比为90%,那限制车 速还是能大幅减少事 故。其他选项： ⑩花生批注： 假设车道较窄导致的 事故只占整体的1%, 车速较快导致的事故 占比为90%,那限制车 速还是能大幅减少事 故。 A 选 项 ，指出电瓶车引发的交通事故主要是由电瓶车过快导致，那么 限制电瓶车车速可以大幅减少交通事故，属于增加论据支持； C 选 项 ，很多城市车道较窄也是导致电瓶车事故的原因，但未说明限 制电瓶车车速后会不会大幅减少电瓶车交通事故⑨,无法质疑； D 选项，机动车、电瓶车主体不一致，无法质疑。 103 逻 辑 判 断','逻辑判断600题','进阶','published','{"globalNumber":128,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400129,6,'逻辑判断','一项最新研究发现，脑部 DNA的变异是使人们患上抑郁症和焦虑症的原因，而且这 种变化会传递给后代。但是，有反对者认为，脑部杏仁核活动的增加会使应对恐慌 的大脑区域的活动增强，这是引发抑郁症和焦虑症的原因。 以下哪项如果为真，最能削弱反对者的观点：','[{"label":"A","content":"DNA的变异是人类许多疾病的罪魁祸首"},{"label":"B","content":"不健康的生活习惯也会引发抑郁症和焦虑症"},{"label":"C","content":"脑部DNA的变异是使杏仁核活动增加的原因"},{"label":"D","content":"有些抑郁症和焦虑症患者的脑部DNA会发生变异"}]','C','。 ⑫花生批注： 此类题目直接寻找正 确答案即可，不要被 其他选项干扰。','逻辑判断600题','进阶','published','{"globalNumber":129,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400130,6,'逻辑判断','碳酸钙是珍珠的主要成分，占珍珠比例的百分之九十，但是，想用皮肤来吸收碳酸钙， 这几乎是不可能的，因为皮肤有多层结构，固体的珍珠粉很难渗入。珍珠粉外敷之 后若有残留粉末，可能会反射出一定的光泽，显得皮肤变白了。其实这只是假象。 所以，想靠着珍珠粉去美白是不太现实的。 42 42 下列选项除了哪项外，均能反驳上述论证：','[{"label":"A","content":"现代技术能让珍珠粉的大小达到百纳米以下，可以被吸入皮肤"},{"label":"B","content":"某明星有长期外用珍珠粉的习惯，年过60仍皮肤润泽柔滑，细腻白皙"},{"label":"C","content":"珍珠粉外敷能部分隔绝空气，减缓空气对皮肤表层细胞的氧化，长期使用能延缓 衰老"},{"label":"D","content":"珍珠粉中的牛磺酸具有加强巨噬细胞吞噬的能力，黑色素进入表皮层之后部分会 被巨噬细胞吞噬"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":130,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400131,6,'逻辑判断','有媒体报道：近10年来，有关癌症病患者的报道日趋增多。可见我们的生活变得越 来越危险了，我们每天都饱受各种机器产生的辐射和各种有害化学物质的侵害，这 些辐射和化学侵害都是致癌的祸首。 以下选项如果为真，能够反驳以上论述的是：','[{"label":"A","content":"机器和化学物质给我们带来了各种便利，让我们节省下更多时间来享受生活"},{"label":"B","content":"随着工业发展，各种大型厂房进驻某地，附近村落的癌症发病率比以往显著提高"},{"label":"C","content":"随着医学技术的不断进步，癌症病患者的生存时间更长，而且更多的人愿意谈及 癌症这个话题了"},{"label":"D","content":"媒体总是喜欢报道骇人听闻的言论来吸引眼球，增加销售量"}]','C','。 105 逻辑判断','逻辑判断600题','进阶','published','{"globalNumber":131,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400132,6,'逻辑判断','为了研究高脂食物对健康的影响，生物系的学生将两组小白鼠作为实验对象，A组 每天喂养高脂食物，B组喂养一般饲料。一个月后，A 组小白鼠体重超标。学生们由 此得出结论：人类长期吃高脂食物会导致发胖。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"低脂食物的营养不全面"},{"label":"B","content":"其他途径也能够增加体重"},{"label":"C","content":"长期吃高脂食物会降低食欲"},{"label":"D","content":"人对高脂食物的吸收能力比小白鼠差"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":132,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400133,6,'逻辑判断','调查发现，用户很少定期清洗电热水器，电热水器经常不清洗，不仅会减弱加热效果， 延长加热时间，还会发生崩裂，损坏内胆，容易引发事故。为了用户能更好的使用 电热水器，某市安监部门及时向该市市民散发了小册子，上面描述了如何定期清洗 电热水器。 下列选项如果正确，最能质疑上述做法效果的是：','[{"label":"A","content":"不当操作也会带来电热水器发生损坏或危险"},{"label":"B","content":"这份小册子被散发到该市所有用电热水器的市民"},{"label":"C","content":"在寒冷的冬天，部分市民在公共澡堂洗澡"},{"label":"D","content":"许多市民不能看明白小册子的清洗流程"}]','D','','逻辑判断600题','进阶','published','{"globalNumber":133,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400134,6,'逻辑判断','学校工会举办“教工好声音”歌唱比赛，赛后参赛者们预测比赛结果。张老师说：“如 果我能获奖，那么李老师也能获奖。”李老师说：“如果我能获奖，那么刘老师也 能获奖。”刘老师说：“如果田老师没获奖，那么我也不能获奖。”比赛结果公布 后发现，上述3位老师说的都对，并且上述四位老师中有三位获奖。 由此可以推出没有获奖的是：','[{"label":"A","content":"张老师"},{"label":"B","content":"李老师"},{"label":"C","content":"刘老师"},{"label":"D","content":"田老师"}]','A','。 107','逻辑判断600题','进阶','published','{"globalNumber":134,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400135,6,'逻辑判断','某研究所人员结构状况如下：所有女性都拥有博士学位，有的男博士有高级职称， 但所里也存在既没有博士学位也没有高级职称的人员。 根据以上陈述，可以推出以下哪项：','[{"label":"A","content":"有的男性没有高级职称"},{"label":"B","content":"有的女性有高级职称"},{"label":"C","content":"所有男性都拥有高级职称"},{"label":"D","content":"有的女性没有高级职称"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":135,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400136,6,'逻辑判断','在某旅行社的股东会上，总经理提出：根据目前公司整体规划，我提议欧洲线和北 美线两条线路至少要开通一条，但南美线因航线问题不能马上开通。董事长表示反对。 下列哪项最能准确表达董事长的意思：','[{"label":"A","content":"欧洲线、北美线和南美线三条线路都开通"},{"label":"B","content":"欧洲线、北美线和南美线三条线路都不开通"},{"label":"C","content":"欧洲线和北美线两条线路至多开通一条，但南美线要马上开通"},{"label":"D","content":"如果南美线不能马上开通，那么欧洲线和北美线两条线路都不能开通"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":136,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400137,6,'逻辑判断','有些海外归国的科学家当选了中国科学院院士。因此，有些中国科学院院士担任了 高校的领导职务。 为使上述推理成立，必须补充下列哪项作为前提：','[{"label":"A","content":"有些海外归国的科学家担任了高校的领导职务"},{"label":"B","content":"有些担任高校领导职务的不是海外归国的科学家"},{"label":"C","content":"所有担任高校领导职务的都是海外归国的科学家"},{"label":"D","content":"所有海外归国的科学家都担任了高校的领导职务"}]','D','【题型分类】前提假设类——断点搭桥 【实战解析】此题为典型三段论，考虑包含“海外归国的科学家”和“担 任高校领导职务”且 为“所有”④类的选项： D 选项，所有海外归国的科学家都担任了高校的领导职务，有些当选 中国科学院院士的是海外归国的科学家②,所以，有些中国科学院院 士担任了高校的领导职务，当选； 其他选项： A 选项、B 选项是“有些”而非“所有”类的选项，排除； C 选项，“所有担任高校领导职务的都是海外归国的科学家”与前提 联结无法继续推出，排除。 ⑱花生批注： A、B至多一个，翻译为： 非A 或非B。 ⑲花生批注： 或命题等价于否一推 一 ，因此“(非欧洲 且非北美)或南美” 等价于“非南美→非 欧洲且非北美”。 2花生批注： 三段论中三个概念应 都出现两次，即海外 归国的科学家、中国 科学院院士、担任高 校领导职务，都出现 两次。 ②花生批注： 三段论一般由一个“所 有”和两个“有些”或“特 例”组成。 2花生批注： 题干论据“有些海外 归国的科学家当选了 中国科学院院士”, 根据“有些A 是B, 可推出有些B 是A”, 可推得“有些当选了 中国科学院院士的是 海外归国的科学家”。 109 3花生批注： “任何人只信赖充分 了解他的人”,可理 解为“只有充分了解 别人，别人才会信任”; “只有才”可翻译为“不 不 ”。 ④花生批注： 论据：一批恐龙骨骼 化石中有毒元素含量 极高； 结论：这些恐龙死于 慢性中毒。','逻辑判断600题','进阶','published','{"globalNumber":137,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400138,6,'逻辑判断','知己知彼，才能百战不殆。这句话同样适用于人际交往之中，一个人只有先了解自己， 才能了解别人；任何人也只信赖充分了解他的人，包括他自己。试想，如果一个人 根本不了解你，他如何值得你信赖呢? 由此可以推出：','[{"label":"A","content":"只有信赖自己，才能信赖别人"},{"label":"B","content":"不了解自己，就不会被任何人信赖"},{"label":"C","content":"他充分了解你，所以他值得你信赖"},{"label":"D","content":"充分了解自己，就可以获得许多人的信赖"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":138,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400139,6,'逻辑判断','研究人员对四川地区出土的一批恐龙骨骼化石进行分析后发现，骨骼化石内的砷、钡、 铬、铀、稀土元素等含量超高),与现代陆生动物相比，其体内的有毒元素要高出 几百甚至上千倍。于是一些古生物学家推测这些恐龙死于慢性中毒。 如果以下各项为真，不能质疑上述推测的是：','[{"label":"A","content":"恐龙化石附近土壤中的有毒元素会渗进化石"},{"label":"B","content":"恐龙化石内还有很多相应的解毒元素"},{"label":"C","content":"这批恐龙化石都是老年恐龙，属于自然死亡"},{"label":"D","content":"在恐龙化石附近的植物化石里，有毒元素含量很少"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":139,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400140,6,'逻辑判断','北京市为了缓解交通压力实行机动车辆限行政策，每辆机动车周一到周五都要限行 一天，周末不限行。某公司有A、B、C、D、E 五辆车，保证每天至少有四辆车可以 上路行驶。已知：E 车周四限行，B 车昨天限行，从今天算起，A、C两车连续四天 都能上路行驶，E 车明天可以上路。 由此可知，下列推测一定正确的是：','[{"label":"A","content":"今天是周四"},{"label":"B","content":"今天是周六"},{"label":"C","content":"A 车周三限行"},{"label":"D","content":"C车周五限行 练习题08"}]','A','【题型分类】分析类——真假分析 【实战解析】分析题干可知： ① B 车昨天限行( A 、C 两车不限行),从今天起A 、C 两车连续四 天不限行，加上昨天，即A 、C 两车从昨天起的连续五天不限行， A 、 C 车在前天、大前天限行； 大前天 前天 昨天 今天 明天 后天 大后天 限行 A/C A/C B ②大前天、前天、昨天，有车辆限行，则这三天非周六周日；而且E 车未在此三天限行，则这三天里没有周四。所以，今天、明天、后天、 大后天包含周四和周六周日，这四天只能是周四、周五、周六、周日； 综上，今天是周四。 111 练习题08 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 题干只有观点：人体 大多数抗菌性细菌来 自食用含菌的肉食。','逻辑判断600题','进阶','published','{"globalNumber":140,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400141,6,'逻辑判断','鉴于常用抗生素会导致细菌的抗药性，从而使细菌在抗菌环境下得以幸存，人体内 所出现的抗菌现象归咎于人对抗菌药的服用，然而一些科学家认为，人体内的大多 数抗菌性细菌来自食用含菌的肉食。 以下哪项如果为真，将最能加强上述科学家的假设：','[{"label":"A","content":"大多数食用肉食发生中毒的人都是使用抗生素药物来治疗的"},{"label":"B","content":"从来没有使用过抗菌类药物的人最不可能产生抗菌性细菌"},{"label":"C","content":"牲畜饲养者声称动物体内的抗菌性细菌不会通过食用肉食而传播给别人"},{"label":"D","content":"牲畜饲养者为了加快牲畜的生长，常常在饲料中加入抗生素"}]','D','。 四海公煮','逻辑判断600题','进阶','published','{"globalNumber":141,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400142,6,'逻辑判断','《道路交通安全法实施条例》规定：黄灯亮时，已越过停止线的车辆可以继续通行。 某司机：该条例并未规定黄灯亮时，未越过停止线的车辆不能通行。某交警：该条 例应当理解为，没越过停车线的车辆不可以继续通行。 下列哪项最能支持上述交警的观点：','[{"label":"A","content":"法律条文的含义是明确的，当事人只能做法律明确许可的事"},{"label":"B","content":"法律条文的文字意思与实际执行情况有时不一，需要具体分析"},{"label":"C","content":"该条例的意思是“黄灯亮时，如果有车辆已越过停止线，那么才可以继续通行”"},{"label":"D","content":"该条例的意思是“黄灯亮只有车辆已越过停止线，才可以继续通行”"}]','D','。 ②花生批注： “不不”可翻译为“只 有才”。 ③花生批注： 虽然C 选项后半句也 有“才”,但D 选项 明显正确，C 选项只 能理解为“如果那么”。','逻辑判断600题','进阶','published','{"globalNumber":142,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400143,6,'逻辑判断','经过长时间市场调研，某创投公司拟选择教育、医药、人工智能、能源、生态5个 领域进行新一轮投资。公司高层关于这轮投资，形成如下意见： ①若教育、生态两领域至少投资其一，则人工智能、能源均投资； ②若教育、医药两领域至少有一不投资，则投资生态而不投资人工智能。 事后得知，该公司高层意见均得到落实。 根据以上信息，关于该公司新一轮投资选择，可以得出以下哪项：','[{"label":"A","content":"教育、能源、生态均投资"},{"label":"B","content":"教育、医药、生态均投资"},{"label":"C","content":"教育、医药、人工智能均投资"},{"label":"D","content":"教育、人工智能、生态均投资"}]','C','⑤。','逻辑判断600题','进阶','published','{"globalNumber":143,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400144,6,'逻辑判断','目前，我国越来越多的新婚夫妇登记结婚前进行私人财产公证。这种做法无论对于 社会还是对于家庭都是有利的，应当提倡，至少不应反对。 以下诸项如果是真的，都能支持上述结论，除了： 四海公煮 逻 辑 判断6 0 0','[{"label":"A","content":"我国的离婚率呈逐年上升的趋势"},{"label":"B","content":"以往的离婚案中，财产分割是最棘手的问题之一"},{"label":"C","content":"婚前财产公证，只要当事人对此举有正确的理解，不会对新婚夫妇的感情产生不 利的影响"},{"label":"D","content":"我国离婚率上升的一个重要原因，是当事人双方社会地位失衡，例如，名人中离 婚率是最高的"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":144,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400145,6,'逻辑判断','在一次篮球比赛中，运动员小昱在进攻时总是会做些小动作，以此得到进攻空间， 在比赛暂停时，校判警告小昱如果再次在比赛中做一些小动作，将判其违规。对此， 小昱反驳说，这些动作是篮球规定中的合法动作，并不是故意的，因此，不应被判违规。 以下哪项如果成立，最能支持小昱对裁判的反驳：','[{"label":"A","content":"小昱一向恃才傲物，该裁判对其早有不满"},{"label":"B","content":"在篮球比赛中，对方运动员并没有对小昱的小动作提出抗议"},{"label":"C","content":"在篮球比赛中，只有选手的故意行为，才能成为判罚的依据"},{"label":"D","content":"在此次篮球比赛中，对方运动员也会做一些小动作"}]','C','。 ⑧花生批注： 结论：动作合法且非 故意，不应叛违规。 ⑨花生批注： 此题断点不明显，通 过选项提示更容易找 到。','逻辑判断600题','进阶','published','{"globalNumber":145,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400146,6,'逻辑判断','张老师将文房四宝装在一个有四层抽屉的柜子里，让学生猜笔、墨、纸、砚分别在 哪一层。按照笔、墨、纸、砚的顺序，小李猜测四宝依次装在第一、二、三、四层， 小王猜测四宝依次装在第一、第三、第四和第二层，小赵猜测四宝依次装在第四、第三、 第一和第二层，而小杨猜测四宝依次装在第四、第二、第三和第一层。张老师说， 小赵一个都没有猜对，小李和小王各猜对了一个，而小杨猜对了两个。 由此可以推测：','[{"label":"A","content":"第一层抽屉里装的是墨"},{"label":"B","content":"第二层抽屉里装的是纸"},{"label":"C","content":"第三层抽屉里装的不是笔"},{"label":"D","content":"第四层抽屉里装的不是砚"}]','D','项 。','逻辑判断600题','进阶','published','{"globalNumber":146,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400147,6,'逻辑判断','孩子们看的电视越多，他们的数学知识就越贫乏。甲市有超过1/3的孩子每天看电 视的时间在5小时以上，在乙市仅有7%的孩子这样做。在甲市只有不到15%的孩子 懂得高等测量与几何学要领，而在乙市却有40%的孩子在这个领域有这个能力。有 鉴于此，如果甲市孩子要在数学上表现出色的话，他们就必须少看电视。 下列哪一项是上述论证所依赖的假设：','[{"label":"A","content":"甲市孩子对高等测量和几何学要领的兴趣比乙市孩子小"},{"label":"B","content":"乙市孩子在功能方面的训练比甲市孩子多"},{"label":"C","content":"如果一个孩子每天看电视的时间不超过1小时，那么他在高等测量和几何学方面 的能力就会提高"},{"label":"D","content":"甲市孩子在高等测量与几何学要领方面所能接受的教育并不比乙市孩子差很多"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":147,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400148,6,'逻辑判断','据某省卫生防疫部门统计，被狗咬伤后到医疗机构接种狂犬疫苗的人中，仅有1%感 染上了狂犬病。但也有些人被狗咬伤后仅是在家自行处理。该省卫生防疫部门据此 推测，被狗咬伤的人群中，感染狂犬病的人所占比例高于1%。 以下最有力支持这一推测的是：','[{"label":"A","content":"该省的狂犬病预防知识普及工作做得不好"},{"label":"B","content":"该省境内饲养的狗大都没有注射狂犬疫苗"},{"label":"C","content":"感染狂犬病的病例必须上报省级防疫部门"},{"label":"D","content":"及时接种疫苗是预防狂犬病的最有效方法"}]','D','【题型分类】支持类——补充论据 ⑬花生批注： 论据：被狗咬伤后有 人到医疗机构接种狂 犬疫苗(狂犬病率1%), 有人在家自行处理； 结论：被狗咬伤后整 体狂犬病率超过1%。 ⑭花生批注： 类似资料分析盐水考 点，一部分占比1%, 要想整体超过1%,另 一部分占比一定超过 1%。 ⑮花生批注： 论据：野生动物出现 在城市街区的新闻越 来越多； 结论：野生动物将占 领城市。 【实战解析】论据和结论见批注。被狗咬伤人群可分为“到医院接种 疫苗”和“在家自行处理”两部分， 根据前者狂犬病率1%,得出整 体狂犬病率高于1%的结论，显然缺少另一部分的患病比例⑨ ,需要 选项提供： D 选项，及时接种疫苗是最有效方法，即在家自行处理患病比例更高 (高于1%),所以被狗咬伤人群患狂犬病比例高于1%,当选。','逻辑判断600题','进阶','published','{"globalNumber":148,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400149,6,'逻辑判断','随着世界各地的城市实行封闭、隔离或者社交限制，街巷变得不再拥挤，热闹繁忙 的人类聚居地开始安静下来。世界范围内关于各种野生动物出现在城市街区的新闻 越来越多，有人据此认为，野生动物将占领城市。 以下哪项如果为真，能够削弱上述结论：','[{"label":"A","content":"封闭、隔离促使居家的人们更多地饲养宠物"},{"label":"B","content":"野生动物的生存本能就是不断地寻找和适应生存环境"},{"label":"C","content":"个别野生动物行为的变化未必能够代表总体动物种群"},{"label":"D","content":"限制措施仅在紧急状态下暂时采用，城市不久将恢复常态"}]','C','项。','逻辑判断600题','进阶','published','{"globalNumber":149,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400150,6,'逻辑判断','某公司为调查员工使用纸张的情况，统计了打印机的纸张消耗数量，根据打印机的 纸张消耗数量，得出结论：平均每个员工每个月要消耗100张A4纸。 下列选项最能削弱上述结论的是：','[{"label":"A","content":"很多员工会通过双面打印来节约用纸"},{"label":"B","content":"少数员工在偶尔周末加班时也使用打印机"},{"label":"C","content":"员工不仅使用打印机进行打印，也会使用打印机进行复印和扫描"},{"label":"D","content":"员工不仅使用打印机，也使用传真机和手写来消耗纸张"}]','D','【题型分类】 一般质疑类——有论据有结论 【实战解析】题干将“打印机消耗纸张”等同于“总消耗”,存在明 显漏洞，即未考虑到其他消耗纸张的情形，可以针对此漏洞攻击： D 选项，指出不仅仅是打印机，还有传真机和手写来消耗纸张，说明 统计不全面，员工每个月消耗的纸张可能不止100张，针对漏洞攻击， 当选； 其他选项：“双面打印”、“周末打印”、“用打印机复印扫描”, 均不会改变打印机消耗纸张的数量，无法质疑。','逻辑判断600题','进阶','published','{"globalNumber":150,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400151,6,'逻辑判断','企业管理学认为，人力资源管理部门在现代企业管理过程中有着十分重要的作用。 但调研发现，该部门并未全程参与公司发展规划的决策，而且公司聘请的高级经理 都是由CEO决定。所以，人力资源管理部门更多的时候只是起到支持和辅助的作用。 下列哪项如果为真，将最能削弱上述论证：','[{"label":"A","content":"人力资源管理部门有权雇佣中层管理人员"},{"label":"B","content":"个别大型公司，人力资源管理部经理有权参加公司最高决策会议"},{"label":"C","content":"人才是公司发展的核心要素，而人力资源管理部门能为公司吸引并留住人才"},{"label":"D","content":"世界500强企业中，人力资源管理部门都是从有一线工作经验的员工中选调人员"}]','C','。 留住人才就是非常重 要的工作。','逻辑判断600题','进阶','published','{"globalNumber":151,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400152,6,'逻辑判断','凡是对顶角都相等，∠ A=∠B, 所以∠A与∠B是对顶角。 下列与上述推理方式一致的是：','[{"label":"A","content":"所有发表的意见都会被记录，小王没有发表意见，所以就没有记录"},{"label":"B","content":"所有的大学生毕业后都要参加工作，小刘是大学生，所以小刘毕业后要参加工作"},{"label":"C","content":"所有运动员在比赛前都要参加训练，小李在比赛前参加了训练，所以小李是运动员"},{"label":"D","content":"所有的犯罪分子都是被告，并非所有被告都是犯罪分子，所以有的被告不是犯罪 分子"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":152,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400153,6,'逻辑判断','对所有的静脉血标本进行检测，没有发现阳性HIV 抗体。 如果上述断定为假，则下列哪项一定为真：','[{"label":"A","content":"要发现阳性HIV 抗体，必须对所有静脉血标本进行检测"},{"label":"B","content":"对所有静脉血标本进行检测，未必能发现阳性HIV 抗体"},{"label":"C","content":"部分静脉血标本尚未进行检测，或者已经发现了阳性HIV 抗体"},{"label":"D","content":"部分静脉血标本尚未进行检测，但是已经发现了阳性HIV 抗体"}]','C','； 其他选项： A 选项，题干矛盾命题可翻译为： 对所有静脉血标本检查→发现阳性 HIV抗体②,此选项是题干矛盾命题的逆命题，无法推出； B 选项，“未必”是“不必然”,题干无相关表述，无法推出； D 选项，“但是”是“且关系”,无法推出。','逻辑判断600题','进阶','published','{"globalNumber":153,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400154,6,'逻辑判断','2006年，国际天文学联合会( IAU) 对太阳系大行星进行了重新定义，结果导致冥王 星被排除出太阳系“九大行星”。最近有天文学家指出，由于冥王星运行在太阳系 中天体密集的一个特殊区域——柯伊伯带，并且被证明是太阳系中第二复杂、最有趣、 比火星更具活力的一颗天体，因此冥王星就是太阳系的第九大行星。 以下各项如果为真，最能质疑上述天文学家结论的是：','[{"label":"A","content":"冥王星位于太阳系的外圈，非常黯淡，其个头甚至比月球还要小"},{"label":"B","content":"冥王星轨道周边还有其他天体，就连其卫星都有它自身一半大小"},{"label":"C","content":"太阳系其他八大行星围绕太阳运行的轨道基本都在同一个平面上"},{"label":"D","content":"太阳系大行星必须有的特点之一是清理了轨道周边的其他天体"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":154,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400155,6,'逻辑判断','进入21世纪后，中国经济总量逐步上升到世界第二位。由此，有人认为：“加入 WTO对一个国家的经济增长具有明显的加速作用。” 以下各项如果为真，最能质疑上述观点的是：','[{"label":"A","content":"中国进入经济高增长轨道与加入WTO几乎同时发生"},{"label":"B","content":"中国的大国基础结构对经济增长具有十分重要作用"},{"label":"C","content":"印度、巴西在加入WTO前后经济增速无明显变化"},{"label":"D","content":"中国有较低劳动成本和较高技能结合的竞争优势"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":155,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400156,6,'逻辑判断','现在有一种观点认为：随着信用卡的普及以及近年来移动支付的发展，硬币将不可 避免地迅速淡出流通市场。 以下各项如果为真，最能反驳上述观点的是：','[{"label":"A","content":"各国的硬币都是用本土的历史、文化及风俗等特色符号铸刻的微型浮雕，其本身 具有很高的收藏价值"},{"label":"B","content":"在银行储蓄卡开始兴起时，人们对硬币的命运也有过相同的预测，但硬币根本没 有因此淡出流通市场"},{"label":"C","content":"硬币本身的面值不高，但是正是这种“不值钱”的特性，让它在零售等方面发挥 着重要的流通作用"},{"label":"D","content":"目前，一些在生活中扮演重要角色的自动贩售机等设备仍然只支持硬币支付，并 且近几年这些设备不会更新换代"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":156,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400157,6,'逻辑判断','有一种观点认为，人体缺水是导致感冒的原因。反对者则认为，并非是缺水，受凉 才是导致感冒的根本原因。 以下哪项如果为真，最能削弱反对者的观点：','[{"label":"A","content":"人体缺水之后，更容易受凉"},{"label":"B","content":"感冒往往伴随着发烧，而发烧通常会导致缺水、怕冷"},{"label":"C","content":"即使没有受凉，人体缺水之后也会出现很多类似感冒的症状"},{"label":"D","content":"受凉之后，更容易导致人体缺水、抵抗力下降，从而引发感冒"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":157,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400158,6,'逻辑判断','某高校外语教研室新招进五位外语老师，每位老师只教授一门外语。并且满足以下 条件： (1)如果小钱教德语，那么小孙不教俄语 (2)或者小李教德语，或者小钱教德语 (3)如果小孙不教俄语，那么小赵不教法语 (4)或者小赵教法语，或者小周不教英语。 以下选项如果为真，可以得出“小李教德语”的结论：','[{"label":"A","content":"小孙不教俄语"},{"label":"B","content":"小钱教德语"},{"label":"C","content":"小周教英语"},{"label":"D","content":"小赵不教法语 50"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":158,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400159,6,'逻辑判断','某推理团要从王、周、吴、郑、李、赵、钱七名队员中挑选四人组成最强大脑参赛队伍， 挑选队员必须满足下列条件： (1)如果李参加，则吴也要参加； (2)除非周参加，否则钱不参加： (3) 王和周中至少有一人参加，但不能都参加； (4) 李和赵中至少有一人参加，但不能都参加。 由此可知，以下必然成立的是：','[{"label":"A","content":"周或钱参加，或者二人都参加"},{"label":"B","content":"李或钱参加，或者二人都参加"},{"label":"C","content":"吴或郑参加，或者二人都参加"},{"label":"D","content":"吴或李参加 ，或者二人都参加"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":159,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400160,6,'逻辑判断','有些受欢迎的电视剧以乡村振兴为题材。 根据以上断定，下列哪项可以断定真假： I 并非所有受欢迎的电视剧都不以乡村振兴为题材 Ⅱ有些受欢迎的电视剧不以乡村振兴为题材 Ⅲ凡受欢迎的电视剧都不以乡村振兴为题材 IV某电视剧不以乡村振兴为题材','[{"label":"A","content":"仅 I"},{"label":"B","content":"I 和 II"},{"label":"C","content":"I 和 III"},{"label":"D","content":"II 和 III 51 练习题09"}]','C','。 ⑨花生批注： 并非“所有都不”,即“所 有都不”的否定，为“有 些是”。 ③花生批注： 所有 有些←特指 逻辑判断 练习题09 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 题干详细介绍了对比 实验过程，戒酒组体 重减轻，非戒酒组体 重不变； 得出戒酒有助于减肥 (即戒酒组减肥的原 因是戒酒)这一结论。 ②花生批注： 对比实验归因类题目 常见支持方式为排除 他因，D 选项排除了 所有其他可能原因， 让结论必然正确；其 余选项均是提高了结 论的可靠性。','逻辑判断600题','进阶','published','{"globalNumber":160,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400161,6,'逻辑判断','为验证戒酒是否有助于减肥，某课题组进行了一次实验，参与实验的人均为饮酒超 过十年以上的人，将参与者分为两组，一组不戒酒，保持以前的饮酒习惯；另一组 完全戒酒。四个月后对实验参与者测量体重，发现戒酒组成员的体重平均减少了3 公斤，而非戒酒组成员的体重基本不变。因此，课题组得出结论：戒酒有助于减肥。 以下哪项如果为真，最能加强实验结论的说服力：','[{"label":"A","content":"戒酒组和饮酒组的平均体重基本相同"},{"label":"B","content":"戒酒组和饮酒组的平均年龄基本相同"},{"label":"C","content":"除戒酒外，每个实验参与者的饮食习惯基本相同"},{"label":"D","content":"除戒酒外，每个实验参与者的其他生存条件基本不变"}]','D','【题型分类】归因类——对比实验 【实战解析】对比实验和原因分析见批注。分析选项： A 选项、B 选项、C 选项均排除了一个和“减肥”有关的其他变量， 可以支持；但D选项排除了其他所有变量，较另三个选项更全面，答 案 为 D 选 项 。','逻辑判断600题','进阶','published','{"globalNumber":161,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400162,6,'逻辑判断','一项国民阅读调查报告显示，2020年我国有31.6%的成年人具有有声阅读的习惯， 较2019年的平均水平提高了1.3%,与此同时，有声阅读的介质正在悄然发生改变。 随着移动互联网兴起，有声阅读平台从早年的电台、听书网站等逐步转移，目前移 动有声APP平台已经成为有声阅读的主流选择。有人认为，未来国民有声阅读规模 将进一步扩大。 以下除哪项外，均支持上述结论：','[{"label":"A","content":"未来音频课程和各种讲述的音视频会更加丰富"},{"label":"B","content":"越来越多的人喜欢利用碎片化的时间收听图书"},{"label":"C","content":"有声阅读的介质将与智能家居、音箱等智能终端相结合"},{"label":"D","content":"个别有声阅读平台尝试从版权上游开始直接与作家合作"}]','D','。 ④花生批注： 论据：许多影视放映 场所把一些并不包含 有关限制内容的影视 片也标以“少儿不宜”; 结论：这样做可以增 加其票房收入。','逻辑判断600题','进阶','published','{"globalNumber":162,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400163,6,'逻辑判断','许多影视放映场所为了增加其票房收入，把一些并不包含有关限制内容的影视片也 标以“少儿不宜”。 这些影视放映厅之所以这样做，是因为确信以下哪组断定： I “ 少儿不宜”的影视片对成年人无害 Ⅱ观众中成年人在数量上远远超过少儿 Ⅲ成年人普遍对标明“少儿不宜”的影视片感兴趣','[{"label":"A","content":"I 和Ⅱ"},{"label":"B","content":"I 和Ⅲ"},{"label":"C","content":"Ⅱ和Ⅲ"},{"label":"D","content":"I 、Ⅱ 、Ⅲ"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":163,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400164,6,'逻辑判断','研究人员回顾了涉及全球16.4万人的近400项研究，这些人使用可穿戴运动追踪器 监测身体活动。结果显示，可穿戴运动追踪器鼓励人们每天多走40分钟(约1800 多步),在5个月内平均减轻体重1公斤。即健身追踪器、计步器和智能手表等可 穿戴运动追踪器，会鼓励人们更多地锻炼和减肥。 下列选项如果为真，最能支持上述结论的是：','[{"label":"A","content":"2014 年至2020年间，全球可穿戴运动追踪器的出货量增长了近1500%,到2020 年全球相关支出达到28亿美元"},{"label":"B","content":"一些增加身体活动的最有效策略包括行为改变技术，例如自我监控和反馈，可穿 戴运动追踪器可以提供这些技术"},{"label":"C","content":"有研究表明，可穿戴运动追踪器不但有降低血压和胆固醇，还能让人们通过增加 锻炼减轻焦虑"},{"label":"D","content":"长期以来，有很多人对可穿戴运动追踪器的有效性、准确性一直持怀疑态度，并 认为其会助长饮食障碍"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":164,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400165,6,'逻辑判断','小张、小李和小王的职业分别是公务员、工程师和教师中的一种，他们的爱好分别 是篮球、乒乓球和羽毛球中的一种。 (1) 爱好篮球和羽毛球的和小张一起去游泳。 (2)爱好乒乓球的经常和工程师一起去爬山。 (3)小李一点也不爱好篮球。 (4)公务员对乒乓球羽毛球一窍不通。 那么小李是：','[{"label":"A","content":"爱好乒乓球的工程师"},{"label":"B","content":"爱好羽毛球的工程师"},{"label":"C","content":"爱好乒乓球的教师"},{"label":"D","content":"爱好羽毛球的教师"}]','B','。 ⑦花生批注： 论据：各项大气污染 数值在近年内实现了 明显下降； 结论：这得益于近年 来本市政府持续采取 的控制大气污染的相 关措施。 ⑧花生批注： 董事会论证有二： 论证一：因为灰狼有 避免与人接触的习性， 所以灰狼不会对游客 造成伤害； 论证二：因为公园为 灰狼准备了足够食物， 所以灰狼也不会对公 园其他野生动物造成 危害。','逻辑判断600题','进阶','published','{"globalNumber":165,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400166,6,'逻辑判断','S 市环保检测中心的统计分析表明，2009年空气质量为优的天数为150天，比2008 年多出22天；二氧化碳、一氧化碳、二氧化氮、可吸入颗粒物四项污染物浓度平均 值 ，与2008年相比分别下降了约21.3%、25.6%、26.2%、15.4%, S 市环保负责人指 出 ，这得益于近年来本市政府持续采取的控制大气污染的相关措施。 以下除哪项外，均能支持上述S 市环保负责人的看法：','[{"label":"A","content":"S 市广泛开展环保宣传，加强了市民的生态理念和环保意识"},{"label":"B","content":"S 市启动了内部控制污染方案：凡是排放不达标的燃煤锅炉停止运行"},{"label":"C","content":"S 市执行了机动车排放国IV 标准，单车排放比国III 标准降低了49%"},{"label":"D","content":"S 市市长办公室最近研究了焚烧秸秆的问题，并着手制定相关条例 53"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":166,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400167,6,'逻辑判断','有着悠久历史的肯尼亚国家自然公园以野生动物在其中自由出没而著称。在这个公 园中，已经有10多年没有出现灰狼。最近，公园的董事会决定引进灰狼。董事会认 为，灰狼不会对游客造成危害，因为灰狼的习性是避免与人接触的；灰狼也不会对 公园中其他野生动物造成危害，因为公园为灰狼准备了足够的食物，如山羊、兔子等。 以下各项如果为真，都能加强题干中董事会的论证，除了：','[{"label":"A","content":"作为灰狼食物的山羊、兔子等，和野生动物一样在公园中自由出没，这增加了公 园的自然气息和游客的乐趣"},{"label":"B","content":"自然公园中，游客通常坐在汽车中游览，不会遭到野兽的直接攻击"},{"label":"C","content":"麋鹿是一种反应极其敏捷的野生动物。灰狼在公园中对麋鹿可能的捕食将减少其 中的不良个体，从总体上有利于麋鹿的优化繁衍"},{"label":"D","content":"公园有完备的排险设施，能及时地监控并有效地排除人或野生动物遭遇的险情"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":167,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400168,6,'逻辑判断','一次羽毛球邀请赛，共有五名运动员：王益、李进、舒砚、赵宇、陈亮，分别来自海南、 江西、浙江、福建、天津。据了解： (1)王益仅与另外两名运动员比赛过； (2)福建运动员仅与另外三名运动员比赛过； (3)李进没有和江西运动员比赛过； (4)江西运动员和舒砚比赛过； (5)江西、浙江、天津的三名运动员相互之间都比赛过； (6)赵宇仅与一名运动员比赛过。 根据上述资料，请问陈亮最可能是来自哪个省：','[{"label":"A","content":"海 南"},{"label":"B","content":"江 西"},{"label":"C","content":"浙江"},{"label":"D","content":"福建"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":168,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400169,6,'逻辑判断','国庆期间，几部新上映的电影大受欢迎。甲、乙、丙、丁是非常要好的朋友，平日 里就经常结伴看电影。甲提议看《中国机长》,关于他们是否看了这部电影，有以 下几个判断： (1)有人看了《中国机长》 (2)有人没看《中国机长》 (3)乙看了《中国机长》 假如以上判断只有一个是正确的，则：','[{"label":"A","content":"甲看了《中国机长》,其他不确定"},{"label":"B","content":"乙看了《中国机长》,其他不确定"},{"label":"C","content":"四人都看了《中国机长》"},{"label":"D","content":"四人都没看 54"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":169,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400170,6,'逻辑判断','某市城市规划设计院的一项调查显示，该市中心城区范围内的全部自行车道，56% 被机动车停车占用，75%有效宽度不足。为了使自行车能够重新在当地中心城区范 围内正常行驶，有人建议应当重新规划并加宽自行车道。 以下最无法质疑上述建议的是：','[{"label":"A","content":"该市机动车停车难问题越来越严重"},{"label":"B","content":"市民未能形成良好的停车习惯"},{"label":"C","content":"对占用自行车道的机动车处罚不够"},{"label":"D","content":"道路交通规划是一个长期的过程"}]','D','。 ⑪花生批注： “特例”可以推出“有 些”。 ⑫花生批注： “有些”和“所有不” 矛盾。 ⑬花生批注： 论据：56% 自行车道被 机动车停车占用，75% 自行车道有效宽度不 足，自行车不能正常 行驶； 结论：为了使自行车 正常行驶，应当重新 规划并加宽自行车道。 ⑭花生批注： 题干按照高龄父亲和 正常年龄父亲分组对 比，高龄父亲子女 DNA存在疾病相关基 因突变； 得出“男性年纪越大 孩子疾病风险越高” 的结论； 隐含了“高龄父亲孩 子疾病的原因是父亲 年龄大”这一归因过 程。 ⑮花生批注： 对比实验归因题常见 错误选项：有些类选 项 ，实验瑕疵，未分 组或分组错误，未提 及原因。 ⑯花生批注： 论据：大部分学校研 究生毕业要发表的论 文退稿率更高(即发 表论文更严格); 结论：现在研究生毕 业要难很多。','逻辑判断600题','进阶','published','{"globalNumber":170,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400171,6,'逻辑判断','研究人员对父母及其子女进行DNA 测序，发现父亲的年龄与子女基因突变存在联系， 高龄父亲的子女DNA存在着与孤独症、精神分裂症等有关的基因突变。因此，研究 人员得出结论，男性要趁早要孩子，年纪越大，孩子的疾病风险越高。 以下论述如果为真，最能质疑该结论的是：','[{"label":"A","content":"男性年龄越大，精子质量下降，包含基因突变片段越多"},{"label":"B","content":"受试群体中男性孤独症、精神分裂症的发病率显著高于女性"},{"label":"C","content":"许多受试夫妻年龄相仿，子女的基因突变更可能来自高龄母亲"},{"label":"D","content":"男性最佳育龄期晚于女性，但整个育龄期显著长于女性"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":171,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400172,6,'逻辑判断','现在研究生毕业的难度比十年前要高得多。因为现在大部分学校都要求研究生毕业 前必须在期刊上发表论文，而众所周知，现在各类期刊的退稿率比十年前提高了好 几倍。 以下最能够质疑上述观点的是：','[{"label":"A","content":"各类期刊对投稿论文的审核标准比十年前严格了很多"},{"label":"B","content":"各类期刊的种类、数量比十年前均略有增长"},{"label":"C","content":"现在的研究生倾向于重复投稿，这会导致被退稿"},{"label":"D","content":"部分专业的研究生不需要在期刊上发表论文也能毕业"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":172,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400173,6,'逻辑判断','某中学甲班学生中，所有喜欢奥数的同学也都喜欢下围棋。 若以上陈述为真，再加上以下哪项，则可以合乎逻辑地推出：有些喜欢看话剧的同 学不喜欢奥数：','[{"label":"A","content":"有些喜欢看话剧的同学也喜欢下围棋"},{"label":"B","content":"有些喜欢奥数的同学不喜欢看话剧"},{"label":"C","content":"有些不喜欢下围棋的同学喜欢看话剧"},{"label":"D","content":"有些不喜欢看话剧的同学喜欢下围棋 55"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":173,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400174,6,'逻辑判断','在经验交流会上，有多个省份的同类机构都提到了某公司新开发的安全管理系统。 他们认为，这套系统运行稳定、操作便捷，对业务帮助很大。小李代表单位参加了 本次经验交流会，会后他提出，为了提高本单位的安全管理水平，建议单位也引进 这套系统。 以下各项如果为真，最能反驳这一建议的是：','[{"label":"A","content":"本单位已经拥有一套运行多年的安全管理系统"},{"label":"B","content":"并不是所有省份的同类机构都使用了这套系统"},{"label":"C","content":"安全管理水平提升需要管理系统和管理机制双管齐下"},{"label":"D","content":"本单位的业务运行机制和其他省份有较大差异"}]','D','','逻辑判断600题','进阶','published','{"globalNumber":174,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400175,6,'逻辑判断','某研究机构对上千名中年人进行了40年的跟踪调查，结果显示，平均每年休假时间 超过3个星期的那些人，死亡率要比休假时间少于3个星期的低37%,因此，在今 后的工作中，我们应尽量让自己享受每年3个星期以上的休假。 下列各项最能削弱上述论断的是：','[{"label":"A","content":"并不是所有人都有条件每年享受超过3个星期的休假"},{"label":"B","content":"在这40年中，人们的工作，生活方式都发生了巨大变化"},{"label":"C","content":"追求更长时间休假的人往往更为关注自己的身体健康状况"},{"label":"D","content":"长时间休假可能会影响工作业绩，进而影响职业生涯发展"}]','C','','逻辑判断600题','进阶','published','{"globalNumber":175,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400176,6,'逻辑判断','依靠供给足够丰富的棋谱样本，人工智能设备就能够通过机器学习掌握如何下棋并 且战胜一流的棋手。现在，人工智能设备没有战胜一流棋手，可见供学习的棋谱样 本不够丰富。 在下列各项中选出与上述推理结构最为相似的一项：','[{"label":"A","content":"阳光和水分充足，水果就一定能长得好。这个苹果长不好，看来一定是阳光和水 分都不充足。"},{"label":"B","content":"所有的生物都是有寿命的。细菌也是生物，因此肯定是有寿命的。"},{"label":"C","content":"努力必然成功。我没有成功，必定不够努力。"},{"label":"D","content":"如果因为刮台风要停课，学生就一定会提前接到通知。学生没有提前接到通知， 可见今天没有停课。"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":176,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400177,6,'逻辑判断','某公司行政部人员手机使用情况如下： ①小王拨打过行政部所有人的电话； ②小李曾经拨打过小赵的电话，但是小赵不曾拨打过其他人的电话； ③不曾接听来自行政部其他人电话的人也就不曾拨打过其他人的电话。 由此可以推出：','[{"label":"A","content":"小赵不曾接听过来自小李的电话"},{"label":"B","content":"小李曾经接听过来自小王的电话"},{"label":"C","content":"行政部曾有人拨打过小王的电话"},{"label":"D","content":"小王接听过来自行政部所有人的电话"}]','C','【题型分类】分析类——日常分析 26花生批注：A 选项，小赵不曾拨打过电话，“非A” 开头，箭头终点，推不下去； B 选项，不能确定小李 接听了谁的电话；D 选项，不能确定是 否接听过所有人电话。【实战解析】题干③的逆否命题可翻译为：拨打过其他人电话→接听 过行政部其他人电话； 26花生批注： A 选项，小赵不曾拨打 过电话，“非A” 开头， 箭头终点，推不下去； B 选项，不能确定小李 接听了谁的电话； D 选项，不能确定是 否接听过所有人电话。 由于①可知，小王接听过行政部其他人电话(即行政部有人拨打过小 王电话); 由于②可知，小李接听过行政部其他人电话(即行政部有人拨打过小 李电话); 观察选项，只有C 选项可推出，当 选⑧。 138','逻辑判断600题','进阶','published','{"globalNumber":177,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400178,6,'逻辑判断','教练在甲、乙、丙三人背上分别贴上了三个数字，三人都能看到对方的数字，但是 看不到自己的数字，甲、乙、丙背上的数字分别用A、B、C代替。甲说B大于C; 乙说A小于C; 丙说A小于B; 教练说他们之中最多有一个人说了假话。 假如教练说的是假话，则甲、乙、丙数字大小的顺序可能是：','[{"label":"A","content":"A>B>C"},{"label":"B","content":"C>B>A"},{"label":"C","content":"B>C>A"},{"label":"D","content":"B>A>C"}]','A','。 ②花生批注： 教练：假话≤1; 教练为假，即假话>1。 28花生批注： 因为题干信息都很简 短，并且关系明确， 代入选项是比较快速 且直接的方法。','逻辑判断600题','进阶','published','{"globalNumber":178,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400179,6,'逻辑判断','某局办公室共有10个文件柜按序号一字排开。其中1个文件柜只放上级文件，2 个 只放本局文件，3个只放各处室材料，4个只放基层单位材料。 要求： (1)1号和10号文件柜放各处室材料； (2)两个放本局文件的文件柜连号； (3)放基层单位材料的文件柜与放本局文件的文件柜不连号； (4)放各处室材料的文件柜与放上级文件的文件柜不连号。 已知4号文件柜放本局文件，5号文件柜放上级文件，由此可以推出：','[{"label":"A","content":"9 号文件柜放基层单位材料"},{"label":"B","content":"2 号文件柜放基层单位材料"},{"label":"C","content":"7 号文件柜放各处室材料"},{"label":"D","content":"6 号文件柜放各处室材料"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":179,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400180,6,'逻辑判断','未来人工智能将取代旅游行业内90%的服务类工作，带来巨大变革。人工智能不是 要模仿人类，而是要超越人类。未来的十年一定是人工智能的时代，我们可以通过 人工智能的技术解决旅游行业的很多问题。要促进人工智能在旅游行业的深入发展， 技术变革和创新型人才必不可少，而高薪和福利将成为招纳人才的关键。 由此可以推出：','[{"label":"A","content":"如果不实行技术变革，人工智能难以在旅游行业深入发展"},{"label":"B","content":"未来是人工智能的时代，人工智能的发展必会颠覆传统旅游行业"},{"label":"C","content":"若能招募到创新型人才，人工智能在旅游行业的变革将会成功实现"},{"label":"D","content":"高薪和福利是当前创新型人才在择业时首先考虑的问题 57 练习题10"}]','A','。 练习题10 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 论据：物质实体 → 可 见→ 没有神秘感； 结论：精神世界不是 物质实体。','逻辑判断600题','进阶','published','{"globalNumber":180,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400181,6,'逻辑判断','所有物质实体都是可见的，而任何可见的东西都没有神秘感，因此精神世界不是物 质实体。 以下哪项最可能是上述论证所假设的：','[{"label":"A","content":"精神世界是不可见的"},{"label":"B","content":"有神秘感的东西是不可见的"},{"label":"C","content":"可见的东西都是物质实体"},{"label":"D","content":"精神世界具有神秘感"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":181,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400182,6,'逻辑判断','通常音乐被认为可以舒缓和改善人的情绪，但有一些人似乎对音乐没有任何情绪上 的反应，研究人员招募了15位宣称对音乐没有情绪反应的人，另外招募了15位认 为自己对喜欢的音乐反应比普通人更强烈的人。研究人员让这些人听各种类型的音 乐，同时对他们进行大脑扫描。对音乐缺乏反应的人的一个特定大脑区域血流量较 另外一组少。研究人员据此推测，缺乏欣赏音乐的能力是因为大脑中负责声音处理 的区域和管理情绪的区域之间的联系较少。 以下哪项如果为真，最能驳斥研究者的推测：','[{"label":"A","content":"音乐的种类和形式繁多，自认为对音乐缺少欣赏能力的人并不了解自己到底喜欢 什么音乐"},{"label":"B","content":"音乐影响情绪的过程和大脑中多巴胺的功能密切相关，而多巴胺水平是由基因决 定的"},{"label":"C","content":"自认为对音乐缺少欣赏能力的人听音乐的时候注意力容易偏离，注意力的缺乏导 致处理声音的脑区激活不足"},{"label":"D","content":"自认为对音乐缺少欣赏能力的人对音乐没有偏好，而有音乐偏好的人听喜欢的音 乐时，更容易产生愉快情绪"}]','C','。 对音乐的情绪反应强烈大脑特定区城的血流量较多果 ；对音乐染乏 情绪反应 对音乐的情绪 反应强烈 大脑特定区城的 血流量较多 四 ：大 脚 特定 区 域 的 血流量较少 归因：缺乏欣赏音乐 的能力是因为大脑中 特定区域的联系较少。 ③花生批注： 若将B选项修改为：“对 音乐缺乏情绪反应的 人们的多巴胺分泌量 较低”,则回到了题 干对比实验中，即多 巴胺低导致对音乐缺 少情绪反应，而不是 大脑两区域联系较少 导致，属于另有他因 质疑。','逻辑判断600题','进阶','published','{"globalNumber":182,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400183,6,'逻辑判断','在公司年度销售冠军评比中，各组得分都不相同。已知： ①“福州组”与“三明组”两组的总分与“宁德组”与“南平组”两组的总分相等； ②“福州组”与“南平组”两组的总分比“三明组”与“宁德组”两组的总分多； ③“福州组”与“宁德组”两组的总分不及“三明组”的得分； ④“三明组”与“南平组”两组的总分小于“龙岩组”的得分。 根据上述条件，5组得分由高到低的顺序是哪项：','[{"label":"A","content":"“龙岩组”“南平组”“三明组”“福州组”“宁德组”"},{"label":"B","content":"“ 南平组”“福州组”“三明组”“龙岩组”“宁德组”"},{"label":"C","content":"“ 南平组”“三明组”“宁德组”“龙岩组”“福州组”"},{"label":"D","content":"“龙岩组”“三明组”“南平组”“宁德组”“福州组” 58"}]','A','⑨。','逻辑判断600题','进阶','published','{"globalNumber":183,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400184,6,'逻辑判断','小吴家有人参与了义务植树活动，除非家里有人参与了义务植树活动，否则该家庭 不可能领到“义务植树参与证”,小李家领取了“义务植树参与证”。 如果以上描述为真，则下列选项中，无法判断真伪的是： (1)小吴家可以领取“义务植树参与证” (2)小李家有人参与了义务植树活动 (3)小吴家有人未参加义务植树活动','[{"label":"A","content":"仅 2"},{"label":"B","content":"仅3"},{"label":"C","content":"1 和 3"},{"label":"D","content":"123"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":184,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400185,6,'逻辑判断','研究人员检查876名志愿者的肠道菌群，并了解他们摄入欧米茄3脂肪酸的数量。 结果显示，摄入欧米茄3脂肪酸较多的志愿者，肠道菌群种类更丰富。因此，研究 人员认为食用三文鱼，补充欧米茄3脂肪酸，确实能够促进肠道健康，降低结肠炎 等肠道疾病罹患风险。 要得出上述结论，必须补充以下哪项作为前提条件：','[{"label":"A","content":"三文鱼中欧米茄3脂肪酸的含量高于其他食物"},{"label":"B","content":"肠道菌群种类越丰富，人体肠道越健康"},{"label":"C","content":"肠道越健康的人，就越不容易患结肠炎"},{"label":"D","content":"结肠炎等肠道疾病严重威胁人体健康"}]','B','⑧。 ⑤花生批注： “非A” 为箭头终点， 无法继续向下推。 ⑥花生批注： “有些”推不出“有 些不”。 ⑦花生批注： 论据：摄入欧米茄3 脂肪酸较多的志愿者， 肠道菌群种类更丰富； 结论：食用三文鱼补 充欧米茄3脂肪酸， 能够促进肠道健康， 降低结肠炎等肠道疾 病罹患风险。 ⑧花生批注： 虽然C 选项提到结肠 炎，但未与论据“搭桥”, 论据结论中断点依然 存在。 ⑨花生批注： 题干将环境污染的原 因归于焚烧秸秆。 ⑩花生批注： 否定此因、因果倒置 均能确定不是“这个 原因”,但另有他因 只是“把水搅浑”, 依然有可能是“这个 原因”,与前两者相比， 另有他因力度较弱。 ⑪花生批注： 论据：存在一些女司 机开车闯祸的新闻和 事实； 结论：“女司机”是“马 路杀手”的代称。','逻辑判断600题','进阶','published','{"globalNumber":185,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400186,6,'逻辑判断','有分析表明，华北平原等地区秸秆焚烧频繁，秸秆焚烧产生大量的有害气体，遇到无风、 逆温等大气扩散不利的天气，造成空气严重污染。借助区域试验，大范围秸秆焚烧 可使北京地区的PM2.5含量在几个小时内飙升几倍，在焚烧秸秆高发期出现的严重 污染天气中，焚烧秸秆带来的污染物对雾霾的贡献率达20%左右，因此，有专家指 出焚烧秸秆是造成环境污染的罪魁祸首。 以下哪项如果为真，最能反驳上述论证：','[{"label":"A","content":"焚烧秸秆是千百年来就有的，而雾霾问题近几年才出现"},{"label":"B","content":"全国来看，机动车保有量较大的城市一年中雾霾天气更多"},{"label":"C","content":"有数据显示，北京、上海等11省(区、 市)未监测到疑似秸秆焚烧火 点 ，但这 些地区仍然是环境污染的重灾区"},{"label":"D","content":"焚烧秸秆虽然使得农村地区空气中烟尘等污染物的浓度急剧增加，但人们普遍认 为农村的空气质量好于城市 59"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":186,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400187,6,'逻辑判断','平时，我们总能听到看到各种女司机开车闯祸的新闻：“温州女司机开路虎连撞3 车2人”,“宁波女子倒车撞死老公，自己伸头被夹身亡”,“女司机买豪车在小 区转悠炫耀，碾死邻居赔偿58万”,因此在很多人的心目中，“女司机”就是“马 路杀手”的代称。 以下哪项如果为真，最能驳斥上述看法：','[{"label":"A","content":"在市区发生的车祸赔付金额2000元以下的轻微交通事故中，女司机的比例并不高"},{"label":"B","content":"女性较男性更心细，驾驶准备工作也细致周密，且饮酒吸烟者较少，容易把精力 集中在驾车上"},{"label":"C","content":"国内男女司机比例大概是7:3,在负有同等以上责任的交通事故中，女司机导 致的为10%左右"},{"label":"D","content":"女司机在急加速、急刹车、超速方面的平均次数均低于男司机，文明驾驶程度明 显好于男司机"}]','C','【题型分类】 一般质疑类——有论据有结论 【实战解析】论据和结论见批注， 一般来说，当人们对于某个群体设 定了一个标签，就可能犯“以偏概全”的错误，因此，可以优先寻找 攻击此类漏洞的选项，依次观察选项： C 选项，假设司机总量为1000人(其中男司机700人，女司机300人), 同等以上责任交通事故司机总量为100人(其中男司机90人，女司 机10人),女司机事故率低于男司机，说明女司机更安全，并非“马 路杀手”,属于用数据质疑，当选； 其他选项： A 选项、B 选项、D 选项分别谈论的是“2000元以下的交通事故女司 机比例不高”、“女司机心细且精力集中”、“女司机文明驾驶程度 较高”,均有极弱质疑，但不能因此就说女司机不是“马路杀手”, 远不如C 选项的用数据质疑。','逻辑判断600题','进阶','published','{"globalNumber":187,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400188,6,'逻辑判断','互联网让迎合细分观众群体的媒体繁荣起来，这些媒体不受传统新闻标准的束缚。 有一项研究在国外某互联网平台上追踪了2006年至2017年的12.6万条新闻 ，结果 显示，我们更有可能分享虚假新闻，而不是真实新闻，这表明人们渴望新奇的内容。 要得到上述研究结论，需要补充的重要前提是：','[{"label":"A","content":"12.6 万条新闻中大部分是假的"},{"label":"B","content":"假新闻不受传统新闻标准的束缚"},{"label":"C","content":"假新闻不受现实束缚，更具新奇感"},{"label":"D","content":"人们传播假新闻是因为不知道真相"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":188,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400189,6,'逻辑判断','每周饮酒2-10次是适量饮酒。有调查发现，每周饮酒2-10次的男士，比每周饮酒 少于2次的男士患心脏病的概率要低。因此，适量饮酒可降低男士患心脏病的风险。 以下哪项为真，最不能削弱该论证：','[{"label":"A","content":"适量饮酒的女士比每周饮酒少于2次的女士患肝炎的概率更高"},{"label":"B","content":"适量饮酒的男士更注意加强身体锻炼"},{"label":"C","content":"适量饮酒的男士普遍比每周饮酒少于2次的男士要年轻"},{"label":"D","content":"男士们都认为，身体良好的情况下可以适当增加饮酒量"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":189,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400190,6,'逻辑判断','场所恐惧症主要表现为对某些特定环境的恐惧，如高处、广场、客观环境和拥挤的 公共场所等，常以自发性惊恐发作开始，然后产生预期焦虑和回避行为，进而出现 条件化的形成。一些临床研究表明，场所恐惧症患者常伴有惊恐发作。然而，有专 家认为最初一次惊恐发作是场所恐惧症起病的必备条件，因而认为场所恐惧症是惊 恐发作发展的后果，应归入惊恐障碍这一类别。 四海公考 逻 辑 判断6 00 o 以下哪项如果为真，最能质疑上述专家观点：','[{"label":"A","content":"场所恐惧症病程常有波动，许多患者可能短期好转甚至缓解"},{"label":"B","content":"场所恐惧症可能与遗传有关，且与惊恐障碍存在一定联系"},{"label":"C","content":"研究发现场所恐惧症起病多在40多岁，且病程趋向慢性"},{"label":"D","content":"研究发现约有23%患者的场所恐惧出现于惊恐发作以前"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":190,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400191,6,'逻辑判断','没有哪位意图作弊的考生能够逃过监考员王老师的眼睛，因为每次王老师觉得考生 状态不正常时，都能在考生身上找出违规携带的作弊物品。 以下如果为真，能够削弱上述论证的有： ①有位考生无意间携带了作弊物品进入考场，却没被王老师发现 ②王老师没有觉得某位考生状态不正常，却在该考生身上发现了作弊物品 ③某考生故意携带了作弊物品进入考场，却没被王老师发现','[{"label":"A","content":"只 有②"},{"label":"B","content":"只有③"},{"label":"C","content":"②和 ③"},{"label":"D","content":"①和 ③"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":191,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400192,6,'逻辑判断','某店铺晚上总是因客人多而忙得不可开交，而白天顾客却很少。为了在不增加店铺 晚间劳动负荷的同时提升营业额，该店经理提出，可以发行只有白天才能到店使用 的低折扣优惠券，这能吸引那些平时没有意愿到店消费的顾客在白天来店铺消费。 以下选项如果为真，最能削弱该店经理建议可行性的是：','[{"label":"A","content":"发行优惠券后店里的许多常客将选择白天而非晚上到店消费"},{"label":"B","content":"低折扣可能使白天客人剧增，导致白天店里也忙的不可开交"},{"label":"C","content":"很难将优惠券有针对性地发放到从未到店消费的新客户手中"},{"label":"D","content":"对于潜在客户来说，夜间到店消费才更符合他们的生活习惯"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":192,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400193,6,'逻辑判断','有研究者分析了公元前735年至公元800年左右的50处玛雅墓葬后发现，玛雅社会 的统治阶级日益青睐以玉米为原料的食物。由于公元800年左右曾多次发生旱灾， 而旱灾频发会严重影响玉米的收成，因此有研究者认为，过度偏重玉米的农业结构 正是导致玛雅文明灭亡的决定性因素。 下列选项最不能削弱上述论证的是：','[{"label":"A","content":"玛雅社会中底层人民并不以玉米为主食"},{"label":"B","content":"旱灾同样会严重影响水稻等作物的收成"},{"label":"C","content":"公元800年左右，玛雅文明受到了外族入侵"},{"label":"D","content":"有严重旱灾的情况下玉米的产量仍能维持一定比例的人口生存 61"}]','B','。 ⑱花生批注： “只有夜间到店消费 才更符合潜在客户的 生活习惯”,“只有 才”可翻译为“不不”, 即不是夜间消费，不 符合潜在用户的生活 习惯，可理解为“白 天的消费券不太会吸 引潜在用户到店消 费 ”。 ⑲花生批注： 论据可简化为：统治 阶级愿意吃玉米、当 时发生多次旱灾影响 玉米收成； 结论：过度偏重玉米 的农业结构导致玛雅 文明灭亡。 ②花生批注： 由统治阶级推出整个 社会灭亡的原因，范 围有所扩大，可针对 未提及人群进行攻击。 逻辑判断 ②花生批注： 可知：前年丁肯定夺 冠','逻辑判断600题','进阶','published','{"globalNumber":193,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400194,6,'逻辑判断','4名网络直播员甲、乙、丙、丁在牡丹、茶花、郁金香、菊花、玫瑰这5种花中选2 种进行直播销售。已知甲没有选茶花和菊花，乙没有选牡丹和玫瑰，只有丙选了郁 金香，4人所选的花卉均不完全相同。 基于上述条件，丁的选择是哪项：','[{"label":"A","content":"如果没有选牡丹，那么一定选了菊花"},{"label":"B","content":"如果没有选茶花，那么一定选了菊花"},{"label":"C","content":"如果没有选茶花，那么一定选了玫瑰"},{"label":"D","content":"如果没有选牡丹，那么一定选了茶花"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":194,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400195,6,'逻辑判断','今年联赛决赛的最后4支队伍是甲、乙、丙和丁。其中N 与T 分别为甲队和丁队的 主教练。有人指出，甲队此前每次夺该项桂冠的赛季都曾战胜过T 教练所在的球队； 过去4年间，丁队在N教练的指导下，每隔一年都能夺得该项桂冠，而去年丁队没 有夺冠。 以下哪项如果为真，与上述表述相矛盾：','[{"label":"A","content":"T 教练可能执教过丁队"},{"label":"B","content":"N 教练去年曾执教丁队"},{"label":"C","content":"甲队曾4次夺得该项冠军"},{"label":"D","content":"丁队前年未获得该项冠军"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":195,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400196,6,'逻辑判断','对于小李、小王和小苗能否考取研究所，有以下4种猜测： (1)小李能考取 (2)要是小王能考取，那么小苗也能考取 (3)或者小王能考取，或者小李能考取 (4)小王能考取 事后证明，这4种猜测中只有一种是对的。根据以上信息，可以得出以下哪项：','[{"label":"A","content":"小李考取了"},{"label":"B","content":"小苗没有考取"},{"label":"C","content":"小苗考取了"},{"label":"D","content":"小李没有考取"}]','D','。 2 花生批注： 或者或者，一真则真。 ②3花生批注： 此题不能“画蛇添足”, 否则容易“掉坑”: 假设①或④为真，③ 都为真，不符合“只 有一真”要求，则 ①④都为假，即小李 小王都没考上，那么 ③也为假； 此时可以判断②为真， 但是，②为真，不能 确定小苗考取； ②为真有三种情况： 小王且小苗，非王且 苗，非王且非苗； 目前知道小王未考上， 但是后两种情况不确 定哪一种发生，即小 苗无法确定是否考取。','逻辑判断600题','进阶','published','{"globalNumber":196,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400197,6,'逻辑判断','某班进行演讲比赛，最后进入决赛的是a 、b 、c 、d 、e五位同学。关于谁是第一名， 班上三位同学甲、乙、丙谈了自己的看法 甲：b 、c 都不可能是第一名 乙：第一名不是b 就是e 丙：第一名绝不是e 比赛结果出来后，发现他们三人中只有一个人的看法是正确的，那么,这次演讲比 赛的第一名是：','[{"label":"A","content":"a"},{"label":"B","content":"b"},{"label":"C","content":"c"},{"label":"D","content":"e"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":197,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400198,6,'逻辑判断','小米熬成稀粥后，大分子淀粉会发生水解反应，产生小分子的糊精和少量脂肪，这 些成分都浮在粥的表面，稍稍冷却后形成一层薄薄的米油。有人说，小米粥上的这 层米油营养价值极高，滋补能力极强，还可以保护胃黏膜。 以下各项如果为真，最能质疑上述观点的组合是： ①未精制的小米富含维生素B1、B2和钾等成分 ②米油没有什么极高营养价值和极强的滋补能力 ③米油可助消化，但助消化并不等于营养价值高 ④研究证明，米油对胃黏膜没有明显的保护作用','[{"label":"A","content":"①③"},{"label":"B","content":"②④"},{"label":"C","content":"①③④"},{"label":"D","content":"②③④"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":198,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400199,6,'逻辑判断','近两年来，国内喜欢京剧的大学生的数量出现了持续性的上升，因此，可以认为近 两年国内大学生的数量正在不断增加。 下列各项中，最能支持上述结论的是：','[{"label":"A","content":"近两年来，京剧推广越来越频繁"},{"label":"B","content":"近两年来，国内喜欢京剧的大学生的数量在国内大学生总人数中所占比例不变"},{"label":"C","content":"今年喜欢京剧的国内大学生的数量是两年前的三倍"},{"label":"D","content":"近两年来，越来越多的外国学生也开始学唱京剧"}]','B','【题型分类】支持类——断点搭桥 【实战解析】论据结论可见批注，国内喜欢京剧大学生和国内大学生 间存在明显断点，需要搭桥，选项中只有B 选项将二者搭桥，可直 接秒选，其逻辑关系如下： 国内喜欢京剧大学生占国内大学生比例不变，若分子增大，则分母必 然增大，即国内大学生总量增加。 25花生批注： 例如： 运动可以改善记忆力， 但记忆力好不代表能 减肥； 这句话只是说明记忆 力好和减肥是两回事， 并没有说明运动不能 减肥。运动可改善记 忆力和运动可减肥， 可同时发生。 26花生批注： 论据：国内喜欢京剧 大学生数量上升； 结论：国内大学生数 量上升。 ②花生批注： A、C、D选项均未将 国内喜欢京剧大学生 和国内大学生总量关 联，均无法支持。 28花生批注： 切记：此类题目“以 我为主”,寻找想要 答案，不要被错误选 项干扰。 155 ⑨花生批注： 论据：按照是否阶段 性回溯将年轻人分为 两组，回溯组记忆单 词效果更好； 结论：将阶段性回溯 学习模式作为老年人 记忆训练测试，可弥 补认知功能劣势。','逻辑判断600题','进阶','published','{"globalNumber":199,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400200,6,'逻辑判断','一项研究中，研究人员指导两组大学生被试学习5列单词，每列10个，被试逐词逐 列学习。实验组被试在学习完每一列单词之后分别进行临时测试，回忆刚刚学习的 那列单词。控制组的被试则不参加第1至第4列单词的临时测试只在完成第5列词 表后进行临时测试。结果发现，在第5列单词的临时测试中，实验组能够准确记住 的单词量是控制组的2倍。研究人员据此认为，将阶段性回溯的学习模式作为老年 人的记忆训练测试，可弥补他们的认知功能劣势。 下列各项如果为真，除哪项外均可以作为上述研究论证的前提：','[{"label":"A","content":"实验组和控制组被试在实验开始前的认知能力测试结果无显著差异"},{"label":"B","content":"老年人认知功能下降主要表现在记忆力降低"},{"label":"C","content":"老年人的记忆增强机制和年轻人的差异不大"},{"label":"D","content":"对于简单事物和复杂事物的学习，阶段性回溯模式均有相同效果 63 练习题 11"}]','D','。 逻辑判断( 练习题 11 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":200,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400201,6,'逻辑判断','新发现的翼龙足迹化石共114个足迹，包括57个前足足迹和57个后足足迹，研究 者推断造迹者是四足行走的。其中含有2种大小和形态不一的翼龙足迹：尺寸较小 的为乌尔禾翼龙足迹，尺寸较大的也属于翼龙足迹属的成员，这两类足迹是由两种 体型不同的翼龙所留。研究人员从乌尔禾翼龙足迹后足提取了解剖学的特征，并首 次与当地发现的翼龙实体化石进行了对比，他们推断，乌尔禾翼龙足迹的造迹者极 有可能是复齿湖翼龙。这些足迹化石密度很高且大小不一，代表有不同年龄层次的 湖翼龙在乌尔禾地区的湖岸边生活。 以下各项如果为真，除哪项外均能支持文中的推论：','[{"label":"A","content":"两足行走的恐龙不会同时留下前足和后足足迹"},{"label":"B","content":"恐龙在不同运动形态下的足迹大小不同"},{"label":"C","content":"不同体型的恐龙留下的足迹大小不同"},{"label":"D","content":"不同年龄的湖翼龙其足迹大小不同"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":201,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400202,6,'逻辑判断','甲每天都会进行锻炼，其锻炼种类有跑步、游泳、举重、做俯卧撑和骑行五种，但 他每天只锻炼其中的一种。已知： (1)跑步一周跑两次，两次在一周内相隔三天 (2)举重的时间是在 一周中第 一 次跑步的前 一 天或后 一 天， 一周只举 一 次 (3)游泳也是一周只游一次，在一周中第二次跑步之前的任意一天 (4)做俯卧撑也仅限一次，时间与一周中第一次跑步那天在一周内相隔4天 (5)有一次骑行的时间是在一周中第一次跑步之前 假定周一为一周的第一天，根据上述陈述，可以推出甲：','[{"label":"A","content":"周一举重"},{"label":"B","content":"周二跑步"},{"label":"C","content":"周四游泳"},{"label":"D","content":"周日骑行"}]','B','。 四海公煮 SIHAIGONGKA⁰ 逻辑判断','逻辑判断600题','进阶','published','{"globalNumber":202,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400203,6,'逻辑判断','部分英国医生宣称，他们开始对苹果iPad 用户类似重复性劳损的病症进行治疗，这 类被戏称为“i 伤害”的病症，主要表现为用户的手和点击、触摸屏幕的手指出现 各种各样的病痛。专家推测：大多数iPad 用户左手拿着平板电脑以保持其稳定，右 手食指点击屏幕发送邮件或生成文件。这使得他们有患上诸如重复性劳损、腕管综 合症以及其他肌腱伤害的风险。 如果以下各项为真，最能支持上述专家推测的是：','[{"label":"A","content":"使用 iPad 的用户患上此类病症的概率比较高"},{"label":"B","content":"使用其他品牌平板电脑的用户出现了类似病症"},{"label":"C","content":"未普及iPad 的地区此类病症出现的比率极少"},{"label":"D","content":"使用台式机的用户患上此类病症的概率比较低"}]','D','。 ④花生批注： D 选项，可翻译为： 甲且乙→丙且丁； 命题为真有三种情况： 甲且乙为真，丙且丁 为真，此时该选项为 假； 甲且乙为假，丙且丁 为真，此时该选项可 能为真(只有丙丁参 加),也可能为假(甲 丙丁或乙丙丁参加); 甲且乙为假，丙且丁 为假，此时该选项为 真(甲乙至少一人不 参加、丙丁至少一人 不参加，参加人数最 多 2人 ) ; 综 上 ，D 选项可能为 假可能为真。 ⑤花生批注： 论据：长时间觉醒学 习后，突触增多阻碍 学习，睡眠能减弱突 触连接，为随后学习 提供充足空间和能量； 结论：睡眠有利于学 习和记忆。','逻辑判断600题','进阶','published','{"globalNumber":203,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400204,6,'逻辑判断','某班举办同学聚会，有些同学因故不能参加。班长说：“312宿舍的甲、乙、丙、 丁四名同学中，最多有两人参加。”团支书说：“班长，我觉得你说的不对。” 如果团支书说的不对，则下列哪项必为假：','[{"label":"A","content":"甲、乙、丙、丁四人中有两人能参加"},{"label":"B","content":"甲、乙、丙、丁四人都不能参加"},{"label":"C","content":"甲、乙、丙、丁四人都能参加"},{"label":"D","content":"如果甲和乙能参加，那么丙和丁也能参加"}]','C','④','逻辑判断600题','进阶','published','{"globalNumber":204,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400205,6,'逻辑判断','近年来的许多研究证实睡眠有利于学习和记忆。不仅是学习后的睡眠具有记忆巩固 功能，而且学习前的睡眠对于随后的学习也是必需的。长时间觉醒学习后，脑内突 触连接增多、增强，导致突触间隙饱和，阻碍随后继续学习。睡眠的作用是减弱突 触连接到基础水平，为随后的学习记忆提供充足的空间和能量。 以下哪项如果为真，最能支持研究人员的观点：','[{"label":"A","content":"睡眠时大脑内的突触停止工作"},{"label":"B","content":"突触的连接活动需要占用空间和能量"},{"label":"C","content":"学习和记忆必须要在觉醒状态下进行"},{"label":"D","content":"睡眠时人体内基础代谢活动将会减慢"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":205,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400206,6,'逻辑判断','我们通常需要7～9小时的睡眠，过长的睡眠可能意味着健康隐患。过去十多年的 随访结果表明，每晚睡眠时间长期超过9小时的老年人，患老年认知功能障碍的风 险是同龄人的两倍。因此，长时间的睡眠是神经退行性疾病如老年认知功能障碍的 早期生物学指标。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"一些参与随访的老年人对自己的睡眠状况并不能准确描述"},{"label":"B","content":"因意外或其他疾病发生大脑损伤的老人会出现过度睡眠"},{"label":"C","content":"一些研究发现，许多睡眠不足7小时的老年人也出现了老年认知功能障碍"},{"label":"D","content":"神经退行性疾病的发生与大脑中聚集的一种蛋白有关，当人体试图清除这一蛋白 时，需要更长的睡眠 65"}]','B','。 161','逻辑判断600题','进阶','published','{"globalNumber":206,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400207,6,'逻辑判断','小王没有吃饭，所以小王今天加班了。 得出上述结论的前提是：','[{"label":"A","content":"所有今天没有加班的人都吃了饭"},{"label":"B","content":"所有没有吃饭的人今天都加班了"},{"label":"C","content":"所有今天加班的人都没有吃饭"},{"label":"D","content":"所有吃了饭的人今天都没有加班"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":207,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400208,6,'逻辑判断','共享单车作为一种新鲜事物，近来发展迅速。在城市的大街小巷，几乎到处可见共 享单车的影子。共享单车构成城市一道新的亮丽风景线，也为人们的出行提供了方便。 但是，有一些市民对整个自行车生产行业表示担忧，他们认为：共享单车的出现和 大量投入使用，使得很多计划购买自行车的个人不再购买。因此，整个自行车行业 的生产和销售量随之减少。 以下哪项如果为真，最能削弱这些市民的结论：','[{"label":"A","content":"不同品牌的自行车生产商将面临更激烈的市场竞争，有些厂家与共享单车运营公 司合作，会生产和销售更多的自行车"},{"label":"B","content":"共享单车也存在很多的问题，比如，存在安全隐患，在有需求时不能及时找到， 有一些民众仍愿意购买专属自己的自行车"},{"label":"C","content":"共享单车由共享单车所属公司委托自行车生产商生产，共享单车的数量远远超过 了因个人需求而产生的购买量"},{"label":"D","content":"共享单车的使用需要网上申请账号，使用时需要进行微信扫码，很多中年人不会 上网，因此他们更愿意自己购买自行车"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":208,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400209,6,'逻辑判断','某部门共有5人，有以下三个命题：①部门中有部分人是女生；②部门中有部分人 是男生；③部门经理是男生，已知这三个命题中有且仅有一个是真的，由此可以推 出该部门：','[{"label":"A","content":"5 人都是女生"},{"label":"B","content":"5 人都是男生"},{"label":"C","content":"只有1人是女生"},{"label":"D","content":"至少有2人是男生"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":209,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400210,6,'逻辑判断','某城市的中心区域车流量大、道路较窄，常年交通拥堵。对此，有市民建议，既然 交通拥堵是由于车多路窄引起的，那么拓宽道路就可以有效解决这一问题。 以下最能削弱上述论证的是：','[{"label":"A","content":"一般来说，遇到下雨天交通拥堵情况会更加严重"},{"label":"B","content":"道路拓宽施工会加剧该路段的交通拥堵问题"},{"label":"C","content":"发展公共交通同样有助于减缓道路拥堵"},{"label":"D","content":"道路拓宽后，行驶的车辆也会相应增加"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":210,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400211,6,'逻辑判断','随着移动终端的发展，个人偏好的数据变得更加容易收集了。有专家认为，这能够 形成一种双赢局面：媒体能够有效地找到自己的信息受众，而个人也能更便捷地获 得符合自己偏好的信息。由于减少了无关信息的干扰，这对于社会创新将是一个重 大利好。 下列能够最有力地质疑上述结论的是：','[{"label":"A","content":"创新更有赖于接收个人偏好以外的信息"},{"label":"B","content":"个人会根据自己的偏好主动选择一些信息提供渠道"},{"label":"C","content":"当前移动终端与互联网的发展尚未能充分收集个人偏好"},{"label":"D","content":"媒体向个人输送符合其偏好信息的同时也发送了更多广告"}]','A','【题型分类】 一般质疑类——有论据有结论 【实战解析】论据结论见批注， 观察选项： A 选项，虽然个人能更便捷找到符合偏好的信息，但是创新依赖偏好 外的信息，所以这种局面反而不利于社会创新，可以质疑； B 选项，“个人选择哪种渠道收集信息”与“是否有助于社会创新” 话题不一致，属无关项； C 选项，题干说的是“能形成一种双赢局面”,是对未来趋势的判断， 而非目前就是这样的现状，该选项无法质疑； D 选项，“发送广告”与“社会创新”话题不一致，无关项； 综上，正确选项为A 选项。 164 四海公煮 逻辑判断','逻辑判断600题','进阶','published','{"globalNumber":211,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400212,6,'逻辑判断','某机关开展干部职工运动会，共有16个队参加拔河比赛，经过两轮比赛，甲、乙、 丙、丁四队进入半决赛。有人预测： (1)甲队不是第一名； (2)第一名一定是甲队或乙队； (3)如果丙队不是第一名，丁队也不是第一名。 如果预测只有一句话是对的，则第一名是谁：','[{"label":"A","content":"甲队"},{"label":"B","content":"乙队"},{"label":"C","content":"丙队"},{"label":"D","content":"丁 队"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":212,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400213,6,'逻辑判断','有研究人员分析发现，那些在公共交通领域财政支出更多的城市空气质量也更好， 因此，该研究人员得出结论：增加城市公共交通财政支出有利于提升城市空气质量。 以下最能削弱上述论断的是：','[{"label":"A","content":"城市空气质量可能会受到短期内天气变化的影响"},{"label":"B","content":"公共交通财政支出高的城市，也有更多的资金用于改善空气质量"},{"label":"C","content":"随着公共交通财政支出的增加，公共交通工具的数量也会相应增加"},{"label":"D","content":"公共交通财政支出的增加并不一定带来公共交通质量的提升"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":213,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400214,6,'逻辑判断','秋冬时节感冒多发，预防感冒的小技巧很受关注。网上一直流传：放置一颗洋葱在 房间里，可以预防感冒，因为洋葱挥发出的含硫化合物有抑菌抗癌的作用，可净化 室内空气。因此，在室内放几个切去两端的洋葱，就可以有效预防感冒。 以下各项如果为真，哪项最能驳斥以上观点：','[{"label":"A","content":"洋葱所含硫化物对肠道的细菌有一定抑制作用，但需要每天口服一定的量"},{"label":"B","content":"人类所患感冒中70%～80%的感冒是由病毒引起的，洋葱对病毒是没有抑制作用的"},{"label":"C","content":"实验证明，室内放置洋葱1小时后，室内细菌总数没有显著减少"},{"label":"D","content":"现有研究尚未发现食物可以有效吸附病菌和病毒 67 逻辑判断"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":214,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400215,6,'逻辑判断','小王打算锻炼身体，他观察了小区长跑队后，发现长跑队的人要比没有坚持长跑的 人更加健康。因此他认为，长跑能增进健康。 以下哪项如果为真，最能质疑小王的论证：','[{"label":"A","content":"身体健康状况不好的人大多无法长期坚持长跑锻炼"},{"label":"B","content":"参加球类活动、游泳等也都能锻炼身体增进健康"},{"label":"C","content":"长期长跑会对膝盖、脚踝等造成损伤"},{"label":"D","content":"就跑步而言，慢跑对健康更加有利"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":215,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400216,6,'逻辑判断','有研究报告说与心跳速度每分钟低于58次的人相比，心跳速度每分钟超过78次 者心脏病发作或者发生其他心血管问题的机率高出39%,死于这类疾病的风险高出 77%,其整体死亡率高出65%,研究人员指出，长期心跳过快导致了心血管疾病。 下列哪项如果为真，最能对该研究人员的观点提出质疑：','[{"label":"A","content":"野外奔跑的兔子心跳很快，但是发现它们患有心血管疾病"},{"label":"B","content":"在老年人中，长期心跳过快的超过39%"},{"label":"C","content":"各种心血管疾病影响身体的血液循环机能，导致心跳过快"},{"label":"D","content":"相对于老年人，年轻人生命力旺盛，心跳较快"}]','C','','逻辑判断600题','进阶','published','{"globalNumber":216,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400217,6,'逻辑判断','在一次摩托车比赛中，有5位运动员的名次可能是这样的(每个名次只能一人): ①赵爱武第二，钱塘江第三；②钱塘江第一，孙达胜第四；③李积红第三，周冠群 第五；④赵爱武第二，孙达胜第四；⑤周冠群第一，李积红第二。比赛结果证明上 述猜测每个人各有一句是正确的。 由此可知，谁是冠军：','[{"label":"A","content":"赵爱武"},{"label":"B","content":"钱塘江"},{"label":"C","content":"孙达胜"},{"label":"D","content":"李积红"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":217,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400218,6,'逻辑判断','据调查，某地90%以上有过迷路经历的司机都没有安装车载卫星导航系统。这表明， 车载卫星导航系统能有效防止司机迷路。 以下最能削弱上述论证的一项是：','[{"label":"A","content":"很多老司机没有安装车载卫星导航系统，很少迷路"},{"label":"B","content":"车载卫星导航系统的使用效果不理想，对防止迷路没有多大作用"},{"label":"C","content":"当地目前只有不足10%的汽车安装了车载卫星导航系统"},{"label":"D","content":"安装了车载卫星导航系统的司机，90%以上经常使用"}]','C','【题型分类】 一般质疑类——比例论证 【实战解析】论据结论见批注。车载导航系统是否可以防止司机迷路 应该比较迷路率③,题干只分析了迷路司机中车载导航系统的安装情 况，未考虑所有司机中车载导航系统的安装情况，直接在选项中寻找 “带数字的分母(即所有司机中车载导航系统的安装情况)”③即可， 观察选项： C 选项，假设所有司机共计1000人(则安装该系统的不足100人， 未安装该系统的超过900人),迷路司机100人(则安装该系统的 不足10人，未安装该系统的超过90人),安装此系统的迷路率为 10-/10 0-, 未安装此系统的迷路率为90+/900+,无法判断该 系统是否有效，可以质疑，当选。 其他选项： A 选 项 ，老司机未按该系统也很少迷路，和该系统是否有效无关； B 选项，直接指出该系统对防止迷路没有多大作用，未指出题干漏洞， 是正确答案的概率极低； D 选项，“使用频率”和该系统是否有效无关，无法质疑。 29花生批注： 论据：90%以上有过迷 路经历的司机都没有 安装车载卫星导航系 统； 结论：车载卫星导航 系统能有效防止司机 迷路。 ③0花生批注： 迷路率=迷路数/司 机数； 安装导航的迷路率= 安装导航的迷路司机 数/安装导航的司机 总数； 没有安装导航的迷路 率=没有安装导航的 迷路司机数/没有安 装导航的司机总数。 ③花生批注： ③2花生批注： 比例类题目要“以我 为主”,直接去选项 中寻找“带数字的分 母”即可。 33花生批注： “特例”可以推“有些”; “张三不会使用网络 支付”可以推出“有 人不会使用网络支 付”。 170 170','逻辑判断600题','进阶','published','{"globalNumber":218,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400219,6,'逻辑判断','甲、乙、丙和丁是某公司销售员，已知公司派遣其中两人前往广州的A、B公司，另 两人前往上海的C、D公司扩展业务，要求甲、丙分成一组，乙、丁分成一组且每人 各负责一家公司。已知甲没有去A公司，乙没有去B公司；丙没有去C公司；丁没 有去D公司。 根据以上陈述肯定可以得出：','[{"label":"A","content":"甲没有去B公司"},{"label":"B","content":"乙没有去A公司"},{"label":"C","content":"丙没有去D公司"},{"label":"D","content":"丁没有去A公司"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":219,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400220,6,'逻辑判断','老年大学组织了一次关于“是否会使用网络支付”的情况调查，某个班共有50个学 生，该班的调查情况如下： ①有人会使用网络支付 ②有人不会使用网络支付 ③张三不会使用网络支付 以上三句话只有一句为真，能够推出的结论是：','[{"label":"A","content":"这个班人人都会使用网络支付"},{"label":"B","content":"这个班人人都不会使用网络支付"},{"label":"C","content":"这个班只有一个人会使用网络支付"},{"label":"D","content":"这个班只有一个人不会使用网络支付 69 练习题12"}]','A','。 练习题 12 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":220,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400221,6,'逻辑判断','近十年来，新飞冰箱厂通过不断引进先进设备和技术，使得劳动生产率大为提高。 即在单位时间里，较少的工人生产了较多的产品。 请问以下哪项如果为真，就一定能支持上述结论： I 和1997年相比，2007年新飞冰箱厂的年利润增加了一倍，工人增加了10%。 Ⅱ和1997年相比，2007年新飞冰箱厂的年产量增加了一倍，工人增加了100人。 Ⅲ和1997年相比，2007年新飞冰箱厂的年产量增加了一倍，工人增加了10%。','[{"label":"A","content":"只有I"},{"label":"B","content":"只有Ⅱ"},{"label":"C","content":"只有Ⅲ"},{"label":"D","content":"只有 I 和Ⅱ"}]','C','。 ①花生批注： 题干只有结论：劳动 生产率提高； 劳动生产率=单位时 间产品/工人数量。 逻辑判断 ②花生批注： 论据可简化为：(不 转变成动物属性基因 的)转基因植物的基 因不会有任何活性； 结论：食用转基因植 物不会发生基因突变。 ③花生批注： 此选项干扰力度极强， 需仔细分析： ①转基因植物的基因 没有被转变为动物属 性基因，即转基因植 物的基因没有任何活 性； 但“活性”与“基因突变” 之间依然存在断点， 不能让论证完整，非 此论证的“前提假设”; ②可“否定代入”: 即使转基因植物基因 被转变为动物属性基 因，其有了活性，食 用转基因植物也可能 不会发生基因突变； “没他也行”的选项， 不会是前提假设类题 目的正确选项。 ④花生批注： A 、B 、C选项均不包 含结论中的“不会发 生基因突变”的新内 容，即使补充到论证 中，结论也无法成立。 所以实战中，找到唯 一包含“不会发生基 因突变”的选项，可 秒选。 ⑤花生批注： 本题也可利用 “大大>小小”秒杀， 借阅>自购， 中文>英文， 所以借阅中文一定多 于自购英文。','逻辑判断600题','进阶','published','{"globalNumber":221,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400222,6,'逻辑判断','转基因植物的基因具有植物属性，若不将其转变为动物属性的基因，即使特意将其 转入动物细胞内，也不会有任何活性。因此，食用转基因植物是不会发生基因突变的。 上述论证的成立，需要补充以下哪项作为前提：','[{"label":"A","content":"转基因植物的基因没有被转变为动物属性基因"},{"label":"B","content":"我们食用的转基因植物的基因没有活性"},{"label":"C","content":"转基因植物的基因没有被转入动物细胞内"},{"label":"D","content":"食用没有活性的基因是不会发生基因突变的"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":222,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400223,6,'逻辑判断','在研究生小刘的书架上放着15本图书，除从图书馆借阅的9本之外，其他均系自购。 其中包括中文图书8本，英文原版书7本。若其中从图书馆借阅的中文图书至多7本， 则可以得出以下哪项：','[{"label":"A","content":"自购的中文图书至少2本"},{"label":"B","content":"自购的英文原版书至少1本"},{"label":"C","content":"自购的中文图书多于从图书馆借阅的英文原版书"},{"label":"D","content":"自购的英文原版书少于从图书馆借阅的中文图书"}]','D','【题型分类】分析类——日常分析 【实战解析】假设借阅的中文书数量为a, 则其他书籍数量如图所示： 借阅9本 自购6本 中文8本 a 8-a 英文7本 9-a 6-(8-a)=a-2 观察上图可知：借阅英文>自购中文，借阅中文>自购英文，直接在 选项中寻找即可，答 案 为 D 选 项⑤。 四海公煮 SI HAIGONGKAO 逻辑判断','逻辑判断600题','进阶','published','{"globalNumber":223,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400224,6,'逻辑判断','某科学家在研究意大利古比奥地区白垩纪末期地层中的黏土层时，发现微量元素铱 的含量比其他时期地层陡然增加了30～160倍，之后人们从全球多处地点取样检测 都得出同样结论：白垩纪末期地层中铱元素含量异常增高的确是普遍性的。科学家 据此推测，在白垩纪末期有一颗巨大的小行星撞击了地球，产生的尘埃遮天蔽日， 造成地表气候环境巨变，从而导致了恐龙的灭亡。 以下哪项如果为真，最能削弱上述科学家的推测： 70','[{"label":"A","content":"小行星一般由硅、铁类元素构成，巨大的小行星落在地球表面，即使经历漫长岁 月也不可能踪迹全无"},{"label":"B","content":"白垩纪末期的岩层大部分是熔岩冷却形成的火成岩，而由小行星撞击地球产生的 尘埃堆积而成的沉积岩只占地表的很小一部分"},{"label":"C","content":"铱元素不仅存在于地球外的天体，也存在于地壳内部"},{"label":"D","content":"已发现的恐龙和恐龙蛋化石全部存在于富含铱元素的黏土层下的地层中"}]','D','。 ⑥花生批注： 题干将恐龙灭绝的原 因归于白垩纪末期小 行星撞击地球； 理由为在白垩纪末期 地层铱元素普遍异常 增高，隐含了铱元素 可能由小行星带到地 球的推测。 ⑦花生批注： 地球演变经历了亿万 年，任何时期行星带 来的沉积岩都应该占 比极小，因为“占比 极小”,无法推出“当 时影响很小”。 逻 辑 判 断 ⑧花生批注： 本题也可采用排除法： 根据④排除C、D选项； 根据⑤排除B选项， 答案只能为A选项。 ⑨花生批注： 论据：感冒分为病毒 性感冒和细菌性感冒； 病毒性感冒一周左右 可以自愈； 结论：大多数感冒无 需服药打针治疗(即 大多数感冒可以自 愈)。 174 174','逻辑判断600题','进阶','published','{"globalNumber":224,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400225,6,'逻辑判断','有历史学家对春秋五霸“齐、晋、楚、秦、宋”的国力做评估，打分结果如下：“齐”、 “晋”两国的总分与“楚”、“秦”的总分相等，“齐”、“秦”两国的总分比“晋”、 “楚”的总分多，“齐”、“楚”两国的总分不及“晋”的得分，“晋”、“秦” 两国的总分小于“宋”的得分。 假如上述研究论述为真，五国的国力得分由高到低的顺序为下列哪项：','[{"label":"A","content":"“宋”“秦”“晋”“齐”“楚”"},{"label":"B","content":"“ 宋”“晋”“秦”“楚”“齐”"},{"label":"C","content":"“ 秦”“齐”“晋”“宋”“楚”"},{"label":"D","content":"“秦”“晋”“楚”“宋”“齐”"}]','A','⑧','逻辑判断600题','进阶','published','{"globalNumber":225,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400226,6,'逻辑判断','在医学上，根据引起感冒的病原体不同，可将感冒分为病毒性感冒和细菌性感冒。 如果没有细菌感染的话，通过人体自身产生的免疫力，感冒一周左右就可以自愈。 所以，大多数感冒无需服药打针治疗。 为使以上结论成立，以下必须为真的一项是：','[{"label":"A","content":"患普通感冒有利于提高人的免疫力"},{"label":"B","content":"人们所患的感冒一般是病毒性感冒"},{"label":"C","content":"服药打针治疗疾病对人体有较大的副作用"},{"label":"D","content":"感冒不止病毒性感冒和细菌性感冒两种"}]','B','【题型分类】前提假设类——断点搭桥 【实战解析】论据和论点见批注，“病毒性感冒”和“大部分感冒” 之间存在明显断点，需要搭桥⑩,B 选项为二者建立联系，为搭桥选项， 可以秒选，其逻辑关系如下： 病毒性感冒一周左右可以自愈，人们所患感冒一般是病毒性感冒，所 以大多数感冒无需服药打针治疗(可以自愈)。 ⑩花生批注： 切记：此类题目“以 我为主”,寻找想要 答案，不要被错误选 项干扰。','逻辑判断600题','进阶','published','{"globalNumber":226,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400227,6,'逻辑判断','所有用心诊治患者的医生，都被证明是医术高超的医生；而用心诊治患者的医生， 都首先把注意力集中放在解决患者的后顾之忧上。因此，那些不首先把注意力放在 解决患者后顾之忧上的医生，都不是医术高超的医生。 为使上述论断成立，必须以下列哪项为前提：','[{"label":"A","content":"不首先把注意力放在解决患者的后顾之忧上的医生，都不是用心诊治患者的医生"},{"label":"B","content":"所有医术高超的医生，都是用心诊治患者的医生"},{"label":"C","content":"所有首先把注意力放在解决患者的后顾之忧上的医生，都是用心诊治患者的医生"},{"label":"D","content":"所有首先把注意力放在解决患者的后顾之忧上的医生，都是医术高超的医生 71 71"}]','B','。 175 ⑪花生批注： 背景：市场一片繁荣； 专家观点：对经济复 苏不要过度自信和乐 观。 ⑫花生批注： 题干对比了适量饮酒 和滴酒不沾人的身体 健康状况，得出更健 康是因为适量饮酒的 结论。','逻辑判断600题','进阶','published','{"globalNumber":227,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400228,6,'逻辑判断','某东南亚国家宣布，11月份该国失业率跌至6.8%,是自2010年以来的最低值。某 经济调查机构发布的报告也显示，在失业率下降的同时，该国新增就业人数出现了 大幅增长，受此消息影响，该国股市开始大涨，银行也开始放松银根，为市场提供 更多信贷，市场呈现一片繁荣的景象。但也有专家提出应该冷静看待这种“繁荣”, 提醒大家对经济复苏不要过度自信和乐观。 以下选项如果为真，最能支持专家观点的一项是：','[{"label":"A","content":"失业率下降的背景是房价上涨、物价升高，消费者购买力下降"},{"label":"B","content":"该国发布的经济数据经常被外国媒体质疑造假"},{"label":"C","content":"工作年龄人口数量增加，但劳动力市场规模因大量退休人口而缩小"},{"label":"D","content":"导致该国11月份出现失业率下降的部分因素是许多知名大企业入驻该国"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":228,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400229,6,'逻辑判断','有数据表明，适量饮酒的人群比滴酒不沾的人群整体健康水平更高。这说明，适量 饮酒有利于身体健康。 以下各项如果为真，最能质疑上述观点的是：','[{"label":"A","content":"酒精对一些关节疾病有一定的疗效，而对大多数消化系统和神经系统疾病有负面 作用"},{"label":"B","content":"一般情况下，身体健康的人更倾向于适量饮酒，而健康问题更容易成为人们拒绝 烟酒的原因"},{"label":"C","content":"适量饮酒者往往比滴酒不沾的人更乐观、自信，对自我评价更高，精神上的愉悦 有助于身体健康"},{"label":"D","content":"所谓饮酒的适量往往因人而异，调查显示，高纬度地区人们饮酒量更大，而低纬 度地区的饮酒量则相对较小"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":229,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400230,6,'逻辑判断','美国一项最新研究发现，肥胖具有“社会传染性”,它很容易从一个人传染到另一 个人身上，社会纽带在肥胖问题上的影响甚至超过基因的作用。研究人员认为，这 主要是由于身体肥胖的亲人和朋友改变了你对于体重可接受的标准，你会认为他们 的体重可以接受。 以下哪项如果为真，最能质疑研究人员的解释：','[{"label":"A","content":"肥胖的人更倾向与肥胖的人交朋友"},{"label":"B","content":"基因对人的肥胖程度的影响其实是不确定的"},{"label":"C","content":"一个人的饮食生活习惯往往会受到家人和朋友的影响"},{"label":"D","content":"很多人由于现代社会压力大、暴饮暴食等原因导致肥胖"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":230,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400231,6,'逻辑判断','最近热播的电视剧涉及教育资源争夺战，不仅把观众的心弦绷紧到了低龄教育阶段， 而且暴露了一个更为深层次的问题，即究竟什么才是好的教育。 一些剧中人以为， 只要孩子能够考到高分进入好的学校，就是最好的教育。 以下哪项如果为真，最能质疑上述观点：','[{"label":"A","content":"应试教育是教育资源长期相对匮乏、社会选拔标准相对单一的后遗症"},{"label":"B","content":"仅仅以分数作为单一评判标准，早已不能满足市场对各种人才的需要"},{"label":"C","content":"近年来，相关部门开展了校外培训机构专项治理，已取得阶段性成效"},{"label":"D","content":"个别孩子以很高的分数考入国内著名高校，最终却走上了犯罪的道路"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":231,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400232,6,'逻辑判断','一项研究显示：汽车尾气中的一氧化碳可以改变空气中的一些植物蛋白的化学特性， 使其成为能导致严重过敏反应的过敏源。所以有人认为：近年来城市中过敏性疾病 的发病率升高，是由于汽车保有量不断增加所致。 假设以下各项为真，最能质疑上述结论的是：','[{"label":"A","content":"遗传、免疫缺陷等人体内在因素也是过敏性疾病发生的原因"},{"label":"B","content":"过敏源可通过食入、吸入、接触等途径进入人体内，导致人体过敏"},{"label":"C","content":"随着医疗水平的提高，许多原本被认识的过敏现象被认定为过敏性疾病"},{"label":"D","content":"机动车尾气中排放的氮氧化物浓度可通过提高油品质量来进行控制"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":232,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400233,6,'逻辑判断','甲、乙、丙、丁、戊、己6人争夺一场比赛的冠军。张明、王刚和李伟对这场比赛 的结果进行了预判： 张明：冠军不是甲，就是乙； 王刚：冠军或者是丙，或者是丁； 李伟：丙、戊、己绝不可能是冠军。 事后得知，只有一人的预判是正确的。 根据以上陈述，可以推出冠军是：','[{"label":"A","content":"甲"},{"label":"B","content":"乙"},{"label":"C","content":"丙"},{"label":"D","content":"丁"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":233,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400234,6,'逻辑判断','某医学研究团队研发了一种新型癌症疫苗，根据其团队发表的相关研究，研究人员 在携带恶性肿瘤的小鼠身上试验取得了惊人的成果，服用药物的小鼠癌细胞完全消 失，并且这种疫苗还可以有效对抗多种癌症，成功率达97%。因此，该疫苗的出现， 代表人类将攻克癌症这个难题。 以下哪项，如果为真，最有助于增强题干结论：','[{"label":"A","content":"试验所用小鼠自身带有极强的抗癌性"},{"label":"B","content":"小鼠细胞结构和癌症患病机理与人类极为类似"},{"label":"C","content":"临床实验中，接受化疗的癌症病人注射疫苗后癌细胞数量明显减少"},{"label":"D","content":"后续研究中发现部分实验小鼠的癌细胞重新出现 73"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":234,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400235,6,'逻辑判断','在某敌占区有王庄、李家湾、老河口、宋屯、东沟5个地下交通站，据可靠情报， 其中3个暴露了，需要紧急撤离。经过多方侦查，得知： (1)若王庄暴露了，则李家湾也暴露了； (2)若老河口暴露了，则宋屯也暴露了； (3)若李家湾暴露了，则老河口也暴露了； (4)若李家湾和宋屯中至少有1个暴露了，则东沟也暴露了。 根据以上信息，可以推出：','[{"label":"A","content":"王庄和李家湾都暴露了"},{"label":"B","content":"王庄和老河口都暴露了"},{"label":"C","content":"老河口和宋屯都暴露了"},{"label":"D","content":"东沟和李家湾都暴露了"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":235,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400236,6,'逻辑判断','提高能源使用效率、鼓励能源灵活利用是英国减少温室气体排放政策的一个必要环节， 它需要采用智能技术，包括通过智能表将能源使用信息从需求方面或客户发送到能 源公司等。该信息可用于制定和实施更高效的能源使用条例。但英国消费者对此态 度不一，因为该技术用于监控和支持能源高效率使用行为时，居民个人及家庭的能 源数据不得不被动分享。所以，个人使用能源相关数据的被动分享有可能成为推广 智能技术的最主要障碍。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"60% 的调查者表示，不愿意因数据被动分享而降低个人能源使用比例"},{"label":"B","content":"60% 的调查者认为，数据的被动分享大大增加个人隐私被侵犯的风险"},{"label":"C","content":"60% 的调查者表示，那些关心气候变化的人更可能接受数据被动分享"},{"label":"D","content":"60% 的调查者认为，数据不可能不被分享，否则智能技术不可能应用"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":236,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400237,6,'逻辑判断','一般认为，7万多年前的多巴火山喷发造成了全球气候变冷及环境恶化，并最终导 致热带非洲以外地区人类的灭绝。近期一项对现生人群的基因研究认为，约6万年 前至5万年前之间曾有一次非洲人群替代其他地区人群的过程，关于现代人的起源， “完全替代假说”是成立的，即非洲人是其他地区人群的直接祖先。 以下哪项如果为真，最能质疑上述研究人员的论证：','[{"label":"A","content":"多巴火山喷发后，热带非洲以外的地区仍有人类活动"},{"label":"B","content":"多巴火山的喷发短时间内仅对附近地区造成毁灭性的影响"},{"label":"C","content":"距今10万年前至4万年前，东亚地区的人类演化链条从来没有中断过"},{"label":"D","content":"尼安德特人在2万年前至3万年前已经灭绝，但现存智人仍保留他们的基因 74"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":237,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400238,6,'逻辑判断','副校长我认为张老师和王老师中至多有一个人可以被推荐为国家级教学名师候选人。 校长：我不同意。 以下选项最能表达校长意见的是：','[{"label":"A","content":"张老师和王老师都不可以被推荐"},{"label":"B","content":"张老师和王老师至少一人可以被推荐"},{"label":"C","content":"张老师和王老师都可以"},{"label":"D","content":"如果王老师被推荐，则张老师也可以"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":238,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400239,6,'逻辑判断','有以下几个条件成立： (1) 如果小王是工人，那么小张不是医生； (2)或者小李是工人，或者小王是工人； (3)如果小张不是医生，那么小赵不是学生； (4) 或者小赵是学生，或者小周不是经理。 以下哪项如果为真，可得出“小李是工人”的结论：','[{"label":"A","content":"小周不是经理"},{"label":"B","content":"小王是工人"},{"label":"C","content":"小赵不是学生"},{"label":"D","content":"小周是经理"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":239,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400240,6,'逻辑判断','某公司需要选派几名员工前往分公司，但由于某种特殊关系，人员分配需满足以下 规律： (1)若选甲，则乙也要选； (2)只有不选甲，才能不选丙； (3)要么不选丙，要么乙和戊中有人不被选中； (4)除非不选丙，否则选丁。 若不选乙，则下列选派正确的是：','[{"label":"A","content":"同时选甲、丙、丁"},{"label":"B","content":"丙不选，丁 、戊都选"},{"label":"C","content":"甲不选，丙、丁都选"},{"label":"D","content":"甲、丁、戊都不选 75 75 练习题 13"}]','C','。 25花生批注： “或者或者”为真， 则“否一推一”。 ⑥花生批注： 翻译规则： “只有才”可翻译为 “不不”; “除非A 否则B” 可翻 译为“非A→B”。 27花生批注： 要么要么,一 真 一 假 为真； 不选乙，则“乙和戊 中有人不被选中”为 真，那么“不选丙”为假， 即要选丙。 练习题 13 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 论据：根据检测结果， 和人类有过接触的白 尾鹿有70%感染上了 某种病毒。 结论：当地野生白尾 鹿中感染了此种病毒 的比例将显著地小于 70%。 ②花生批注： 只知道“量之比”和” 某部分比例”,无法 推出“整体和另一部 分比例”。','逻辑判断600题','进阶','published','{"globalNumber":240,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400241,6,'逻辑判断','美国马萨诸塞州的防疫部门最近发表了一份检测报告，在该州境内接受检疫的野生 白尾鹿里面，有70%感染上了某种病毒。据研究，该病毒最初是从人传播到鹿身上的， 随后发生变异，可在鹿群中间传播。目前防疫部门只对和人类有过接触的白尾鹿进 行检疫。防疫部门的专家由此推测，州内的野生白尾鹿中感染了此种病毒的比例将 显著地小于70%。 下列各项如果为真，哪项最能够支持上述论点：','[{"label":"A","content":"在马萨诸塞州境内，感染了这种病毒的人只占全部人数的0.2%"},{"label":"B","content":"马萨诸塞州内与人有过接触的野生白尾鹿，只占其总数的20%"},{"label":"C","content":"感染此种病毒的白尾鹿远比健康的白尾鹿表现得更愿意与人类接触"},{"label":"D","content":"在附近的几个州并未出现大量关于白尾鹿感染病毒的报告"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":241,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400242,6,'逻辑判断','某仓库失窃，四个保管员因涉嫌而被传讯。四人的供述如下： 甲：我们四人都没有作案。 乙：我们中有人作案。 丙：乙和丁至少有一人没有作案。 丁：我没有作案。 如果四人中有两人说的是真话，有两人说的是假话，则以下哪项断定成立：','[{"label":"A","content":"说真话的是甲和丙"},{"label":"B","content":"说真话的是甲和丁"},{"label":"C","content":"说真话的是乙和丙"},{"label":"D","content":"说真话的是乙和丁"}]','C','【题型分类】分析类——真假分析 【实战解析】两真两假③题目先寻找矛盾，观察四个条件可知，甲 乙 矛盾④,则丙丁也应一真一假； 再用假设法判断丙丁，若丁为真，则丙为真，不符合题干要求，故丁 为假(丁作案),丙为真(乙未作案); 丁为假(丁作案)推出乙为真(有些人作案),故甲为假。 所以说假话的是甲、丁，说真话的是乙、丙，C 选项正确。 ③花生批注： 两真两假题目常用方 法：找矛盾，用假设 法判断剩余二人。 ④花生批注： “所有不”和“有些是” 矛盾。 187 ⑤花生批注： 论据：PM2.5浓度显著 降低，减少了气溶胶 对HO₂自由基的吸收； 结论：PM2.5浓度显著 降低，导致臭氧增加。 ⑥花生批注： A、B、D 选项，均未 提及自由基与臭氧含 量的关系，无法为断 点搭桥，无法支持。 ⑦花生批注： 论据：幼儿教育管理 中的竞争意识意识使 得孩子认为自己必须 超越别人才能获得荣 誉； 结论：这样的竞争意 识破坏了孩子自身的 兴趣爱好。','逻辑判断600题','进阶','published','{"globalNumber":242,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400243,6,'逻辑判断','地表臭氧是由氮氧化物( NOx) 和挥发性有机化合物 ( VOCs) 在阳光照射下通过光化 学反应产生的。在某国城市地区，夏季臭氧经常成为首要大气污染物。一项研究发现， 在过去五年中该国北方地区主要大城市的PM2.5浓度显著降低，减少了气溶胶对HO₂ 自由基的吸收，因此PM2.5浓度显著降低导致了城市夏季臭氧的增加。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"臭氧和PM2.5两种污染物对人体的危害程度相当"},{"label":"B","content":"大气中的PM2.5浓度与气溶胶的吸收性显著相关"},{"label":"C","content":"大气中自由基的数量与城市夏季臭氧含量正相关"},{"label":"D","content":"该国城市地区在过去五年中NOx 和 VOCs 的排放量均有所增加 四海公煮"}]','C','【题型分类】支持类——断点搭桥 【实战解析】论据结论见批注。“气溶胶对HO₂ 自由基的吸收”与“夏 季臭氧”间明显存在断点，需要搭桥，只有C 选项同时包含二者，可 以秒选⑨,其逻辑关系如下： PM2.5 浓度显著降低，减少了气溶胶对HO₂ 自由基的吸收(自由基 数量提高),大气中自由基的数量与城市夏季臭氧含量正相关(城市 夏季臭氧随之提高),因此， PM2.5 浓度显著降低导致了城市夏季臭 氧的增加。','逻辑判断600题','进阶','published','{"globalNumber":243,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400244,6,'逻辑判断','幼儿教育管理中的“第一”意识和“最好”意识不仅明确宣扬竞争，甚至还鼓励竞 争，第一个入园的孩子、吃饭吃得最干净的孩子、第一个入睡的孩子永远只有一位， 这样的竞争意识使得孩子认为自己必须超越别人才能获得荣誉。因此，这样的竞争 意识破坏了孩子自身的兴趣爱好。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"幼儿竞争意识的培养不利于孩子自身的全面发展"},{"label":"B","content":"幼儿在竞争意识下会将注意力聚焦在能否获得荣誉上"},{"label":"C","content":"幼儿为获得荣誉超越别人是培养自身兴趣爱好的障碍"},{"label":"D","content":"幼儿的竞争意识不利于自我管理和自我约束能力的培养"}]','C','【题型分类】支持类——断点搭桥 【实战解析】论据结论见批注。“必须超越别人才能获得荣誉”与“孩 子自身的兴趣爱好”间明显存在断点，需要搭桥，只有C 选项同时包 含二者，可 以 秒 选⑧,其逻辑关系如下： 竞争意识使得孩子认为自己必须超越别人才能获得荣誉，孩子为获得 荣誉超越别人阻碍了自身兴趣爱好的培养，因此，竞争意识破坏了孩 子自身的兴趣爱好。 ⑧花生批注： A、B、D选项，均未 提及获得荣誉与兴趣 培养的关系，无法为 断点搭桥，无法支持。','逻辑判断600题','进阶','published','{"globalNumber":244,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400245,6,'逻辑判断','右下方有一个的方阵，其中每行、每列均有5个小方格。每格种应填1个字，每行、 每列均要填上“德”“能”“勤”“绩”“廉”5个字，不能重复，也不能遗漏。 方阵中有些方格已填上了字。 勤 ? 绩 ? 能 绩 ? 德 勤 德 ? 德 ? 勤 根据要求，中间一列(有问号处)应填上的5个字自上而下依次是：','[{"label":"A","content":"德、能、勤、绩、廉"},{"label":"B","content":"德、廉、能、勤、绩"},{"label":"C","content":"绩、能、廉、德、勤"},{"label":"D","content":"廉、德、能、勤、绩"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":245,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400246,6,'逻辑判断','某公司产品的各项性能都比竞争对手的更好。所以，如果该公司能够降低产品的市 场定价，与竞争对手的价格持平，那么该公司产品一定会迅速占领市场。 下列选项若为真，最能削弱上述论断的是：','[{"label":"A","content":"该公司产品的生产成本较高，降低市场定价将会极大影响公司利润"},{"label":"B","content":"与竞争对手相比，该公司的产品宣传力度和售后服务不具显著优势"},{"label":"C","content":"该公司的生产规模很小，其产量仅能满足市场需求的百分之一"},{"label":"D","content":"该公司产品设计瞄准的是高端市场，降低价格不符合其市场定位"}]','C','。 190 四海公煮','逻辑判断600题','进阶','published','{"globalNumber":246,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400247,6,'逻辑判断','国土资源部、住房和城乡建设部联合印发《利用集体建设用地建设租赁住房试点方 案》,正式允许城中村、城郊村、城边村集体建设用地建设租赁住房，引起各方关注。 有观点认为，集体建设用地建设租赁住房入市后，将使大量有购房意愿和购房能力 的人去租房，进而平抑房价。 以下哪项如果为真，将最能质疑上述观点：','[{"label":"A","content":"集体建设用地建设租赁住房试点会导致商品房建设用地供应量减少"},{"label":"B","content":"允许集体建设用地建设租赁住房会使农民农业生产收入受损，试点方案的推进会 受到阻碍"},{"label":"C","content":"该试点方案的出台赋予了城中村、城郊村、城边村的出租房合法地位"},{"label":"D","content":"该试点方案出台前就有大量集体建设用地偷偷入市，租房市场需求已经得到满足"}]','D','。 ⑩花生批注： 题干只有结论：集体 建设用地建设租赁住 房入市后，将使大量 原本要购房者去租房， 进而平抑房价。 ⑪花生批注： “副作用”选项，没 有直接攻击题干中谈 论的此方案的作用， 一般不选。 191 逻辑判断600 ⑫花生批注： 论据：政府官员与公 民对于政府行动中的 义务规则理解相同； 结论：国家故意无视 国际法，该国政府官 员也会不支持他们的 政府(即该国政府官 员也是支持他们政府 遵守国家法的)。 ⑬花生批注： 前提假设类常见正确 答案：断点搭桥，补 充漏洞，能与不能(必 要条件)。 ⑭花生批注： 题干按照“看电视时 间长、看电视时间短” 进行分组对比，将“幼 儿身体素质较差”这 一事实归因于“看电 视时长较长”。','逻辑判断600题','进阶','published','{"globalNumber":247,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400248,6,'逻辑判断','国家的政府官员和公民对于政府在其行动中负有义务遵守规则的理解是相同的。因此， 如果一个国家故意无视国际法，该国政府官员的态度也会变得不支持他们的政府。 上述推论是以下哪一个假设为前提的：','[{"label":"A","content":"人们对政府义务的理解经常改变"},{"label":"B","content":"每个国家的公民相信政府应该遵守国际法"},{"label":"C","content":"一个国家的公民赞成政府通过合法的方式发展其国际影响力"},{"label":"D","content":"当选的政府官员比任命的政府官员更可能怀疑政府行动的明智性"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":248,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400249,6,'逻辑判断','研究人员对1300多名两岁半到四岁半之间幼儿情况进行调查，这些孩子在两岁半时 平均每周看电视8.8小时，此后该时间逐步延长，到四岁半时达到平均每周14.8小 时，在四岁半时对这些孩子进行的身体素质测试显示，那些看电视时间较长的孩子， 其身体素质明显较差。因此，看电视是导致幼儿身体素质较差的原因。 以下哪项如果为真，最能削弱上述论证：','[{"label":"A","content":"对体育运动没有兴趣的孩子会把精力更多地放在看电视上"},{"label":"B","content":"让孩子看电视是现在不少家长哄孩子安静的手段"},{"label":"C","content":"看电视时间较长的孩子，其腰围普遍较粗，肥胖倾向更明显"},{"label":"D","content":"看电视时间太长会导致孩子久坐不动，这是对孩子生长发育不利的因素"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":249,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400250,6,'逻辑判断','已知：如果王超和王强不加入读书会，那么周芳加入读书会，若要必然推出“王强 加入读书会”,则需要增加下列哪项作为前提：','[{"label":"A","content":"周芳不加入读书会"},{"label":"B","content":"周芳不加入读书会，或王超不加入读书会"},{"label":"C","content":"周芳加入读书会，而王超不加入读书会"},{"label":"D","content":"王超和周芳都不加入读书会"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":250,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400251,6,'逻辑判断','某市举行春季音乐节系列活动，其中一项活动首次邀请了某知名交响乐团前来该市 演出，该市交响乐爱好者对此十分期待。考虑到该乐团的影响力，主办方预计为期 两天的交响乐团演出将“一票难求”。但开始售票后发现，实际情况并非如此。 以下哪项为真，最能解释这一情况：','[{"label":"A","content":"音乐节的其他活动吸引了许多观众"},{"label":"B","content":"交响乐未能被该市大部分群众所接受"},{"label":"C","content":"音乐节活动期间该市一直为阴雨天气"},{"label":"D","content":"此次交响乐团演出门票价格过高"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":251,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400252,6,'逻辑判断','未剥皮的文玩核桃价格从两年前的20元/斤涨到了今天的120元/斤，可见文玩核 桃的种植者们正在哄抬物价，相关部门应出台措施规范市场，控制因炒作所致的价 格上升。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"由于病虫害和过度采摘，文玩核桃的产量较前两年明显减少"},{"label":"B","content":"文玩核桃的产区距离城市主要消费地较远，运输费用高"},{"label":"C","content":"由于价格的上升，更多人进入到文玩核桃种植业，希望获利"},{"label":"D","content":"近两年来文玩核桃市场已经形成了一个相对固定的买家群体"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":252,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400253,6,'逻辑判断','某市公安机关为了人民生命财产安全，减少环境污染，发布了禁止出售烟花爆竹禁令， 今年该市没有市民被烟花爆竹炸伤，这说明，禁令得到了有效实施。 以下哪项如果为真，最能质疑上述论证：','[{"label":"A","content":"该市消防部门出警次数比往年多"},{"label":"B","content":"市民看到有人燃放烟花爆竹"},{"label":"C","content":"警方收到有人家中堆放大量烟花爆竹的举报"},{"label":"D","content":"警方捣毁了几个生产烟花爆竹的窝点"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":253,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400254,6,'逻辑判断','赵青一定是一位杰出的执教人员。因为她调到我们大学执教女排才一年，球队的成 绩突飞猛进。 以下哪项，如果为真，最有可能削弱上述论证：','[{"label":"A","content":"赵青以前曾经入选过国家青年女排，后来因为伤病提前退役。"},{"label":"B","content":"赵青之前的教练一直是男性，对于女运动员的运动生理和心理了解不够。"},{"label":"C","content":"调到大学担任女教排练之后，赵青在学校领导那里立下了军令状，一定要拿全国 大学生联赛的冠军，结果只得了一个铜牌。"},{"label":"D","content":"女排队员尽管是学生，但是对于赵青教练的指导都非常佩服，并自觉地加强训练。 79 79"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":254,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400255,6,'逻辑判断','心理学家对影响人类个性和行为的因素是环境还是基因仍有不同的见解。行为学派 的学者更相信对人类个性和行为影响最大的是环境而非基因，但是，最近一项实验 表明，一起成长起来的同卵双生子的个性和行为相似之处比一起成长起来的非同卵 双生子多。因此，这项结论认为，基因在决定个性和行为方面有至关重要的作用。 下列哪项如果被证实，对该研究结论能够提出最大的质疑：','[{"label":"A","content":"在不同家庭抚养的同卵双胞胎表现出性格的相同之处比同种情况下非同卵双胞胎 表现出来的相同之处多"},{"label":"B","content":"不论双胞胎行为表现如何，父母对待同卵双胞胎的方式总是容易激发出相似的个 性特征，而对待非同卵双胞胎的方式并非如此"},{"label":"C","content":"拥有同卵双胞胎和非同卵双胞胎的父母一致认为他们的孩子从幼儿时期起个性就 固定了"},{"label":"D","content":"亲生父母和他们的同卵双胞胎之间会有许多相似的个性，而养父母和双胞胎之间 相似个性没有多少"}]','B','。 197 25花生批注： 既成事实：男孩小学 至大学均全面落后于 同年龄段女孩(即“男 孩危机”); 原因分析：“男孩危机” 是不适当的家庭学校 教育方法导致。','逻辑判断600题','进阶','published','{"globalNumber":255,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400256,6,'逻辑判断','“男孩危机”是指男孩调皮捣蛋、胆小怕事、学习成绩不如女孩好等现象。近年来， “男孩危机”现象成为儿童教育专家关注的一个重要问题，而对“现在男孩为什么 从小学、中学到大学全面落后于同年龄段的女孩”的疑问，某教育专家通过分析指出， 是家庭和学校不适当的教育方法导致了“男孩危机”现象。 下列哪项如果为真，最能对该专家的观点提出质疑：','[{"label":"A","content":"母亲和女性教师在现代家庭和学校教育充当了重要的角色"},{"label":"B","content":"因激素水平的差异，男孩天性比女孩更爱运动，这耗去了他们大量的精力"},{"label":"C","content":"男孩在心智成熟方面要晚于女孩，大学毕业后他们在事业上更容易成功"},{"label":"D","content":"家庭对独生子女的过度呵护，在很大程度上限制了男孩发散性思维的拓展和冒险 性格的养成"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":256,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400257,6,'逻辑判断','玉不琢不成器，树不修不成材。有了管教，方知敬畏；有了敬畏，方知底线；有了底线， 方知对错。 如果上述判断是真的，则可以推出：','[{"label":"A","content":"如果知道敬畏，就会知道对错"},{"label":"B","content":"如果知道对错，就说明知道敬畏"},{"label":"C","content":"如果不知道底线，就说明缺乏管教"},{"label":"D","content":"所有不成材的树都是没修剪过的树 四海公考 逻辑判断"}]','B','⑥花生批注： “方知”是“才知道” 的意思。 【题型分类】推出类——等价推出 【实战解析】题干可翻译为：①玉不琢→不成器，树不修 → 不成材； ②花 生批注： 其他选项：A选项是②的否命题， C 选项是②的逆命题， D 选项是①的逆命题 (所有都可翻译为前 推后)。② 缺乏管教 → 不知敬畏 → 不知底线 → 不知对错； 其他选项： A选项是②的否命题， C 选项是②的逆命题， D 选项是①的逆命题 (所有都可翻译为前 推后)。 观察选项，B 选项是②的逆否命题，可以等价推出，当 选②。','逻辑判断600题','进阶','published','{"globalNumber":257,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400258,6,'逻辑判断','与劳动、资本、技术等要素一样，所有数据财产都属于信息时代的经济要素。只有 明确数据财产的权属，才能建立和完善数据要素市场。只有建立数据财产制度，才 能充分调动数据处理者在数据开发利用和流通中的积极性，并且才能使静态的数据 资源在动态流转中跃变为具有经济价值的资产。只有数据资源真正成为具有经济价 值的资产，才能推动数据产业的发展，并且才能实现经济的数字化转型。 由此可以推出：','[{"label":"A","content":"一旦明确了数据财产的权属，就能建立和完善数据要素市场"},{"label":"B","content":"静态的数据资源只有在动态流转中才能跃变为具有经济价值的资产"},{"label":"C","content":"若数据资源未能真正成为具有经济价值的资产就不能实现经济的数字化转型"},{"label":"D","content":"数据财产制度建立起来了，数据处理者在数据开发利用和流通中的积极性就能充 分调动起来"}]','C','。 ③花生批注： 一般来说，“顿号” 表示并列，但此时应 理解为“或”关系， 因为根据常识可知， 不能同时被判处有期 徒刑和拘役。 ③花生批注： (1)翻译为： ①非丙→ 甲且乙； ②甲且乙→非丙； ①的逆否命题为： ③非甲或非乙→丙； (2)翻译为： ④非(非丙或非甲), 即：丙且甲。 33花生批注： 其他选项： B 选项若为假， 非甲且乙应成立； C 选项若为假， 非乙且非丙应成立； D 选项若为假， 丙且非甲应成立； 但根据目前已知的情 况，上述均不确定成 立。','逻辑判断600题','进阶','published','{"globalNumber":258,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400259,6,'逻辑判断','根据某国法律规定，只有被判处三年以下有期徒刑、拘役的被告人才可能适用缓刑， 如果张某因盗窃罪没有被判处缓刑，则下列推论一定正确的是：','[{"label":"A","content":"张某一定被判处了三年以上有期徒刑"},{"label":"B","content":"张某一定被判处了三年以下有期徒刑"},{"label":"C","content":"张某可能被判处了拘役"},{"label":"D","content":"张某一定被判处了拘役"}]','C','【题型分类】推出类——正推逆推 【实战解析】题干可翻译为：适用缓刑 →被判处三年以下有期徒刑、 拘役⑨; “张某未被判处缓刑”是箭头的“终点”,无法推出任何信息，所以 只能选择带有“可能”的 C 选项。','逻辑判断600题','进阶','published','{"globalNumber":259,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400260,6,'逻辑判断','某地官员腐败成风，已知的情况有： (1)当且仅当丙不贪污，甲和乙贪污； (2)“丙不贪污或甲不贪污”是谎言。 由此可知，下列说法一定错误的是：','[{"label":"A","content":"甲、乙、丙三人都贪污"},{"label":"B","content":"如果甲不贪污，那么乙不贪污"},{"label":"C","content":"如果乙不贪污，那么丙贪污"},{"label":"D","content":"如果丙贪污，那么甲贪污 练习题14"}]','A','【题型分类】分析类——真假分析 【实战解析】①可翻译为：非丙→ 甲且乙，甲且乙→非丙；②可翻译为： 丙且甲。分析选项： A 选项，甲乙丙都贪污，与“甲且乙→非丙”矛盾，一定为假，当 选⑤。 四海公煮 sIHAIGONGKA⁰ _逻辑判断 练习题 14 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":260,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400261,6,'逻辑判断','医生告诫人们，抽烟喝酒有害健康，但又有学者从统计学角度发现，一些根据习俗 从不抽烟不喝酒的民族，平均寿命要比经常抽烟喝酒的民族短5～10岁。因此学者 推测，抽烟喝酒虽然可能损伤肺和肝的功能，但不一定会影响人的寿命。 以下哪项如果为真，最能质疑上述观点：','[{"label":"A","content":"抽烟和喝酒的时候能让大脑获得欣快感，排解压力，感到愉悦"},{"label":"B","content":"那些根据习俗而杜绝烟酒的民族其饮食也相对单一，并且热量极高"},{"label":"C","content":"抽烟喝酒是肺癌和肝癌的重要原因，而这两种疾病位于疾病死亡谱的前两位"},{"label":"D","content":"烟酒可以刺激大脑分泌多巴胺，让人体各器官进入放松状态，促进身体修复"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":261,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400262,6,'逻辑判断','一起盗窃案发生，经调查共有二人合伙作案。警察逮捕了甲、乙、丙、丁四名嫌疑人， 罪犯必是其中二人。经询问， 甲说：“丁是罪犯。” 乙说：“甲是罪犯。” 丙说：“我不是罪犯。” 丁说：“我也不是罪犯。” 经调查，四人中二人说了假话，二人说了真话。 则下列哪项可能为真：','[{"label":"A","content":"甲、丁二人合伙作案"},{"label":"B","content":"丙、丁二人合伙作案"},{"label":"C","content":"甲、丙二人合伙作案"},{"label":"D","content":"甲、乙二人合伙作案"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":262,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400263,6,'逻辑判断','近年来，越来越多的人参加国家司法考试，可以说，所有想从事律师职业的人都想 要获得国家法律职业资格证书。小陈也想获得国家法律职业资格证书，所以，小陈 一定是想从事律师职业了。 下列哪项如果为真，最能加强上述断定：','[{"label":"A","content":"只有获得国家法律职业资格证书的人，才有资格从事律师职业"},{"label":"B","content":"目前越来越多学习法律的人具有国家法律职业资格证书"},{"label":"C","content":"国家司法考试号称“国考”,许多法律工作岗位把获得国家法律职业资格证书作 为人才招聘的前提条件"},{"label":"D","content":"只有想从事律师工作的人，才想获得国家法律职业资格证书"}]','D','【题型分类】支持类——断点搭桥 【实战解析】论据结论见批注。此题论据中的“想从事律师执业 → 想 要获得国家法律职业资格证书”有迷惑作用，其不能将论据和结论中 的断点搭桥⑥,需另外寻找所需要的“桥”: A 选项，翻译为“有资格从事律师职业→获得法律证书”,与断点方 向相反，无法搭桥支持； B 选项、C 选项，均未提及结论中新内容“想从事律师职业”,无法 搭桥支持； D 选项，翻译为“想获得法律证书 → 想从事律师职业”,恰好连接论 据与结论中的断点，当选。 ⑤花生批注： 论据：所有想从事律 师职业的人都想要获 得国家法律职业资格 证书，小陈想要获得 国家法律职业资格证 书； 结论：小陈想从事律 师职业。 ⑥花生批注： 论据：小陈想要获得 法律证书； 结论：小陈想从事律 师职业。 断点在“证书”与“职 业”间。 ⑦花生批注： 论据：胡夫金字塔附 近发现食宿条件不错 的工匠居住村落，且 在墓穴中发现工匠遗 骸和医疗痕迹； 结论：胡夫金字塔不 是由奴隶、而是自由 民所建造。','逻辑判断600题','进阶','published','{"globalNumber":263,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400264,6,'逻辑判断','多年来，历史学家普遍认为，胡夫金字塔是奴隶建造的。但近年来，考古学家在胡 夫金字塔附近发现了工匠居住的村落及生活设施。这些遗迹表明，那里曾住过几千 名工匠，食宿条件有充分保证。考古学家还在附近墓穴中发现了这些工匠的骸骨， 同时也发现了一些金属手术器械和死者骨折后得到医治的痕迹。考古学家认为，这 表明金字塔是由埃及的自由民建造的，而非奴隶。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"古埃及的村落中居住了大量的自由民"},{"label":"B","content":"在古埃及，奴隶死后不会在墓穴中安葬"},{"label":"C","content":"古埃及自由民的数量足以建造胡夫金字塔"},{"label":"D","content":"在这些村落遗迹中还发现了妇女和婴儿的骸骨"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":264,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400265,6,'逻辑判断','如果“我们班有的同学不会使用计算机”是一个真判断，下面不能确定其真假的是：','[{"label":"A","content":"我们班至少有一个同学不会使用计算机"},{"label":"B","content":"我们班所有的同学都会使用计算机"},{"label":"C","content":"我们班有的同学会使用计算机"},{"label":"D","content":"不会使用计算机的有些是我们班的同学"}]','C','【题型分类】分析类——范畴分析 【实战解析】题干可简化为“有些不”,观察选项： A 选项，“至少有一个同学不会”,即“有些不”,和题干一致，可 确定为真； ⑧花生批注：“有些A是B” 等价 于“有些B 是A”。B 选项，“所有都”与“有些不”矛盾，可确定为假； ⑧花生批注： “有些A是B” 等价 于“有些B 是A”。 C 选项，“有些不”推不出“有些”,无法判断真假； D 选 项 ， “有些不会计算机的是我班同学”等价于“有些我班同学不 会计算机”⑧,和题干意思一致，可确定为真： 综上，不能确定真假的是C 选项。','逻辑判断600题','进阶','published','{"globalNumber":265,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400266,6,'逻辑判断','某项报告显示，2017年第二季度，全国近八成城市拥堵同比得到缓解，其中降幅最 大的为T 市 ，T 市二季度高峰拥堵延时指数为1.64,即高峰出行时间是畅通状态下 的1.64倍。该市交通状况负责人指出，这得益于近来本市政府持续采取的解决交通 拥堵的相关措施。 以下除哪项外，均能支持上述T 市交通状况负责人的看法：','[{"label":"A","content":"T 市提高了停车收费标准"},{"label":"B","content":"T市多条地铁线即将投入运营"},{"label":"C","content":"T市鼓励共享单车的大量投放以及使用"},{"label":"D","content":"T 市广泛展开宣传，加强了市民绿色出行的意识"}]','B','。 205 ⑩花生批注： 题干按照今年和去年 分组对比，将今年偷 盗案件下降的原因归 于照明的改善。 ⑪花生批注： 可以考虑盐水思想： 2019年和2018年发生 的偷盗总数一样，而 2019年团结里小区发 生的偷盗数量少了， 也就是其他小区的偷 盗数量多了，可以是 2019年的团结小区和 其他小区构成子女的 对比实验。','逻辑判断600题','进阶','published','{"globalNumber":266,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400267,6,'逻辑判断','如果天气晴朗，我们就举办拔河比赛 如果风很大，我们就不举办拔河比赛； 如果不举办拔河比赛，就举办演讲比赛； 假定上面的陈述属实，实际情况我们正举办拔河比赛，则下面哪项必定为真： I. 天气晴朗 II. 风不大 III. 不举办演讲比赛','[{"label":"A","content":"仅 I"},{"label":"B","content":"仅 II"},{"label":"C","content":"仅 I,III"},{"label":"D","content":"II,III"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":267,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400268,6,'逻辑判断','在2018年12月， 团结里小区修理并改善了小区的照明设施。2019年，该小区偷盗 和试图偷盗的案件比前一年下降了，由于潜在的小偷通常受较好的照明条件的威慑， 偷盗案件的下降归功于照明的改善。 以下哪项如果为真，最能强化上述论证：','[{"label":"A","content":"大多数小区的偷盗案发生于上午10点到下午4点之间"},{"label":"B","content":"团结里是其所在街道十三个小区之一"},{"label":"C","content":"在团结里所在的街道，2019年发生的偷盗案和2018年发生的一样多"},{"label":"D","content":"2019 年在团结里小区巡逻的保安的人数在夜间加倍了"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":268,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400269,6,'逻辑判断','为进一步加强塑料污染治理，某市决定开展不可降解塑料袋专项治理行动，倡导消 费者重拎布袋子，重提菜篮子，鼓励循环使用“共享购物袋”。但是在经过一段时 间后，发现效果并不好，大部分人还在使用塑料袋，因此有观点认为造成该现象的 原因是该市的居民素质不高。 下列哪项如果为真，最能质疑上述观点：','[{"label":"A","content":"该市数次被评为国家卫生城市"},{"label":"B","content":"该市市民的消费以线上购物为主"},{"label":"C","content":"该市辖区内有多所国家重点高校"},{"label":"D","content":"该市商家为招来顾客免费提供塑料袋"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":269,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400270,6,'逻辑判断','20 世纪50年代以来，人类丢弃了多达10亿吨塑料，这种垃圾可能存在数百年甚至 数千年。近日，一个科研小组在亚马逊雨林中发现一种名为内生菌的真菌，它能降 解普通的聚氨酯塑料。科研人员认为利用这种真菌的特性，将有望帮助人类消除塑 料垃圾所带来的威胁。 科研人员的判断还需基于以下哪一前提：','[{"label":"A","content":"塑料垃圾是人类活动产生的最主要的废弃物种类"},{"label":"B","content":"内生菌在任何条件下都可以很好地分解塑料制品"},{"label":"C","content":"目前绝大多数塑料垃圾都属于普通的聚氨酯塑料"},{"label":"D","content":"这种真菌在地球上其他地区也能正常地存活生长"}]','C','【题型分类】前提假设类——断点搭桥 【实战解析】论据和结论见批注。论据的“聚氨酯塑料”和结论的“塑 料垃圾”存在断点，需要搭桥，C 选项为二者建立联系，可以秒选⑤, 其逻辑关系如下： 内生菌真菌能降解普通的聚氨酯塑料，目前绝大多数塑料垃圾都是聚 氨酯塑料，所以该真菌有望帮助人类消除塑料垃圾的威胁。','逻辑判断600题','进阶','published','{"globalNumber":270,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400271,6,'逻辑判断','最近的一项研究发现，与以摄入动物蛋白为主的人相比，摄入植物蛋白较多的人， 死于心血管疾病的风险要低31%,总体死亡风险低20%左右。有人据此得出结论， 多摄入植物蛋白更有利于人体健康。 以下哪项如果为真，最能削弱上述论证：','[{"label":"A","content":"动物蛋白和植物蛋白的消化吸收率不同，烹调方式也大不相同"},{"label":"B","content":"多摄入植物蛋白的人往往是因为拥有良好的生活习惯才更健康长寿"},{"label":"C","content":"植物蛋白含有动物蛋白缺乏的纤维，纤维与较低的心血管疾病风险密切相关"},{"label":"D","content":"获取动物蛋白的同时会容易摄入过多热量、胆固醇和饱和脂肪，增加肥胖风险"}]','B','【题型分类】归因类——对比实验归因 【 实战解析】对比实验与原因分析见批注， 分析选项： A 选项，动物蛋白和植物蛋白的消化吸收率和烹调方式是否相同，与 人体健康关联不紧密，无法质疑； B 选项，多摄入植物蛋白的人因为拥有良好的生活习惯才更健康长寿， 明确的说明摄入植物蛋白更健康是因为良好生活习惯，而不是因为植 物蛋白，属于否定此因质疑； C 选项，指出植物蛋白特有的纤维与较低的心血管疾病密切相关，解 释了为什么心血管疾病风险较低是因为摄入植物蛋白，属于解释说明 支持； D 选项，引入“获取动物蛋白容易增加肥胖风险”的新变量，摄入动 物蛋白相对不健康的原因可能是容易肥胖，从而增加心血管疾病和死 亡风险，属于另有他因质疑； 综上，B选项的否定此因力度强度D选项的另有他因①,B 选项是正 确答案。 ⑪花生批注： 否定此因、因果倒置 均能确定不是“这个 原因”,但另有他因 只是“把水搅浑”, 依然有可能是“这个 原因”,与前两者相比， 另有他因力度较弱。 209 ⑱花生批注： 此类题目，不用考虑 推理是否正确，只需 找到逻辑一致选项(对 要对得一样，错要错 的一样)。 ⑲花生批注： B选项，先说的“所以”, 后说的“因为”,调 整顺序即可。 ②⑳花生批注： 题干论据按照“使用 石器前”和“使用石 器后”分组对比，结 果使用石器后，人类 演化形成较小的牙齿 和脸型，由此，将人 类脸型变化的原因， 归于“使用工具后减 弱了咀嚼的力量”。','逻辑判断600题','进阶','published','{"globalNumber":271,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400272,6,'逻辑判断','所有有学问的人都戴眼镜，我是文盲一个。所以，我不戴眼镜。 以下哪个选项所犯逻辑错误与题干最为类似：','[{"label":"A","content":"小明是大学生，小明爱刷短视频。所以，大学生爱刷短视频"},{"label":"B","content":"山羊都长胡子，这只动物肯定不长胡子，因为它不是山羊"},{"label":"C","content":"山西的风景名胜不是一天能逛完的，晋祠是山西的风景名胜。所以，晋祠哪能一 天逛完呢"},{"label":"D","content":"有些四川人特别爱吃辣，小张是四川人，他肯定吃辣"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":272,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400273,6,'逻辑判断','研究显示，约200万年前，人类开始使用石器处理食物，例如切肉和捣碎植物。与 此同时，人类逐渐演化形成较小的牙齿和脸型，以及更弱的咀嚼肌和咬力。因此研 究者推测，工具的使用减弱了咀嚼的力量，从而导致人类脸型的变化。 以下哪项如果为真，最能削弱上述研究者的观点：','[{"label":"A","content":"对与人类较为接近的灵长类动物进行研究，发现它们白天有一半时间用于咀嚼， 它们的口腔肌肉非常发达、脸型也较大。"},{"label":"B","content":"200 万年前人类食物类型发生了变化，这加速了人类脸型的变化。"},{"label":"C","content":"在利用石器处理食物后，越来越多的食物经过了程度更高的处理，变得易于咀嚼"},{"label":"D","content":"早期人类进化出较小的咀嚼结构，这一过程使其他变化成为可能，比如大脑体积 的增大。"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":273,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400274,6,'逻辑判断','如今越来越多企业认识到中欧班列具有时效更高、周转更快等优势，从而选择通过 中欧班列发运货物。例如，在广州大朗站，2021年前9个月已开行出口中欧班列97列、 发运标箱9698个、货值29.47亿元，同比分别增长25.97%、33.80%、19.94%。尽 管大朗站的工作人员数量没有明显增加，但有不少企业发现，大朗站货物通关效率 比去年更高了。 下列选项最能解释这一现象的是：','[{"label":"A","content":"珠三角地区增设了多个通关口岸"},{"label":"B","content":"当地海关简化了通关流程"},{"label":"C","content":"中欧班列的列车运行速度有所提高"},{"label":"D","content":"当地货物通关时间较去年有所减少 85"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":274,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400275,6,'逻辑判断','啤酒与人类健康的关系向来受到科学家关注。由于女性的手指骨骼会最先出现骨质 疏松症状。研究人员选择对她们的指骨进行超声波成像扫描。扫描结果显示，常喝 啤酒的女性和不喝啤酒的女性骨密度有显著差异，前者的骨密度高于后者。所以， 研究人员认为喝啤酒有助于女性预防骨质疏松。 以下如果为真，最能削弱上述结论的是：','[{"label":"A","content":"有喝啤酒习惯的女性大多喜欢参加体育运动，身体健壮。骨骼密度本来就相对较高"},{"label":"B","content":"啤酒中含有的黄豆芽苷元是否能有效防止骨骼老化还有待于进一步研究"},{"label":"C","content":"啤酒中的酒精不利于钙质的吸收，而缺钙容易导致骨骼发育不良"},{"label":"D","content":"每天喝200毫升啤酒的女性，其骨骼密度高于每天喝500毫升啤酒的女性"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":275,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400276,6,'逻辑判断','假如“人工智能发展到了最高的层级，才可以表达类似于人类的情感”为假，那么 以下为真的是：','[{"label":"A","content":"人工智能现在已经发展到了最高的层级，可以表达类似于人类的情感"},{"label":"B","content":"人工智能不能表达类似于人类的情感，就没有发展到最高的层级"},{"label":"C","content":"人工智能没有发展到最高的层级，也可以表达类似于人类的情感"},{"label":"D","content":"人工智能可以表达类似于人类的情感，不一定发展到了最高的层级"}]','C','。 25花生批注： 即使认为二者一致， 此选项也无法质疑， 题干中实验结果就是 喝啤酒女性骨密度明 显更高，C 选项无法 质疑此“既成事实”。 213 213','逻辑判断600题','进阶','published','{"globalNumber":276,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400277,6,'逻辑判断','H市在公共场所中的每一块绿地都配备了垃圾桶。这些垃圾桶或者标有“可回收垃圾” 或者标有“不可回收垃圾” 如果上述陈述为真，则下列哪项一定为真： I.H 市配备的垃圾桶土有的标有“可回收垃圾” II. 如果H市有一块绿地没有配备垃圾桶，那么该绿地不属于公共场所 III. 如果H市有块绿地配备了标有“不可回收垃圾”的垃圾桶，那么它属于公共场所','[{"label":"A","content":"只有I"},{"label":"B","content":"只有II"},{"label":"C","content":"只有III"},{"label":"D","content":"I 和 II"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":277,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400278,6,'逻辑判断','①如果小孙不是讲师，那么小赵不是副教授 ②如果小赵是助教，那么小孙不是讲师 ③或者小赵是副教授，或者小李不是教授 ④或者小钱是助教，或者小赵是助教 如果上述四个条件成立，则以下哪项为真，可得出“小钱是助教”的结论：','[{"label":"A","content":"小李不是教授"},{"label":"B","content":"小赵是助教"},{"label":"C","content":"小赵不是副教授"},{"label":"D","content":"小李是教授 86 86 更 多 资 料 添 加 ：KZ4327"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":278,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400279,6,'逻辑判断','挣更多的钱能让人更快乐，至少在某种程度上是这样的。但是新的研究表明，反过 来也是如此，快乐的人能挣更多的钱。伦敦大学的研究人员在对一万多名美国人进 行研究后发现，那些情绪积极、在成长过程中对生活感到更满意的人，在达到29岁 的年龄时其收入也较高。 以下哪项最能对上述研究结论提出质疑：','[{"label":"A","content":"在比较富裕的家庭中成长起来的年轻人对生活大都持消极态度"},{"label":"B","content":"除了情绪，专业化程度和工作能力也会直接影响收入水平"},{"label":"C","content":"对生活感到更满意的年轻人大都出生于比较富裕的家庭，而且都具有良好的职业 背景"},{"label":"D","content":"应该比较一下被调查对象的职业分布情况"}]','C','。 8花生批注： 题干论据按照情绪积 极和消极分组对比， 结果积极的人29岁时 收入也更高； 得出快乐的人能挣更 多的钱这一结论。 隐含了赚钱更多是因 为更快乐的归因过程。 29花生批注： 对比实验归因类的常 见错误选项：有些类 选项，实验瑕疵，分 组错误或未分组，未 谈论原因。 ③花生批注： 富裕家庭意味着本身 有钱，而非“更赚钱”。 ③花生批注： 若改成“实验中这些 快乐的人，还有更高 的专业化程度和工作 能力”,即是另有他 因质疑。 ③花生批注： 命题A→B 的真假判 断： 只在A 且非B时为假； 前件为假(即非A成立， 不能满足A 且非B), 命题为真； 后件为真(即B 成立， 不能满足A 且非B), 命题为真。 3花生批注： 第二种思路： 第二张、第三张，已 经不能满足“五角星 且非3”,所以命题已 经为真，无需判断； 第一张，第四张，还 有可能满足“五角星 且非3”,所以需要翻 转验证。','逻辑判断600题','进阶','published','{"globalNumber":279,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400280,6,'逻辑判断','如图所示四张卡片均一面是图案，一面是阿拉伯数字。现在断定：如果一面是五角星， 那么另一面是3。现要检验该断定正确与否，且只允许翻动以下两张卡片，则应选择：','[{"label":"A","content":"第一张和第三张"},{"label":"B","content":"第一张和第四张"},{"label":"C","content":"第 二张和第三张"},{"label":"D","content":"第二张和第四张 87 练习题15"}]','B','。 四海公煮 SIHAIGONaKA0 . 逻辑判断 练习题15 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":280,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400281,6,'逻辑判断','一家刚开业的餐厅决定开展促销活动，部分菜品的售价甚至低于成本价，在这种情 况下，销售量越大，餐厅的经济损失就越大。这一决定遭到很多餐厅员工反对，但 餐厅老板依然坚持这一决定。 下列最能支持餐厅老板决定的是：','[{"label":"A","content":"薄利多销的方式有利于提高餐厅营业收入"},{"label":"B","content":"便宜的餐馆更容易受到消费者的欢迎"},{"label":"C","content":"扩大知名度对于新开业的餐厅至关重要"},{"label":"D","content":"许多餐厅在开业时都开展打折促销活动"}]','C','。 ①花生批注： 题干可简化为：虽然 促销活动带来经济损 失，但老板依然坚持。 ②花生批注： 各个餐厅的实际情况 不同，不能一概而论， 此种类比支持是正确 答案概率很低。 ③花生批注： 论据：新能源汽车着 火事故车辆中，乘用 车占69.6%,专用车次 之，公交车最低； 结论：新能源汽车中， 乘用车安全性低于专 用车和公交车。 ④花生批注： ⑤花生批注： 比例类题目要“以我 为主”,直接去选项 中寻找“带数字的分 母”即可。','逻辑判断600题','进阶','published','{"globalNumber":281,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400282,6,'逻辑判断','从2019年5月1日至2019年底，某机构统计的新能源车辆事故共计113起，着火 事故占有一定比例。在着火事故车辆中，乘用车占比达到69.6%,专用车次之，公 交车最低。这说明，在新能源车辆中，乘用车的安全性大大低于专用车和公交车。 以下哪项如果为真，最能质疑上述结论：','[{"label":"A","content":"新能源汽车中乘用车的利润最高，企业对其安全性设施的研发投入也最高"},{"label":"B","content":"新能源专用车和公交车的司机一般驾龄较长、水平较高，出车事故率较低"},{"label":"C","content":"在新能源汽车的着火事故中，乘用车的伤亡人数远远少于专用车和公交车"},{"label":"D","content":"据该机构统计，新能源专用车和公交车保有量不到新能源汽车总量的10%"}]','D','【题型分类】一般质疑类 比例类论证 【实战解析】论据结论见批注。汽车安全性应该比较事故率④ ,题干 只比较了事故的占比，未考虑各类车保有量， 直接在选项中寻找“带 数字的分母(即各类车保有量占比)”即可⑤,观察选项： D 选项，假设新能源车辆共计1000量(则乘用车超过900量，其他 新能源不足100量),着火事故车辆100量(则乘用车69.6量，其他 新能源30.4量),乘用车事故率小于10%,其他新能源事故率超过 30%; 乘用车事故率较低，可见更安全，质疑了结论，当选。','逻辑判断600题','进阶','published','{"globalNumber":282,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400283,6,'逻辑判断','甲和乙今年都报考了研究生，关于他们的考试有如下四个断言： ①他们两人至少有一个考上 ②甲并不必然考上 ③乙确实考上了 ④并非是甲可能没考上 最后录取结果表明：这四个断言中有两个是真的，两个是假的。 则下面哪一个结果可以从上述条件推出：','[{"label":"A","content":"甲考上了，乙没考上"},{"label":"B","content":"甲和乙都考上了"},{"label":"C","content":"甲和乙都没考上"},{"label":"D","content":"乙考上了，甲没考上"}]','A','【题型分类】分析类——真假分析 【实战解析】四人说法可分别翻译为：①甲或乙，②甲非必然考上， ③乙，④甲必然考上； 观察可知，②④矛盾，则①③一真一假； 再用假设法判断①③,若③为真，则①为真，则为③假(即乙未考上), ①为真(即甲考上),可确定甲考上，乙未考上，A 选项正确。','逻辑判断600题','进阶','published','{"globalNumber":283,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400284,6,'逻辑判断','小甲过生日，准备叫上小乙、小丙、小丁一起去户外烤肉，他们买了鸡腿、鱿鱼、 牛肉三种不同的食物，并存在如下推测： ①如果小丙买鸡腿，那么小甲买牛肉； ②如果小丙不买鸡腿，那么小乙买鱿鱼； ③只有小丁买了鸡腿，小甲才买牛肉； ④除非小乙买鱿鱼，否则小丁不买鸡腿。 由此可以推出：','[{"label":"A","content":"小乙买鱿鱼"},{"label":"B","content":"小甲买牛肉"},{"label":"C","content":"小丙买鸡腿"},{"label":"D","content":"小丁买鸡腿"}]','A','。 逻辑判断 ⑧花生批注： 结论：学前儿童低估 有意识的人的思维， 而高估无意识的人的 思维。 ⑨花生批注： “有意识的人”、“无 意识的人”都是成年 人的判断。 ⑩花生批注： 例如：有人认为B 、C、 D 选项均不正确。 其隐含的前提应是 “A选项是正确的(即 他的评判标准是正确 的)”。 ⑪花生批注： 学前儿童对人类思维 的判断是不合理的， 即学前儿童判断能力 不太成熟和稳定。 ⑫花生批注： “判断是否合理”和 “是否积极做判断” 无关； 例如：做题时积极思 考，不代表做的就是 对的。','逻辑判断600题','进阶','published','{"globalNumber":284,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400285,6,'逻辑判断','学前儿童低估有意识的人的思维，而高估无意识的人的思维，甚至一个成年人显然 在进行思考时，他们也认为这个人并非在思考着；他们似乎对自己或其他人可能在 思考什么,没有多少认识。同时，他们却高估某个沉睡中的人所具有的自我知觉和 决断能力。 上述论断的前提假设是：','[{"label":"A","content":"成年人对人类思维的判断是比较合理的"},{"label":"B","content":"学前儿童的判断能力不太成熟和稳定"},{"label":"C","content":"沉睡中的人所具有的思维能力并不容易为人所了解"},{"label":"D","content":"学前儿童也是在积极主动地作出心理判断"}]','A','。 四海公考','逻辑判断600题','进阶','published','{"globalNumber":285,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400286,6,'逻辑判断','很多大学生临近毕业找工作，都会面临工作面试。面试在求职过程中非常重要。经 过面试，如果应聘者的性格特征不适合待聘工作的要求，则不可能被录用。 以上论断是建立在以下哪项假设基础上：','[{"label":"A","content":"面试官能够准确地分辨出哪些性格特征是工作所需要的"},{"label":"B","content":"若一个人的性格特征适合工作的要求，他就一定被录用"},{"label":"C","content":"必须经过面试才能取得工作"},{"label":"D","content":"面试的唯一目的就是甄别应聘者的性格特征"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":286,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400287,6,'逻辑判断','四月中旬，某省召开了文化馆建设会议，各市文化馆都派出了一名骨干参会。在进 行了全体大会后，会议又组织了小组讨论，其中甲、乙、丙、丁、戊五人被分到同 一小组，关于他们，有如下的信息： (1)他们来自A、B、C、D、E 五个市的文化馆。 (2)甲只与其中两人认识。 (3)来自B、C、E 三市的三人之前一起参加过会议，相互熟悉。 (4)D市的与会者认识三人。 (5)乙不是B 市的，并且和B市与会者头次见面。 (6)C市与会者和丙相识。 (7)丁只与一个人见过面。 根据以上信息，可以推断，戊来自哪座城市的文化馆：','[{"label":"A","content":"B市"},{"label":"B","content":"C市"},{"label":"C","content":"D市"},{"label":"D","content":"E 市 89"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":287,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400288,6,'逻辑判断','某省光电技术发展取得巨大突破，预计太阳能资源量将增长150%以上。有专家称该 省将成为光电大省，太阳能资源可以满足该省上千万居民的生活和工农业发展的用 电需求，促进当地经济发展。 该专家观点成立的假设前提是：','[{"label":"A","content":"该省的特殊地形利于生成光电资源"},{"label":"B","content":"目前该省电力资源无法满足实际需求"},{"label":"C","content":"光电资源清洁，光电技术发展迅猛"},{"label":"D","content":"该省实际的太阳能发电量能达到预期"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":288,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400289,6,'逻辑判断','据某一年的调查报告显示，75%的重大刑事案件未成年罪犯多是单亲家庭。这说明， 单亲家庭将极大增加未成年人犯罪。 以下各项如果为真，最能削弱上述结论的是：','[{"label":"A","content":"这一年，许多家庭父母离婚是因为孩子是罪犯"},{"label":"B","content":"这一年的罪犯数量比上一年增加了70%"},{"label":"C","content":"许多未成年罪犯的父母关系很好，对孩子极其关爱"},{"label":"D","content":"总犯罪量不变，这一年成年人犯罪的案件数有惊人的增长"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":289,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400290,6,'逻辑判断','相对于不喜欢瑜伽的女性，经常做瑜伽的女性身体普遍更健康，由此可见，瑜伽可 以锻炼身体，有利于保持健康。 下列选项如果为真，最能削弱上述论断的是：','[{"label":"A","content":"很多女性练瑜伽是因为兴趣，而不是为了锻炼身体"},{"label":"B","content":"身体不太好的女性一般不去练瑜伽"},{"label":"C","content":"瑜伽锻炼有一定的难度，容易令人受伤"},{"label":"D","content":"研究表明，游泳比瑜伽更能锻炼身体"}]','B','项。','逻辑判断600题','进阶','published','{"globalNumber":290,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400291,6,'逻辑判断','甲说：尽管政府努力通过积极的就业政策和开展全民创业活动降低失业率，但是这 一计划仍然失败了，因为在本市实施一年后失业率并没有什么变化。乙说：但是在 计划开始的最初一段时间，本地的失业率是有降低的，该计划还是有帮助的。 以下哪项为真，最能削弱乙的论断：','[{"label":"A","content":"政府将实施更加积极的就业政策"},{"label":"B","content":"该地的失业率在全国范围内属于平均水平以下"},{"label":"C","content":"该地的失业率在当前一段时间内出现了上升"},{"label":"D","content":"在政府计划开始的一段时间里，该地居民外出打工的人数有明显增加"}]','D','【题型分类】 一般质疑类 有论据有结论 【实战解析】论据结论可见批注，分析选项： A 选项，谈的是未来实施政策的问题，未谈论该计划是否有作用，无 关项； B 选项，该地失业率在全国处于较低水平，说明计划可能有用，属于 增加论据支持； C 选项，“当前”和“计划实施最初一段时间”时间不符合，无关项； D 选 项②,虽然计划最初一段时间本地就业率有所下降，但那段时间 里该地居民外出打工人数有明显增加，所以失业率下降可能和后者有 关，计划不一定是有作用的，可以质疑，当选。 四海公考 SIHAIG0NGKAO 逻辑判断','逻辑判断600题','进阶','published','{"globalNumber":291,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400292,6,'逻辑判断','一项针对1.1万名2000年到2002年出生于英国的儿童的研究发现，在5岁时，三 分之二以上的孩子每天看1～3小时的电视，15%的孩子坐在电视机前的时间超过3 小时，而仅有2%的孩子从来不看电视。两年后的随访结果显示，那些5岁时每天看 电视时间超过3小时的孩子，表现出更多的反社会倾向，如脾气更暴躁、爱偷东西等。 据此，研究人员认为让孩子长时间看电视会让孩子变得更难管教。 下列选项如果为真，最能反驳上述结论的是：','[{"label":"A","content":"长时间看电视的孩子缺乏时间意识，自制力较差"},{"label":"B","content":"长时间看电视的孩子与同龄人相处的时间少，性格更孤僻"},{"label":"C","content":"看电视挤占了孩子们户外活动的时间，不利于其健康成长"},{"label":"D","content":"放纵孩子长时间看电视的父母多因工作繁忙而疏于对孩子的教导"}]','D','。 3花生批注： 题干按照5岁时看电 视是否超过3小时分 组对比，结果为超过3 小时的孩子表现出更 多反社会倾向； 得出孩子更难管教的 原因是长时间看电视 这一结论。 花生批注： 题干实验按照打游戏 和不打游戏分组对比， 实验结果为打游戏组 学生更执拗任性； 得出实验中学生执拗 任性的原因是打游戏 的结论。 25花生批注： 对比实验归因类常见 错误选项：“有些” 类选项、实验瑕疵、 未谈论原因、分组错 误或未分组。 个别学生如何，不能 质疑甲组执拗任性比 例更高这一整体性事 实。 ⑥花生批注： 题干实验按照TH 基 因某位点是否是T 碱 基分组对比，实验结 果为T 碱基组女性拖 延倾向更严重； 得出实验中女性拖延 是基因导致的结论。','逻辑判断600题','进阶','published','{"globalNumber":292,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400293,6,'逻辑判断','一位心理学家对初中二年级的两组学生做了调查，甲组的学生每天打电脑游戏的时 间平均约一小时，乙组学生从不打电脑游戏，结果发现，甲组学生中执拗任性者所 占比例要远远高于乙组学生。于是，他认为，打电脑游戏容易使孩子执拗任性。 以下哪个选项为真，将对这位心理学家的论点构成挑战：','[{"label":"A","content":"甲组中有的学生并不执拗任性"},{"label":"B","content":"乙组中有的学生比甲组中有的学生执拗任性"},{"label":"C","content":"乙组中很多学生非常听话"},{"label":"D","content":"甲组中很多学生的执拗任性是他们家长的溺爱造成的"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":293,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400294,6,'逻辑判断','有研究小组对278名健康男性和女性进行了基因分析与问卷调查，发现女性TH基因 中的rs10770141 位点碱基的类型与拖延症有很大关系，当rs10770141 位点是T 碱 基时，TH 基因的活性更强，多巴胺水平更高，这样的女性拖延倾向也更严重。研究 者据此认为，女性拖延的倾向可能是受基因控制的，很难改变。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"有研究结果表明，有拖延倾向的人，其大脑内参与情绪处理的区域——杏仁核更大"},{"label":"B","content":"调节体内雌激素水平，可以刺激或抑制TH基因的表达，从而影响生产多巴胺的 神经元的发育和分化"},{"label":"C","content":"高水平的多巴胺会提高认知灵活性，并拓宽注意力的范围，但也更容易使人分心， 不能坚持完成一件事"},{"label":"D","content":"TH 基因不仅影响多巴胺的分泌，也会影响去甲肾上腺素的分泌，进而影响行动 控制并增加个体拖延倾向 91"}]','A','。 ②花生批注： 例如：“多吃白米饭 导致某人患糖尿病” 和“锻炼会影响血糖 值”是两回事，可以 同时成立，互不冲突。 28花生批注：','逻辑判断600题','进阶','published','{"globalNumber":294,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400295,6,'逻辑判断','某社区选派党员参与疫情防控工作，小张或者小雷至少有一人参加，同时还需满足 以下条件： ①如果有小雷，就必须有小夏； ②小夏小张至多只能有一人； ③若有小张就必须有小孙； ④有小孙就必须有小夏。 如果以上为真，那么参与疫情防控的工作人员一定有：','[{"label":"A","content":"小张和小夏"},{"label":"B","content":"小夏和小孙"},{"label":"C","content":"小孙和小雷"},{"label":"D","content":"小雷和小夏"}]','D','【题型分类】推出类——正推逆推、两难推理 【实战解析】③和④联立可得⑥小张→ 小孙→ 小夏，①翻译为小雷→ 小夏，根据⑤⑧可知小夏必须参加，又根据②可知小张不能参加，再 根据⑤可确定小雷必须参加； 综上，必须参加的有小夏和小雷，D 选项正确。','逻辑判断600题','进阶','published','{"globalNumber":295,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400296,6,'逻辑判断','一位父亲对女儿说：一个女孩子将来要想在社会上立足，赢得别人的尊重，必须有 一番事业；要有一番事业，必须在读书时就懂得与人沟通，懂得为人处事；如果在 校期间，只知道读书，不与外界接触，是不可能学会沟通和为人处事的。 从父亲的告诫中，可以得出： ①女孩子要赢得他人尊重，不能不学会沟通和为人处事 ②不会沟通，不懂为人处事，女孩子不可能有一番事业 ③女孩子未赢得他人尊重，是因为只知道读书，不懂如何与外界接触','[{"label":"A","content":"①和 ②"},{"label":"B","content":"①②和③"},{"label":"C","content":"①和 ③"},{"label":"D","content":"仅①"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":296,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400297,6,'逻辑判断','评估读写障碍学生的传统方式是当一个孩子在读写方面遭遇了异常困难，其家长和 老师坐到一起，通过纸质测试收集信息并评估孩子的优势和劣势，以确诊和制定适 当的干预方案。目前某科技公司发明了一种读写障碍筛查工具，即通过电脑和眼动 追踪摄像机，对每一个学生进行测试，以此找出少部分可能有读写障碍倾向的孩子， 该公司市场管销人员表示，这种眼动追踪技术潜力无限，有望在学校得到普及。 以下哪项如果为真，最能削弱上述观点：','[{"label":"A","content":"单纯通过纸笔测试，很难直接读取结果，要花费大量时间"},{"label":"B","content":"教育工作者不一定都是科学家或研究者，他们可能没有足够的资源去理解该如何 充分利用测试的结果"},{"label":"C","content":"此技术只是一个筛查工具，主要目的是在早期就能找到那些有阅读障碍倾向的孩 子，而不是一个诊断工具"},{"label":"D","content":"眼动仪可分辨出读写障碍者和非读写障碍者之间的阅读差异，但这些差异很可能 只是阅读障碍的结果而非原因"}]','B','。 ③④花生批注： 题干论据介绍了评估 读写障碍学生的传统 方式和某公司发明的 读写障碍筛查工具。 结论：该公司发明的 读写障碍筛查工具有 望在学校得到普及。 35花生批注： 题干均为所有、有些 表述，属于范畴分析 类题目，考虑一分为 二画图法。 36花生批注： 若存在所有A都是B, 所有B 都是C, 一般 用C 和非C 一分为二。','逻辑判断600题','进阶','published','{"globalNumber":297,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400298,6,'逻辑判断','王村的所有男人都喜欢钓鱼，有些王村的男人在城里打工，有些喜欢电子游戏的人 也在城里打工，喜欢电子游戏的人都不喜欢自驾游，所有喜欢钓鱼的人都喜欢自驾游。 如果以上陈述属实，那么以下各项都可能为真，除了：','[{"label":"A","content":"王村的所有男人都喜欢自驾游"},{"label":"B","content":"有些王村的男人喜欢电子游戏"},{"label":"C","content":"有些在城里打工的人不喜欢钓鱼"},{"label":"D","content":"喜欢钓鱼的人都是王村的男人"}]','B','【题型分类】分析类——范畴分析 【实战解析】王村所有男人喜欢钓鱼，所有喜欢钓鱼的都喜欢自驾游， 可根据自驾游和非自驾游一分为二，具体图示如下： 非自驾游电子游戏城市打工B自驾游钓鱼王村男人城市打工A 非自驾游 电子游戏 城市打工B 自驾游 钓鱼 王村男人 城市打工A A 选项，王村男人均在喜欢自驾游一侧，必定正确； B 选项，王村男人与喜欢电子游戏无交集，必定错误； C 选项，城里打工B 在喜欢钓鱼圈外，即有些城里打工者不喜欢钓鱼， 必定正确； D 选项，王村男人可能和喜欢钓鱼的集合重合，即喜欢钓鱼的人可能 都是王村男人，可能正确； 综上，除了B 选项，其他选项都必然或可能为真。','逻辑判断600题','进阶','published','{"globalNumber":298,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400299,6,'逻辑判断','黑脉金斑蝶的幼虫以乳草植物为食，这种植物所含的毒素使得黑脉金斑蝶对一些捕 食它的动物有毒。副王侠蝶的外形和黑脉金斑蝶非常相似，但它的幼虫并不以乳草 植物为食。因此有研究者认为，副王侠蝶之所以很少被捕食，是因为它和黑脉金斑 蝶在外形上相似。 下列哪项如果为真，最能削弱研究者的论证：','[{"label":"A","content":"副王侠蝶对大多数捕食它的动物都有毒"},{"label":"B","content":"有些动物在捕食了副王侠蝶后并没有中毒"},{"label":"C","content":"有些捕食黑脉金斑蝶的动物也捕食副王侠蝶"},{"label":"D","content":"蝴蝶具有通过自身的毒性来抵御捕食者的保护机制"}]','A','，属于另有他因质疑。','逻辑判断600题','进阶','published','{"globalNumber":299,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400300,6,'逻辑判断','如果“除非小王是大学生，否则他不会说英语”为假，则：','[{"label":"A","content":"小王不是大学生，但是他会说英语"},{"label":"B","content":"小王是大学生，但是他并不会说英语"},{"label":"C","content":"小王不是大学生，他不会说英语"},{"label":"D","content":"小王是大学生，他会说英语 93 练习题16"}]','A','。 ③花生批注： “有些”可以质疑“所 有不”,但原因类题 目多属于普遍性分析， 而非绝对化的“所有”。 “有些”类选项属于 原因类题目典型错误 选项，选择可能性极 低。 38花生批注： 除 非 A 否 则B 、 必 须 A 否 则 B、A 否 则B, 均翻译为“非 A→B”。 231 练习题 16 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 归因：素食导致抑郁 症风险增大。 ②花生批注： “研究人员在对工作 状态、家庭历史和孩 子数量等变量进行调 整之后”即排除他因， 对比实验归因题可用 排除他因支持，但本 题已经排除他因，以 解释说明方式支持。','逻辑判断600题','进阶','published','{"globalNumber":300,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400301,6,'逻辑判断','一研究机构针对9700名素食者展开调查。研究人员在对工作状态、家庭历史和孩子 数量等变量进行调整之后，发现素食者患抑郁症的几率依然要高于肉食者。该研究 表明，素食者可能会增大患抑郁症的风险。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"抑郁症受自身炎症反应的影响较大，具有抗炎作用的 w-3 脂肪酸常见于鱼类"},{"label":"B","content":"与肉食者相比，素食者喝酒抽烟更少、运动更多，生活更有规律，更容易满足"},{"label":"C","content":"叶酸广泛存在于很多动植物产品中，它可帮助身体生成调节情绪的神经递质，摄 取更多的人患抑郁症的风险更低"},{"label":"D","content":"人类的食物多种多样，各种食物所含的营养成分也不完全相同，但任何一种食物 都不能提供人体所需的全部营养"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":301,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400302,6,'逻辑判断','甲、乙、丙、丁四人参加某公司的招聘考试。小张认为：“不是甲被录取，就是乙 被录取。”小李认为：“甲和丙两人都能被录取。”小王认为：“不能说如果丁被 录取则丙被录取。”小赵认为：“丁不能被录取。” 如果上述四人中只有一人说错了，那么哪两人一定会被录取：','[{"label":"A","content":"乙 、丁"},{"label":"B","content":"甲、乙"},{"label":"C","content":"丁、丙"},{"label":"D","content":"甲、丙"}]','D','。 ③花生批注： “不能说如果丁被录 取则丙被录取”,翻 译为：“丁→丙”为假， 即丁且非丙成立。','逻辑判断600题','进阶','published','{"globalNumber":302,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400303,6,'逻辑判断','奥杜威峡谷是早期人类的活动地之一，也是火山活动活跃的地区。科学家对一些来 自奥杜威峡谷的170万年前的火山沉积物进行了研究，意外地在沉积物中发现了一 种由超嗜热细菌合成的脂类，科学家推断，奥杜威峡谷在170万年前存在高温温泉， 生活在这里的古人类很有可能借助这些温泉煮熟食物。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"在其他古人类遗址中也发现了借助温泉煮食物的遗迹"},{"label":"B","content":"奥杜威峡谷是地质活动活跃的构造区，火山活动频繁"},{"label":"C","content":"超嗜热细菌通常在水温超过80℃的环境中生长"},{"label":"D","content":"只有经过火山活动才能形成火山沉积物"}]','C','【题型分类】支持类——断点搭桥 ④花生批注： 论据：在火山沉积物 中发现一种由超嗜热 细菌合成的脂类； 结论：存在高温温泉， 古人类用温泉煮熟食 物。 前文是背景介绍，可 略读。 ⑤花生批注： 既成事实：男女大脑 大小存在差异。 ⑥花生批注： 原因分析：造成差异 的原因是雄性激素而 非遗传信息。 【实战解析】论据结论可见批注，脂类和高温温泉存在明显断点，需 要搭桥，选项中只有C 选项将二者搭桥，可直接秒选，其逻辑关系如下： 奥杜威峡谷发现超嗜热细菌合成的脂类，这种脂类通常在水温超过 80°的环境中生长(即高温温泉),所以峡谷存在高温温泉，供人类 煮熟食物； A 、B 、D 选项均未将脂类和高温温泉关联，均无法支持。','逻辑判断600题','进阶','published','{"globalNumber":303,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400304,6,'逻辑判断','人类男女大脑存在大小差异，关于人类男性和女性的大脑大小差异，以及形成这一 区别的具体机制仍旧不得而知。性别差异主要体现在两个方面，一是遗传物质，二 是性激素。科学家发现，与遗传信息相比雄性激素可能是造成大脑性别差异的主要 原因。 逻辑判断 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"来自于雌性和雄性细胞系的类器官遗传物质对性激素的响应基本一致"},{"label":"B","content":"雄性激素可促进神经元细胞增殖，并促使兴奋性神经元数目增加"},{"label":"C","content":"男性和女性在自闭症、神经分裂症等脑部疾病的易感性方面有所区别"},{"label":"D","content":"男性和女性在大脑结构和功能上有差异，其形态学和行为学指标均有所不同"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":304,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400305,6,'逻辑判断','互联网公司从社会招聘成熟的计算机人才，往往需要提供相当高的薪酬福利，并且 难以挖掘到核心人才。而毕业生初入社会，大部分都踏实肯干，前期成本也不高， 后期还可以进行优胜劣汰的选择。因此，互联网公司更愿意培养这些新人。 以下选项如果为真，最能质疑上述判断的是：','[{"label":"A","content":"在互联网行业，毕业生也存在流动的可能性"},{"label":"B","content":"相较于工作经验，互联网公司更关注薪酬成本和人员的稳定性"},{"label":"C","content":"成熟的计算机人才进入互联网公司后带来的收益要远远高于毕业生"},{"label":"D","content":"需要接受大量培训，毕业生才能具备接近成熟计算机人才的工作能力"}]','C','。 ⑦花生批注： 论据：成熟员工薪酬 高还难找，新人踏实 肯干前期成本不高后 期还可优胜劣汰； 结论：互联网公司更 愿意培养新人。 ⑧花生批注： 企业招聘可以类比成 购买商品，应衡量“性 价比”,毕业生价格低， 但成熟人才“性能(收 益)”强，不一定毕 业生更受青睐； 并且C 选项使用了程 度词“远远高于”, 体现出了成熟人才在 为公司创收方面的巨 大优势，是很强烈的 质疑。 ⑨花生批注： D 选项与题干也稍显 重复，之所以称之为 “计算机人才”和“这 些新人”,已经体现 出能力上的差异，题 干是在此前提下因毕 业生成本低得出的结 论； 此时再指出这一点， 可看作无法质疑。 235 ⑩花生批注： 冠军是C, ①②为假， ③为真。 ⑪花生批注： 论据：新招聘员工均 超过1米7; 结论：公司所有员工 均超过1米7。','逻辑判断600题','进阶','published','{"globalNumber":305,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400306,6,'逻辑判断','田径场上正在进行100米决赛。参加决赛的是A、B、C、D、E、F六个人。小李、小 张、小王对谁会取得冠军谈了自己的看法： 小张认为，冠军不是A就是B; 小王坚信，冠军绝不是C; 小李则认为，D 、F都不可能取得冠军。 比赛结束后，人们发现三个人中只有一个人的看法是正确的。 问：谁是100米决赛的冠军：','[{"label":"A","content":"A"},{"label":"B","content":"B"},{"label":"C","content":"C"},{"label":"D","content":"E"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":306,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400307,6,'逻辑判断','某公司发布招聘启事，要求招收身高1米7以上的员工，因而在严格按照招聘规则 完成招聘后，该公司所有人身高都高于1米7。 以上结论基于的前提是：','[{"label":"A","content":"该公司在招聘发布前，公司员工身高都超过1米7"},{"label":"B","content":"该公司领导及管理岗位员工身高都超过1米7"},{"label":"C","content":"该公司所有应聘者身高都超过1 米 7"},{"label":"D","content":"对于身高1米7及以下的优秀人员不设置特殊招聘 95"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":307,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400308,6,'逻辑判断','红斑狼疮药物研发是国际药学界公认的最具挑战性的研究领域之一。由于发病机制 不清和疾病的异质性，临床长期缺乏新型治疗药物。目前，1944年问世的抗疟疾药 物羟氯喹是红斑狼疮治疗的常规药物。因此，作为首选的抗疟药类别，升级版的羟 氯喹——青蒿素有望成为治疗红斑狼疮的有效药物。 以下除哪项外，均能支持上述结论：','[{"label":"A","content":"有研究表明青蒿素的“近亲”——青蒿琥酯、马来酸蒿乙醚胺等，都对红斑狼疮 有治疗效果"},{"label":"B","content":"青蒿素对红斑狼疮的治疗效果目前正在进行相关试验，预计将在未来五年内完成 这一试验"},{"label":"C","content":"目前动物实验已经证明除了系统性红斑狼疮，青蒿素还对类风湿关节炎等其他疾 病有一定治疗效果"},{"label":"D","content":"针对红斑狼疮的治疗中，羟氰喹可发挥免疫抑制作用，青蒿素具有同样的免疫抑 制活性"}]','B','。 237 ⑮花生批注： 这段文字都在分析环 太事务署的性质，因 为种种，他是一个企 业。 ⑯花生批注： 环太事务署自己赚钱 自己花，可理解为有 财务自由。若从此设 置正确答案，应为“有 财务自由就独立性很 强”; 另外，严谨的说，此 题结论中的新内容是 “独立性强”,“强” 是重点，而非“有”。 ⑪花生批注： 切记：此类题目“以 我为主”,寻找想要 答案，不要被错误选 项干扰。 ⑱花生批注： 且关系，一假则假。 ⑲花生批注： “非亮且非强”为假， 强没吃，那么只能是 亮亮吃了。','逻辑判断600题','进阶','published','{"globalNumber":308,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400309,6,'逻辑判断','国家利益面前，没有部门利益。环太事务署的独立性还要看国家的整体需要，环太 事务署并非“国中之国”。该机构表面上看是M国国务院的一个行政机构，并为其 亚太地区的决策提供咨询和参考，但他的财务不在该国国家预算体系之内，自己赚 钱自己花。实际上是一个企业。就此而言，环太事务署的独立性其实很强。 下列哪项最可能是以上论述所假设的前提：','[{"label":"A","content":"没有财务自由，就没有独立性"},{"label":"B","content":"比之行政机构，企业具有很强的独立性"},{"label":"C","content":"机构的独立性要服从国家的整体需要"},{"label":"D","content":"国家利益高于集体利益，集体利益高于个人利益"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":309,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400310,6,'逻辑判断','“小课桌”有三个小朋友。明明、强强和亮亮，为鼓励小朋友认真学习，老师在桌 上放了一把糖果，告诉三个小朋友只有等作业做完老师检查后才能吃。结果在老师 离开教室不到半小时，所有糖果都没了，老师追问此事。明明说：“我等不及，我 吃了。”强强说：“我没吃。”亮亮说：“反正我和强强没吃。” 假设只有一个人说谎，则说谎的人是：','[{"label":"A","content":"明明"},{"label":"B","content":"强强"},{"label":"C","content":"亮亮"},{"label":"D","content":"不知道 四海公煮 逻辑判断"}]','C','。 四海公考','逻辑判断600题','进阶','published','{"globalNumber":310,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400311,6,'逻辑判断','一项新研究认为，茶里含有的某种物质能增强身体的抵抗力，它可以使免疫系统攻 击入侵的细菌、病毒和霉菌等，这是咖啡所不具备的。这项研究中，共有20名志愿 者参与了实验，其中10人每天喝5杯茶，另10人每天喝5杯咖啡。 一个月后，研 究人员抽取志愿者血液并接触大肠杆菌，发现喝茶组的血细胞分泌的干扰素数量是 实验前的5倍，而喝咖啡组的血细胞分泌的干扰素数量与实验前无异。 下列选项如果为真，最能削弱以上研究结论的是：','[{"label":"A","content":"喝茶组志愿者参加该实验后更注重运动"},{"label":"B","content":"另有研究表明，多喝咖啡同样具有增强体质的功效"},{"label":"C","content":"细菌在地球上存在了亿万年都没有灭绝"},{"label":"D","content":"干净整洁的环境有助于增强人的身体抵抗力"}]','A','。 ②⑳花生批注： 题干按照“喝咖啡” 与“喝茶”将实验对 象分成两组，得出结 果，即喝茶组分泌的 干扰素数量是实验前 的两倍，而咖啡组无 异。由 此 ，将“身体 抵抗力高”的原因归 于“茶里含有的某种 物质”。 239 逻辑判断 ②花生批注： 或者或者，一真则真。 花生批注： 特例可推出有些，“丁 偷吃糖果”可推出“有 人偷吃糖果”。 3花生批注： 论据：实验中金鱼鳞 添加褪黑素后，骨质 疏松现象得到抑制； 结论：未来可利用褪 黑素开发药物帮助宇 航员预防和治疗骨质 疏松。','逻辑判断600题','进阶','published','{"globalNumber":311,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400312,6,'逻辑判断','家里有四个孩子，分别为甲、乙、丙和丁，一天，放在餐桌上的糖果少了几颗，母 亲问是谁偷吃了糖果，四个孩子各有说辞： 甲说：我们中有人偷吃了糖果； 乙说：我们四个都没偷吃糖果； 丙说：乙和丁至少有一人没有偷吃糖果； 丁说：我没偷吃糖果。 如果四个孩子中有两个说真话，有两个说假话，则说真话的是：','[{"label":"A","content":"说真话的是甲和丙"},{"label":"B","content":"说真话的是甲和丁"},{"label":"C","content":"说真话的是乙和丙"},{"label":"D","content":"说真话的是乙和丁"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":312,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400313,6,'逻辑判断','在太空环境下，失重及较高水平的电离辐射环境容易造成宇航员骨质疏松。近日， 在国际空间站宇航员的配合下，研究人员利用金鱼鳞在太空进行了有关褪黑素与骨 质疏松关系的实验，发现与不添加褪黑素的金鱼鳞相比，人为添加褪黑素后金鱼鳞 骨质疏松现象得到抑制，骨质疏松速度放慢。研究人员认为，未来有可能利用褪黑 素开发药物，帮助进入太空的宇航员预防和治疗骨质疏松。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"除预防和治疗骨质疏松外，褪黑素还有助于改善宇航员的睡眠水平"},{"label":"B","content":"金鱼鳞的骨芽细胞，即处于骨细胞早期发育阶段的细胞能够产生褪黑素"},{"label":"C","content":"目前，尚没有药物能够很好地预防和治疗宇航员在太空失重情况下导致的骨质疏松"},{"label":"D","content":"在褪黑素的作用下，金鱼鳞和人类骨骼具有同样的应答机制，可用作骨骼研究的 模型 97 逻辑判断"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":313,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400314,6,'逻辑判断','“地球一小时”是世界自然基金会应对全球气候变化所提出的一项倡议，希望家庭 及商户在每年3月的最后一个星期六20:30～21:30期间熄灯1小时。“地球一小时” 能减少的用电量主要来自照明用电。据统计，照明用电量约占用电总量的12%,其 中只有部分用户参与熄灯活动。因此，在活动中减少的电能消耗量是微乎其微的。 有市民据此认为，“地球一小时”并没有取得什么实际的效果。 以下哪项如果为真，最能质疑上述市民的看法：','[{"label":"A","content":"每年“地球一小时”活动所节省的用电量可供一个大型城市用电三天"},{"label":"B","content":"“ 地球一小时”造成短时间内用电骤减，给电网管理带来困难"},{"label":"C","content":"尽管现在参与活动的人数有限，但是将来参与人员的比例会越来越大"},{"label":"D","content":"“地球一小时”的目的是呼吁人们节约能源，保护地球"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":314,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400315,6,'逻辑判断','研究人员研究了来自110万人的DNA,得出了一个评分系统。利用该系统可以通过 检测某人的DNA 来大致预测某人的受教育程度。结果发现，那些基因得分最低的人 只有10%的机会从大学毕业；相比之下，那些基因得分在前五分之一的人，有50% 的机会从大学毕业。这是有史以来最大规模的人类认知遗传学研究。有些人据此以为， 人类的基因与学历之间有极大联系。 下列哪项如果为真，最能质疑这些人的观点。','[{"label":"A","content":"在110万被研究者中，抽样显示，只有不到30%的人是大学毕业的"},{"label":"B","content":"在大学毕业的被研究者中，其父母之一是大学毕业的超过50%"},{"label":"C","content":"在110万被研究者中，有超过60%的人是大学毕业的"},{"label":"D","content":"基因得分最居中的人，也有40%的机会从大学毕业"}]','C','②。 7花生批注： 此题A、C 、D 选项均 为资料分析盐水知识 点。','逻辑判断600题','进阶','published','{"globalNumber":315,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400316,6,'逻辑判断','近年来科技的迅猛发展为科幻小说创作提供了启发，也为科幻小说创作提供了丰富 的素材。科幻小说的主题即是围绕着科技幻想、揭示科技发展带来的社会问题及其 给人类带来的启示而展开的。因此科幻小说的蓬勃发展是科技发展的结果。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"伴随着西方工业革命产生的科幻小说经历了初创、成熟和鼎盛三个历史时期"},{"label":"B","content":"科技发展拓展了科幻小说的想象空间，科幻小说为科技发展提供了人文视角"},{"label":"C","content":"科技只是科幻小说中的背景元素，科幻小说本质上还是要讲述一个完整的故事"},{"label":"D","content":"科幻小说展现了人类的愿望，最终推动科技发展将那些梦想变为现实"}]','D','【题型分类】归因类——一般归因 【实战解析】原因分析见批注，分析选项： A 选项介绍西方科幻小说发展历程、B 选项介绍科技与小说相互作用、 C 选项介绍科技与可换线小说的关系，均未谈及原因，无法质疑； D 选项，用“最终”体现时间先后，先有科幻小说展现愿望(果), 后有科技发展变为现实(因),属于因果倒置质疑，当选。 28花生批注： 前文可看作背景与分 析，结论是对上文总 结，全文就一个结论： 科技发展是因，科幻 小说发展是果。 243 9花生批注： 论据：指纹纹路会发 生变化； 结论：指纹不应该再 用于案件侦破。','逻辑判断600题','进阶','published','{"globalNumber":316,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400317,6,'逻辑判断','众所周知，每个人的指纹都是不同的，指纹才是每个人独一无二的身份证，因此指 纹常常用在案件侦破中。然而科学家的最新研究发现，随着机体老化，指纹纹路排 列会发生不可逆转的变化，因此科学家得出结论：指纹不应该再用于案件侦破中。 以下哪项如果为真，最能质疑上述结论：','[{"label":"A","content":"指纹是目前案件侦破的最关键证据，许多重案犯是依靠指纹才被抓捕归案的"},{"label":"B","content":"除了指纹，每个人的DNA也是独一无二的且不会随着时间变化而发生改变"},{"label":"C","content":"除了纹路排列，指纹的其他几项指标也是指纹识别技术的重要依据"},{"label":"D","content":"指纹纹路排列发生变化有规律可循，这一规律是普遍适用的"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":317,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400318,6,'逻辑判断','夕阳红合唱团有中老年团员30名。关于这30名团员，记者小王、小李、小赵有如下讨论 小王说：“这些团员中有些是来自燕园小区。” 小李说：“团员中的张大妈不是来自燕园小区。” 小赵说：“这些团员中有些不是来自燕园小区。” 以上陈述仅有一真，由此可以推出：','[{"label":"A","content":"30 名团员都不是来自燕园小区"},{"label":"B","content":"有些团员不是来自燕园小区"},{"label":"C","content":"张大妈不是来自燕园小区"},{"label":"D","content":"30 名团员都是来自燕园小区"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":318,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400319,6,'逻辑判断','某公司所有的销售人员都是男性，所有的文秘都是女性，所有的已婚者都是文秘， 公司的总经理尚未结婚。 据此，我们可以知道：','[{"label":"A","content":"总经理是男性"},{"label":"B","content":"已婚者中有男性"},{"label":"C","content":"女员工中可能有未婚者"},{"label":"D","content":"销售人员中有的已经结婚"}]','C','。 ③6花生批注： 论据：珊瑚乐于彼此 靠近生活； 结论：可通过追踪珊 瑚集群的生长变化情 况来修复珊瑚礁，防 止濒危珊瑚灭绝。 ③花生批注： 考上公务员有难度， 不代表备考方法都无 用。','逻辑判断600题','进阶','published','{"globalNumber":319,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400320,6,'逻辑判断','珊瑚礁纷繁复杂的颜色看起来似乎非常混乱，但一项新研究显示，许多珊瑚的生长 并不是随机的，它们很乐于彼此靠近地生活。在一个区域内，珊瑚越多，它们抵挡 风浪的能力就越强；珊瑚集群还能扰动流经的海水，使营养物质在珊瑚礁内分布得 更加均匀；更多的邻居也意味着更多的交配机会，有性繁殖的成功率也会更高。研 究者据此推断，可以通过追踪珊瑚集群的生长变化情况来修复珊瑚礁，防止濒危珊 瑚灭绝。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"在不同的海区，珊瑚集群的生长规律差异很大，而且会随外界变化而移动，追踪 其群落变化有着较高的难度"},{"label":"B","content":"珊瑚的生长对环境要求很高，如果对环境不加保护，珊瑚将停止生长，出现“白 化”现象而大量死亡"},{"label":"C","content":"遭遇风暴后，珊瑚虫被损毁，一些幸存的珊瑚会在间隙里迅速生长，在曾经由单 一珊瑚主导的地点形成多样的珊瑚集群"},{"label":"D","content":"许多珍稀的珊瑚物种将后代释放到水中，其幼体经过浮游阶段找到合适的栖息地 后才继续生长，这些物种往往分散得较为稀疏，不成群落 练习题17"}]','D','。 246 练习题 1 7 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":320,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400321,6,'逻辑判断','四个人玩抽牌游戏，每个人从一副去掉大小王的扑克牌中抽取一张。 甲说：“我抽中的是黑桃。” 乙说：“我抽中的是红桃。” 丙说：“我抽中的不是红桃。” 丁说：“我抽中的是梅花。” 已知四人抽取的扑克牌花色各不相同，且有一人说谎。 根据上述条件，下列说法正确的是：','[{"label":"A","content":"甲乙丙丁均有可能说谎"},{"label":"B","content":"可以推知每个人抽取的扑克牌花色"},{"label":"C","content":"丙可能抽中方块"},{"label":"D","content":"乙抽中的牌一定是红桃"}]','D','。 ①花生批注： 常见矛盾关系有三种： A 与非A(A 或B 与非 A 且非B 、A且B 与非 A或非B ); 所有和有些不、有些 和所有不； A→B 与 A 且非B。 ②花生批注： 若假设某人为真，依 然无法判断另三人谁 为假； 若假设某人为假，则 另外三人都为真。 ③花生批注： 扑克牌有四种花色， 则四人应红桃、梅花、 黑桃、方片各一种。 247 247 ④花生批注： 论据：摄入高度加工 的碳水化合物使人产 生饥饿感； 结论：摄入高度加工 的碳水化合物会导致 人肥胖。 ⑤花生批注： A、B、D选项未建立 饥饿感和肥胖之间的 联系，均无法将断点 搭桥。 ⑥花生批注： 切记：此类题目“以 我为主”,寻找想要 答案，不要被错误选 项干扰。','逻辑判断600题','进阶','published','{"globalNumber":321,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400322,6,'逻辑判断','当人们摄入高度加工的碳水化合物会导致人体不分泌胰高血糖素，缺乏胰高血糖素 使得人体不能取得足够能量，从而使人产生饥饿感。某研究者据此认为，摄入高度 加工的碳水化合物会导致人肥胖。 要使研究者的推论成立，需要补充的前提是：','[{"label":"A","content":"摄入未高度加工的碳水化合物不会导致人肥胖"},{"label":"B","content":"人体缺乏胰高血糖素时会感到饥饿"},{"label":"C","content":"饥饿感会导致人体摄入超过其所需的能量"},{"label":"D","content":"碳水化合物是为人体提供能量的主要物质"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":322,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400323,6,'逻辑判断','2018年某品牌咖啡连锁店全年亏损8亿元，财经人士认为该品牌咖啡连锁店的盲目 扩张、补贴烧钱必然导致资金链断裂，因此有的分店纷纷裁员也是可能的。 以下哪项判断最为接近：','[{"label":"A","content":"该品牌咖啡连锁店的盲目扩张、补贴烧钱的盲目扩张不可能不导致资金链断裂， 有的分店不必然不裁员"},{"label":"B","content":"该品牌咖啡连锁店的盲目扩张、补贴烧钱的盲目扩张可能不导致资金链断裂，有 的分店不必然不会裁员"},{"label":"C","content":"该品牌咖啡连锁店的盲目扩张、补贴烧钱的盲目扩张可能导致资金链断裂，有的 分店不一定不裁员"},{"label":"D","content":"该品牌咖啡连锁店的盲目扩张、补贴烧钱的盲目扩张不可能不导致资金链断裂， 有的分店不一定会裁员"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":323,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400324,6,'逻辑判断','某教师对美国高中生和中国高中生做了一项测试。他问被试者相同的问题“一张A4 纸如果对折，最多可以折几次”,结果发现，听到问题后，大部分美国高中生马上 开始动手折纸，然后根据实际情况回答能折的次数，而大部分中国高中生听到问题 后马上回答：无穷多次。这位教师由此得出结论，美国高中生注重实践，而中国高 中生注重理论。 以下哪项是这位教师得出结论所必须的假设：','[{"label":"A","content":"理论与实践是相对立的"},{"label":"B","content":"只要开始动手折纸并根据实际情况来回答问题，就是注重实践"},{"label":"C","content":"只要开始动手折纸并根据实际情况来回答问题，就是不注重理论"},{"label":"D","content":"只要马上回答“无穷多次”,就是不注重实践"}]','B','⑩花生批注： 切记：此类题目“以 我为主”,寻找想要 答案，不要被错误选 项干扰。 ⑪花生批注： 虽然此选项未建立“回 答无穷多次和注重理 论”之间的联系，但 与其他选项相比，已 经是最优选项。 【题型分类】前提假设类——断点搭桥 【实战解析】论据和论点见批注，这位教师看到美国高中生动手折纸， 就认为是注重实践，看到中国高中生直接回答，就认为是注重理论， 中间存在断点，需要搭桥⑩,观察选项： A 选项，无法连接断点，理论和实践是否对立与题干论证无关，排除； B 选 项 ，建立了动手折纸和注重实践之间的关系①,当选； C 选项、D 选项，为同质选项，不注重理论不等于注重实践，不注重 实践也不等于注重理论，均无法连接断点，排除。 ⑫花生批注： 肥胖、压力、环境等 多种因素都可能和美 国人寿命有关联，但 美国人寿命增速下降 的具体原因到底是什 么,该选项并没有指 出。','逻辑判断600题','进阶','published','{"globalNumber":324,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400325,6,'逻辑判断','近期研究发现，肥胖导致美国人寿命增长速度有所下降。 下列说法如果为真，最能支持上述结论的是：','[{"label":"A","content":"在过去几十年，美国白人，尤其是女性的死亡率正在上升"},{"label":"B","content":"美国肥胖率从1976-1980年的15%,上升到2013-2014年的38%"},{"label":"C","content":"肥胖会带来很多健康风险，如糖尿病、心血管疾病等"},{"label":"D","content":"身体质量指数与美国人寿命之间存在很强的关联性"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":325,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400326,6,'逻辑判断','某贫困县11个贫困乡，经过三年的努力，其脱贫情况有如下说法： ①该县金沙乡脱贫了 ②该县所有的乡都脱贫了 ③该县有的乡脱贫了 ④该县有的乡没有脱贫 经过详细调查，发现上述说法只有两个是正确的，可见：','[{"label":"A","content":"该县有的乡脱贫了，但也有的乡没有脱贫"},{"label":"B","content":"该县金沙乡脱贫了"},{"label":"C","content":"该县所有的乡都脱贫了"},{"label":"D","content":"该县所有的乡都没有脱贫"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":326,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400327,6,'逻辑判断','甲地的市民非常喜欢吸烟，经常出现因吸烟而引起的火灾事故，影响了甲地的治安 环境，为了改善甲地的治安环境，市政府决定减少甲地的香烟生产量。 以下说法如果为真，最能对市政府的决定构成质疑的是：','[{"label":"A","content":"甲地市场上的香烟大多数产自其他地方"},{"label":"B","content":"甲地的治安环境相比其他城市更差"},{"label":"C","content":"甲地的经济收入主要来源于香烟生产"},{"label":"D","content":"有些火灾事故不是由吸烟引起的"}]','A','。 251 ⑱花生批注： 也可看作是否定此因 质疑； 关节炎的根本原因不 是阴冷天穿得少，而 是劳损、感染、创伤。','逻辑判断600题','进阶','published','{"globalNumber":327,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400328,6,'逻辑判断','张女士特别爱美，多年来喜欢在冬天穿裙子以显示她婀娜多姿的身材。从去年冬天起， 每到阴冷天，她都感觉到膝关节疼痛。后经医生诊断，她得了关节炎。于是张女士认为， 阴冷天穿得少是导致关节炎的原因。 以下哪项如果为真，最能质疑张女士的观点：','[{"label":"A","content":"日本一些年轻女士喜欢冬天穿裙子，却并没有因为阴冷天穿得少而患上关节炎"},{"label":"B","content":"现代医学研究表明导致关节炎的根本原因是劳损、感染或创伤，阴冷天穿得少关 节炎易发作"},{"label":"C","content":"张女士的姐姐和她生活在一个城市，多年来也喜欢在冬天穿裙子，但没得关节炎"},{"label":"D","content":"阴冷天穿得多的人群中也有很多得了关节炎，而且以中老年人居多"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":328,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400329,6,'逻辑判断','一户人家养了四只猫，其中一只猫偷吃了他家里的鱼。主人对它们进行审问，只有 一只猫说真话。这四只猫的回答如下： 甲：“乙是偷鱼贼。” 乙：“丙是偷鱼贼。” 丙：“甲或者乙是偷鱼贼。” 丁：“乙或者丙是偷鱼贼。” 根据以上陈述，请确定以下哪项陈述为假：','[{"label":"A","content":"甲不是偷鱼贼"},{"label":"B","content":"乙不是偷鱼贼"},{"label":"C","content":"丙说真话"},{"label":"D","content":"丁说假话"}]','A','。 ⑲花生批注： “A或B”的矛盾是“非 A或非B” 。','逻辑判断600题','进阶','published','{"globalNumber":329,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400330,6,'逻辑判断','人们常说，读书可以增长知识、陶冶性情。有专家指出，读书还可以治病，特别是 对于一些社会因素引起的心理疾病，如抑郁、压抑、恐慌、烦恼等，读书有很好的 疗效。 以下哪项如果为具，最能文持上还专豕的观点：','[{"label":"A","content":"读书能够促使患者转变思维方式，提高认知能力，重新认识世界和认识自己"},{"label":"B","content":"患者能够从阅读中有意无意获得情感上的认同和慰藉，释放内心的焦虑和不安"},{"label":"C","content":"汉代大学问家刘向十分重视读书的医疗作用，认为书犹药也，善读之可以医愚"},{"label":"D","content":"阅读能使大脑中产生一种神经肽，可以增强细胞免疫力，有益于人的身体健康"}]','B','【题型分类】支持类——补充论据 【实战解析】题干论点见批注，观察选项： A 选项、C 选项、D 选项，均为无关选项，分别指出“读书可以改变 思维方式和提高认知能力”、“读书可以医愚”、“读书有益身体健 康”,均未提及读书对于心理疾病的影响，均无法支持； B 选项，指出读书可以让患者释放焦虑和不安，从而治疗相应的心理 疾病，属于补充论据支持，当选； ②⑳花生批注： 结论：读书可以治病， 特别是对于一些社会 因素引起的心理疾病， 有很好的疗效。 ②花生批注： 论据：美利奴羊的卷 发，毛发外侧的细胞 长度比卷曲内侧的细 胞长很多； 论点：毛发卷曲的“秘 密”已经揭晓，新型 美发产品或许不久就 会问世。 花生批注： B 、C 、D 选项均未将 “羊”与“人”关联， 均无法断点搭桥。 3花生批注： 论据：老王尝试新疗 法后已生存5年； 结论：医生认为新疗 法有效果且应该推广。','逻辑判断600题','进阶','published','{"globalNumber":330,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400331,6,'逻辑判断','为了发现人类头发自然卷的原因，研究人员用六只自然卷的美利奴羊作为研究，他 们将其毛发样本的染色体片段放在显微镜下观察，研究发现：对于卷曲的头发，毛 发卷曲的毛发外侧的细胞长度比卷曲内侧的细胞长很多，因此有人认为：毛发卷曲 的“秘密”已经揭晓，新型美发产品或许不久就会问世。 下列各项如果为真，可以作为上述论证前提的是：','[{"label":"A","content":"人类的自然卷头发基因和美利奴羊的毛发基因近似"},{"label":"B","content":"新型美发产品可改变人类自然卷毛发的细胞增长速度"},{"label":"C","content":"人类发生卷曲的毛发外侧和内侧的细胞数量基本一样"},{"label":"D","content":"美发产品研究人员很快会将此实验的研究结果公诸于众"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":331,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400332,6,'逻辑判断','老王是胰腺癌晚期患者，医生曾告知他可能只能存活几个月。他在医生建议下，尝 试了一种免疫新疗法，现在已生存了5年。根据老王的情况，医生认为这种免疫新 疗法对治疗胰腺癌有效果，应该进行推广。 以下哪项如果为真，不能削弱医生的观点：','[{"label":"A","content":"这种免疫新疗法在临床中尚未得到大面积推广"},{"label":"B","content":"这种免疫新疗法所起到的效果与老王的个人体质有关"},{"label":"C","content":"即使只做手术和化疗，也会有2%左右的胰腺癌患者存活超过5年"},{"label":"D","content":"一种新的治疗方法是否可以推广应慎重决定，不能仅根据个案作出判断"}]','A','【题型分类】 一般质疑类——有论据有结论 【实战解析】论据结论见批注，可有理由的说明新疗法可能无效或不 一定适合推广来进行质疑； A 选项，指出新疗法还未大面积推广，但未大面积推广无法说明该疗 法无效②,无法质疑； B 选项，虽然老王已存活5年，但与老王个人体质有关，所以其他人 不一定有同样效果，该免疫新疗法可能无效，可以质疑； C 选项，虽然老王已存活5年，但即使不使用新疗法只使用老疗法也 有2%左右患者可存活5年，老王可能就是此2%,所以该免疫新疗法 可能无效果，可以质疑； D 选项，新疗法是否推广不能仅依靠个案且老王是个案，所以该方法 不一定适合推广，可以质疑； 综上，A 选项无法质疑医生观点。 ④花生批注： 任何一种新疗法都是 从“未大面积推广” 到“普遍接受使用”, 现在未大面积推广不 代表不应该推广，也 不代表该疗法无效果。','逻辑判断600题','进阶','published','{"globalNumber":332,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400333,6,'逻辑判断','随着人口老龄化程度加剧，慢性病患者和失能、半失能老人数量与日俱增。近年来 某市不少医院推出“互联网+护理”服务，老人们在家通过手机APP下单，医护人 员就可以上门提供服务。省去了老人们频繁跑医院的烦恼。但是，自该项服务推出 以来，“成交量”始终不温不火。不少医院表示，去年一年的接单量不足50单。可 见，该市老人对“互联网+护理”服务的需求并不高。 以下除哪项外，均能削弱上述结论：','[{"label":"A","content":"只有符合条件的护士才能从事这一服务，但其中有时间上门服务的护士数量有限"},{"label":"B","content":"医护人员上门服务的费用需要病人自理，医保不予报销，不少老人认为费用太高"},{"label":"C","content":"多数老人对手机操作不熟悉，不会通过手机APP下单预约医护人员上门提供服务"},{"label":"D","content":"不少老人还没有形成“花钱买服务”的消费观念，他们更愿意到医院排队、挂号"}]','D','【题型分类】归因类——一般他因 逻辑判断 6花生批注： 老人更愿意到医院排 队挂号，意味着不愿 意“不去医院就享受 服务”,即不愿意通 过“互联网+护理” 享受服务，可理解为 对此种服务需求不高。 7 花生批注： A 、B 、C选项都是客 观存在的困难，说明 可能有需求，但是没 办法使用“互联网+ 护理”; D 选项是老人主观意 愿，就是“不愿意”, 说明确实需求不高。 28花生批注： 题干通过对老年女性 行走步数和寿命之间 的实验得出结果，即 不管是零星散步还是 长时间行走，寿命都 会增长； 由此，将实验中老年 女性寿命长归因为走 路，并以严谨逻辑关 系的形式将结论表述 出来。 【实战解析】既成事实和原因分析见批注，分析选项： A 选项，指出能上门服务的护士数量有限，那么“成交量”低的原因 就可能是上门护士数量不足，不一定是需求不高，另有他因质疑； B 选项，指出上门服务医保不能报销，老人认为费用高，那么“成交量” 低的原因就可能是“不报销”,不一定是需求不高，另有他因质疑； C 选项，指出多数老人不会用此APP, 那么“成交量”低的原因就可 能是“老人不会用”,不一定是需求不高，另有他因质疑； D 选项，指出不少老人更愿意到医院排队挂号， 还未形成“用APP 花钱买服务”的理念⑨,意味着对“互联网+护理”服务的需求确实 不高，支持结论，不能质疑； 综上，不能质疑的只有D 选项，且A选项、B选项、C选项同质②。','逻辑判断600题','进阶','published','{"globalNumber":333,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400334,6,'逻辑判断','某研究将行走模式分为两类：一类是零星地短时间行走，另一类是不间断地行走10 分钟以上。该研究追踪了某国16732名66岁至78岁女性，4年随访期间有804名 女性去世。结果发现，不管是零星散步还是较长时间的不间断行走，步数更多的人 寿命更长；在约4500步之后，这种效应趋于稳定。研究者提出，只要开始走路，就 能降低老年女性死亡风险。 以下各项如果为真，哪项不能质疑研究者的结论：','[{"label":"A","content":"中青年女性的生活方式和老年女性有很大不同，每天行走步数与死亡率没有显著 关联"},{"label":"B","content":"正确的走路方式，才能使身体变得健壮，不当的走路方式和姿势，会危害身体健康"},{"label":"C","content":"在这个年龄段，每天能够自主行走达到一定步数，通常意味着有更好的整体健康 状况"},{"label":"D","content":"能够坚持走路的人，或者有更多的生活内容，或者有更好的健康意识 ，这两者均 有益健康 103"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":334,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400335,6,'逻辑判断','新冠肺炎疫情已成为一种全球性现象，它迅速席卷各个国家，是全世界共同面临的 重大问题。被波及的各国需要彼此汲取经验，其中包括关于病毒的性质、彻底消灭 或遏制病毒所必需的社会措施以及抗疫所需的医疗和防护设备等等。由此看来它会 让世界各国变得更加紧密。 以下哪项如果为真，最能质疑上述推断：','[{"label":"A","content":"东亚地区应对新冠肺炎疫情好于其他国家的原因之一是他们有应对“非典”时合 作的经验"},{"label":"B","content":"新冠肺炎疫情带来的威胁如此之大，引发了社会所有阶层的担忧和恐惧，大家开 始抱团取暖"},{"label":"C","content":"自从新冠肺炎疫情发生以来，中国就遭到少数西方媒体及政客恶意并令人惊讶的 无端攻击"},{"label":"D","content":"新冠肺炎疫情给国际文化、经济等方面交流带来了巨大冲击，短期内很难恢复到 疫情前水平"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":335,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400336,6,'逻辑判断','为什么一些灵长类动物的大脑尺寸比其它动物要大?原因通常被认为是社会行为， 即灵长类动物生活于更大更复杂的社会群体中，为了更好地处理各种社会关系，它 们需要更大的大脑。 以下哪项如果为真，不能质疑上述观点：','[{"label":"A","content":"通过灵长类动物的饮食特点而非社群复杂性，能够更容易预测大脑的大小"},{"label":"B","content":"猩猩等一些灵长类动物通常是独居生活，但它们的大脑也很大"},{"label":"C","content":"大脑皮层的大小与大脑尺寸没有直接关联，但对于灵长类动物的认知、空间推理 能力等非常重要"},{"label":"D","content":"灵长类动物中，食果类的大脑比食叶类大，这是因为果实在时间和空间上更分散， 找到果实是一项更为复杂的任务"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":336,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400337,6,'逻辑判断','对甲、乙、丙三人有如下判断： ①有人喜欢游泳； ②有人不喜欢游泳； ③甲喜欢游泳。 如果以上判断中只有一个为真，那么可以推出：','[{"label":"A","content":"乙喜欢游泳"},{"label":"B","content":"乙不喜欢游泳"},{"label":"C","content":"丙喜欢游泳"},{"label":"D","content":"甲不喜欢游泳，但乙喜欢游泳"}]','B','','逻辑判断600题','进阶','published','{"globalNumber":337,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400338,6,'逻辑判断','关于某单位行政部的12名员工，有如下三个判断： ①有人会熟练地操作电脑； ②有人不会熟练地操作电脑； ③新来的小刘不会熟练地操作电脑。 若这三个判断中只有一句为真，以下哪项也一定为真：','[{"label":"A","content":"12 名员工都会熟练地操作电脑"},{"label":"B","content":"12 名员工都不会熟练地操作电脑"},{"label":"C","content":"仅有一人会熟练地操作电脑"},{"label":"D","content":"仅有一人不会熟练地操作电脑"}]','A','。 259 ④花生批注： 前文可看作背景介绍， 题目只有结论：对没 有正确垃圾分类的市 民进行罚款，这样人 们为避免罚款就可能 会正确进行垃圾分类。 ④②花生批注： 前提假设类题目常见 三类选项：断点搭桥、 补充漏洞、能与不能 (即必要条件)。 ④③花生批注： 前提假设题目要选择 “没他不行”选项， 而非“有他更好(没 他也行)”选项。','逻辑判断600题','进阶','published','{"globalNumber":338,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400339,6,'逻辑判断','许多城市都实行了垃圾分类，但不少市民在丢垃圾时仍然没有正确地分类投放。有 专家建议对没有正确垃圾分类的人罚款，这样人们为避免罚款就可能会正确地分类 投放垃圾。 上述论证若成立，则必须补充的前提是：','[{"label":"A","content":"与正确进行垃圾分类相比，人们更加不愿意被罚款"},{"label":"B","content":"每一个没有正确进行垃圾分类的人都一定会被抓到并罚款"},{"label":"C","content":"罚款金额的大小不会影响到垃圾分类政策的效果"},{"label":"D","content":"对没正确垃圾分类的人罚款是改变其行为的唯一有效方法"}]','A','【题型分类】前提假设类——能与不能 【实战解析】 题干中没有明显断点和漏洞，优先考虑“能与不能(即 必要条件)”⑫,观察选项： A 选项，指出与正确进行垃圾分类相比，人们更加不愿意被罚款，即 在罚款和正确垃圾分类中，人们会选择正确垃圾分类，可看作必要条 件； 否定代入，如果与正确垃圾分类相比，人们更愿意罚款，即使出台罚 款政策，人们也不会进行正确垃圾分类，属于“没他不行”选项； B 选项，指出所有没有正确垃圾分类的人都一定会被抓到并罚款，属 于“有他更好 ”选项，即使这种行为有的没被发现，这种罚款政策 也会起到威慑作用，人们依然可能为避免被罚款而选择正确垃圾分类， 并非前提假设类题目正确选项； C 选项，罚款金额大小会不会影响政策效果和人们如何选择无关，无 关项； D 选项，即使罚款不是改变市民行为的唯一有效方法，罚款也可能会 使更多市民正确进行垃圾分类，属于“没他也行”选项； 综上，只有A 选项是结论成立的前提。','逻辑判断600题','进阶','published','{"globalNumber":339,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400340,6,'逻辑判断','小雨期末考试前，妈妈对她说：“如果这次考试进入全班前三名。我就奖励你一台 iPad 或者带你去香港旅游。” 以下哪项如果为真，说明妈妈没有兑现承诺：','[{"label":"A","content":"小雨进入全班前三名，妈妈没有带她去香港旅游，但奖励了她一部 iPhone"},{"label":"B","content":"小雨进入全班前三名，妈妈奖励她一台iPad 并送了一双回力板鞋"},{"label":"C","content":"小雨没有进入全班前三名，妈妈没有带她去香港旅游，但送了他一台iPad"},{"label":"D","content":"小雨没有进入全班前三名，妈妈没有送她 iPad, 也没有带她去香港旅行 练习题18"}]','A','。 ④花生批注： A 选 项 的 “ 奖 励 iPhone” 可理解为“没 有奖励iPad”, 同时没 有去香港旅游。 261 练习题 18 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 论据：葡萄酒中的白 藜芦醇对心脏有益、 能防止骨质疏松和肌 肉萎缩； 结论：宇航员可补充 白藜芦醇。 ②花生批注： A 、C 、D 无关选项： 未提及宇航员或失重 环境，没有建立宇航 员与骨骼、肌肉之间 的联系，不能支持。 此类题目“以我为主”, 寻找想要答案，不要 被错误选项干扰。 ③花生批注： 失重状态 服用白藜芦醇 小鼠 健康 对照组 小鼠 骨头肌肉 密度下降','逻辑判断600题','进阶','published','{"globalNumber":340,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400341,6,'逻辑判断','葡萄酒中含有白藜芦醇和类黄酮等对心脏有益的抗氧化剂。一项新研究表明，白藜 芦醇能防止骨质疏松和肌肉萎缩。由此，有关研究人员推断，那些长时间在国际空 间站或者宇宙飞船上的宇航员或许可以补充一下白藜芦醇。 以下哪项如果为真，最能支持上述研究人员的推断：','[{"label":"A","content":"研究人员发现由于残疾或者其他因素而很少活动的人会比经常活动的人更容易出 现骨质疏松和肌肉萎缩等症状，如果能喝点葡萄酒，则可以获益"},{"label":"B","content":"研究人员模拟失重状态，对老鼠进行试验，一个对照组未接受任何特殊处理，另 一组则每天服用白藜芦醇。结果对照组的老鼠骨头和肌肉的密度都降低了，而服 用白藜芦醇的一组则没有出现这些症状"},{"label":"C","content":"研究人员发现由于残疾或者其他因素而很少活动的人，如果每天服用一定量的白 藜芦醇，则可以改善骨质疏松和肌肉萎缩等症状"},{"label":"D","content":"研究人员发现，葡萄酒能对抗失重所造成的负面影响"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":341,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400342,6,'逻辑判断','研究人员招募了33名年龄在50-65岁之间的糖尿病前期患者。这些患者超重，并且 随着年龄增长，记忆力下降。在12周的时间里，除了每天早餐或晚餐食用一包可与 水混合的补充粉剂之外，参与者被要求禁食任何种类的浆果类水果。其中一半的参 与者接受了相当于半杯完整蓝莓的粉末，而另一半则接受了安慰剂。研究人员测试 了参与者某些认知能力的下降水平，如工作记忆、心理灵活性和自我控制等执行功 能后发现，蓝莓治疗组的患者此方面表现有明显改善。因此研究人员认为，在某些 中年人群的日常饮食中添加蓝莓或会降低患老年痴呆症的几率。 下列选项如果为真，最能加强上述结论的是：','[{"label":"A","content":"蓝莓含有高水平的抗氧化剂花青素，有助于增强细胞内的能量产生"},{"label":"B","content":"增强记忆力可以促进大脑细胞发育，有效降低老年痴呆的发生几率"},{"label":"C","content":"蓝莓因其丰富的营养价值被联合国粮农组织列为人类五大健康食品之一"},{"label":"D","content":"本次研究还发现蓝莓治疗组的患者空腹胰岛素水平相对安慰剂治疗组较低⑤"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":342,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400343,6,'逻辑判断','主流观点认为，气候变化是人类双足行走的主要驱动力。几百万年前，非洲森林的 面积开始缩减，草原面积大量增长。在树木很少的环境中，双足行走的意义很明显： 站起来，能让人类祖先的视线越过生长丰茂的草，看到捕食者和猎物。因此，草原 面积大量增长使得最善于站立的祖先更有可能存活，他们的基因得以传承下来。 以下哪项如果为真，最能削弱上述论证：','[{"label":"A","content":"人类祖先从四腿行走到双足行走的过程中，多处身体结构发生了转变"},{"label":"B","content":"在发现早期双足行走人类化石的区域，还发现了大量同时代的森林动植物化石"},{"label":"C","content":"新生儿表现出一些人类祖先曾经在树上居住的迹象"},{"label":"D","content":"早期人类的膝关节与现代人类的膝关节惊人的相似"}]','B','⑥花生批注： 归因类常见错误选项： “有些”、实验瑕疵、 非原因类选项。【题型分类】归因类——一般归因类 归因类常见错误选项： “有些”、实验瑕疵、 非原因类选项。 【实战解析】题干将人类双足行走的原因归于草原，分析选项： A 选项、C 选项、D 选项，均未谈及人类双足行走的原因⑥,无法质疑； B 选项，人类开始双足行走区域发现大量同时代森林动植物化石，说 明当时所处环境可能依然为森林，此时环境还未是草原，即人类双足 行走的原因不一定是草原，属于否定此因质疑，当选。','逻辑判断600题','进阶','published','{"globalNumber":343,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400344,6,'逻辑判断','科学家选择了两块“受伤的雨林”——原生雨林被砍光，在失去土壤韧性后又被用 来放牧，最终长满了一种被称为“栅栏草”的入侵植物，原生雨林没有机会喘息与 再生。研究人员将其中一块地均匀覆盖上近半米的咖啡果肉，另一块土地则什么也 不做，任其自然。两年之后，两块地发生了迥然不同的剧变：被咖啡果肉覆盖的那块， “栅栏草”已经完全消失，取而代之的是本应属于这里的热带树种的年轻树冠；而 另一块地则依然被“栅栏草”霸占着。由此可见，咖啡果肉有助于热带雨林的生态恢复。 以下各项如果为真，除哪项外均能支持以上结论：','[{"label":"A","content":"覆盖咖啡果肉是一次“集中施肥”的过程，能够使土地更有韧性，生产恢复能力 更佳"},{"label":"B","content":"咖啡果肉是制作咖啡豆后的废料，其味道会吸引食草型动物前来觅食，改变周边 的环境"},{"label":"C","content":"咖啡果肉中富含碳、氮、磷等植物生长所需要的营养成分，能够为雨林修复按下 “加速键”"},{"label":"D","content":"半米高的咖啡果肉会形成密不透风的“隔绝”层，在重压之下“栅栏草”被抑制 生长，窒息死亡"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":344,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400345,6,'逻辑判断','学校通知：从我校当年省级大创项目中评选出10%的项目，推荐申报本年度国家级 大创项目。小张的大创项目是我校当年优秀的省级大创项目，所以小张的项目可能 推荐申报国家级大创项目。 下列哪项如果为真，最能加强上述论证：','[{"label":"A","content":"该校省级大创项目的优秀率只有10%"},{"label":"B","content":"只有国家级大创项目，才是优秀省级大创项目"},{"label":"C","content":"想要成为国家级大创项目， 一定要是省级大创项目"},{"label":"D","content":"除非是省级大创项目，否则就不是一个国家级大创项目"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":345,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400346,6,'逻辑判断','经过一年各项网球公开赛的比拼，甲乙丙丁四名男单选手来争夺最后的积分排名， 相关专家预测： (1)第一名或者是甲，或者是乙； (2)如果丙不是第一名，丁也不是第一名； (3)甲不是第一名。 赛后发现，专家的预测中，只有一句是对的。则第一名是：','[{"label":"A","content":"甲"},{"label":"B","content":"乙"},{"label":"C","content":"丙"},{"label":"D","content":"丁"}]','D','⑫花生批注：②因“后件为真”,命题为真。【题型分类】分析类——真假分析 ⑫花生批注： ②因“后件为真”, 命题为真。 【实战解析】三句话中没有矛盾，可使用假设法： 假设甲或乙是第一名，即丁不是第一名，此时①②②均为真，不符合“只 有一真”要求； ⑬花生批注：丙不是第一名，丁是 第一名，即A且非B. 则A→B为假。假设丙是第一名，即甲、丁都不是第一名，此时②③均为真，不符合“只 有一真”要求； ⑬花生批注： 丙不是第一名，丁是 第一名，即A且非B. 则A→B为假。 假设丁是第一名，则①假、②假⑬、③真，符合题目要求，D 选项正确。','逻辑判断600题','进阶','published','{"globalNumber":346,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400347,6,'逻辑判断','研究人员发现，摄入高盐饮食的小鼠对抗由大肠杆菌引起的肾脏感染和由李斯特细 菌引发的全身感染的能力较弱。随后，他们在正常饮食基础上，每天给10名20至 50岁的健康男女额外增加6克盐。 一周后，与服用额外食盐之前相比，这些人体内 一些免疫细胞(中性粒细胞)吞噬和杀死细菌的能力大大受损。研究人员得出结论， 高盐饮食可能损害人体抵抗细菌感染的能力。 以下哪项不能支持上述结论：','[{"label":"A","content":"当人体内盐含量高时，尿素会积聚在肾脏内，而尿素会抑制中性粒细胞"},{"label":"B","content":"对50岁以上有基础疾病的男女进行相同的研究发现，男性因高盐饮食造成的疾 病负担高于女性"},{"label":"C","content":"摄入过量盐分时，身体会释放激素，使人体排泄更多盐。这些激素包括皮质激素， 具有抑制全身免疫系统的副作用"},{"label":"D","content":"对20岁以下健康男女进行相同的研究发现，这些人体内的部分免疫细胞吞噬和 杀死细菌的能力受损程度高于高年龄段人群"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":347,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400348,6,'逻辑判断','近日，有动物实验研究发现，在正常饮食中加入一定剂量的苦瓜水提取物，可降低 Ⅱ型糖尿病小鼠的高血糖。这是由于苦瓜中含有一种类似胰岛素的物质，能够降低 血糖。有人据此认为，Ⅱ型糖尿病患者多吃苦瓜有助于降低血糖水平。 以下哪项如果为真，最能质疑上述论证：','[{"label":"A","content":"苦瓜含糖量低，对血糖的影响小"},{"label":"B","content":"日常食用的苦瓜中，苦瓜水提取物含量极少"},{"label":"C","content":"苦瓜水提取物可能会导致血清总蛋白轻微降低"},{"label":"D","content":"苦瓜水提取物对I 型糖尿病小鼠的血糖无显著影响"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":348,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400349,6,'逻辑判断','小葵根据某美食点评app 的高分榜推荐，光顾了三家，其菜肴都非常美味，小葵认为， 下次和朋友聚餐也可以选择该app 的上榜餐厅，其菜品一定不会让人失望。 下列选项如果为真，不能削弱上述论断的是：','[{"label":"A","content":"该app中的餐厅得分是根据餐厅环境，用餐服务和菜肴口味三个方面综合评价得出"},{"label":"B","content":"和朋友聚会通常会选择位于热闹商圈的餐厅"},{"label":"C","content":"该app 中有相当数量的餐厅为了排名靠前，存在刷好评、刷高分的现象"},{"label":"D","content":"小葵光顾过的三家上榜餐厅恰好是她喜爱的广西菜餐厅"}]','B','【题型分类】 一般质疑类 【实战解析】本题论据结论见批注，有理由的得出“菜品可能让人失望” 即可质疑； A 选项，虽然这三家店铺菜品美味，但评分还包含餐厅环境和用餐服 务，所以其他店铺可能因这两项获得高分，其菜品可能让人失望，可 以质疑； B 选项，讨论的是选择何商圈的餐厅，未提及菜品是否让人失望，无 关项； C 选项，虽然这三家店铺菜品美味，但有店铺存在刷好评现象，所以 其他店铺可能因刷好评获得高分，其菜品可能让人失望，可以质疑； D 选项，虽然这三家店铺菜品美味，但可能是正对其口味(爱吃广西 菜),所以其他店铺菜品可能因不对其口味让人失望，可以质疑； 综上，不能质疑的是B 选项。 ⑯花生批注： “极少”就是告诉我 们，可能需要吃特大 量的苦瓜才可能会有 作用，但是这个特大 量可能或超过人体可 食用量的范围，所以 不一定能达到降血糖 的作用。 ⑰花生批注： 论据：已光顾的三家 app高分店铺菜肴都非 常美味； 结论：所有app高分店 铺菜品都不会让人失 望。 ⑱花生批注： 若受害者是敢，四人 均为真话。 从最大信息入手，诚 不是旁观者、目击者、 受害者，只能是救助 者； 而义不是目击者、受 害者，则义只能是旁 观者；孝只能是目击 者，此时③为真，符 合题目要求。 ⑲花生批注： 三段论一般由一个“所 有”和两个“有些”或“特 例”组成。 2花生批注： 三段论三个概念应分 别出现两次，例如此 题的“司法人员”、“法 律专业”、“审判工作” 均要出现两次。','逻辑判断600题','进阶','published','{"globalNumber":349,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400350,6,'逻辑判断','在一起事件中的四名被调查者分别是受害者、目击者、救助者和旁观者。他们在接 受调查时分别作了如下陈述：①孝：诚不是旁观者。②诚：义不是目击者。③敢： 孝不是救助者。④义：诚不是目击者。进一步调查得知：他们四人的陈述如果是关 于受害者的就是假的，如果是对其他人的就是真的。 由此可见，受害者是：','[{"label":"A","content":"孝"},{"label":"B","content":"诚"},{"label":"C","content":"敢"},{"label":"D","content":"义"}]','C','【题型分类】分析类——真假分析 【实战解析】分析可知，由题干信息直接推理四人身份较为困难，因 此可采用代入法，依次代入选项： A 选项，若受害者是孝，则③为假(孝是救助者),和假设不符，假 设错误； B 选项，若受害者是诚，则①③为假(诚是旁观者和目击者),和假 设不符，假设错误； C 选项，若受害者是敢，则四人均为真话， 先保留； D 选项，若受害者是义，则②为假(义是目击者),和假设不符，假 设错误； 综上，答案只能是C 选项。','逻辑判断600题','进阶','published','{"globalNumber":350,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400351,6,'逻辑判断','某些司法人员是法律专业的，因此某些法律专业的人做审判工作。 若要上述成立，则要补充以下哪项作为前提：','[{"label":"A","content":"所有司法人员都做审判工作"},{"label":"B","content":"某些司法人员不是做审判工作的"},{"label":"C","content":"某些法律专业的人不是审判员"},{"label":"D","content":"所有法律专业的人都是审判员"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":351,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400352,6,'逻辑判断','一份研究报告称，上世纪八九十年代，某国北方因燃煤取暖导致的空气污染使人均 寿命减少5.5年。该研究以取暖分界线为准，选取了该线以北和以南共90座城市， 收集了1981年到2000年间这些城市每日的总悬浮颗粒物浓度数据，以及1991年到 2000年间这些城市各年龄段死亡率、预期寿命和死于心肺疾病的数据。研究结果显 示，取暖线以北的总悬浮颗粒物比以南地区跳跃性地高出了200微克/立方米，相 应地，人均寿命也发生了变化，北方比南方减少了5.5年。 以下除哪项外，均能削弱上述结论：','[{"label":"A","content":"空气污染只是影响人类寿命的多种因素之一"},{"label":"B","content":"由于工业燃煤用量大，南方燃煤总量比北方大体相当"},{"label":"C","content":"并非所有的总悬浮颗粒物都是由燃煤导致的"},{"label":"D","content":"近年来随着生活水平提高，该国取暖分界线逐渐南移"}]','D','。 25花生批注： 可以理解为上半年较 其他公司发展趋缓的 原因在于本公司一般 是下半年效益好。','逻辑判断600题','进阶','published','{"globalNumber":352,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400353,6,'逻辑判断','在国家发展新兴产业的大背景下，某公司虽然在某产业长期处于领先地位，但上半 年的生产数据显示，领先优势越来越小，在邀请专家进行企业诊断后，专家认为该 公司领先优势缩小的原因在于公司虽然管理制度健全，但由于企业文化缺乏进取心， 导致在好的政策环境下公司发展趋缓。 以下哪项如果为真，不能反驳专家的观点：','[{"label":"A","content":"相较沿海地区同类公司受益于健全的产业链，公司处于内地，其发展有所受限"},{"label":"B","content":"发展趋缓的原因在于长期以来公司下半年的生产数据一般高于上半年"},{"label":"C","content":"公司一直注重加强企业文化建设，形成了和谐的企业氛围"},{"label":"D","content":"企业文化并不是一个公司的核心竞争力，关键问题在于新产品研发力度不够"}]','C','。 四海公考 逻辑判断','逻辑判断600题','进阶','published','{"globalNumber":353,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400354,6,'逻辑判断','世界这么大，为什么唯有澳大利亚拥有种类如此繁多的有袋类动物?人们不禁推测： 有袋类动物是在澳大利亚独立演化出来的。从地理上看，澳大利亚是一个与外界不 相连的孤岛，因此这类动物在演化出来后很难向外界扩散。然而事实上，人们发现 的最古老的有袋类动物化石是1.1亿年前生活在北美洲的三角齿兽化石。专家据此 推断，有袋类动物很可能起源于北美洲，之后才迁移至澳大利亚。 以下哪项如果为真，最可能是专家推断的前提：','[{"label":"A","content":"现今除了澳大利亚，南美洲草原也生活着一些有袋类动物"},{"label":"B","content":"北美洲的气候环境适宜，天敌少，更适合有袋类动物生存"},{"label":"C","content":"如此早期的三角齿兽化石目前还未在除了北美洲以外的地方发现"},{"label":"D","content":"1.1 亿年前地球上的各大洲连在一起，有袋类动物可利用陆桥穿行"}]','D','【题型分类】前提假设类——必要条件(能与不能) 【实战解析】论据结论见批注，未发现明显断点和漏洞，依次观察选项： A 选项、B 选项均未谈及澳大利亚有袋动物起源问题，排除； C 选项，“如此早期的化石还未在北美以外地区发现②”和“最古老 的此类化石发现在北美洲”意思相近，重复题干论据，有一定支持， 但并非是前提假设类需要选项； D 选项，指出1.1亿年前地球各大洲连在一起，有袋动物可以穿行， 可看作“能与不能(即必要条件)”类⑧选项，若有袋动物不可穿行， 那么溴大利亚有袋动物就不会从北美洲迁移而来，属于“没他不行” 选项，当选。','逻辑判断600题','进阶','published','{"globalNumber":354,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400355,6,'逻辑判断','有调查显示，那些作息时间不同的夫妻，虽然每天相处的时间较少，但他们发生争 吵的次数比作息时间基本相同的夫妻更多。因此，为了建立良好的夫妻关系，夫妻 之间应当尽量有相同的作息时间。 最能削弱上述论点的一项是：','[{"label":"A","content":"夫妻产生矛盾后，往往以作息时间不同来表现不满"},{"label":"B","content":"具有同事关系的夫妻更容易在工作上产生矛盾"},{"label":"C","content":"作息时间不同的夫妻更容易产生矛盾"},{"label":"D","content":"生活习惯不同是夫妻产生矛盾的主要原因"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":355,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400356,6,'逻辑判断','考古学家对安第斯地区出土的900年到2800年前的人类骨骼进行了研究。从中提取 出的某些化学同位素成分，反映出那里的人当时多以玉米为食。“玉米文化”带动 了安第斯地区的人口增长，当时爆发的几次大规模战争也与争夺稀缺的适种玉米的 土壤有关，战争导致了社会体系不断变革和发展。因此他们得出结论“农业推动了 古代安第斯社会的发展”。 以下哪项如果为真，最能质疑上述结论：','[{"label":"A","content":"安第斯地区的印加文明早在2800年前就经历了几次较大的社会变革"},{"label":"B","content":"安第斯地区3600年前的人类以沿海打渔为主，直到2800年前左右才逐渐向内陆 迁徙"},{"label":"C","content":"从人类骨骼中提取的另一些化学同位素反映了人们当时也食用马铃薯和豆类"},{"label":"D","content":"安第斯地区的社会体系拥有中央政府和地方政府，后又衍生出多种社会形态"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":356,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400357,6,'逻辑判断','某县计划引进一种生长快、肉质好的良种牛，在本县推广养殖，以提高农民养牛的 经济收益。 以下最能对该计划可行性提出质疑的是：','[{"label":"A","content":"该良种牛不适应当地气候"},{"label":"B","content":"当地农民养牛的积极性不高"},{"label":"C","content":"该良种牛的养殖成本较高"},{"label":"D","content":"当地农民没有饲养过该良种牛"}]','A','【题型分类】 一般质疑类——有论据有结论 【实战解析】论据结论见批注，分析选项： A 选项，虽然该种牛生长快肉质好，但是该良种牛不适合当地气候(养 殖不了),所以不适合在本县推广养殖，可以质疑； 35花生批注：若改成“该良种牛养 殖成本高于养殖收 益 ”, 就是强烈质疑， 但说成本，不说利润， 无法质疑。C 选项，强干扰项，成本高不意味着“不赚钱”,从利润角度考虑， 成本高，可能带来的经济利润更高，如果是这样，依然可以推广养殖⑤, 质疑较弱； 35花生批注： 若改成“该良种牛养 殖成本高于养殖收 益 ”, 就是强烈质疑， 但说成本，不说利润， 无法质疑。 B 选项、D 选项，分别从“农民养牛积极性”、“养殖经验”角度提 出此计划实施的困难，但肯定可以通过一些措施解决，若养牛是赚钱 的，该计划是可以推广的； 综上，只有在A 选项成立时，该计划是完全不可行的，所以A 选项正确。 36花生批注： 四人说的话整理为： 小天：是明明； 小月：是小天； 萍萍：不是萍萍； 明明：不是明明。 ③花生批注： 本题也可以采用选项 代入法，依次代入选 项，验证是否符合“两 人说真话，两人说假 话”这个条件，进而 确定正确选项。 38花生批注： 两真两假题目常用方 法：找矛盾，用假设 法判断剩余二人。','逻辑判断600题','进阶','published','{"globalNumber":357,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400358,6,'逻辑判断','某校区的自行车经常失窃，某一次门卫赵某抓获了四名嫌疑人，经询问： 小天说：“是明明偷了自行车。” 小月说：“是小天偷了自行车。” 萍萍说：“我没有偷自行车。” 明明说：“我也没有偷自行车。” 经调查，是其中两人偷了自行车，并且有两人说了真话，有两人说了假话，则可能 为真的选项是：','[{"label":"A","content":"小天和萍萍偷了自行车"},{"label":"B","content":"萍萍和明明偷了自行车"},{"label":"C","content":"小天和明明偷了自行车"},{"label":"D","content":"小天和小月偷了自行车"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":358,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400359,6,'逻辑判断','某中学的教师都很有爱心。有些经常志愿献血的教师免费为学习困难的学生补课， 凡是资助了贫困生的教师都和困难家庭结成了帮困对子，但所有免费为学习困难的 学生补课的教师都没有人和困难家庭结成帮困对子。 根据以上前提，下列哪项一定为真：','[{"label":"A","content":"有些经常志愿献血的教师没有资助贫困生"},{"label":"B","content":"有些资助了贫困生的教师没有志愿献血"},{"label":"C","content":"有些资助了贫困生的教师经常献血"},{"label":"D","content":"有些经常志愿献血的教师跟困难家庭结成了帮困对子"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":359,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400360,6,'逻辑判断','现如今，气候也正影响着“海洋居民”的生存环境，不要让更多的生物黯然离场， 人类的警醒和努力或许能为它们的生存带去希望。 以下哪项如果为真，最能支持上述观点：','[{"label":"A","content":"人类可以凭借技术保护海洋生物"},{"label":"B","content":"人类的警醒和努力可以改善气候环境"},{"label":"C","content":"只有人类与海洋和平共处，才能避免遭遇史前海怪一样的命运"},{"label":"D","content":"尽管人类有自命不凡的智慧，但是在重大灾难面前，一样是渺小的 练习题19"}]','B','。 39花生批注： 如图所示，左侧资助 贫困生教师圈内未写 出“献血”相关信息， 推不出“有些”。 ④花生批注： 论据：气候威胁海洋 生物生存； 结论：人类能帮助海 洋生物。 ④花生批注： A 选项虽可支持，但未 贴合论据“气候问题”, 不如B选项恰当。 ④②花生批注： A、C 、D无关选项： 未提及气候，没有建 立气候与人类的警醒 和努力之间的联系， 无法消除断点，非此 类问题的正确选项。 练习题 19 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 论据：神话叙述的是 先民心灵的期许和精 神追求，但不是历史 事实。 结论：史书或者考古 并不能证伪神话。 ②花生批注： A、B、C选项均没有 为“不是历史事件” 和“不能证伪”建立 联系，因此无法支持。 ③花生批注： 此句有“只有才”逻 辑关联词，可理解为 “只有与历史事实有 关的叙述，史书或者 考古才能证伪”,可 翻译为“非历史事实， 史书或者考古不能证 伪”。','逻辑判断600题','进阶','published','{"globalNumber":360,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400361,6,'逻辑判断','神话是远古时代人民的集体口头创作，它包括神的故事和神化英雄传说，它表现了 古代人民对自然力的斗争和对理想的追求，表达的是先民对超能力的崇拜和对美好 生活的向往。它叙述的是先民心灵的期许和精神追求，但不是历史事实，因此，史 书或者考古并不能证伪它。 以下哪项如果为真，最能支持以上论述：','[{"label":"A","content":"神话未必被史书所记载或者留下史迹"},{"label":"B","content":"任何文学作品都要反映人民的精神追求"},{"label":"C","content":"史书并不叙述先民心灵的期许和精神追求"},{"label":"D","content":"史书或者考古只能证伪与历史事实有关的叙述"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":361,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400362,6,'逻辑判断','书画展的主办方决定，除非是来自美术学院的应届毕业生，否则不能取得本次大学 生书画展览的资格。 以下哪项，如果为真，说明主办方上述决定没有得到贯彻： I. 李丽是来自美术学院的应届毕业生，没有取得展览资格 Ⅱ. 黄雷是来自人文学院的大三学生，取得了展览资格 Ⅲ.刘婷不是美术学院的学生，取得了展览资格','[{"label":"A","content":"仅 I 和Ⅱ"},{"label":"B","content":"仅 I 和Ⅲ"},{"label":"C","content":"仅Ⅱ和Ⅲ"},{"label":"D","content":"I 、Ⅱ 、Ⅲ"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":362,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400363,6,'逻辑判断','如果停电了，冰箱就不能正常使用，甲家中的冰箱不能正常使用，因此，甲家中一 定停电了。 下列选项推理逻辑与题干的最为类似的是：','[{"label":"A","content":"只有经常锻炼才能身体健康，小华身体健康，所 以 ，小华经常锻炼"},{"label":"B","content":"除非有新来的员工，否则我们公司的员工都是未婚的，小李已婚，所以，他是新 来的员工"},{"label":"C","content":"如果小明努力学习，就能当上学习委员，小明没有努力学习，所以，小明没有当 上学习委员"},{"label":"D","content":"如果劳动节放假，小张一定会回家，小张劳动节回家了，因此，一定是劳动节放 假了"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":363,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400364,6,'逻辑判断','除法定节假日外，小明一周工作五天。周五他在志愿者协会工作，其余四天都在律 师事务所上班。上周没有法定节假日，因此，上周周一、周二、周三和周四小明一 定在律师事务所上班。 上述结论成立的前提是：','[{"label":"A","content":"小明上上周是周一到周四在律师事务所上班"},{"label":"B","content":"律师事务所实行每周四天工作日制度"},{"label":"C","content":"上周周六、周日小明没有上班"},{"label":"D","content":"律师事务所不允许员工请假"}]','C','【题型分类】前提假设——补充漏洞 【实战解析】论据结论见批注； 分析题干：除去周五，上周还剩六天；若想断定小明是周一至周四在 律所上班，需要补充漏洞，即剩余的周六周日不上班⑦。逻辑关系如下： 小明周五在志愿者协会工作，这一周有四天在律所上班，周六周日不 上班，则周一至周四在律所工作； 综上，答 案 为 C 选 项⑧。','逻辑判断600题','进阶','published','{"globalNumber":364,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400365,6,'逻辑判断','医学界早就知道，碳酸锂既具有抑制多种病毒(有些与新冠病毒相似)的能力；又 能增加淋巴细胞水平以预防和减少炎症活动；炎症活动是导致新冠肺炎的主要原因。 一项临床试验因此招募30名新冠肺炎住院患者，随机分配其中15名 (A 组)接受 常规治疗，另外15名( B组 )接受碳酸锂治疗。试验结论是：碳酸锂治疗对新冠肺 炎住院患者安全且有效。 以下各项如果为真，能支持试验结论的是： ①该试验证明，碳酸锂治疗对15名患者都没有副作用 ②该试验取得了令人鼓舞的结果，得到国际科学界肯定 ③与A组 比 ，B 组患者淋巴细胞防御水平增强，致炎症活动的炎性细胞因子水平降低 ④与A组比，B组患者新冠持续性症状减轻得更快，住院天数及死亡风险更明显减少','[{"label":"A","content":"①③"},{"label":"B","content":"②④"},{"label":"C","content":"①③④"},{"label":"D","content":"①②③④"}]','C','，①③④。 逻辑判断 ⑫花生批注： 题干将地球转速放缓 时期强震多发的原因 归于地球转速放缓。 ⑬花生批注： 论据：海水中的钠离 子会阻止肥皂中的钠 离子在水中充分溶解。 结论：在海水中，肥 皂不起清洁作用。','逻辑判断600题','进阶','published','{"globalNumber":365,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400366,6,'逻辑判断','研究人员发现，在过去的一个半世纪中，出现过几次地球转速放缓时期，这种时期 每次会持续5年左右，更为关键的是，地球转速放缓的同时伴随着强震增多。研究 人员据此得出结论：地球转速放缓导致强震多发。 以下哪项如果为真，最能质疑上述结论：','[{"label":"A","content":"在地球转速放缓时期，每年约发生25～30次强震，在其他时期，约为15次"},{"label":"B","content":"在地球转速放缓时期，发生火山喷发的次数与其他时期相比没有明显变化"},{"label":"C","content":"地球转速放缓，会使昼夜长短发生变化，昼夜长短变化导致全球强震多发"},{"label":"D","content":"地核的轻微变化，导致地球的转速放缓，也导致全球范围内的强震多发"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":366,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400367,6,'逻辑判断','肥皂是脂肪酸金属盐的总称，金属主要是钠或钾等碱金属。海水中的钠和肥皂中的 钠原子实际上都是以离子的形式存在的，由于离子间的平衡，海水中的钠离子会阻 止肥皂中的钠离子在水中充分溶解。因此，在海水中，肥皂不起清洁作用。 以下哪项最适合作为上述论证的前提：','[{"label":"A","content":"肥皂中的钠要先溶解才能发挥清洁作用"},{"label":"B","content":"海水中的钠离子可以从海水中分离出来"},{"label":"C","content":"肥皂要与水共同使用才能发挥清洁作用"},{"label":"D","content":"肥皂分子结构中的钠离子是不溶于水的"}]','A','【题型分类】前提假设——断点搭桥⑧ 【实战解析】论据和结论见批注。“无法充分溶解”和“不起清洁作用” 之间明显存在断点，需要搭桥，A 选项为二者建立了联系，可直接秒选， 其逻辑关系如下： 肥皂只有在钠溶解时才能发挥清洁作用⑥,在海水中肥皂的钠离子无 法充分溶解，所以肥皂在海水中不起清洁作用；。','逻辑判断600题','进阶','published','{"globalNumber":367,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400368,6,'逻辑判断','一项研究选取80名13岁到25岁出现精神分裂症早期症状的年轻人作为被试对象， 随机选取其中的一半人服用鱼油片剂3个月，另一半人都用安慰剂3个月。研究人 员对受试者跟踪考察7年后发现，在服用鱼油片剂组中，只有10%的人罹患精神分 裂症；而在服用安慰剂组中，罹患这种疾病的人则高达40%。由此，研究人员得出结论： 服用鱼油片剂有助于青少年预防精神分裂症。 以下各项如果为真，则除了哪项均能质疑上述研究人员的结论：','[{"label":"A","content":"被试对象的数量仍然偏少，且每个被试者在7年中的发展差异较大"},{"label":"B","content":"被试对象的年龄跨度较大，实验开始时有人可能已是青年而非少年"},{"label":"C","content":"鱼油片剂曾被尝试治疗成年精神分裂症患者，但实验发现没有效果"},{"label":"D","content":"被试对象服用鱼油片剂的时间较短，不足以形成稳定、明显的疗效"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":368,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400369,6,'逻辑判断','小张、小李、小薛三名研究生在选择导师时有如下标准： 小张：只要他是正教授，我就报考他的研究生 小李：只有正教授才可以当我的研究生导师 小薛：只要他有真才实学，我就报考他的研究生 如果有一位有真才实学的副教授正招收研究生，不可能做他学生的是：','[{"label":"A","content":"小张"},{"label":"B","content":"小李"},{"label":"C","content":"小薛"},{"label":"D","content":"小张和小李 逻辑判断"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":369,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400370,6,'逻辑判断','近来，有科学家研究了历史上气候变化对人类社会的影响。他们发现，全球超过 80%的国家及地区在气候寒冷时期爆发的战争次数是温暖时期的两倍；在中国过去 的1000多年里，战争、大范围动乱和朝代更替大都对应着特别漫长的寒冷时期；欧 洲1550年到1850年的“小冰期”与欧洲历史上发生过的猎巫事件甚至法国大革命 之间都存在紧密的联系。由此，他们得出结论：气候变冷会导致社会冲突和朝代更 替的发生。 以下哪项如果为真，最能质疑上述科学家的观点：','[{"label":"A","content":"气候变化总在发生，社会冲突、朝代更替也总在发生，共同发生变化的东西不一 定存在因果联系"},{"label":"B","content":"气候变暖是引发人类冲突与战争的重要原因，例如，在1981年到2002年间的温 度升高期间，撒哈拉以南非洲国家内战的次数比平时有所增加"},{"label":"C","content":"2003 年，由于印度洋升温影响季风活动，导致苏丹达尔富尔地区降水大幅度下降， 引发粮食和水资源严重短缺，继而引发武装冲突"},{"label":"D","content":"气候变冷比气候变暖更可怕，气候变冷意味着农作物收成下降，粮食、能源供应 紧张，人们的日常生活受到更为严重的影响"}]','A','。 ⑲花生批注： 通过举例论证(在中 国、欧洲发生的社会 重要事件均与气候变 冷存在紧密联系)将 “社会冲突和朝代更 替的发生”的原因归 于“气候变冷”。 20花生批注： 历史上，气候变冷和 战争频发总是同时发 生，题干因此认为二 者间有因果关系，A选 项指出，同时发生不 一定有因果关系，直 接质疑； 但此种质疑方式较少 见，一般来说，对比 实验归因均是因统计 学上的相关性猜测因 果关系，此选项也可 放在其他对比实验归 因题中。 285 ②花生批注： “特例”可以推出“有 些”。 2花生批注： “有些不”和“所有” 矛盾。 3花生批注： 论据：折纸测试中， 听莫扎特音乐的学生 有明显进步； 结论：听古典音乐有 助于提高儿童智商。','逻辑判断600题','进阶','published','{"globalNumber":370,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400371,6,'逻辑判断','河南大学艺术专业有42名同学，关于这些同学，小张小李小赵有如下讨论： 小张说：有些同学是河南人 小李说：牛牛不是河南人 小赵说：有些同学不是河南人 然而三个人只有一个为真，以下哪个选项为真：','[{"label":"A","content":"42 名同学都是河南人"},{"label":"B","content":"有些同学不是河南人"},{"label":"C","content":"牛牛不是河南人"},{"label":"D","content":"42 名同学都不是河南人"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":371,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400372,6,'逻辑判断','听古典音乐有助于提高儿童智商，这一发现被形象地称作“莫扎特效应”。心理学 家弗朗西斯 ·罗彻对36位大学生做了一个实验，他让其中18位学生在做一些空间 推理题之前听10分钟莫扎特的D小调奏鸣曲。结果，在将一张纸叠几次剪开后会是 什么形状的测试中，这18人有明显进步。 以下各项如果为真，最不能削弱上述观点的是：','[{"label":"A","content":"听古典音乐的效果有1.5个智商点的提高，但仅限于折纸实验"},{"label":"B","content":"听了莫扎特音乐的学生学习能力本身就比其他学生更强"},{"label":"C","content":"听反向莫扎特音乐(把莫扎特音乐的音符以相反序列排列)对人有负效应，即其 行为认知能力减退"},{"label":"D","content":"演奏乐器时的触觉反应刺激了大脑中的皮层，使得人的脑功能达到最优化状态"}]','D','【题型分类】 一般质疑类——有论据有结论 【实战解析】论据和结论见批注，观察选项： A 选项，听古典音乐提高智商只限于折纸实验，即听古典音乐对折纸 有帮助，但智商是认知能力，只对折纸实验有帮助不能说明对提升智 商有作用，可以质疑； ④花生批注：论据是“折纸实验表 现好”,结论是“提 高了智商”;论据是听“莫扎特音 乐”,结论是“古典 音乐”;A 、C 选项分别针对以 上漏洞进行攻击。B 选项，引入“本身学习能力更强”的新变量，即折纸实验表现好可 能是因为本身学习能力强，而不是因为听了莫扎特音乐，属于另有他 因质疑； ④花生批注： 论据是“折纸实验表 现好”,结论是“提 高了智商”; 论据是听“莫扎特音 乐”,结论是“古典 音乐”; A 、C 选项分别针对以 上漏洞进行攻击。 C 选项，反向莫扎特音乐也可能属于古典音乐，听有的古典音乐可能 让认知能力减退，所以不能说听古典音乐有助于提高智商，可以质疑； D 选项，选项讨论的是“演奏乐器”对人的影响，题干中讨论的是“听” 古典音乐对儿童智商的影响，话题不一致，完全无关； 综 上 ，无法质疑的为D选项。','逻辑判断600题','进阶','published','{"globalNumber":372,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400373,6,'逻辑判断','网店的客服诉求大致可以分为售前问题、售后问题和投诉。随着人工智能技术的发展， 其中一部分重复性高、内容简单的问题，可以通过智能客服来答复。在智能客服系 统完善后，它甚至能够比人工客服更快速、准确地回答这些问题。有人据此认为， 网店人工客服这一岗位将会很快消失。 以下选项中最无法削弱上述论断的是：','[{"label":"A","content":"智能客服的研发成本远高于雇用数名人工客服"},{"label":"B","content":"智能客服无法与客户进行情感交流，开展客户维护"},{"label":"C","content":"智能客服对复杂问题的回应能力不如人工客服"},{"label":"D","content":"智能客服的完善需要相对漫长的过程"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":373,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400374,6,'逻辑判断','在某次电子产品促销会中，某款电子产品特别受消费者欢迎。促销会负责人总结经 验时说，看来只有投入了大量广告费用做宣传的电子产品才有好的市场接受度。 以下哪项如果为真，最能质疑负责人的论述：','[{"label":"A","content":"某款电子产品的外观设计增加了更多科技元素，尽管没有做广告宣传，仍然受到 市场欢迎"},{"label":"B","content":"最关注电子产品的广告群体是青年人，而参加此次促销会的消费者恰好青年人多"},{"label":"C","content":"某款电子产品投入了大量广告费用做宣传，但由于其价格过高，并不受市场欢迎"},{"label":"D","content":"某些电子产品投入了大量广告费用做宣传，但是实际上并不具备所宣传的部分功能"}]','A','。 能说明“食用腌制食品和消化道癌症无关”②,可以质疑； 食用腌制食品2次以上消化道正常目 ：食用腌制食品多的反 而消化道癌症可能性 小，结论本身违背常 识，很可能是有其他 原因造成了反常的结 能说明“食用腌制食品和消化道癌症无关”②,可以质疑； 食用腌制食品2次以上 消化道正常 目 ： 食用腌制食品多的反 而消化道癌症可能性 小，结论本身违背常 识，很可能是有其他 原因造成了反常的结','逻辑判断600题','进阶','published','{"globalNumber":374,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400375,6,'逻辑判断','一项针对某地区的调查显示，每周至少食用2次腌制食品的人患消化道癌症的可能 性比每周食用腌制食品少于2次的人更低。因此，食用腌制食品并不会引发消化道 癌症。 以下选项如果为真，最不能削弱上述论证的是：','[{"label":"A","content":"相较其他地区而言，该地区的人更习惯于食用腌制食品"},{"label":"B","content":"很多人在消化道出现不适时，会少吃或不吃腌制食品"},{"label":"C","content":"该研究由某家腌制食品企业资助，选择研究对象时具有倾向性"},{"label":"D","content":"食用腌制食品次数多的人每次的食用量一般很少"}]','A','。 果 ； 即本身消化道不适， 造成了患消化道癌症 可能性大； 食用腌制食品也可能 会增加患消化道癌症 的 可 能 性 ，无法排除 此 种 可 能 ，即削弱题 干结论的“否定此因 ”。 33花生批注： 题干均为所有、有些 表述，属于范畴分析 类题目，考虑一分为 二画图法。','逻辑判断600题','进阶','published','{"globalNumber":375,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400376,6,'逻辑判断','某公司的部门经理经过讨论，一致认为周末应加班赶工作进度。该公司25岁以下的 员工中有一部分报名了周末的户外拓展运动，报名户外拓展运动的员工一致反对加班。 由此可以推出：','[{"label":"A","content":"所有部门经理年龄都在25岁以上"},{"label":"B","content":"部门经理中有人报名了户外拓展运动"},{"label":"C","content":"报名户外拓展运动的都小于25岁"},{"label":"D","content":"2 5 岁以下的员工有部分不是部门经理"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":376,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400377,6,'逻辑判断','如果张生喜欢摄影，则他会喜欢旅游；如果他不喜欢摄影，他则会喜欢驾车；但如 果张生不喜欢旅游，则他对驾车就不感兴趣了。 据此，可推出张生：','[{"label":"A","content":"喜欢旅游"},{"label":"B","content":"喜欢驾车"},{"label":"C","content":"不喜欢驾车"},{"label":"D","content":"喜欢摄影"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":377,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400378,6,'逻辑判断','有一件未留姓名的好人好事在某社区传开，甲、乙、丙、丁四人有如下对话： 甲说：“这件事肯定是乙、丙、丁三人中的一位做的”。 乙说：“我没做这件事，好人好事是丙做的”。 丙说：“此事是甲和乙中的一位做的”。 丁说：“乙说的是事实”。 经调查，证实这4人中只有两人说的符合实际。由此推出：','[{"label":"A","content":"是甲做的好事"},{"label":"B","content":"是乙做的好事"},{"label":"C","content":"是丙做的好事"},{"label":"D","content":"是丁做的好事"}]','B','。 291 ③5花生批注： 论据：表面摩擦大， 不利于滑冰运动(即 滑冰运动需要表面摩 擦小),当达到零下7 摄氏度时，可移动的 水分子达到最多； 结论：冰场其温度都 保持了零下7摄氏度 左右。 36花生批注： A、B、D选项均没有 提到二者的关系，无 法搭桥，非“隐含前提”。 ③花生批注： “改正错误”→“认 识错误”。','逻辑判断600题','进阶','published','{"globalNumber":378,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400379,6,'逻辑判断','当水结冰时，每个水分子都会通过氢键抓住周围的水分子，形成晶体结构，但冰层 表面的水分子无法像冰面内部一样形成规则的晶体结构，会杂乱无序地游荡在其表 面，形成厚度约为100纳米量级的水分子层，随着温度变化，水分子层中可移动水 分子数量也在发生变化，极度低温下，冰与正常的固体没有区别，表面摩擦是非常 大的，不利于滑冰运动；当达到零下7摄氏度时，可移动的水分子达到最多，因此 冰场的温度都保持了零下7摄氏度左右。 上述论证成立须基于下列哪一前提：','[{"label":"A","content":"冰的表面最光滑时，冰面的摩擦力达到最小"},{"label":"B","content":"物体从冰面划过时，摩擦使冰面融化产生了水"},{"label":"C","content":"冰面水分子层中可移动的水分子越多，冰面越光滑"},{"label":"D","content":"冰面的水分子层既具有固态冰的弹性，也有液态水的黏性"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":379,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400380,6,'逻辑判断','有人说：“只有认识错误，才能改正错误。” 如果以上判断是真的，可能出现的情况是： ①某人认识了错误，没有能改正错误。 ②某人没有认识错误，改正了错误。 ③某人没有认识错误，没能改正错误。 ④某人认识了错误，改正了错误。','[{"label":"A","content":"①"},{"label":"B","content":"①②③"},{"label":"C","content":"③④"},{"label":"D","content":"①③④ 练习题20"}]','D','。 38花生批注： 命题“A→B” 为真， 只有“A 且非B” 为假 (对应②); 其他三种情况：A 且B、 非A 且B 、非 A 且非 B 均为真。 练习题20 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":380,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400381,6,'逻辑判断','如今，晚上开灯睡觉的人不在少数。有些人是因为晚上睡太晚，结果忘记关灯或懒 得关灯；还有些人则是因为害怕黑漆漆的环境所以直接不关灯，感觉在明亮的环境 中睡觉更有“安全感”。科研人员对睡眠时室内光线的强弱与人体健康状况之间的 关系做过多项研究，发现如果睡眠环境中的光线过于明亮，会使人昼夜节律出现紊乱， 会增加肥胖的风险。 以下哪项如果为真，最能支持上述观点：','[{"label":"A","content":"过于明亮将导致美洛托宁的松果体激素分泌减少，而该激素可以调解体重和糖脂 代谢"},{"label":"B","content":"人们肥胖风险的增加，往往由社会节奏过快、压力过大以及不好的生活习惯所导致"},{"label":"C","content":"经过研究机构统计，肥胖人群中的一部分人习惯开灯睡觉，一旦关灯便会失眠"},{"label":"D","content":"都市夜晚的光污染使得一些人在睡眠时的环境过于明亮，会使人的昼夜节律出现 紊乱"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":381,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400382,6,'逻辑判断','任何无法量化及不设定时限的目标都是无效目标。而任何无效的目标都没有实际操 作的方法。因此，详细的职业规划不是无法量化及不设定时限的目标。 为使上述论证成立，必须补充以下哪项作为前提：','[{"label":"A","content":"详细的职业规划不都是无效的目标。"},{"label":"B","content":"详细的职业规划有实际操作的方法。"},{"label":"C","content":"有效的目标都是可以量化和设定时限的目标。"},{"label":"D","content":"无法量化及不设定时限的目标没有实际操作的方法"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":382,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400383,6,'逻辑判断','某公司30岁以下的年轻员工中有一部分报名参加了公司在周末举办的外语培训班。 该公司的部门经理一致同意在本周末开展野外拓展训练。所有报名参加外语培训班 的员工都反对在本周末开展拓展训练。 由此可以推出：','[{"label":"A","content":"所有部门经理年龄都在30岁以上"},{"label":"B","content":"该公司部门经理中有人报名参加了周末的外语培训班"},{"label":"C","content":"报名参加周末外语培训班的员工都是30岁以下的年轻人"},{"label":"D","content":"有些30岁以下的年轻员工不是部门经理 119 119"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":383,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400384,6,'逻辑判断','在司法审判中，所谓肯定性误判是把无罪者判为有罪，否定性误判是把有罪者判为 无罪。肯定性误判就是所谓的错判，否定性误判就是所谓的错放。而司法公正的根 本原则是“不放过一个坏人，不冤枉一个好人”。某法学家认为，目前，衡量一个 法院在办案中是否对司法公正的原则贯彻得足够好，就看它肯定性误判率是否足够 低。 以下哪项如果为真，能最有力地加强法学家的观点：','[{"label":"A","content":"错放，只是放过了坏人；错判，则是既放过了坏人，又冤枉了好人"},{"label":"B","content":"宁可错判，不可错放，是“左”的思想在司法界的反映"},{"label":"C","content":"错放所造成的损失，大多数情况下是可以弥补的；错判对被害人造成的伤害， 一 般是无法弥补的"},{"label":"D","content":"各个法院的否定性误判率基本相同"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":384,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400385,6,'逻辑判断','废弃塑料堆积物正在海洋表面漂浮，有些甚至与超200万平方公里的格陵兰岛面积 相当，对海洋生态系统构成威胁。科学家最近研制成功并推广运用了一种新型塑料。 它是在一种廉价无毒的醛化合物中，“烹制”木头或其他非食用植物原料如农业废 弃物等生产出来的。团队称，如能用这种新型塑料替代传统塑料就能减少甚至消除 海洋塑料污染。 以下各项如果为真，最能支持团队结论的是：','[{"label":"A","content":"非食用植物原料制成的塑料，在使用过后，会自行降解，融入水土"},{"label":"B","content":"非食用植物原料制成的塑料，比传统塑料热稳定性更好，更加环保"},{"label":"C","content":"这种新塑料成本低廉、强度高、易加工，完全可替代传统塑料"},{"label":"D","content":"生产这种新塑料可让农、林业废弃物得到充分利用，促进绿色发展"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":385,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400386,6,'逻辑判断','全班17位同学中有9位同学参加了舞蹈课外兴趣小组，7人参加了合唱课外兴趣小组。 如果以上陈述为真，不能推出以下哪项：','[{"label":"A","content":"如果有2人两项都参加，则至少有3人两项都没参加"},{"label":"B","content":"可能有人两项课外兴趣小组都参加了"},{"label":"C","content":"肯定有人两项课外兴趣小组都没有参加"},{"label":"D","content":"肯定有人两项课外兴趣小组都参加"}]','D','【题型分类】分析类——日常分析 【实战解析】此题可利用容斥思想解题： A 选项，如果有2人两项都参加，则参加舞蹈和合唱课外兴趣小组的 人数=9+7 - 2=14人②,那么就有3人两项都没参加，可以推出： B 选项，参加舞蹈小组和合唱小组的同学可能重合，可以推出； C 选项，参加舞蹈和合唱课外兴趣小组的人数最多可能有9+7=16人， 那么肯定有人两个小组都没参加，可以推出； D 选项，参加舞蹈小组和合唱小组的同学可能无交集，不能推出，当选。 ⑧花生批注：题干详细介绍了实验 过程，施加肥料甲的 大棚有较高西瓜产量， 未施加肥料甲的大棚 西瓜产量较低；得出第一个大棚西瓜 产量高是因为肥料甲 的结论。 ⑧花生批注： 题干详细介绍了实验 过程，施加肥料甲的 大棚有较高西瓜产量， 未施加肥料甲的大棚 西瓜产量较低； 得出第一个大棚西瓜 产量高是因为肥料甲 的结论。','逻辑判断600题','进阶','published','{"globalNumber":386,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400387,6,'逻辑判断','在两个实验大棚内种上相同数量的西瓜苗，只给第一个大棚施加肥料甲，但不给第 二个大棚施加。第一个大棚产出1800千克西瓜，第二个大棚产出1200千克西瓜。 除了水以外，没有向这两个大棚施加任何其他东西，故必定是肥料甲导致了第一个 大棚有较高的西瓜产量。 如果以下陈述为真，最严重削弱上述论证的是：','[{"label":"A","content":"两个大棚占地面积相差很多"},{"label":"B","content":"两个大棚的土质和日照量有所不同"},{"label":"C","content":"少量的肥料甲从第一个大棚渗入第二个大棚"},{"label":"D","content":"在两个大棚中种植了相同品种的西瓜苗"}]','B','。 299 ⑨花生批注： 题干可简化为： 用植物油代替动物油， 可以降低血液胆固醇 水平，从而可以降低 心脏病发病率。 ⑩花生批注： 例如：人的素质提高 应让好人变多，坏人 变少；人的总数少了， 无法说明人的素质变 高了。','逻辑判断600题','进阶','published','{"globalNumber":387,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400388,6,'逻辑判断','用植物油(主要成分：不饱和脂肪酸)代替动物油(饱和脂肪酸)可以改善心脏健 康的说法可追溯到20世纪60年代——那时的研究发现，这种饮食转换可以降低血 液胆固醇水平，因此可以降低心脏病发病率，有研究者曾经在文章中建议：如果人 们采用植物油烹制的饮食可能更有利于心脏的健康。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"在长期食用植物油的人群中，男性患心脏病的风险比女性低5%左右"},{"label":"B","content":"植物油包含很多种类，不是每个种类都能明显降低冠心病发生的风险"},{"label":"C","content":"血清中低密度胆固醇高，高密度胆固醇低时，心血管疾病发生的几率才会增加"},{"label":"D","content":"配合健康的饮食习惯，基于饱和脂肪酸的饮食也可有效降低心脏病的死亡风险"}]','C','【题型分类】 一般质疑类——无论据有结论 【实战解析】题干只介绍了一项研究发现，可看作只有结论，有理由 的质疑结论。分析选项： A 选项，指出食用植物油的男性心脏病风险较女性低5%,但不清楚 食用植物油是否会降低心脏病发病率，无法质疑； B 选项，冠心病只是心脏疾病的一种，即使不是每种植物油都能明显 降低冠心病风险，也无法说明食用植物油不会降低心脏病发病率，无 法质疑； C 选项，心血管疾病发病率增加和“低密度胆固醇高和高密度胆固醇 低”有关， 所以要降低心血管疾病发病率，应降低低密度胆固醇，提 高高密度胆固醇⑩: 食用植物油可以降低胆固醇整体水平，不能说明其可以降低心脏病发 病率；针对“胆固醇”和“心脏病发病率”间的断点进行攻击，可以质疑； D 选项，基于饱和脂肪酸和食用植物油是两回事，可能都可以降低心 脏病发病率，无法质疑； 综 上 ，C 选项是正确答案。','逻辑判断600题','进阶','published','{"globalNumber":388,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400389,6,'逻辑判断','有人认为，十二生肖起源于动物崇拜。这是因为在原始社会中，人类的生产力水平 很低，猪、牛、羊等牲畜与农事活动关系密切，动物崇拜也就随之而生。除此之外， 虎 、蛇等动物可能威胁到人类的自身安全，往往被视为强大的象征，人们也会因为 感到恐惧而形成动物崇拜。 以下选项如果为真，最能反驳上述判断的是：','[{"label":"A","content":"十二生肖中只有龙不是现实中存在的动物"},{"label":"B","content":"“过街老鼠人人喊打”,但它是十二生肖之首"},{"label":"C","content":"鸡、鸭、鹅与农事活动关系密切，但只有鸡属于十二生肖"},{"label":"D","content":"牛和猪都与农事相关，但他们在十二生肖中的位置相距很远"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":389,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400390,6,'逻辑判断','当我们在陌生的地方入睡时，往往会度过一个不安的夜晚，起床后也会感到昏沉乏力， 这种现象被称为首夜效应。脑部扫描显示：在第一夜，受试者的一侧半脑会像平常 一样安然入睡，但另一个半脑却保持较为活跃的状态，有时半球状态还会出现切换。 因此研究人员认为：处在新环境时，我们的大脑会在第一个晚上开启监控模式，有 一侧大脑半球保持警觉状态，因此人们常常感觉没有睡好。 以下哪项如果为真，最能削弱上述推论：','[{"label":"A","content":"在家中入睡时，人们的大脑也会出现一侧脑半球无活动、一侧脑半球较活跃的情况"},{"label":"B","content":"旅行时如果人们携带自己的枕头或者住宿环境与自己房间类似，就不会出现首夜 现象"},{"label":"C","content":"深度睡眠时，人的大脑频率处于 o 波，而外宿的首夜，o 波出现的时间并未明 显减少"},{"label":"D","content":"两侧脑半球中左半脑更容易察觉声音，入睡后听到响动时，左半球就会出现脑电 活动"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":390,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400391,6,'逻辑判断','甲、乙两队参加比赛，关于甲、乙两队是否最终能够夺得奖牌，有如下断言。 I. 甲队不可能夺不到奖牌 II. 甲队不一定夺得奖牌 III. 乙队夺得了奖牌 IV. 甲、乙两队至少有一队能夺得奖牌 已知以上断言有两句为真，两句为假，由此可以推知：','[{"label":"A","content":"甲、乙两队都没有夺得奖牌"},{"label":"B","content":"甲、乙两队都夺得了奖牌"},{"label":"C","content":"甲队夺得了奖牌，乙队未夺得"},{"label":"D","content":"乙队夺得了奖牌，甲队未夺得"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":391,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400392,6,'逻辑判断','2020年疫情肆虐，但电商直播逆势崛起，一季度全国电商直播超过400万场，“万 物可播、全民可播”成为一个响亮的口号。一项针对消费者和商家的调查显示，在 电商直播中，许多消费者能以优惠的价格购买到心仪的商品，商家也能提升其销售额。 有专家据此推断，电商直播的商业模式在疫情过后仍会受到商家和消费者的追捧。 以下各项如果为真，则除哪项外均能削弱上述专家的观点：','[{"label":"A","content":"低价促销已经成为当前直播带货的常态，这种价格竞争让商家无利润可赚"},{"label":"B","content":"直播带货往往造成线上线下的价格不一致，不利于商家维护企业品牌形象"},{"label":"C","content":"许多消费者购买直播销售的商品后遇到了以次充好、售后维权困难等情况"},{"label":"D","content":"个别带货主播为了利益常常夸大自己的销售数据，而消费者对此并不知情 122"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":392,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400393,6,'逻辑判断','大众通常认为，早期的音乐训练能增强个体的乐声和语音处理能力。但有些心理学 家对此表示怀疑。研究人员调查了出生于1959年到1985年之间的1211对同卵双胞 胎和1358对异卵双胞胎，记录他们的音乐练习时间，评估他们的音乐能力。他们发 现，练习更长时间并不能表现出更出色的音乐能力，比如一对基因相同的同卵双胞 胎的音乐练习时间相差20228小时，但他们的音乐能力完全相同。这些研究者认为， 如果没有正确的基因，即使练习2万小时也没有意义，音乐能力是由基因决定的。 以下哪项如果为真，最能驳斥研究者的结论：','[{"label":"A","content":"音乐能力评估采用手指模拟快节奏音乐的方式，而手指的灵活性受遗传影响"},{"label":"B","content":"具有遗传上优越的听觉技能的个体可能自我选择成为音乐家，练习时间更长"},{"label":"C","content":"同卵双胞胎之间通常有“心灵感应”,影响了个体在音乐能力测试中的表现"},{"label":"D","content":"音乐能力差的个体会低估自己的练习时间，以便维持心理平衡"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":393,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400394,6,'逻辑判断','星座预测就是根据星辰的位置及其各种变化来预测人世间的各种事物。有很多人相 信并依照星座预测制定每天的日程。因此，有人认为星座预测是正确的，否则也不 会有这么多人相信。 以下哪项如果为真，最能反驳上述观点：','[{"label":"A","content":"星座确实存在"},{"label":"B","content":"有更多的人不相信星座预测"},{"label":"C","content":"未成年人才相信星座预测"},{"label":"D","content":"会有很多的人相信非常不科学的事情"}]','D','【题型分类】一般质疑类——严谨逻辑关系 【实战解析】题干结论可翻译为：星座预测不正确→不会有这么多人 相 信。 上述命题的矛盾为“星座预测不正确并且有很多人相信”,观察选项， D 选项可以理解为“不科学的事情(星座预测就是不科学的事情)并 且很多人相信”,当选。 ②花生批注： (必须/除非 )A否 则B, 可翻译为“非 A→B”; 记忆口诀：否A 则B。 ②3花生批注： 论据：珠穆朗玛峰海 拔在5000米到6000米 的冰川出现快速融化； 结论：喜马拉雅地区 的冰川最终将消失殆 尽。','逻辑判断600题','进阶','published','{"globalNumber":394,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400395,6,'逻辑判断','二氧化碳的排放量剧增导致全球气候变暖，使珠穆朗玛峰所在的喜马拉雅地区冰川 面临急剧缩小的危险。研究显示，珠峰海拔在5000米到6000米的冰川集中区域出 现快速融化的现象，这些地方将只在冬季而不是在温暖的季节时看到结冰。专家推 论说，根据未来的气候变化趋势，喜马拉雅地区的冰川减少的速度还有可能加快， 如果本世纪内气温如预计的一样继续升高，该地区的冰川最终将消失殆尽。 如果以下各项为真，最能削弱上述论证的是：','[{"label":"A","content":"喜马拉雅冰川每年缩小约到0.1%到0.6%"},{"label":"B","content":"喜马拉雅其他地区冰川对温度不敏感"},{"label":"C","content":"过去50年珠峰周边冰川覆盖面积减少了33.3%"},{"label":"D","content":"珠穆朗玛峰7000米以上区域未出现冰川快速融化现象 123"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":395,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400396,6,'逻辑判断','在心泉乡发展研讨会上，王书记认为：“或者发展养蚕业，或者发展畜牧业。”周 乡长认为：“心泉乡人多地少，应加强劳动力培训，大力开发对外劳务输出。”李 书记认为：“只有发展特殊作物种植，才是山乡心泉的唯一出路。”张乡长认为：“充 分发挥心泉优势，发展旅游业，别无选择。” 经过专家论证，上述四位的意见有两位被认为是可行的，那么意见可行的两位是：','[{"label":"A","content":"王书记和周乡长"},{"label":"B","content":"王书记和李书记"},{"label":"C","content":"李书记和周乡长"},{"label":"D","content":"王书记和张乡长"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":396,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400397,6,'逻辑判断','甲、乙、丙、丁、戊、己、庚七人表演配乐诗朗诵，为确保表演效果，需要安排朗诵顺序。 已知： (1)甲要么第一个朗诵，要么最后一个朗诵； (2)乙和丙之间有三人； (3)丁和戊之间有三人，且丁先朗诵； (4)丁在乙之前朗诵。 根据上述条件，以下哪项可能为真：','[{"label":"A","content":"丙第二个朗诵"},{"label":"B","content":"乙第四个朗诵"},{"label":"C","content":"庚第二个朗诵"},{"label":"D","content":"丁第四个朗诵"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":397,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400398,6,'逻辑判断','雅思成绩对学生申请国外大学非常重要。被申请的学校会对申请者的雅思成绩进行 审核，如果申请者的英语水平没有达到其要求，则该申请者不可能被录用。 最有可能是上述论证的预设前提的是：','[{"label":"A","content":"被申请的学校要求，只有考雅思，才能申请该学校"},{"label":"B","content":"若一个人雅思成绩非常好，则他一定能够被录用"},{"label":"C","content":"雅思成绩能够准确反映申请者的英语水平"},{"label":"D","content":"若一个人雅思成绩没有达标，则一定不可能被录用"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":398,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400399,6,'逻辑判断','某办公室甲、乙、丙、丁四人对本办公室当选先进工作者的职工进行如下预测： 甲：乙和丙要么都当选，要么都落选。 乙：最多只有2人当选。 丙：我不可能当选。 丁：你们中肯定有人的预测是错的。 结果发现四个人中只有一个人说对了，问以下哪项判断是正确的：','[{"label":"A","content":"甲当选了"},{"label":"B","content":"乙当选了"},{"label":"C","content":"丙未当选"},{"label":"D","content":"丁未当选"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":399,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400400,6,'逻辑判断','研究发现，如果小学生每天玩乐(如：做游戏)30分钟，持续两个月与记忆相关的 脑区神经组织显著增加，且这种效应可持续很长时间，与非玩乐情境下的小学生相比， 玩乐情境下的孩子更能想出新鲜的点子。人们据此认为，适当的玩乐有助于激发小 学生的创造力，使其拥有更聪明的大脑。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"玩乐有助于小学生为充满高挑战性和不确定性的未来做好准备"},{"label":"B","content":"让孩子自由地玩耍比让孩子坐着听老师讲故事更能有效地降低孩子上学的焦虑"},{"label":"C","content":"通常情况下，与记忆相关的脑区神经组织的增加会带来更活跃、更天马行空的思维"},{"label":"D","content":"动物实验表明，在游戏资源丰富的环境中长大的小白鼠，大脑神经突触要比匮乏 环境下的小白鼠多出近50% 练习题21"}]','C','【题型分类】支持类——断点搭桥 【实战解析】论据结论可见批注，“脑区神经组织显著增加”与“创 造力”之间存在明显断点，需要搭桥，选项中只有C 选项将二者搭桥， 可直接秒选。 其逻辑关系如下：每天玩乐导致脑区神经组织增加，脑区神经组织带 来更活跃的思维，从而激发创造力，使其拥有更聪明的大脑。 练习题21 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":400,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400401,6,'逻辑判断','根据近几年的调查发现，随着人类社会不断进步，物质生活水平不断提高，人们越 来越重视心理健康问题，成年人中患抑郁症的病例在逐年减少。但是，这还不足以 得出抑郁症发病率在逐年下降的结论。 下列哪项为真，最能加强上述推论：','[{"label":"A","content":"近年来未成年人得抑郁症的比例明显增加了"},{"label":"B","content":"近年来防治抑郁症的医疗条件有了很大改善"},{"label":"C","content":"比起癌症、心血管疾病，近年来对抑郁症的防治缺乏重视"},{"label":"D","content":"对抑郁症的治疗目前还有难度，患者不可能在短期内得到治愈"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":401,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400402,6,'逻辑判断','某单位事业编制招聘录用名单已经公布，已知： (1)只要甲被录取，乙就不被录取； (2)只要乙不被录取，甲就被录取； (3)甲被录取。 已知这三个判断只有一个真，两个假。由此推出：','[{"label":"A","content":"甲乙都被录取"},{"label":"B","content":"甲乙都未被录取"},{"label":"C","content":"甲被录取，乙未被录取"},{"label":"D","content":"甲未被录取，乙被录取"}]','B','【题型分类】分析类——真假分析 【实战解析】三句话中没有明显矛盾，可使用假设法： 假设(3)为真(甲被录取),则(2)为真③,不符合“只有一真”要求， 所以(3)一定为假(甲没有被录取); 甲未录取，则 ( 1 ) 为 真④,又因“只有一真”,故(2)为假，则“乙 未录取且甲未录取”⑤,B 选项正确。','逻辑判断600题','进阶','published','{"globalNumber":402,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400403,6,'逻辑判断','矿产勘探人员观察发现，不同颜色和形状的矿物结晶体虽然有各自不同的名称和表 象，但可能是化学组成相同的物质在不同的物理化学条件下结晶成不同结构的晶体， 而且一般都有着不同的物理特征。所以说，不同的矿物种类可以有相同的化学成分。 下列选项最能支持上述论断的是：','[{"label":"A","content":"二氧化碳和干冰名称不同而且表象也不同"},{"label":"B","content":"不同颜色的矿物晶体暴露在空气里会变色"},{"label":"C","content":"分析仪器能快速判断矿物晶体的化学成分"},{"label":"D","content":"二氧化硅可以有12种不同的矿物结晶"}]','D','。 四海公考 SIHAI GONGKA0','逻辑判断600题','进阶','published','{"globalNumber":403,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400404,6,'逻辑判断','在我们这个高速发展的社会，拆迁和建设的速度早已超出了人们的想象。而城市的 发展总是伴随着城市的拆迁和建设。因此，有人认为城市的发展是导致城市拆迁和 建设的根本原因。 逻辑判断600o 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"很少进行拆迁和建设的城市，往往都会发展得比较慢"},{"label":"B","content":"经济发展水平的提高，促进城市发展，带动城市的拆建"},{"label":"C","content":"城市的发展过程必然会带来了很多正面的和负面的影响"},{"label":"D","content":"除城市发展外，工业化也是导致城市拆迁和建设的原因"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":404,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400405,6,'逻辑判断','面试是公司招聘的一个不可取代的环节，因为通过面试，公司可以了解应聘者的能力， 那些能力不适合公司需求的应聘者将被淘汰。 以下哪项是上述论证最可能假设的：','[{"label":"A","content":"面试的唯一目的是了解应聘者的能力"},{"label":"B","content":"能力是确定是否录用应聘者的最主要因素"},{"label":"C","content":"只有经验丰富的面试官才能通过面试准确把握应聘者的能力"},{"label":"D","content":"应聘者的能力很难通过招聘的其他环节展示"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":405,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400406,6,'逻辑判断','捍卫法律尊严，保护消费者权益，让违法失信惩戒机制释放更大效果，“知信、用信、 守信”的社会氛围才会更加浓厚，虚假广告的生存空间才会愈加逼仄，整个社会的 诚信度才能不断跃升。 如果上述论断为真，那么下列哪项也一定为真：','[{"label":"A","content":"如果不保护消费者权益，就无法捍卫法律尊严"},{"label":"B","content":"要让整个社会的诚信度跃升，就要让违法失信惩戒机制释放更大效果"},{"label":"C","content":"一旦虚假广告的生存空间愈加逼仄，整个社会的诚信度就能不断跃升"},{"label":"D","content":"“ 知信、用信、守信”的社会氛围更加浓厚以后，虚假广告的生存空间就愈加逼 仄了"}]','B','【题型分类】推出类——等价推出 【实战解析】分析题干可知：捍卫法律尊严、保护消费者权益、让违 法失信惩戒机制释放更大效果之间无推出关系，排除A 选项； “知信用信守信”的社会氛围更加浓厚、虚假广告的生存空间愈加逼 仄、整个社会的诚信度不断跃升之间无推出关系，排除C 选项、D 选项； 只有B 选项，和原命题的等价，“只有才”可翻译为“后推前”,当选。 四海公煮 sIHAIGoNGKA⁰ 逻辑判断600o','逻辑判断600题','进阶','published','{"globalNumber":406,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400407,6,'逻辑判断','近日，一名8岁幼儿因学跳舞发生脊柱损伤造成的截瘫的病例引发关注。一项调查 显示，近年来每年因练习舞蹈造成幼儿明显受伤的病例明显增加。某专家认为，这 主要是由于舞蹈老师缺乏必要的安全急救意识造成的。 以下哪项如果为真，能削弱上述结论：','[{"label":"A","content":"调查显示，近年来学习舞蹈的幼儿人数明显增多，发生意外的风险随之增加"},{"label":"B","content":"调查显示，某些正规的舞蹈机构配备了专业医疗保健人员"},{"label":"C","content":"国家对舞蹈教师的舞蹈技能考核标准逐年提高"},{"label":"D","content":"舞蹈教师在练习舞蹈时也受过伤，经常自行处理，并未发生截瘫现象 127 127"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":407,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400408,6,'逻辑判断','A市某高校研究人员对2.3万名成年人的工作、生活和健康信息进行调查，了解他 们的工作时长，周末加班、工作条件以及心理状况。研究人员发现，加班最多(1 周工作超过55小时)的女性，抑郁症状比1周工作35小时至40小时的女性高7.3%。 下列选项如果为真，最能支持上述结果的是：','[{"label":"A","content":"参与调查的成年人均为本地市民"},{"label":"B","content":"1 周工作时长超过55小时的男性明显表现出亢奋心理"},{"label":"C","content":"研究人员发现，对于周末加班，男女都会感觉心情郁闷"},{"label":"D","content":"多数女性家务压力比男性大，工作时长过长会增加压力，加重责任感"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":408,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400409,6,'逻辑判断','某景区举办萤火虫展，每天都会吸引大批游客来观赏。数日后，该景区萤火虫的数 量急剧下降。景区负责人认为是游客的不文明行为破坏了萤火虫的生存环境。 下列哪项如果为真，能够支持景区负责人观点：','[{"label":"A","content":"萤火虫对生存环境的要求很高"},{"label":"B","content":"游客不文明的行为在其他景区也存在"},{"label":"C","content":"自规范游客行为后萤火虫死亡数量急剧下降"},{"label":"D","content":"和萤火虫同类的昆虫数量受游客行为影响不大"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":409,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400410,6,'逻辑判断','自1999年，人类在哥伦比亚西南部发现彩毛腿蜂鸟不久之后，彩毛腿蜂鸟的数量急 剧减少，被世界自然保护联盟红色名录列入极危级别。所以人类的捕杀导致彩毛腿 蜂鸟濒临灭绝。 下列哪项如果为真，能够对上述结论提出最大的质疑：','[{"label":"A","content":"由于人类的砍伐，每年平均有8.3%适合彩毛腿蜂鸟的栖息地消失掉"},{"label":"B","content":"彩毛腿蜂鸟的翅膀微黑，脚呈粉红色，非常可爱"},{"label":"C","content":"人类在发现彩毛腿蜂鸟后，向其栖息地引进了其他物种"},{"label":"D","content":"世界自然保护联盟红色名录记载的都是濒临灭绝的生物"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":410,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400411,6,'逻辑判断','有人建议，英语四六级考试应该改变统一考试模式，实行社会化改革，由社会机构组织， 大学生自愿选择报考，大学与用人单位自主认可，而不再是所有学生必须统一参加、 企事业单位招聘统一要求成绩的考试，这能令大学英语教育摆脱应试教育。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"大学生自愿选择报考有助于学生自主学习"},{"label":"B","content":"社会机构组织英语考试也会导致应试教育"},{"label":"C","content":"企事业单位招聘并没有统一要求英语成绩"},{"label":"D","content":"英语应试教育不仅仅是四六级统一考试造成的 四海公煮 SIHAI GoNGKAO 逻辑判断"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":411,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400412,6,'逻辑判断','甲、乙、丙、丁、戊、己、庚7人开会时坐成一排，已知： ①乙在丙左边，间隔2人； ②戊在丁右边，间隔3人； ③庚在己左边，间隔1人； ④甲在最左边； ⑤戊不在最右边。 由此可知，己坐的位置是：','[{"label":"A","content":"左五"},{"label":"B","content":"左六"},{"label":"C","content":"左四"},{"label":"D","content":"左三"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":412,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400413,6,'逻辑判断','乡间公路上发生一起车祸，肇事司机是位女性。据这位女司机介绍，当时她发现路 边有一餐馆所以准备停车用餐，误将油门当刹车，汽车径直向前撞向路边车辆，连 撞两车后方才停下，万幸的是车上乘客仅受轻伤。有目击者对这起车祸做出如下评论： 女司机更容易出车祸。 以下哪项如果为真，最能质疑上述评论：','[{"label":"A","content":"有的男司机开车时比较敏捷和果断，很少出车祸"},{"label":"B","content":"有的女司机开车时比较细心和冷静，很少出车祸"},{"label":"C","content":"肇事司机已有8年驾龄，技术娴熟，以前从未出过车祸"},{"label":"D","content":"女司机各有不同，对肇事女司机不能轻率概括、以偏概全"}]','D','。 判 断 2花生批注： 论据：一位女司机发 生车祸； 结论：女司机更容易 发生车祸。 3花生批注： “有些”类选项，可 当做“一个”考虑质 疑力度；“有些”类 选项在严谨逻辑关系 题目中可强烈质疑“所 有”类选项。 ④花生批注： ①赵一>香辣排骨； ②钱二>孙三； ③胡椒猪肚>酸汤肥 牛； ④香辣排骨>秘制番 茄； ⑤吃胡椒猪肚的不是 孙三就是李四。 25花生批注： 胡椒猪肚(李四)> 酸汤肥牛(赵 一)> 香辣排骨(钱二)> 秘制番茄(孙三)。 ⑥花生批注： 既成事实：现代人喜 欢徒步； 分析原因：他们热爱 自然、回归自然，获 取内心的宁静。','逻辑判断600题','进阶','published','{"globalNumber":413,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400414,6,'逻辑判断','赵一、钱二、孙三、李四去吃火锅，服务员端上来的锅底有酸汤肥牛、香辣排骨、 秘制番茄、胡椒猪肚。已知：赵一比选择香辣排骨锅底的人年龄大，孙三比钱二年 龄小，吃酸汤肥牛锅底的人比吃胡椒猪肚锅底的人年龄小，吃香辣排骨锅底的人比 吃秘制番茄锅底的人年龄大，吃胡椒猪肚锅底的人不是孙三就是李四。 根据以上条件，下列可以推出的是：','[{"label":"A","content":"吃秘制番茄锅底的是赵一"},{"label":"B","content":"吃香辣排骨锅底的是孙三"},{"label":"C","content":"只能确定一人吃什么火锅锅底"},{"label":"D","content":"四人各自吃什么火锅锅底都能确定"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":414,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400415,6,'逻辑判断','作为一种户外运动，徒步正成为越来越多人的生活方式。徒步者们大多喜欢走在美 丽清新的城市近郊、乡村荒野、风景名胜或国家公园中。为什么有些现代人喜欢徒步? 这是他们热爱自然、回归自然的表现，徒步者希望通过回归自然获得内心的宁静。 以下哪项如果为真，不能质疑上述观点：','[{"label":"A","content":"很多人希望通过徒步来锻炼身体，增强活力，促进身体健康"},{"label":"B","content":"徒步者反对现代社会所推崇的“速度”价值，希望自己的生活“慢下来”"},{"label":"C","content":"徒步容易激发创造力，很早就被人作为潜心思考或科学发现的重要方式"},{"label":"D","content":"国家公园、带薪休假、行走文学等要素的出现，让现代人徒步成为可能 逻辑判断"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":415,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400416,6,'逻辑判断','据统计，最近五年内，某国每年都在诸如大型粒子加速器、高能物理实验室等领域 进行巨额投资，建成了一些设施并投入运转，但在相关领域的一流国际期刊上发表 的论文数量没有显著增长。一些专家认为，在这些领域的硬件方面作出巨额投入并 不见得对该国的科研发展有很大的积极意义。 为了使上述结论成立，必须补充下列哪项命题作为前提：','[{"label":"A","content":"最近五年在高能物理领域内的研究人才数量有明显增长"},{"label":"B","content":"最近五年该国相关领域的科研人员在国际刊物上发表的文章总数并没有显著增加"},{"label":"C","content":"在一流国际刊物上发表文章的数量是衡量科研发展水平的重要指标"},{"label":"D","content":"大型粒子加速器本来就不一定会导致该国科研水平明显提高"}]','C','。 ②花 生批注： 例如：身体健康让报 效祖国成为可能，身 体健康是报效祖国的 前提条件，有好身体 才能报效祖国。 但身体健康并非报效 祖国的原因，报效祖 国的原因可能是爱国。 28花生批注： 论据：某国在硬件方 面做出巨额投入，但 一流国际期刊发表的 论文没有显著增长； 结论：巨额投入不见 得对该国科研发展有 很大积极意义。 29花生批注： A、B、D选项均未将 一流国际期刊发表论 文与科研发展水平建 立联系，均无法将断 点搭桥。 ③0花生批注： 切记：此类题目“以 我为主”,寻找想要 答案，不要被错误选 项干扰。 321 321 ③花生批注： 题干中看似矛盾实则 合理的现象是： 甲品牌汽车最受女性 青睐(女性购买者占 比8成),但乙品牌 汽车女性购买量第一。 ③花生批注： 例如：甲销售量为 100,女性客户为80; 乙销售量1000,即使 有10%的女性客户， 女性客户人数也超过 了甲品牌。','逻辑判断600题','进阶','published','{"globalNumber":416,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400417,6,'逻辑判断','一项调查显示甲品牌汽车的购买者中，有8成都是女性，是最受女性青睐的汽车品牌。 但是，最近连续6个月的女性购车量排行榜却显示，乙品牌汽车的女性购买量位居 第一。 以下选项如果为真，最能解释上述现象的是：','[{"label":"A","content":"甲品牌汽车的销量远低于乙品牌汽车"},{"label":"B","content":"乙品牌汽车的女性买主所占比例为75%"},{"label":"C","content":"排行榜设立的目的之一是引导消费者的购车意图"},{"label":"D","content":"购买意愿和购买行为并不总是一致的，不可混为一谈"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":417,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400418,6,'逻辑判断','自从某中学在高三年级实行班主任岗位目标责任制后，学校的升学率逐年上升。由 此可见，只有实行班主任岗位目标责任制，才能使该校的升学率稳步增长。 以下哪项如果为真，最能削弱上述论证：','[{"label":"A","content":"近几年高校扩招，学生升学率整体形势较好"},{"label":"B","content":"没有实行班主任岗位目标责任制的A中学，近几年的升学率也在稳步上升"},{"label":"C","content":"前年该校开始实行教师薪酬改革，极大地调动了广大教师的积极性"},{"label":"D","content":"如果该校没有实行班主任岗位目标责任制，近两年的升学率会上升得更快"}]','D','【题型分类】 一般质疑类——严谨逻辑关系 【实战解析】题干结论是严谨逻辑关系，可翻译为：未实行班主任岗 位目标责任制→该校升学率不能稳步增长。想要削弱可以优先考虑A 且非B类选项③,即：未实行班主任岗位目标责任制且该校升学率稳 步增长。分析选项，D选项通过“假设”的形式给出了“未实行班主 任岗位目标责任制且该校升学率上升更快”⑧,与题干结论矛盾，当选； 其他选项： A 选项、C 选项，分别指出“近几年高校扩招”、“教师薪酬改革调 动了教师积极性”,即升学率稳步增长的原因不一定是因为班主任岗 位目标责任制，属于另有他因质疑，但本题属于严谨逻辑关系，“另 有他因”是归因类题目常见的质疑方式； B 选项，主体和题干不一致，虽然也能构成异因同果的三圈质疑， 但依然不如D 选项恰当。','逻辑判断600题','进阶','published','{"globalNumber":418,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400419,6,'逻辑判断','一些研究人员以859名初中生为被试者，连续三年在每年5月测量被试者的抑郁水 平、自我伤害度以及父母心理控制程度，研究人员根据被试者三次测量后抑郁和自 伤程度的发展轨迹，将被试者分为“低抑郁一低自伤一稳定组”“中抑郁一中自伤一 降低组”“低抑郁一低自伤一增长组”3组，经过对照发现，父母心理控制水平越 高的青少年属于“低抑郁一低自伤一增长组”的可能性越大，因此，父母心理控制 是造成青少年抑郁和自伤的主要人际因素。 以下哪项如果为真，最能支持上述观点：','[{"label":"A","content":"三年中青少年感知到的父母心理控制并没有下降"},{"label":"B","content":"青少年抑郁和自伤的发展轨迹在男女生中没有差异"},{"label":"C","content":"师生关系和同伴关系不能显著预测青少年抑郁和自伤的发展轨迹"},{"label":"D","content":"青少年个体的抑郁水平持续增强时也会随之提高其自伤行为的频率"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":419,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400420,6,'逻辑判断','汽车行业作为制造业中技术含量、智能化程度和产业集中度较高的代表，已经成为 了德国“工业4.0”的先导阵地。长期处于2.0工业思维的中国汽车制造业要在全 球占有一席之地，进行技术创新与变革和拥有丰富经验的资深人才必不可少，而高 薪和福利成为吸引人才的制胜法宝。 由此可以推出：','[{"label":"A","content":"如果能够吸引到资深人才，中国汽车制造业的改革就能成功"},{"label":"B","content":"高薪和福利是很多中国职场人士选择职业时的一个重要关注点"},{"label":"C","content":"不进行技术变革，中国汽车制造业就不能在全球占有一席之地"},{"label":"D","content":"德国汽车制造业在世界汽车行业具有举足轻重的地位和影响力 练习题22"}]','C','。 ③9花生批注： 题干命题的逆否命题 为“非技术创新改革 或未拥有人才→ 中国 汽车制造业不占有一 席之地”。 练习题22 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 论据：唾液内含有腮 腺激素，腮腺激素可 增强肌肉等组织活力， 强化血管弹性，提高 结缔组织生命力； 结论：用唾液涂抹面 部可以美容养颜。 ②花生批注： 前提假设类题目常见 正确答案为断点搭桥、 补充漏洞、能与不能(必 要条件); 观察选项也可看作是 在四个选项中寻找上 述三类选项。','逻辑判断600题','进阶','published','{"globalNumber":420,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400421,6,'逻辑判断','永葆青春，返老还童是我们每个人都追求的事情，唾液中就含有这样子极具魅力的 物质——腮腺激素，这种激素是由腮腺分泌的，许多学者认为它是“返老还童”的 激素。腮腺激素能增加肌肉，血管，结缔组织，骨骼，软骨和牙齿的活力，尤其能 强化血管的弹性，提高结缔组织的生命力。所以，用唾液涂抹面部，常常能收到意 想不到的美容养颜效果。 以上结论必须基于以下哪项假设：','[{"label":"A","content":"腮腺激素离开人体环境后不会变质，不会影响其效用的发挥"},{"label":"B","content":"具有美容作用的腮腺激素只能从人体中取得，其他动物的唾液则不具有这样的特点"},{"label":"C","content":"该研究是由专业科研团队花费数月时间，收集了上万名志愿者的样本情况完成的"},{"label":"D","content":"大部分人都能接受用唾液涂脸的美容方式"}]','A','【题型分类】前提假设——能与不能 【实战解析】论据结论见批注，未发现明显断点和漏洞，依次观察 选项： A 选项，指出腮腺激素离开人体后不会变质，依然有效用，可看作“能 与不能(即必要条件)”②类选项，若离开人体后发生变质，失去效用， 那么唾液涂抹脸部就不会实现美容养颜，属于“没他不行”选项，当选； B 选项、C 选项、D 选项均未谈及涂抹涂脸的美容养颜效用问题，排除。','逻辑判断600题','进阶','published','{"globalNumber":421,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400422,6,'逻辑判断','四位体育赛事评论员在比赛前对网球比赛的结果进行推测，他们都特别注意两位本 地选手张三和李四。 甲说：如果张三能打入决赛，那李四也能打入决赛。 乙说：依我看本地选手都不能打入决赛。 丙说：不管李四能否打入决赛，张三不能打入决赛。 厂说：我看李四不能打入决赛，但张三能打入决赛。 比赛结束后，发现上述推测只有一个为真，则以下哪项一定为真：','[{"label":"A","content":"丙的推测成立"},{"label":"B","content":"乙的推测成立"},{"label":"C","content":"如果李四能打入决赛，则丁的推测成立"},{"label":"D","content":"如果李四能打入决赛，则甲的推测成立"}]','D','【题型分类】分析类——真假分析 【实战解析】此类题目可首先找矛盾，甲丁③矛盾，则甲丁一真一假， 乙丙为假，排除A 、B 选项； 若李四打进决赛，此时甲为真(前件为假命题为真)⑨,D 选项正确， ③花生批注： 甲：张三→李四；丁： 张三且非李四； A→B与A且非B矛盾。 ④花生批注： 命题A→B 的真假判 断： 只在A且非B时为假； 前件为假(即非A成立， 不能满足A且非B), 命题为真； 后件为真(即B成立， 不能满足A且非B), 命题为真。 当选。','逻辑判断600题','进阶','published','{"globalNumber":422,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400423,6,'逻辑判断','对气候变暖的治理应当是为二氧化碳找出路，而不仅仅是减少排放或简单地掩埋它， 为此科学家提出富碳农业的理念，将人类活动特别是工业生产中产生的二氧化碳捕 集后，以高于大气中二氧化碳含量几倍的浓度，释放在密闭的人造气候小区域中， 利用相关科学技术，创造一个高效率的光合作用环境，从而极大提高农林作物的产量， 科学家认为富碳农业将成为解决气候变暖问题的重要途径。 下列陈述如果为真，哪项最能支持科学家的结论：','[{"label":"A","content":"传统农业需要使用阳光下的土地，而富碳农业可以不受此限制"},{"label":"B","content":"人造气候区域很难高效地使用太阳光来促进光合作用的发生"},{"label":"C","content":"现代技术能以较低的成本实现二氧化碳的捕集、运输和在密闭场所的释放"},{"label":"D","content":"富碳农业可以利用盐碱地、沙漠地、荒漠地等解决土地短缺问题"}]','C','【题型分类】支持类——必要条件 【实战解析】题干有结论有论据，具体见批注；结论和论据之间无明 显的断点和漏洞，依次观察选项： A 选项、D 选项，重点谈论富碳农业和土地的关系，未提及富碳农业 和气候变暖的关系，话题不一致，排除； B 选项，指出人造气候区域很难促进光合作用的发生，即富碳农业不 一定会提高农林作物的产量，削弱题干论证，排除； C 选项，指出现代技术可以以较低的成本实现二氧化碳的捕集、运输 和释放，可看作“必要条件(即能与不能)”类选项，若现代技术不 能实现二氧化碳的捕集、运输和释放，那么富碳农业也就不能解决气 候变暖问题，属于“没他不行”选项，当选。','逻辑判断600题','进阶','published','{"globalNumber":423,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400424,6,'逻辑判断','某项研究中，研究者追踪了该国19万名在1974年至1994年期间出生的人的医疗数 据，他们在2006年至2012年期间做过智力测试。在做智力测试时，大约有35%的 调查对象正因感染而住院。研究人员发现，那些因感染而住院者的智商分数平均比 一般人低1.76分。而那些因感染住了5次及以上医院的人，智商分数平均比一般人 低9.44分。研究人员指出，人体感染会造成个体智商下降。 以下哪项如果为真，最能削弱以上结论：','[{"label":"A","content":"大脑周围组织感染会影响大脑的智力水平"},{"label":"B","content":"有证据表明，感染会影响痴呆病人的认知能力"},{"label":"C","content":"智商是对心智能力的评价方式，存在着测量误差"},{"label":"D","content":"患病使得患者情绪紧张，测试时注意力不集中"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":424,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400425,6,'逻辑判断','某中学高中部所有喜欢球类运动的学生都参加过学校的运动会。因此，有些喜欢美 术的同学不喜欢球类运动。 为使上述论证成立，关于该中学高中部学生的断定必须假设的是：','[{"label":"A","content":"所有喜欢球类运动的学生都不喜欢美术"},{"label":"B","content":"参加过学校运动会的学生都喜欢球类运动"},{"label":"C","content":"所有喜欢美术的同学都没参加过学校的运动会"},{"label":"D","content":"有些喜欢美术的同学没有参加过学校的运动会"}]','D','。 ⑧花生批注： 三段论一般由一个“所 有”和两个“有些”或“特 例”组成。 ⑨花生批注： 三段论三个概念应分 别出现两次，例如此 题的“喜欢球类”、 “参加过运动会”、“喜 欢美术”均要出现两次。','逻辑判断600题','进阶','published','{"globalNumber":425,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400426,6,'逻辑判断','螺旋锥蝇是一种极具攻击性的食肉蝇，偏好鲜血和活肉，喜欢攻击恒温动物(比如 人类、牲畜)身上的小伤口，传播各类病菌。科学研究发现，雌螺旋锥蝇是单配性的， 一生只能交配一次。据此，有科学家提出一种“以蝇制蝇”的昆虫绝育方法来消灭 螺旋锥蝇，即将雄蝇置于超高辐射之下使其失去繁殖能力后放生到野外，如果雌蝇 与之交配，产下的卵将不会孵化，日积月累，整个螺旋锥蝇种族就会自然消失。 以下各项如果为真，则除哪项外均能质疑上述科学家的建议：','[{"label":"A","content":"经实验改造的绝育雄蝇数量不一定多于自然状态下有生育能力的雄蝇"},{"label":"B","content":"用放射性手段改变雄螺旋锥蝇的特性，可能会破坏大自然的生态平衡"},{"label":"C","content":"雌螺旋锥蝇有可能会排斥经过超高辐射而失去繁殖能力的雄螺旋锥蝇"},{"label":"D","content":"虽然雌螺旋锥蝇是单配性的，但雄螺旋锥蝇可与多只雌螺旋锥蝇交配"}]','D','①。','逻辑判断600题','进阶','published','{"globalNumber":426,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400427,6,'逻辑判断','泛欧亚语系包括日语、韩语、通古斯语、蒙古语、突厥语，在整个欧亚大陆传播， 从东面的日本、韩国、西伯利亚一直延伸到西面的土耳其，其起源和传播途径一直 存在争议。有一种“牧民假说”,认为泛欧亚语系起于公元前2000年到1000年左右， 是当时亚洲东都草原牧民的语言，后因这些牧民向外游牧迁徙面传播开来。 以下哪项组合为真，最能质疑“牧民假说”: ①古代辽河流域农民不断向东向北向西，迁徙到新水源地居住并从事农业生产劳动 ②有研究认为，泛欧亚语系是由人口扩数、农牧业发展等原因向东向北向西传播的 ③随着这些农民的迁徙，泛欧亚语系被带到了韩国、日本，西伯利亚和土耳其等地 ④最新研究证明，泛欧亚语系起源于9000年前的中国辽河流域，是当地农民的语言','[{"label":"A","content":"①②③"},{"label":"B","content":"①③④"},{"label":"C","content":"①②④"},{"label":"D","content":"②③④"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":427,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400428,6,'逻辑判断','某网购平台发布了一份网购调研报告，分析亚洲女性的网购特点。分析显示，当代 亚洲女性在网购服饰、化妆品方面的决定权为88%,在网购家居用品方面的决定权 为85%。研究者由此认为，那些喜爱网购的亚洲女性在家庭中拥有更大的控制权。 以下哪项如果为真，最能反驳上述结论：','[{"label":"A","content":"喜爱网购的亚洲女性的网购支出只占其家庭消费支出的25%"},{"label":"B","content":"亚洲女性中，习惯上网购物的人数只占女性总人数的30%左右"},{"label":"C","content":"亚洲女性在购买贵重商品时往往会与丈夫商量，共同决定"},{"label":"D","content":"一些亚洲女性经济不独立，对家庭收入没有贡献"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":428,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400429,6,'逻辑判断','2008年上半年原油期货价格一度上涨到每桶147美元，是2000年同期价格的4.2倍， 年均增长20%,而同期世界经济年均增长率在5%左右，世界石油消费需求并没有出 现跳跃式的、急剧的增长。这说明原油价格的迅速攀升并不是由于世界石油供求关 系的变化引起的，而是国际投机资本在石油期货市场进行疯狂投机的结果。 如果以下各项为真，哪项不能质疑上述推论：','[{"label":"A","content":"2000 年至2008年，各国政府普遍加大了石油的战略储备量"},{"label":"B","content":"较小的经济增长率总带来较大的石油需求增长率"},{"label":"C","content":"石油需求变化率和石油价格变化率并不对称"},{"label":"D","content":"即便对于国际投机资本本身，投资石油期货也是风险巨大"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":429,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400430,6,'逻辑判断','9月初大学入学报到时，有多家手机运营商到某大学校园进行产品销售宣传。有好 几家运营商推出了免费套餐服务。但是其中一家运营商推出了价格优惠的套餐，同 时其业务员向学生宣传说：其他运营商所谓的“免费”套餐是通过出售消费者的身 份信息来获得运营费用的。 134 以下哪项如果为真，最能质疑该业务员的宣传：','[{"label":"A","content":"免费套餐运营商所提供的手机信号质量很差"},{"label":"B","content":"免费套餐运营商是通过广告来获得运营费用的"},{"label":"C","content":"有法律明确规定，手机运营商不得出售消费者的身份信息"},{"label":"D","content":"很难保证价格优惠的运营商不会同样出售消费者的身份信息"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":430,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400431,6,'逻辑判断','某国的科研机构跟踪研究了出生于上世纪50至70年代的1万多人的精神健康状况， 其间测试了他们在13岁至18岁时的语言能力、空间感知能力和归纳能力。结果发现， 在此期间语言能力远低于同龄人水平的青少年，成年后患精神分裂症等精神疾病的 风险较高。研究人员认为，青少年期语言能力的高低将是预测成年后精神疾病的重 要指标。 以下哪项如果为真，能够质疑上述观点：','[{"label":"A","content":"青少年期激素分泌水平异常，影响大脑发育，导致语言能力发展迟缓"},{"label":"B","content":"患精神分裂症的青少年，其归纳能力相比语言能力的发展更加缓慢"},{"label":"C","content":"许多精神健康的脑肿瘤患者在青少年时期也经常出现语言能力发展迟缓的问题"},{"label":"D","content":"适当的教育可显著提高青少年的语言能力，但对中老年人影响不大"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":431,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400432,6,'逻辑判断','提起极地冰，很多人眼前总是浮现出一幅洁白无瑕，晶莹剔透的景观，然而，在 北 纬 7 1 度 ，西经168度附近的北冰洋海域，“雪龙”号首次驶入一片“脏”冰区足见 一块淡蓝色的浮冰中间夹杂了许多黄色冰块，这种黄色冰块，既出现在当年的新生 冰块上，也出现在多年冰块上，对于“人类造成的污染已经殃及极地浮冰”的说法， 有专家解释说这只是生活在极地冰中的一种特有生物——黄褐色的冰藻。 如果以下各项为真，能够反驳专家上述观点的是：','[{"label":"A","content":"在新生冰块上形成冰藻需要多年"},{"label":"B","content":"北极冰中生长有冰藻并不是普遍现象"},{"label":"C","content":"近年来人类踏上北极的次数逐年增加"},{"label":"D","content":"北冰洋周围陆地常有沙尘天气"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":432,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400433,6,'逻辑判断','研究显示，在115摄氏度下，将甜玉米分别加热10分钟、25分钟和50分钟后发现， 其抗自由基的活性分别升高了22%、44%和53%,因此，加热时间越长的玉米，抗衰 老的作用越好。 以下各项如果为真，无法削弱上述结论的是：','[{"label":"A","content":"加热65分钟后，玉米抗自由基的活性反而降低了"},{"label":"B","content":"与甜玉米相比，糯玉米在加热相同时间后，其抗自由基的活性增高的幅度很小"},{"label":"C","content":"甜玉米是玉米中比较少见的一种，不具有代表性"},{"label":"D","content":"对于玉米来说，并非是抗自由基的活性越高，其抗衰老的作用越好 135"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":433,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400434,6,'逻辑判断','甲、乙、丙、丁4个人在一起议论今年种植冬瓜，南瓜，西瓜，丝瓜的情况。甲说： “乙和丙每人种了两种瓜，但是乙和丙一共种了三种瓜”。乙说：“甲只种了西瓜， 我和甲一共种了三种瓜”。丙说：“丁种了三种瓜，有一种瓜丁没有种，我却种了”。 丁说：“我没有种西瓜”。 已知所有人说的都是真话，下列说法错误的是：','[{"label":"A","content":"甲和丙一共种了两种瓜"},{"label":"B","content":"丙和丁一共种了4种瓜"},{"label":"C","content":"乙和丙可能都种了西瓜"},{"label":"D","content":"甲和丁一共种了4种瓜"}]','C','； D 选项，如图所示，甲丁共种四种瓜，正确。 四 海公 煮 SIHAIGONGKAO','逻辑判断600题','进阶','published','{"globalNumber":434,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400435,6,'逻辑判断','甲、乙、丙、丁四人的血型各不相同，甲说：“我是A型。”乙说：“我是0型。” 丙说：“我是AB型。”丁说：“我不是AB型。”四人中只有一个人的话是假的。 以下哪项成立：','[{"label":"A","content":"无论谁说假话，都能推出四个人的血型情况"},{"label":"B","content":"乙的话假，可推出四个人的血型情况"},{"label":"C","content":"丙的话假，可推出四个人的血型情况"},{"label":"D","content":"丁的话假，可推出四个人的血型情况"}]','B','项 ( 若 将A 选 项 理 解为无论甲乙谁说假 话，都能推出四人血 型，那么A 选项也正 确 ) 。','逻辑判断600题','进阶','published','{"globalNumber":435,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400436,6,'逻辑判断','甲乙丙丁四位同学刚好住在以三坊七巷为中心的东西南北四个方向，他们发现甲住 在丙的西南方向，丙住在乙的东南方向。 根据以上陈述，可以得出下列哪项结论：','[{"label":"A","content":"三坊七巷在甲的北面"},{"label":"B","content":"丁住在乙的东南方"},{"label":"C","content":"丙住在丁的东北方"},{"label":"D","content":"乙住在三坊七巷的南面"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":436,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400437,6,'逻辑判断','现代企业在管理过程中发现，人力资源管理部门对于公司的发展虽然十分重要，但 由于该部门并没有全程参与公司发展战略的决策，而且公司聘请的高级经理均由 CEO决定，所以人力资源管理部门更多的时候起到的是支持和辅助的作用。 如果以下各项为真，最能削弱上述论证的是：','[{"label":"A","content":"世界500强的企业中，人力资源管理部门的员工一般都有丰富的经验"},{"label":"B","content":"人力资源管理部门能为公司设计出人性化的报酬体系，进而留住人才"},{"label":"C","content":"世界上最大的物流公司，人力资源部经理有权参加公司最高决策会议"},{"label":"D","content":"人力资源部虽没有决定雇用高级经理的权力，但有权雇用中层管理者"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":437,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400438,6,'逻辑判断','为了确保我校代表队能够夺冠，A 领导对教练施压，要求更换几位参赛队员。A领导 坚持认为，预选赛突然冒尖的几个人应该更换为平时成绩一直居前且预选赛稳定发 挥但预选赛落选的人员。 A领导的行为最主要基于他做出的以下哪一种假设： 逻辑判断600','[{"label":"A","content":"认真遴选参赛人员，是参赛方的职责所在"},{"label":"B","content":"其他领导面对参赛人员的名单也会做出类似的调整建议"},{"label":"C","content":"A 领导提议更换的新参赛人员将会一如既往地稳定发挥"},{"label":"D","content":"预选赛突然冒尖的队员几个月前成绩不如提议更换的新参赛队员"}]','C','。 ③0花生批注： “能与不能”即必要 条件，可从反面思考， 若领导建议更换的参 赛人员不能一如既往 的稳定发挥，该建议 就不可行，所以此类 选项可看作必要条件 的前提假设。 ③花生批注： 前提假设类题目三种 常见选项：断点搭桥， 补充漏洞，能与不能(必 要条件 ); 看到“能不能”"可 不可以”选项，应重视。 ③花生批注： “没有”可理解为“所 有都不”,其矛盾为“有 些是”。 33花生批注： “有些不”的矛盾为“所 有都是”。 ③④花生批注： A→B 为假，则A 且 非B为真。','逻辑判断600题','进阶','published','{"globalNumber":438,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400439,6,'逻辑判断','小李、小张、小马、小王在一起讨论N地区的廉租房建设情况： 小李说：“N地区的廉租房建设得都不错。” 小张说：“N 地区没有廉租房建设得好。” 小马说：“N地区有的廉租房建设得不好。” 小王说：“N 地区还是有廉租房建设得不错的。” 假如小张和小马都说错了，那么,可以推出：','[{"label":"A","content":"小李说错了"},{"label":"B","content":"小李和小王说错了"},{"label":"C","content":"小王说错了"},{"label":"D","content":"小王说对了"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":439,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400440,6,'逻辑判断','陶言诚人如其名，说话很讲信用，有一次单位召开田径运动会，他说：“如果我得 了短跑冠军，我就开始练习长跑。” 以下哪项为真，则说明陶言诚没有兑现承诺： I. 陶言诚得了短跑冠军，没有开始练习长跑 Ⅱ. 陶言诚没有得短跑冠军，却开始练习长跑 Ⅲ. 陶言诚没有得短跑冠军，没有开始练习长跑','[{"label":"A","content":"仅 I"},{"label":"B","content":"仅Ⅱ"},{"label":"C","content":"仅Ⅲ"},{"label":"D","content":"仅 I 和Ⅱ 练习题23"}]','A','。 练习题23 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":440,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400441,6,'逻辑判断','某单位评选优秀员工，要从男员工甲、乙、丙中选出2名，从女员工丁、戊、己、 庚中选出2名，共4名，已知 ①甲、丙不能同时入选 ②丁、己不能同时入选 ③戊、庚不能同时入选 ④乙、戊不能同时入选 更 多 资 料 添 加 ：KZ4327 若同时满足以上条件，可以选出：','[{"label":"A","content":"丁入选优秀员工"},{"label":"B","content":"庚入选优秀员工"},{"label":"C","content":"丙入选优秀员工"},{"label":"D","content":"戊入选优秀员工"}]','B','①。','逻辑判断600题','进阶','published','{"globalNumber":441,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400442,6,'逻辑判断','为了提高国内青少年的身体素质，有人建议增加义务教育阶段体育课的课时。因为 体育课课时越多，中小学生进行体育锻炼的时间越长，他们的身体素质就会越好。 要使上述论证成立，必须补充的前提是：','[{"label":"A","content":"中 小学生会在体育课上进行体育锻炼"},{"label":"B","content":"体育课课时越少，中小学生体育锻炼时间也越短"},{"label":"C","content":"体育课是中小学生提升身体素质的唯一途径"},{"label":"D","content":"增加体育锻炼时间有利于提高身体素质"}]','A','【题型分类】前提假设类——能与不能 【实战解析】题干中没有明显断点和漏洞，优先考虑“能与不能”③, 观察选项： A 选项，指出体育课上会进行体育锻炼(即“能进行”、“可以进行”), 可看作“能与不能(即必要条件)”选项，若体育课上不能进行体育 锻炼，即使体育课时再多，也无法改变青少年身体素质，属于“没他 不行”选项； B 选项、D 选项，与题干论据中的逻辑相同，重复了题干论据，不是 论证前提； C 选项，即使体育课不是中小学生提升身体素质的唯一途径，增加体 育课课时也可能提升青少年身体素质，属于“没他也行”选项； 综上，只有A 选项是结论成立的前提。','逻辑判断600题','进阶','published','{"globalNumber":442,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400443,6,'逻辑判断','由于按揭贷款的利率下调，人们每月还贷压力减小，因此一家机构预测某地的商品 房销售量会增长，但实际上，销售量并未出现明显增长。 下列哪项如果为真，最能解释以上现象：','[{"label":"A","content":"当地一直存在人口外流的现象"},{"label":"B","content":"本地的商品房价格没有明显下降"},{"label":"C","content":"有的开发商取消了购房优惠政策"},{"label":"D","content":"因经济环境不好，当地人均收入下降"}]','D','【题型分类】解释解释类 【实战解析】题干矛盾见批注，分析选项： A 选项，商品房销量短期看政策，长期看人口。因此人口外流并不能 解释出台政策利好后短期内房价的波动；并且，人口外流是一真存在 的情况，无法解释出现新变化(政策利好)后，为什么销售量未增长； B 选项，利率下降是刺激商品房销量的利好政策，即使房价没有下降， 商品房销量也应该上涨，该项不能解释题干矛盾； C 选项，“有的”开发商取消优惠，属于个别现象，无法解释市场整 体表现； D 选 项 ，因为当地人均收入下降，所以百姓手里资金变少，所以即使 还贷压力减少⑤,商品房销量依然没有增加，该项可以解释题干矛盾； 综上，本题选D ⑤花生批注： 虽然还贷少了，但是 收入也少了，相互抵消， 所以销售量无变化。','逻辑判断600题','进阶','published','{"globalNumber":443,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400444,6,'逻辑判断','新学期开始，小彤、小薇、小倩都买了新手机，手机的牌子分别是苹果、小米、华为。 她们让室友小涵猜她们买的是什么牌子的手机。小涵猜道：“小彤买的是苹果手机， 小倩买的不是华为手机，小薇买的不是苹果手机。”事实上，小涵的上述猜测，只 对了一个。 由上述断定可推出以下哪项结论：','[{"label":"A","content":"小彤买的是小米，小薇买的是苹果，小倩买的是华为"},{"label":"B","content":"小彤买的是苹果，小薇买的是华为，小倩买的是小米"},{"label":"C","content":"小彤买的是苹果，小薇买的是小米，小倩买的是华为"},{"label":"D","content":"小彤买的是华为，小薇买的是苹果，小倩买的是小米"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":444,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400445,6,'逻辑判断','不同于以往的整车充电模式，换电模式是将新能源汽车的电池进行更换，以满足车 主的续航需求，是一种将车和电池分离进行补能的模式，某市积极投入新能源汽车 方面的建设，同时该市的新能源汽车换电站数量增长1.52倍，由于该市今年年初出 台了换电站建设政府补贴政策，因此有人认为，该补贴政策的出台，增强了市场主 体的积极性，是该市今年换电站建设数量增长的原因。 以下哪项如果为真，不能削弱上述结论：','[{"label":"A","content":"据统计，该市换电站建设数量连续三年同比增长超过1.5倍"},{"label":"B","content":"该市政府从今年年初开始开展多部门协同配合，助力换电站建设"},{"label":"C","content":"临近省市均采取了除政府补贴政策以外的其他措施促进换电站建设"},{"label":"D","content":"与去年相比，该市新能源汽车数量大幅增长，对换电站的市场需求增加"}]','C','C。','逻辑判断600题','进阶','published','{"globalNumber":445,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400446,6,'逻辑判断','宿舍有甲乙丙丁四名室友，某日，宿舍里的凳子少了几把，辅导员问是谁拿走了凳子， 四位室友各有说辞： 甲说：“我们中有人拿走了凳子” 乙说：“我们四人都没有拿走凳子” 丙说：“乙和丁至少有一人没有拿走凳子” 丁说：“我没有拿走凳子” 如果室友中有两人说的是真话，两人说的是假话，则说真话的是：','[{"label":"A","content":"甲和丙"},{"label":"B","content":"甲和丁"},{"label":"C","content":"乙和丙"},{"label":"D","content":"乙和丁"}]','A','。 ⑪花 生批注： “特例”可推出“有些”。','逻辑判断600题','进阶','published','{"globalNumber":446,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400447,6,'逻辑判断','天天公司将生产线由A县搬至B 县，这对两个县来说都是好事，因为这一做法提高 了两县企业的平均生产效率。 若上述论断成立，则必须补充的前提是： ①天天公司的生产效率比A县其他企业都低 ②天天公司的生产效率低于A县企业的平均生产效率 ③B县企业的平均生产效率低于A县企业 ④B县企业的生产效率普遍低于A县企业','[{"label":"A","content":"①④"},{"label":"B","content":"①③"},{"label":"C","content":"②③"},{"label":"D","content":"②④ 139"}]','C','。 ⑬花生批注： 题干论据进行对比实 验，按照“陆地和海洋” 进行分组，将“物种 更加多样化”归因于“陆 地物理布局更加破碎”。','逻辑判断600题','进阶','published','{"globalNumber":447,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400448,6,'逻辑判断','地球表面的大部分都被海洋覆盖，生命也诞生于海洋之中。然而，据估计，地球有 80%的物种生活在陆地上，而海洋中仅为15%,剩下的5%生活在淡水中。研究者认为， 陆地栖息地的物理布局相对海洋可能更加支离破碎，是导致陆地物种更加多样化的 主要原因之一。 以下哪项如果为真，最能加强上述研究者的观点：','[{"label":"A","content":"地球表面可分成热带、南温带、北温带、南寒带、北寒带五个温度带，各温度带 物种差异性大，种类丰富"},{"label":"B","content":"深海相对于有阳光照射的浅海岸地区而言，基本上像个冰箱，而且门已经关上很 久，物种远不如浅海丰富"},{"label":"C","content":"根据某群岛记录显示，随着时间推移，自然选择甚至可以把两个岛屿上相同物种 的不同族群变成截然不同的物种"},{"label":"D","content":"森林覆盖许多陆地，而树叶和枝干形成新的生态环境，海洋中的珊瑚也起同样作 用，但覆盖海底的面积没那么大"}]','C','。 四海公煮 逻辑判断','逻辑判断600题','进阶','published','{"globalNumber":448,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400449,6,'逻辑判断','大学毕业的张、王、李、赵4人应聘到了同一家大型公司，每人负责一项工作。其 中一人为行政管理，一人做销售，一人做研发，另一人做安保。已知： ①张不做行政管理，也不做安保； ②王不做行政管理，也不做研发； ③如果张没有做研发，那么赵也没有做行政管理； ④李不做行政管理，也不做安保； ⑤赵不做研发，也不做安保。 由此可以推出：','[{"label":"A","content":"张做销售，李做研发"},{"label":"B","content":"赵做研发，李做销售"},{"label":"C","content":"李做销售，张做研发"},{"label":"D","content":"李做研发，赵做安保"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":449,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400450,6,'逻辑判断','在A市的B 区有多家茶馆，这些茶馆要么会有评书表演，要么会有弹唱表演。 如果上述论断为真，则以下哪项一定为真： ①如果A市的一家茶馆没有任何文艺表演，那么它一定不在B 区 ②如果A市的一家茶馆有文艺表演，那么它一定在B 区。 ③ A市 B区的一些茶馆有评书表演。','[{"label":"A","content":"仅①"},{"label":"B","content":"仅②"},{"label":"C","content":"仅③"},{"label":"D","content":"①②③"}]','A','。 347 ⑪花生批注： 论据：Y 染色体中的基 因一直在减少。 结论：Y 染色体的消亡 会导致人类消亡。 ⑱花生批注： 虽然Y 染色体消亡， 但人类有其他繁殖方 法，所以人类也不一 定走向消亡。 ⑲花生批注： 论据：在模拟火星的 土壤中种出了安全健 康的可食用农作物。 结论：殖民火星的希 望又向前迈进了一步。','逻辑判断600题','进阶','published','{"globalNumber":450,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400451,6,'逻辑判断','有研究表明，要成为男性至少需要拥有一条Y染色体。3亿年前，男性特有的Y 染 色体在产生之际含有1438个基因，但现在只剩下45个。按照这种速度，Y染色体 将在大约1000万年内消失殆尽。因此，随着Y染色体的消亡，人类也将走向消亡。 如果以下各项为真，最不能质疑上述论证的是：','[{"label":"A","content":"恒河猴Y染色体基因确实经历过早期高速的丧失过程，但在过去的2500万年内 则未丢失任何一个基因"},{"label":"B","content":"男性即使失去Y染色体也有可能继续生存下去，因为其他染色体有类似基因可以 分担Y染色体的功能"},{"label":"C","content":"人类进化过程中，可以找到单性繁殖或无性繁殖后代的方法，从而避免因基因缺 失引发的繁殖风险"},{"label":"D","content":"Y 染色体存在独特的回文结构，该结构具有自我修复功能，可以保持丢失基因的 信 息 ，实现基因再生"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":451,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400452,6,'逻辑判断','荷兰研究人员一直在试图模拟月球和火星的土壤条件进行农作物栽培实验。他们对 该项实验种出的小红萝卜、豌豆、黑麦和西红柿进行初步分析。实验结果令人充满 希望，这些产品不仅安全，而且可能比在地球土壤种出的农作物更健康。英国媒体称， 能在火星土壤种出可食用作物，殖民火星的希望又向前迈进了一步。 如果以下各项为真，不能质疑英国媒体说法的是：','[{"label":"A","content":"火星土壤重金属占比和地球土壤不一样"},{"label":"B","content":"在另一个同类实验中土豆的长势很糟糕"},{"label":"C","content":"从实验到真正付诸实践还有很长的路要走"},{"label":"D","content":"月球、火星、地球的气候条件有很大不同"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":452,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400453,6,'逻辑判断','为了解当下大学生对军事的关注程度，某教授列举了20种军事装备，请30位大学 生识别。结果显示，多数人只识别出2到6种装备，极少数人识别出15种以上， 甚 至有人全部都不能识别。其中“海鹞战斗机”的辨识率最高，30人中有19人识别正确； “舰载式战斗机”所有人都未能识别。20种军事装备的整体识别错误率超过75%。 该实验者由此得出，当代大学生对军事的关注程度并没有提高，甚至有所下降。 以下哪项如果为真，最能对该教授的结论构成质疑：','[{"label":"A","content":"教授选取的20种军事装备不具有代表性"},{"label":"B","content":"教授选取的30位大学生均不是军事院校的学生"},{"label":"C","content":"“舰载式战斗机”这种战斗装备有些军事迷也未能识别"},{"label":"D","content":"教授选取的30位大学生中约50%有对军事不感兴趣 141 141"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":453,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400454,6,'逻辑判断','科学家奇克发现，体重指数( BMI, 一种利用身高与体重的比例来衡量胖瘦的方法) 和记忆衰退之间具有清晰的联系。在实验中，BMI更高的参加者表现得更加糟糕。 奇克的研究结果显示，肥胖可能会引起脑萎缩和记忆衰退。 以下哪项如果为真，最能质疑上述结论：','[{"label":"A","content":"通过外科手术将肥胖的腹部脂肪移植入消瘦的小鼠体中，发现这些脂肪造成了消 瘦小鼠的脑部炎症，改变了突触功能，导致了被移植小鼠的认知障碍"},{"label":"B","content":"一个包括了500名参与者的脑部扫描研究证实，肥胖与因年龄增长而造成的大脑 退化有密切关系，这种影响在中年人中尤为明显"},{"label":"C","content":"某医学院报道，海马体位于大脑深处，负责学习和记忆的功能，腹部脂肪含量较 高的中年人，其海马体的容量要比纤瘦的人小"},{"label":"D","content":"有科学家发现，午餐时被分散注意力的人对于午餐的记忆比较模糊，导致他们在 晚餐时会感到更饥饿，吃得更多。由此得出结论，记忆缺陷会引起体重增长"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":454,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400455,6,'逻辑判断','民间有“三九补一冬，来年无病痛”和“冬令进补，开春打虎”等说法，所以大多 数人都认为冬季是最佳进补的季节。 以下哪项如果为真，最能削弱上述观点：','[{"label":"A","content":"当人们缺乏某些必需的营养时，应根据情况选用对应的补药"},{"label":"B","content":"冬天空气干燥，及时补充水分或多吃水果，对人体健康有益"},{"label":"C","content":"如果不缺乏营养，过分补充某一种营养，可能会对身体有害"},{"label":"D","content":"过去冬天保暖措施不佳且人多数营养不良，现在情况已相反"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":455,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400456,6,'逻辑判断','为摸清青山乡的贫困状况，某调查组决定在该乡东坡村、南江村、西河村及北山村 展开实地调查。调查组由张军、王刚、李伟、蒋松4位中年人与赵新、钱芳、朱海、 程明4位年青人组成。为了方便调查，调查组决定两人一组，中青搭配，各选一村 展开调查，各组所调查的村落并不相同。因各人对青山乡贫困状况的了解差异，所 以有如下情况： (1)张军选择去北山村，赵新选择去南江村； (2)东坡村和南江村，钱芳至少选择一个； (3)如果王刚去西河村，则朱海也去西河村； (4)如果钱芳去东坡村，则程明去西河村。 事实上，四村调查顺利展开，上述8人的选择也都得以实现。 根据上述信息，可以得出下列哪两人一定没有结伴调查：','[{"label":"A","content":"张军和朱海"},{"label":"B","content":"王刚和程明"},{"label":"C","content":"李伟和钱芳"},{"label":"D","content":"蒋松和赵新"}]','B','。 四海公考 SIHAI GONGKA0','逻辑判断600题','进阶','published','{"globalNumber":456,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400457,6,'逻辑判断','六位同学参加体能测试，学号分别是1至6号。测试结果出来后，五名考官分别说 了五句话： ①1号、5号、6号三人中只有两人达标 ②1号和2号两人最少有一个达标 ③2号和3号两人要么都达标，要么都没有达标 ④1号和4号两人中只有一人达标 ⑤3号和4号两人中也只有一人达标 以上都是事实。据此，可以推出全部达标人数是：','[{"label":"A","content":"3"},{"label":"B","content":"4"},{"label":"C","content":"5"},{"label":"D","content":"6"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":457,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400458,6,'逻辑判断','从世界经济的发展历程来看，如果一国或者地区的经济保持着稳定的增长速度，大 多数商品和服务的价格必然会随之上涨，只要这种涨幅始终在一个较小的区间内就 不会对经济造成负面影响。 由此可以推出，在一定时期内：','[{"label":"A","content":"如果大多数商品价格上涨，说明该国经济在稳定增长"},{"label":"B","content":"如果大多数商品价格涨幅过大，对该国经济必然有负面影响"},{"label":"C","content":"如果大多数商品价格不上涨，说明该国经济没有保持稳定增长"},{"label":"D","content":"如果经济发展水平下降，该国的大多数商品价格也会下降"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":458,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400459,6,'逻辑判断','尽管在大多数看来，地震并非人力所能影响或控制，但是最新的一项研究成果却显示， 人类排放温室气体的行为是导致地震频发的原因。 对此 ，有反对者指出，地震是由 气候变化引起的，气候变化可能会引起地球板块运动，从而刺激地震的发生。但研 究人员也强调，虽然板块运动可能会导致地震出现，但这是一个非常漫长的过程， 而非突发性的事件。 以下哪项如果为真，最能削弱反对者的观点：','[{"label":"A","content":"之前科学界公认，地震引发的地壳运动会对气候的变化带来影响"},{"label":"B","content":"研究结果显示，人类排放温室气体的行为是导致气候变化的原因"},{"label":"C","content":"印度洋季风使得印度洋板块活动加速大约20%,每年多移动约1厘米的距离"},{"label":"D","content":"目前全球气候变暖是否会导致更大规模地震的发生，还未得到相关证据证实"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":459,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400460,6,'逻辑判断','张、王、李、孟4人到上海、广州、成都、西安4城市调研，每人调研2个城市， 且4人调研的城市均不完全相同。已知： (1)若李、孟均不去成都，则王去广州； (2)若王去上海或广州，则张、李均不去西安。 若只有李去了广州且张未去成都，则可以得出下列哪项：','[{"label":"A","content":"张、孟均去上海"},{"label":"B","content":"张、孟均去成都"},{"label":"C","content":"张、孟均不去上海"},{"label":"D","content":"张、孟均不去成都 练习题24"}]','A','。 ③花生批注： 张去西安或李去西安 → 王不去上海且不去 广州。 翻译规则：“A 或B” 的否定是“非A 且非 B”。 ③花生批注： 王不去广州 → 李去成 都或孟去成都。 练习题24 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 既成事实：冷事件后， 龙山文化南移代替大 汶口文化，大汶口文 化向南迁移； 原因分析：极端气候 变化导致文化变迁。','逻辑判断600题','进阶','published','{"globalNumber":460,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400461,6,'逻辑判断','5000多年前某地是大汶口文化，但在距今约4400年的时候，为龙山文化所替代。是 什么原因导致这两种文化的更迭?考古人员发现，在距今约4400年的时候，发生了 一次严重的“冷事件”,环境由原来的温暖湿润转变为寒冷干燥，植被大量减少，藻类、 水生植物基本绝迹了，大汶口文化向南迁移，而龙山文化由北迁到此地。他们据此认为， 距今4400年左右的极端气候变化，可能是导致这次文化变迁的主要原因。 以下哪项如果为真，最能支持上述论证：','[{"label":"A","content":"大汶口文化有不断向南方迁移的传统"},{"label":"B","content":"龙山文化刚迁来时，人口较多，但之后逐渐减少，在距今约4000年的时候消失了"},{"label":"C","content":"大汶口文化的族群以藻类和水生植物作为食物的主要来源"},{"label":"D","content":"不同生存方式的族群对气候和环境都有相对稳定的需求 更 多 资 料 添 加 ：KZ4327"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":461,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400462,6,'逻辑判断','在不同语言中，数字的发音和写法都不一样。一些科学家认为，代表不同文化背景 的语言，会对人们大脑处理数学信息的方式产生影响。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"相比欧洲，亚洲地区的人们在进行数量大小比较时，大脑中个别区域的活跃程度 有所不同"},{"label":"B","content":"在同一国家，不同方言区的人们进行数学运算时，大脑语言区的神经传递路线并 不十分一致"},{"label":"C","content":"研究发现，以英语为母语的人进行心算时主要依赖大脑的语言区，而以中文为母 语的人主要动用了大脑的视觉信息识别区"},{"label":"D","content":"研究发现，不同专业背景的人们在计算数学题时会选择不同的思考方法，但都会 不同程度地依赖大脑的语言区"}]','C','。 ②花生批注： 题干只有结论：代表 不同文化背景的语言， 会影响人们大脑处理 数学信息的方式。 ③花生批注： 例如，我国江浙地区 的多种方言虽然发音 与用法不同，但是具 有相似的文化与历史 背景。 357 逻辑判断 ④花生批注： 全部推理过程如下： 假设乙为真，则甲为真 (前件为假命题为真); 假设丙为真，则甲为真 (后件为真命题为真); 则乙丙均为假，实际 为甲作案、乙未作案； 则甲为假( A 且非丙成 立 ，A→B 为假); 那么唯一一真为丁； 实际情况为：甲作案， 乙丁未作案，丙不确定。 ⑤花生批注： 既成事实：火星上的 奥林帕斯山是太阳系 中已知的最高火山 ⑥花生批注： 原因分析：相比地球 而言，火星的重力较 低且火山喷发的频率 较高，造山熔岩流在 火星上持续的时间比 在地球上要长得多 ⑦花生批注： 题干将火星上山峰更 高的原因归于火星重 力较低且火山喷发频 率高。','逻辑判断600题','进阶','published','{"globalNumber":462,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400463,6,'逻辑判断','甲、乙、丙、丁四人因涉嫌盗窃案被传唤。 甲说：如果我作案，乙也会参与； 乙说：甲没有干； 丙说：乙作了案； 丁说：我没有干。 已知以上说法只有一个是真的，下列选项成立的是：','[{"label":"A","content":"丁作了案"},{"label":"B","content":"四人都没有作案"},{"label":"C","content":"乙作了案"},{"label":"D","content":"甲作了案"}]','D','④。','逻辑判断600题','进阶','published','{"globalNumber":463,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400464,6,'逻辑判断','火星的奥林帕斯山是太阳系中已知的最高火山，高度为25000米，几乎是地球上最 高峰——珠穆朗玛峰的3倍。研究人员认为奥林帕斯山具有如此令人称奇的高度， 主要是因为相比地球而言，火星的重力较低且火山喷发的频率较高，造山熔岩流在 火星上持续的时间比在地球上要长得多，故而形成了巨大火山。 以下哪项为真，最能削弱上述结论：','[{"label":"A","content":"土星、木星属于气体星球，由于没有地幔运动，也就没有火山爆发"},{"label":"B","content":"地球上的河流常会侵蚀山脉的边缘物质，引发山体滑坡，这就限制了山峰生长"},{"label":"C","content":"金星与地球重力相近，金星上火山喷发的频率极高，可谓火山密布，但火山大多 不高"},{"label":"D","content":"一些与火星相似的星体，虽火山喷发活跃，熔岩持续出现，但因为星体表面构造 的变化，熔岩无法堆积，并未形成大型火山"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":464,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400465,6,'逻辑判断','人类与疟疾已经进行了几个世纪的斗争，但一直是“治标不治本”——无法阻断疟 疾传染源。日前研究者培育出一种经过基因改造的蚊子，它具备了不再感染疟疾的 能力，并且能妨碍野生蚊子繁衍，从而有效切断人与蚊子的疟疾传播途径，假以时日， 就能根绝疟疾这个顽症。 以下哪项如果为真，最能支持上述结论：','[{"label":"A","content":"转基因蚊子的体质比野生蚊子差，一旦被放到野外很容易死亡"},{"label":"B","content":"转基因蚊子只在疟疾存在时才有生存优势，当生存环境中没有疟疾时，它们和野 生蚊子的存活率是相同的"},{"label":"C","content":"转基因蚊子的生殖能力在繁衍了9代后显著增加，可能带来野生蚊子种群的灭亡"},{"label":"D","content":"转基因蚊子与野生蚊子交配产下的后代并不都具有抗疟疾基因，但在基因层面上 都会产生突变，形成新型蚊子"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":465,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400466,6,'逻辑判断','游隼会掠食黑腹滨鹂，黑腹滨鹏能持续飞行数小时。20世纪70年代，由于杀虫剂 的使用游隼数量减少，黑腹滨鹏持续飞行的时间变少，休憩时间更多；到了90年代， 杀虫剂因监管而减少，游隼又回来了，黑腹滨鹂的飞行行为恢复如前。因此，有动 物学家认为是对天敌的恐惧改变了黑腹滨鹏的飞行行为。 以下哪项如果为真，最能反驳动物学家的观点：','[{"label":"A","content":"游隼的数量变化跟杀虫剂的使用没有关系"},{"label":"B","content":"滥用杀虫剂会严重影响黑腹滨鹏的食物链"},{"label":"C","content":"游隼并不是黑腹滨鹏唯一的天敌"},{"label":"D","content":"杀虫剂会对黑腹滨鹂的身体机能造成伤害"}]','D','。 20世纪90年代 游隼数量多 杀虫剂未影响黑腹滨鹏的 身体机能 黑腹滨鹏飞行时间增加 休息时间减少','逻辑判断600题','进阶','published','{"globalNumber":466,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400467,6,'逻辑判断','由于一种新的电池技术装置的出现，手机在几分钟内充满电很快就会变成现实。这 种新装置是一种超级电容器，它储存电流的方式是通过让带电离子聚集到多孔材料 表面，而非像传统电池那样通过化学反应储存这些离子。因此这种超级电容器能在 几分钟内储满电。研究人员认为这种技术装置将会替代传统电池。 以下哪项如果为真，不能支持上述结论：','[{"label":"A","content":"超级电容器能够储存大量电能，保证长时间正常运行"},{"label":"B","content":"超级电容器能循环使用数百万次，相比之下传统电池只能使用数千次"},{"label":"C","content":"超级电容器可嵌入汽车底盘为汽车提供动力，可更方便地进行无线充电"},{"label":"D","content":"超级电容器充电时所耗电能比传统电池少90%,但供电时间比后者长10倍"}]','C','。 ⑬花生批注： 论据：超级电容器有 诸多优势； 结论：超级电容器将 会替代传统电池应用 于手机充电中，使得 手机在几分钟内充满 电成为现实。 逻辑判断600 ⑭花生批注： 论据：茶叶中溶解于 水的物质是有限的， 营养物质仍然存留在 茶叶中； 结论：人们应该将喝 剩的茶叶吃掉。','逻辑判断600题','进阶','published','{"globalNumber":467,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400468,6,'逻辑判断','茶叶是中国人喜爱的健康饮品。一般人将茶叶冲泡饮用几次之后，就将喝剩的茶叶 倒掉。某专家对此指出，其实茶叶中能够溶解于水的物质是有限的，大量有营养的 物质仍然保留在茶叶中，白白倒掉实在可惜，人们应该将喝剩的茶叶吃掉。 以下哪项如果为真，最能反驳该专家的观点：','[{"label":"A","content":"茶叶中许多没有营养的物质也不能溶于水"},{"label":"B","content":"茶叶中含有茶叶碱和微量元素，可以提神醒脑"},{"label":"C","content":"一般人喝茶已成为习惯，并非为了吸收营养物质"},{"label":"D","content":"很多人将喝剩的茶叶留下来做茶饼，茶叶蛋等"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":468,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400469,6,'逻辑判断','不可能所有人都喜欢你。 以下选项中与上述断定的意思最为接近的是：','[{"label":"A","content":"必然有的人喜欢你"},{"label":"B","content":"必然有的人不喜欢你"},{"label":"C","content":"可能有的人喜欢你"},{"label":"D","content":"可能有的人不喜欢你"}]','B','。 四海公考sI HAIGONGKA⁰ 逻辑判断6000 四海公考 sI HAIGONGKA⁰ 逻辑判断6000','逻辑判断600题','进阶','published','{"globalNumber":469,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400470,6,'逻辑判断','自从前年甲航运公司实行了经理任期目标责任制之后，公司的经济效益也随之逐年 上升。可见，只有实行经理任期目标责任制，才能使甲公司经济效益稳步增长。 以下哪项如果为真，最能削弱上述论证：','[{"label":"A","content":"近两年国家经济发展速度较快，航运行业的整体形势大好"},{"label":"B","content":"没实行任期目标责任制的乙航运公司，近两年的经济效益也稳步增长"},{"label":"C","content":"前年甲公司开始实行职工薪酬管理制度改革，极大地调动了公司员工的积极性"},{"label":"D","content":"如果甲航运公司没有实行任期目标责任制，近两年的经济效益会增长得更快 147 147"}]','D','【题型分类】 一般质疑类——严谨逻辑关系 【实战解析】题干结论是严谨逻辑关系，可翻译为：未实行经理目标 责任制→ 甲公司经济效益不能稳步增长。想要削弱可以优先考虑A且 非B类选项⑤,即：未实行经理目标责任制且甲公司经济效益稳步增长。 分析选项，D选项通过“假设”的形式给出了“不实行经理任期目标 责任制且近两年甲公司经济效益增长更快”,与题干结论矛盾，当选； 其他选项： ⑮花生批注： 严谨逻辑关系题目的 完美选项为“A且非B”, 直接寻找此类选项即 可，尽量避免被其他 选项干扰。 ⑯花生批注： 严谨的“A且非B” 选 项应写成“甲公司未 实行经理目标责任制 且经济效益稳步增长”, 但题干中已说明“甲 公司实行了经理目标 责任制”,二者冲突， 所以此选项以假设形 式给出近似的“A 且非 B”; 此种质疑方式已经多 次出现，严谨逻辑关系 题目中，有时会用“A→ 非B” 代替“A 且非B” 质疑“A→B” 。 A 选项、C 选 项 ，分别指出“近两年航运行业整体形势大好”、“实 行职工薪酬管理制度改革”,即经济稳步增长的原因不一定是因为经 理目标责任制，属于另有他因质疑。但本题属于严谨逻辑关系，“另 有他因”是归因类题目常见的质疑方式； B 选项，主体和题干不一致，虽然也能构成异因同果的三圈质疑 ， ⑰花生批注： 实行经理目标责任制 的甲公司和未实行的 乙公司，经济效益均 稳步增长，即经济增 长可能和经理目标责 任制无关。 但依然不如D 选项恰当。','逻辑判断600题','进阶','published','{"globalNumber":470,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400471,6,'逻辑判断','某考生正在填报志愿，有法律、管理、经济、金融、审计和会计6个专业是考虑填 报的专业，但是综合各方面因素，有如下的考虑： 如果填报法律专业，那么就不填报管理专业，但要填报会计专业； 只有不填报审计专业时，才填报金融或经济专业； 如果不填报经济专业，那么也不填报会计专业； 法律专业一直是自己想读的专业，一定要填。 由此可以推出该考生：','[{"label":"A","content":"填报了金融和经济专业"},{"label":"B","content":"管理专业和经济专业都没填报"},{"label":"C","content":"填报了法律专业，还填报了金融专业"},{"label":"D","content":"填报了会计专业，但没填报审计专业"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":471,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400472,6,'逻辑判断','超级高铁与大众的出行密切相关，它最吸引人之处，就是其运行速度远超轮轨式高 铁列车，时速可达600千米至1200千米，甚至有很多人断言能够达到4000千米以上。 这类超级高铁有一个共同的特点，就是列车须在密闭的真空或者低气压管道中运行。 具体而言就是通过抽取空气达到接近真空的低气压环境，采用气动悬浮或者磁悬浮 驱动技术，让列车在全天候、无轮轨阻力、低空气阻力和低噪音模式下超高速运行。 以下各项如果为真，最能质疑超级高铁实现可能性的是：','[{"label":"A","content":"超级高铁在某些线路中无法实现低气压管道的密封"},{"label":"B","content":"在超级高铁运行的真空管道中设备维护将异常艰难和昂贵"},{"label":"C","content":"在真空或低气压管道中超级高铁的某些必要设备将无法使用"},{"label":"D","content":"超级高铁一旦出现失控将对乘客的人身安全带来可怕的后果"}]','C','。 ⑲花生批注： 根据“必要条件在箭头 后面”,选项可翻译为： 超级高铁实现 → 必要 设备可以使用。','逻辑判断600题','进阶','published','{"globalNumber":472,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400473,6,'逻辑判断','当前，乡村教师留不住是个大问题。对此，有人认为，只要大幅提升乡村教师待遇， 就能让他们安心留下来，从而有效解决这一问题。 以下选项中无法削弱上述论断的是：','[{"label":"A","content":"不是所有乡村教师都看重待遇"},{"label":"B","content":"有的乡村教师收入很高"},{"label":"C","content":"乡村教师收入普遍偏低"},{"label":"D","content":"不少乡村教师由于生活环境差而辞职"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":473,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400474,6,'逻辑判断','某教师收集了本班学生的语文学习兴趣、每天的学习时长等信息，结合期末考试语 文成绩分析后发现，与每天语文学习时长不足2小时的学生相比，学习超过2小时 的学生学习兴致普遍更高，其语文期末考试平均分也更高。该教师由此得出结论， 增加语文学习时长能够有效培养学习兴趣，进而提高语文成绩。 下列选项若为真，最能质疑上述结论的是：','[{"label":"A","content":"该班级期末考试语文成绩最好的学生每天学习语文1小时"},{"label":"B","content":"该班级的语文期末考试平均分高于其他班级"},{"label":"C","content":"语文学习兴趣高的学生拥有更好的学习习惯"},{"label":"D","content":"只有语文学习兴趣高的学生才乐于花更长时间学习语文"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":474,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400475,6,'逻辑判断','自从刘教授的计算机安装了杀毒软件之后，它就没有中病毒了。由此可见只有安装 了杀毒软件，才能使计算机不中病毒。 以下哪项如果为真，最能削弱上述论证：','[{"label":"A","content":"计算机病毒一般是通过网络和U盘拷贝两种途径传播，不上网的计算机很少中病毒"},{"label":"B","content":"近两年网络安全行业发展速度较快，病毒的生存空间越来越小"},{"label":"C","content":"刘教授的另外一台计算机没有安装杀毒软件，也很少中病毒"},{"label":"D","content":"如果计算机没有安装杀毒软件，计算机的速度会更快"}]','C','。 其他选项： A 选项，不确定不上网的计算机是否安装了杀毒软件，且很少中病毒 也可能中病毒； B 选项、D 选项，未提及安装杀毒软件和计算机中病毒之间的关系， 与题干话题不一致，属于无关选项。','逻辑判断600题','进阶','published','{"globalNumber":475,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400476,6,'逻辑判断','雨果说：“多建一所学校，就少建一座监狱。”马克 · 吐温说：“你每关闭一所学校， 你就必须开设一座监狱。”在他们看来，教育能够减少犯罪。有学者认为，近年来， 随着教育的大规模扩大，学历程度越高，犯罪率越低。 以下哪项如果为真，最能反驳该学者的观点：','[{"label":"A","content":"2015 年，某高校一名本科生杀死自己的母亲，事后潜逃"},{"label":"B","content":"学历越高的人，对各项法律条文规定就越了解，就越容易钻法律的空子，实施犯罪"},{"label":"C","content":"近年来，大部分犯罪为经济犯罪，高学历人群的犯罪率明显高于低学历人群"},{"label":"D","content":"文化水平低的人，对法律了解相对较少，而且通常低学历者的生存状况较差，更 容易铤而走险"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":476,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400477,6,'逻辑判断','和谐小区里的居民具有乐于助人的良好风尚。在该小区里，凡帮助过老刘的人，老 张都帮助过，一个人，只要有一人没帮助过他，老周就帮助过他。老王新搬来不久， 还没有帮助过其他人。 根据以上陈述，可以得出以下哪项：','[{"label":"A","content":"老周没有帮助过老张"},{"label":"B","content":"老周没有帮助过老王"},{"label":"C","content":"老刘与老张互相帮助过"},{"label":"D","content":"老张和老周互相帮助过"}]','D','','逻辑判断600题','进阶','published','{"globalNumber":477,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400478,6,'逻辑判断','老张：你在这儿摆摊设点属于占道经营! 小王：这儿是中山北路又不是中山北道，我占的什么道? 以下哪项与上述对话方式最为相似：','[{"label":"A","content":"甲：你这种执法行为一点人情味都没有 乙：我严格执法是为了保障人民群众的生命财产安全。"},{"label":"B","content":"甲：你成天打游戏是在虚度年华! 乙：我只有在游戏中才觉得年华没有虚度。"},{"label":"C","content":"甲：你工作时间不能抽烟! 乙：我抽烟时从不工作。"},{"label":"D","content":"甲：你这种说法是栽赃陷害! 乙：你这种说法是血口喷人!"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":478,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400479,6,'逻辑判断','随着“二孩政策”的实施，母乳喂养越来越多地成为广大年轻女性在生儿育女过程 中不可回避的话题。医学专家建议，婴儿出生后最初6个月最好进行纯母乳喂养， 而父母也都希望为孩子提供最好的营养。但统计显示，近年来我国0-6个月婴儿的 纯母乳喂养率却明显偏低，婴儿6个月内的纯母乳喂养率在农村为30%,在城市仅 为16%。 以下各项如果为真，则除了哪项均能解释上述统计结果：','[{"label":"A","content":"职场女性往往因工作压力大、工作环境不允许等原因而陷入母乳喂养困窘"},{"label":"B","content":"母乳喂养可降低儿童患病率，给孩子健康带来的益处可一直延续到成人期"},{"label":"C","content":"很多母亲并不了解母乳喂养的种种优势，反而把配方奶粉想象得过于美好"},{"label":"D","content":"母亲因为夜晚哺乳而影响睡眠质量，她们的工作生活节奏被哺乳完全打乱"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":479,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400480,6,'逻辑判断','有人认为“意象”是一个外来词，是英文“image” 的译文，并把它和20世纪初的 英美意象派诗歌联系起来。但其实，意象是中国古代文艺理论固有的概念和词语， 并不是外来的东西。 以下各项如果为真，最能证明“意象”在我国的原生性的是：','[{"label":"A","content":"英美意象派所提倡的“image”是指运用想象、幻想、譬喻所构成的各种具体鲜明的、 可以感知的诗歌形象，与中国的“意象”含义不相同"},{"label":"B","content":"很多主张把自己的情绪全部隐藏在意象背后，通过意象将它们暗示出来的英美意 象派诗人实际上是深受中国古代诗歌的影响"},{"label":"C","content":"我国古代诗歌诞生远远早于英美诗歌，我国古代的传说故事是很多英美意象派诗 人创作的灵感来源"},{"label":"D","content":"意象在南朝《文心雕龙》等著作中有提及，它没有确定的涵义和一致用法，有的 指意中之象，有的指意和象，有的接近于今天所说的艺术形象 150 练习题25"}]','D','。 370 练习题25 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":480,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400481,6,'逻辑判断','儿童票是社会关爱儿童的一种体现，在现实中，经常以儿童的身高作为能否购买儿 童票的标准，这种做法实施起来方便高效，但对个体的差异缺乏尊重。如果孩子年 龄小、个子却比较高，就会在出行过程中被要求重新量身高或补票。因此，用身高 作为能否购买儿童票的标准是不合理的。 上述推论暗含的前提是：','[{"label":"A","content":"准确界定孩子是否为儿童的标准应当是年龄"},{"label":"B","content":"以身高为标准不符合儿童的权利保护原则"},{"label":"C","content":"公众普遍反对以身高作为衡量儿童票的标准"},{"label":"D","content":"相关部门应当着手设定更为合理的儿童衡量标准"}]','A','。 ①花生批注： 论据：现实中经常以儿 童的身高作为购买儿 童票标准，若 孩 子 年 龄小个子高也要补票； 结论：用身高作为能 否购买儿童票的标准 是不合理的。 ②花生批注： 例如：某人认为此题选 B、C、D选项都是错的， 需要补充的前提为“此 题A选项是正确的”。 ③花生批注： 前提假设类题目选择 的选项应是“没他不行” 的，“没他也行”、“有 他更好”不会是此类 题目的正确答案。 371 371 ④花生批注： 题干要解释的现象： 不知道销售是机器人， 销售额高； 知道销售是机器人， 销售额下降近80%。 ⑤花生批注： 用变化解释变化： “知情”与“不知情” 的销售额差异巨大， 必须用“知情”与“不 知情”时的一个变化， 来解释“销售额”的 变化。 ⑥花生批注： 该题按照“是否使用 药物”进行分组，将“某 病实验组死亡率低” 这一事实归因于“使 用了该种药物”。 实验组 病死率为8.8% 结论：该药 具有明 对照组 病死率为39% 物对此病症 显的疗效','逻辑判断600题','进阶','published','{"globalNumber":481,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400482,6,'逻辑判断','一项研究发现，在潜在顾客不知情的情况下，新型人工智能聊天机器人的销售业绩 是缺乏经验的新员工的4倍多，然而，一旦顾客在决定购买前知道自己一直在和人 工智能打交道，销售额会立刻下降近80%。 以下最能解释这一现象的是：','[{"label":"A","content":"顾客喜欢和有经验的真人打交道"},{"label":"B","content":"与人工智能机器人交流只能获取程序性信息"},{"label":"C","content":"顾客与人工智能打交道缺少真实感"},{"label":"D","content":"用人工智能机器人做销售必须公布其人工智能身份"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":482,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400483,6,'逻辑判断','在针对某病症的一项医药疗效的双盲实验中，某课题组将实验对象分成两个组：实 验组和对照组，两组的重症率都在20%左右，和同期患该病症的整体重症率相当。 实验结果显示：对照组18例中死亡7人，病死率为39%;使用该药的实验组34例 中死亡3人，病死率仅为8.8%。课题组由此认为，该药物对此病症具有明显的疗效。 下列哪项如果为真，最能质疑课题组的结论：','[{"label":"A","content":"该药物组成成分并没有全部公开"},{"label":"B","content":"同期患该病症的整体死亡率为4.7%"},{"label":"C","content":"在普通人群中，患该病症的人数不到1%"},{"label":"D","content":"在古代医药典籍中，就已经记载有该药物的配方 151"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":483,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400484,6,'逻辑判断','作为抗衰老药物，雷帕霉素延长寿命的秘密在于能够阻断mTOR 通道——这也是控制 着影响细胞生长繁殖流程的“主开关”之一。当食物充足时，这种通道从激素和营 养物质中获得信号使细胞吸收营养并生长，但细胞进行新陈代谢和生长的过程中会 产生激发细胞老化的副产物；当限制食物热量的摄入时，这个通道可以发出信号使 细胞停止生长，借此来延缓衰老。雷帕霉素可能是目前已发现的最有效可靠的抗衰 老药物。 以下哪项如果为真，不能支持上述结论：','[{"label":"A","content":"由于具有抑制细胞生长的作用，雷帕霉素被用于治疗某些癌症"},{"label":"B","content":"雷帕霉素在延缓衰老的同时，使人更易受到细菌和病毒的侵袭"},{"label":"C","content":"试验研究已经证明雷帕霉素能够延长酵母、蠕虫和果蝇的寿命"},{"label":"D","content":"雷帕霉素可以阻断mTOR 通道，而不需要限制食物热量的摄入"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":484,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400485,6,'逻辑判断','某科研机构提出潮湿的沙子是古埃及人在沙漠中搬运巨大石块和雕像的关键。研究 人员指出，古埃及人将沉重的石块放上滑橇后，先在滑橇前铺设一层潮湿的沙子， 再牵引它们，这种搬运方式起到了意想不到的效果。在实验中，研究人员使用流变 仪测试沙子的硬度，以证实需要多少牵引力才能使一定数量的沙子变形，并在此基 础上设计了牵引模型，从中发现将潮湿的沙子铺在滑橇前能更容易移动重物，而且 沙子所含水分决定了沙子的硬度和牵引力。 如果以下哪项为真，最能支持上述结论：','[{"label":"A","content":"在一幅古埃及墓室壁画中， 名男子站在滑橇前方，似乎正在浇水"},{"label":"B","content":"滑橇牵引力与沙子硬度成反比，潮湿沙子的硬度是干燥沙子的两倍"},{"label":"C","content":"实验证明，铺设在滑橇前的潮湿沙子容易堆积，形成较大滑动阻力"},{"label":"D","content":"一个实验室版的埃及滑橇被成功建造，能够模拟古埃及工地的实况"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":485,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400486,6,'逻辑判断','研究人员给一群实验用的小鼠提供相同的食物，这些小鼠中有部分小鼠的下丘脑部 位有不可恢复的损伤，而另一些则没有。一段时间后，研究人员发现那些下丘脑部 位有损伤的小鼠出现了肥胖的症状。研究人员认为，下丘脑特定部位的损伤是导致 小鼠肥胖的原因。 以下哪项如果为真，最能支持研究人员的结论：','[{"label":"A","content":"下丘脑部位未损伤的那些小鼠未出现肥胖的症状"},{"label":"B","content":"已有相当多研究人员致力于研究小鼠脑部损伤与肥胖之间的关系"},{"label":"C","content":"研究人员发现，下丘脑部位损伤的小鼠患糖尿病的比例高于正常水平"},{"label":"D","content":"下丘脑部位损伤的小鼠与食用高脂饮食导致肥胖的小鼠肥胖程度相当 四海公考SIHAIGoNGKAO - 逻辑判断6 00 四海公考"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":486,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400487,6,'逻辑判断','某村年轻女性多于年轻男性，这部分年轻人中外出务工的多于在家种地的。 如果上述表述为真，则下列哪一项为真：','[{"label":"A","content":"外出务工的年轻女性多于外出务工的年轻男性"},{"label":"B","content":"在家种地的年轻男性少于外出务工的年轻女性"},{"label":"C","content":"在家种地的年轻男性少于外出务工的年轻男性"},{"label":"D","content":"在家种地的年轻女性多于在家种地的年轻男性"}]','B','；','逻辑判断600题','进阶','published','{"globalNumber":487,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400488,6,'逻辑判断','有些喜欢爬山的人也喜欢游泳，所有喜欢爬山的人都不喜欢踢毽子，所有喜欢跳广 场舞的人都喜欢踢毽子。幸福小区所有的中年女性都喜欢跳广场舞，其中有些人还 喜欢游泳。 根据以上陈述，可以推出以下哪项不可能为真：','[{"label":"A","content":"所有喜欢踢毽子的人都喜欢跳广场舞"},{"label":"B","content":"有些喜欢跳广场舞的人也喜欢游泳"},{"label":"C","content":"幸福小区有些中年女性喜欢爬山"},{"label":"D","content":"幸福小区所有的中年女性都喜欢踢毽子"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":488,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400489,6,'逻辑判断','某公司年会，准备排练一个话剧节目，需要四个男演员，分别是男一号、男二号、男三号、 男四号，经过抽签，由甲、乙、丙、丁四个人各演一个角色。已知：①丙不当男一号， 也不当男四号；②乙不当男一号，也不当男三号；③丁不当男三号，也不当男四号； ④甲不当男一号，也不当男四号；⑤除非丁不当男一号，否则甲当男三号。 由此可以推出：','[{"label":"A","content":"乙当男三号，丁当男四号"},{"label":"B","content":"甲当男二号，丙当男三号"},{"label":"C","content":"丙当男二号，甲当男三号"},{"label":"D","content":"丁当男三号，丙当男二号"}]','C','【题型分类】分享类——日常分析 【实战解析】整理题干信息如下： ①丙≠男一号，丙≠男四号； ②乙≠男一号，乙≠男三号； ③丁≠男三号，丁≠男四号； ⑬花生批注：“除非A 否 则B” 翻 译为“非A → B”;记忆口诀：否A 则B。④甲≠男一号，甲≠男四号； ⑬花生批注： “除非A 否 则B” 翻 译为“非A → B”; 记忆口诀：否A 则B。 ⑤丁是男一号→ 甲是男三号⑤; 由①②④可知，丁为男一号；由⑤可知，甲是男三号；由①可知，丙 是男二号，则乙是男四号； 综上，丁男一，丙男二，甲男三，乙男四，观察选项，只有C 选项正确。 377 ⑭花生批注： 题干可翻译且简化为： ①人才梯队 → 吸纳培 养人才； ②扩展规模→人才梯 队。 ⑮花生批注： 其他选项： B 选项是“B 且C” 、 C 选项是“非A且B”、 D选项是“非A且C”, 均无法质疑。 ⑯花生批注： 张某看法为：A→B, 李某不同意，即李某 看法为“A 且非B”。 ⑪花生批注： 翻译原则： 不所有=有些不，不 有些=所有不； 不必然=可能不，不 可能=必然不。 翻译过程如下： 非(所有灾难都必然 有明显的征兆)=(非 所有)灾难都必然有 明显的征兆=有些灾 难(不必然)有明显 征兆=有些灾难可能 没有明显征兆； 非(有些灾难可能难 以避免)=(非有些) 灾难可能难以避免= 所有灾难(不可能) 难以避免=所有灾难 必然(不能难以)避 免=所有灾难必然可 以避免。','逻辑判断600题','进阶','published','{"globalNumber":489,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400490,6,'逻辑判断','一个企业只有一直在吸纳人才和培养人才，才能建立起战略性的人才梯队。而战略 性的人才梯队，是一个企业不断扩展其规模所必需的。 以下哪种情况如果存在，最能削弱以上断定：','[{"label":"A","content":"甲企业不断扩展其规模，但没有一直在吸纳人才"},{"label":"B","content":"乙企业一直在培养人才，并建立起战略性的人才梯队"},{"label":"C","content":"丙企业建立起战略性的人才梯队，但并没有不断扩展其规模"},{"label":"D","content":"丁企业没有不断扩展其规模，但一直在吸纳人才和培养人才"}]','A','【题型分类】 一般质疑类——严谨逻辑关系 【实战解析】题干逻辑可以串联为：扩展规模( A)→ 人才梯队( B) →吸纳培养人才( C) 。 直接寻找矛盾即可，A 选项为“A 且非C”, 与题干矛盾，当 选⑤A。','逻辑判断600题','进阶','published','{"globalNumber":490,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400491,6,'逻辑判断','张某：除非所有的灾难都必然有明显的征兆，否则有些灾难可能难以避免。李某： 我不同意你的看法。以下哪项符合李某的意思：','[{"label":"A","content":"尽管有些灾难可能没有明显的征兆，但是所有的灾难都是必然可以避免"},{"label":"B","content":"尽管有些灾难有明显的征兆，但是有些灾难必然可以避免"},{"label":"C","content":"尽管所有灾难可能没有明显的征兆，但是有些灾难必然可以避免"},{"label":"D","content":"虽然有些灾难可能没有明显的征兆，但是有些灾难必然可以避免"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":491,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400492,6,'逻辑判断','41摄氏度是人体发烧时才能达到的体温。不久前，研究人员将试管中的皮肤细胞每 周两次，每次1小时暴露在41摄氏度的空气里。结果发现，这些细胞不但没有受到 损害，反而生命力更加旺盛。他们由此推测，适度的高温可以起到延长寿命、抗衰老、 美容的效果。 下列不能对上述观点构成质疑的一项是：','[{"label":"A","content":"常患感冒的人并没有比常人更长寿"},{"label":"B","content":"影响衰老过程的主要不是皮肤细胞"},{"label":"C","content":"皮肤细胞不能代表所有的人体细胞"},{"label":"D","content":"体温暂时升高会对人体中有些细胞造成伤害"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":492,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400493,6,'逻辑判断','某班主任对班级纪律情况进行如下三个描述：“该班所有学生都遵守纪律”,“该 班学生并不都遵守纪律”,“李明遵守纪律”,其中有两个描述是假的。 根据题干，仍不能确定下面哪个选项的真假：','[{"label":"A","content":"李明未遵守纪律"},{"label":"B","content":"该班所有学生都不遵守纪律"},{"label":"C","content":"该班有些学生不遵守纪律"},{"label":"D","content":"该班所有学生都遵守纪律"}]','B','','逻辑判断600题','进阶','published','{"globalNumber":493,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400494,6,'逻辑判断','张三、李四、王五三人分别参加在甲、乙、丙三地举行的羽毛球、游泳、划船三项比赛， 比赛中他们都得了冠军，已知张三没到丙地去划船，王五没参加在乙地举行的游泳 比赛，划船冠军不是王五。请问游泳冠军是：','[{"label":"A","content":"张三"},{"label":"B","content":"李四"},{"label":"C","content":"王五"},{"label":"D","content":"未知数"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":494,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400495,6,'逻辑判断','小红、小明、小李、小张四人涉嫌某案被传讯。 小红说：作案者是小明。 小明说：作案者是小红。 小李说：作案者不是我。 小张说：作案者在我们四人中。 154 四海公煮逻辑判断 四海公煮 如果四人中，有且仅有一人说真话，则以下哪项断定成立：','[{"label":"A","content":"作案者是小红"},{"label":"B","content":"作案者是小明"},{"label":"C","content":"作案者是小李"},{"label":"D","content":"题干中条件不足以断定谁是作案者"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":495,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400496,6,'逻辑判断','几只猴子分一筐桃子，结果没有两只猴子分到的桃子数量完全相同；没有一只猴子 恰好是分到5个桃子；没有猴子分到的桃子数等于或超过全部猴子数。 如果上述统计是真实的，则下列哪项断定也一定是真的： I. 这些猴子中，有一只猴子1个桃子都没有分到 Ⅱ.这些猴子的数量，不少于3只 Ⅲ. 这些猴子的数量，不多于5只','[{"label":"A","content":"只有 I 和Ⅱ"},{"label":"B","content":"只 有I 和 Ⅲ"},{"label":"C","content":"只有 I"},{"label":"D","content":"I 、Ⅱ 和Ⅲ"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":496,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400497,6,'逻辑判断','有六位选手甲、乙、丙、丁、戊、庚参加足球队队员选拔。已知： (1)如果选拔甲，那么必须同时选拔乙和丙； (2)如果选拔戊，则必须同时淘汰丙和丁； (3)除非选拔戊，否则淘汰庚； (4)甲是主力，必须选拔。 根据以上信息，下列一定为真的是：','[{"label":"A","content":"选拔戊并且淘汰丙"},{"label":"B","content":"同时选拔丙和丁"},{"label":"C","content":"同时淘汰戊和庚"},{"label":"D","content":"选拔戊并且淘汰丁"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":497,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400498,6,'逻辑判断','洗碗和叠衣服这些家务活让你心情不佳?有研究者做了一项调查，调查涉及6000多 名63岁至99岁的女性志愿者。研究人员发现，与基本不动的老人相比，每天从事 30分钟家务的女性志愿者死亡风险低12%。因此，研究人员认为做家务这类简单活 动有助于延年益寿。 以下哪项如果为真，最能削弱上述研究者的观点：','[{"label":"A","content":"这项研究关注的是老年女性，那些年轻时就喜欢运动的人步入老年后也能保持运 动的习惯"},{"label":"B","content":"很多老年人可以培养自己的爱好，比如学习书法、摄影，旅游等，这有助于延年 益寿"},{"label":"C","content":"我国有55.4万个老年协会组织，老年志愿者达2000万人，覆盖了全国绝大多数 的城镇社区和农村社区"},{"label":"D","content":"老年健身操是兼中外之长，融体育、舞蹈、音乐为一体而形成的一套具有我国特 点的健身方法 155"}]','A','。 花生批注： 将一部分女性志愿者 死亡风险低(延年益 寿)的原因归于做家 务之类的简单活动。 28花生批注： 此选项表述较隐晦， 可先排除其他选项， 再 向 他 因 质 疑 上 “靠”,他因质疑“把 水搅混”即可。 9花生批注： 对比实验归因题，正 确选项要回归实验， 和实验分组一致，脱 离实验的“他因”往 往是强干扰项。 383 逻辑判断600 ③0花生批注： 论据：“嫦娥5号”带 回了月球月壤； 结论：获得月壤可以 帮助研究太阳系其他 行星(如火星、水星等) 表面物质。 ③花生批注： 找到断点后，可直接在 选项中寻找想要答案， 不要被其他选项过度 干扰。','逻辑判断600题','进阶','published','{"globalNumber":498,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400499,6,'逻辑判断','11月24日,“嫦娥5号”于文昌卫星发射中心顺利发射,任务是在月球表面收集 灰尘和碎片,也就是月壤,并带回地球,以帮助了解月球的演化。同时,有天文学 家认为,获得月壤也可以帮助研究人员更准确地确定太阳系其他行星(如火星、水 星等)表面物质的年龄。 要使天文学家的观点成立,可以补充的前提是:','[{"label":"A","content":"月球表面的灰尘和碎片等物质与太阳系其他行星的表面物质成分相似"},{"label":"B","content":"月壤由月球岩石在遭受陨石撞击和太阳风轰击等空间风化作用后形成"},{"label":"C","content":"月球与太阳系其他行星基本形成于同一时期"},{"label":"D","content":"对月壤的研究还可以为人类未来在其他太空领域的探索打下基础"}]','A','【题型分类】前提假设类——断点搭桥 【实战解析】论据和结论见批注；“月球月壤”与“其他行星表面物质” 存在断点，需要搭桥⑨。分析选项： A选项，月球表面物质和其他行星表面物质成分相似，将“月球月壤” 与“其他行星表面物质”之间建立联系，属于断点搭桥支持，可直接 秒选。 其他选项： B 选项、D 选项未提及其他行星、C 选项未提及“表面物质”,均无 法断点搭桥。','逻辑判断600题','进阶','published','{"globalNumber":499,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400500,6,'逻辑判断','现有四种药,可放在黑、白、红、绿、蓝这五个库房里。已知,每种药只放在一个 库房又多了一点儿装不下,且每种药只能存放在两个库房。药品A放在黑、白库房, 药品B放在绿、蓝库房,而红库房里只有药品C, 四种药放的库房均不完全相同。 基于上述条件,药品D存放在哪个库房:','[{"label":"A","content":"如果没有存放在绿库房,那么一定要存放在白库房"},{"label":"B","content":"如果没有存放在绿库房,那么一定要存放在黑库房"},{"label":"C","content":"如果没有存放在黑库房,那么一定要存放在白库房"},{"label":"D","content":"如果没有存放在黑库房,那么一定要存放在蓝库房 SIO煮 逻辑判断 练习题26"}]','C','。 逻辑判断 练习题 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 论据：参加讲座的人 相信UFO 真的存在； 结论：有些非常严谨 的科学家也相信UFO 真的存在。 ②花生批注： A、B、D选项均未将 参加讲座的人和有些 非常严谨的科学家关 联，均无法支持。 ③花生批注： 论据：①市场调节并 且②尊重体力劳动者； 结论：月嫂收入超过 医学博士是正常的。','逻辑判断600题','进阶','published','{"globalNumber":500,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400501,6,'逻辑判断','参与讲座的人曾跟军方有关联，他们所有人都相信 UFO真的存在，而且大部分人觉 得应该研究UFO问题。国家原子试验博物馆举行的讲座虽然规模不大，但演讲者都 是非常可信的。由此可见，有些非常严谨的科学家也相信 UFO真的存在。 以下哪项如果为真，最能支持上述论证：','[{"label":"A","content":"有些科学家跟军方有关联"},{"label":"B","content":"演讲者有些不是严谨的科学家"},{"label":"C","content":"部分参与讲座的人是非常严谨的科学家"},{"label":"D","content":"科学家的讲座都是非常严谨可信的"}]','C','【题型分类】支持类——断点搭桥 【实战解析】论据结论可见批注，参加讲座的人和有些非常严谨的科 学家之间存在明显断点，需要搭桥，选项中只有C 选项将二者搭桥， 可直接秒选，其逻辑关系如下： 所有参加讲座的人都相信UFO 存在部分+有些参与讲座的人是非常 严谨的科学家→有些非常严谨的科学家也相信UFO 真的存在。','逻辑判断600题','进阶','published','{"globalNumber":501,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400502,6,'逻辑判断','近来，月嫂收入成为人们讨论的热门话题。有人要求政府加强监管，并质疑月嫂的 收入为何能高过一个医学博士的月薪。也有人反驳说，月嫂的收入为什么不能高过 医学博士呢?月嫂收入的提高，一方面是市场调节的结果，另一方面反映了我国越 来越重视体力劳动，尊重体力劳动者是社会的进步。 下列哪项陈述不能支持反驳者的观点：','[{"label":"A","content":"收入高低不完全取决于学历高低"},{"label":"B","content":"有些月嫂非常优秀，具有博士学位"},{"label":"C","content":"随着新生儿的增多，出现“一嫂难求”的现象"},{"label":"D","content":"谁能放下身段去赚辛苦钱，谁就值得尊重"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":502,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400503,6,'逻辑判断','友谊是获得人生幸福的重要途径。按照古罗马哲学家西塞罗的说法，“友谊只存在 于好人之间，终生不渝的友谊是最难的事情”;另一位西班牙哲学家乔洛 ·商塔亚 纳认为，“友谊几乎都是一颗心的一部分与另一颗心的一部分之结合，人们只能是 局部的朋友”。 以上陈述如果为真，则下列一定为真的是：','[{"label":"A","content":"终生不渝的友谊是最为宝贵的财富"},{"label":"B","content":"坏人与坏人之间一定不会存在友谊"},{"label":"C","content":"好人之间一定存在某种局部的友谊"},{"label":"D","content":"友谊是获得人生幸福的最重要途径"}]','B','⑤。 387 ⑥花生批注： 对比实验： 患抑郁症 没 患 抑 郁症 玩手机122分钟 玩 手 机 5 9 分钟 归因：更容易患抑郁症 是因为玩手机时间长。','逻辑判断600题','进阶','published','{"globalNumber":503,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400504,6,'逻辑判断','某调查发现，患抑郁症的人平均每天使用手机的时间达122分钟以上，而没有患抑 郁症的人平均每天使用手机的时间为59分钟。有人提出，玩手机可能会影响情绪， 使用手机的时间越多，抑郁的可能性越大。 以下哪项如果为真，不能支持以上结论：','[{"label":"A","content":"长时间玩手机，尤其是睡前玩手机，可能会造成睡眠时间的不足，而导致情绪容 易出问题"},{"label":"B","content":"长时间玩手机，会接触海量数据，这些数据不能及时处理，易造成情绪低迷、烦 躁和疲劳，增加抑郁风险"},{"label":"C","content":"人把过多时间和精力放在手机上，必然和现实中的人接触减少，逃避面对现实是 抑郁的特征之一"},{"label":"D","content":"长期玩手机的人，通常把大部分时间用在上网和打游戏，而不是和朋友聊天，缺 少人际支持是抑郁的风险因素"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":504,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400505,6,'逻辑判断','小陈以售卖玩具为生，但他只在星期一、星期二、星期三、星期五和星期六卖玩具， 并且只卖4种玩具：玩具无人机、充气气球、橡皮泥和玩具汽车。每个售卖日，他 上午只卖1种玩具，下午也只卖1种玩具，而且还知道如下情况： ①小陈只在1个上午和3个下午卖橡皮泥 ②小陈在而且只在两个连续的下午卖玩具无人机 ③星期六，小陈既不卖玩具无人机，也不卖充气气球 基于上述情况，请问哪一天小陈一定会卖玩具无人机：','[{"label":"A","content":"星期一"},{"label":"B","content":"星期二"},{"label":"C","content":"星期三"},{"label":"D","content":"星期五"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":505,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400506,6,'逻辑判断','从1995年起，印度某地每年有数百名贫困儿童患上一种急性大脑疾病。患儿常在清 晨出现癫痫症状，许多儿童很快死亡。这种情况通常发生于每年5月-7月。该地区 盛产荔枝，5月-7月恰好是荔枝成熟的时间，因此有人怀疑这种疾病可能与荔枝有 关。研究发现，所有荔枝中都含有亚甲环丙基甘氨酸和次甘氨酸，没熟的荔枝中这 两种物质含量更高。研究者认为，这些患者属于次甘氨酸和亚甲环丙基甘氨酸中毒， 疾病爆发确实与大量食用荔枝有关。 以下哪项如果为真，最能支持以上结论：','[{"label":"A","content":"所有患儿的尿样本中均检测出了亚甲环丙基甘氨酸和次甘氨酸"},{"label":"B","content":"居民根据官方建议限制了儿童每日吃荔枝数量，两年后患病人数大幅降低"},{"label":"C","content":"相比没有出现症状的儿童，生病儿童患病前吃过荔枝的可能性更高"},{"label":"D","content":"相比没有出现症状的儿童，生病儿童更有可能吃下生的或者腐烂的荔枝"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":506,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400507,6,'逻辑判断','在一列国际列车上，来自英国、意大利、日本、德国四国的甲、乙、丙、丁四位旅 客恰好相聚在某个车厢中。他们每人除了会说本国语言外，还会说其他三国语言中 的一种，有一种语言三个人都会说。这四位旅客交谈的有关情况如下： (1)乙不会说英语，当甲与丙交谈时，他却能替他们作翻译； (2)甲是日本人，丁不会说日语，但他俩却能毫无困难地交谈； (3)乙、丙、丁三人找不到一种共同的语言进行交谈； (4)在四人中，没有一人既能用日语交谈，又能用意大利语交谈。 据此，可以推出三个人都会说的那种语言是：','[{"label":"A","content":"日语"},{"label":"B","content":"德语"},{"label":"C","content":"英语"},{"label":"D","content":"意大利语"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":507,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400508,6,'逻辑判断','北方某市有甲、乙两条十字交叉的马路，每年冬季都有成群的乌鸦聚集于甲路边的 树 上 ，但乙路边的树上基本没有乌鸦。有鸟类爱好者发现，甲路两旁的杨树要比乙 路多数倍。据此，该鸟类爱好者断言，乌鸦更喜欢停留在杨树多的地方过冬。 以下哪项如果为真，最能削弱上述鸟类爱好者的断言：','[{"label":"A","content":"在夏秋之交，甲、乙两条路旁的树上都会聚集大量的乌鸦"},{"label":"B","content":"近二十年来该市特别重视道路绿化，为鸟类提供了良好的栖息环境"},{"label":"C","content":"乙路是南北方向，凛冽的北风长驱直入，而甲路旁边的建筑能有效阻挡北风"},{"label":"D","content":"该市有一条与甲路平行的路，杨树的数量与乙路差不多，但冬季几乎没有乌鸦"}]','C','。 391 ⑪花生批注： 题干按照今年和去年 分组对比，将今年小 区环境卫生明显改善 的原因归于聘用了大 量清洁人员。 ⑫花生批注： 对比实验归因题的常 见错误选项：“有些” 类选项、实验瑕疵、 分组错误或未分组， 未谈论原因选项。 ⑬花生批注： 论据：公立高中高考 上线率高于私立高中； 结论：公立高中教学 水平高于私立高中。','逻辑判断600题','进阶','published','{"globalNumber":508,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400509,6,'逻辑判断','光明小区的物业表示，和去年相比，今年小区的环境卫生有明显的改善。物业责任 人认为，这是由于小区聘用了大量的清洁人员。 下列选项如果为真，最不能削弱上述结论的是：','[{"label":"A","content":"今年年初，光明小区业主委员会召开会议对小区环境问题进行了认真研究"},{"label":"B","content":"许多业主认为，聘用大量清洁人员成本巨大"},{"label":"C","content":"今年年初，光明小区增设了一倍的垃圾桶"},{"label":"D","content":"今年小区安装了监控，实行人验识别，对乱丢垃圾的人有所约束"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":509,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400510,6,'逻辑判断','一般都有私立高中比公立高中要好的误解，实际上公立高中的高考上线率比私立高 中要高，从这点可以清楚的看到私立高中的教学水平比其他学校都低。 下面选项中，最能够有力地削弱上文论证的是：','[{"label":"A","content":"在公立高中工作的老师赚钱比私立高中的老师少"},{"label":"B","content":"公立高中买不起私立高中的高级硬件设施"},{"label":"C","content":"私立高中的重点是培养学生的全面素质"},{"label":"D","content":"进入私立高中学生能力没有公立高中的强"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":510,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400511,6,'逻辑判断','北方航空公司实行对教师机票六五折优惠，这实际上是吸引乘客的一种策略，该航 空公司没有实际让利，某天某航班的满员超过90%的，就停售当天优惠价机票，而 即使在高峰期时，航班的满员也很少超过90%的，有座位空着，何不以优惠价促销 它呢? 以下哪个如果是真，将最有力地削弱上述论证：','[{"label":"A","content":"绝大多数教师乘客并不是因为票价优惠才选择北方航空公司"},{"label":"B","content":"北方航空公司实施优惠价的7月份的营业额比未实施优惠价的2月份增加了30%"},{"label":"C","content":"实施教师优惠票价是表示对教师职业的一种尊重，不应该用功利的角度进行评价"},{"label":"D","content":"该航空公司在实施教师优惠价的同时实施季节性调价"}]','A','⑥。','逻辑判断600题','进阶','published','{"globalNumber":511,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400512,6,'逻辑判断','春天到了，柳絮漫天飞舞，一些新型冠状病毒颗粒会附着在柳絮上，而这些柳絮会 携带着病毒随风飘扬，从而导致新型冠状病毒大面积跨区域性传播。 以下除哪项外，均能削弱上述结论：','[{"label":"A","content":"人体需要吸入大约2公斤沾满新型冠状病毒颗粒的柳絮才可能被病毒感染"},{"label":"B","content":"目前新型冠状病毒被有效的控制在医院的负压病房中，无法逃逸到外部环境中"},{"label":"C","content":"新型冠状病毒在布料表面上的半衰期(病毒损失率数感染能力的时间)约为10 小时"},{"label":"D","content":"自然风会迅速吹走并稀释附在柳絮上的病毒颗粒，有效降低局部空间中的病毒浓度"}]','C','。 394','逻辑判断600题','进阶','published','{"globalNumber":512,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400513,6,'逻辑判断','智能手机惠及千家万户，极大地方便了人们的购物消费。但最近一位英国女士非常 烦恼。起因是，她养的一只非洲鹦鹉学着她的话，帮她在网上买了一大堆物品，使 她蒙受很大的经济损失。对此，有新闻评论员认为，要杜绝此类事件再次发生，就 得关掉手机的语音购物功能，或者不养非洲鹦鹉。 以下哪项描述的事实，最能质疑该评论员的观点：','[{"label":"A","content":"小龙养了许多八哥，也没关手机的语音购物功能，但没出现此类事件"},{"label":"B","content":"小丽养了中国鹦鹉，也没关手机的语音购物功能，但没出现此类事件"},{"label":"C","content":"小红养了非洲鹦鹉，也没关手机的语音购物功能，但没出现此类事件"},{"label":"D","content":"小明没养非洲鹦鹉，也没关手机的语音购物功能，却出现了此类事件"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":513,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400514,6,'逻辑判断','中国全国工业固体废物年产生量达8.2亿吨，综合利用率约46%。全国城市生活垃 圾年产生量为1.4亿吨，达到无害化处理要求的不到10%。为此科学家提出将生活 固体废物中的厨余固废和落叶等植物类固废用于堆肥，既可以减轻环境压力，又可 以用作肥料、改良土壤。堆肥法的优点是占地面积小，投资少，有较好的经济效益 和环境效益。因此，科学家认为合理使用堆肥是解决环境问题的重要途径。 以下哪项为真，能够最有力地削弱科学家的结论：','[{"label":"A","content":"垃圾无害化处理技术已经日渐成熟"},{"label":"B","content":"将固体废物用作堆肥，前提是能够将固体废物进行正确分类"},{"label":"C","content":"环境问题主要由工业固体废物引起，生活固体废物对环境威胁较小"},{"label":"D","content":"堆肥的使用具有季节性和地域性，并非所有土地和作物可以使用堆肥"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":514,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400515,6,'逻辑判断','某单位举行职工象棋比赛，李、王、吴、许、马、朱、田7人进入了决赛。对于最终结果， 甲、乙、丙、丁4人预测如下： 第一名 第二名 第三名 第四名 第五名 第六名 第七名 甲 马 田 李 王 朱 吴 许 乙 李 王 吴 许 朱 马 田 丙 马 王 许 朱 李 吴 田 丁 马 李 田 许 朱 吴 王 比赛结束后，发现他们4人预测的名次正确率都超过了一半。 根据以上信息，可以推出获得第三名的是：','[{"label":"A","content":"李"},{"label":"B","content":"吴"},{"label":"C","content":"许"},{"label":"D","content":"田"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":515,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400516,6,'逻辑判断','近年来，一些鸟类学家发现某市农村地区的麻雀数量越来越少，而城区的麻雀数量 却逐年递增，它们将巢筑在居民房屋的墙洞或室外的许多建筑墙体孔穴中。因此， 有鸟类学家认为，该市的城区正变得越来越适宜麻雀的生存。 下列选项中，最不能支持上述论断的是：','[{"label":"A","content":"该市开展了许多保护鸟类的公益活动，增强了人们保护鸟类的意识"},{"label":"B","content":"近年来，该市城区增加了绿化面积，极大改善了城区生态服务功能"},{"label":"C","content":"该市农村在农业生产中普遍使用的农药显著影响了麻雀的存活率"},{"label":"D","content":"除了昆虫等天然食物外，城区的生活垃圾为麻雀提供了更多的食物来源"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":516,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400517,6,'逻辑判断','某单位周一至周五对外接待，接待时上午，下午各有一名工作人员值班，值班工作 人员有5名，分别是张欣、王武、李明、赵刚和崔林。值班任务分派依据以下条件： (1) 每周每位工作人员至少值班一次 (2)同一周内同一位工作人员不能连续两天值班 (3)李明从不分派上午值班 (4)崔林为周一和周三下午值班，除此以外没有值班任务 (5) 赵刚和王武不在同一天值班 问：一周内李明最多值几次班：','[{"label":"A","content":"1"},{"label":"B","content":"2"},{"label":"C","content":"3"},{"label":"D","content":"4 逻辑判断"}]','B','。 398','逻辑判断600题','进阶','published','{"globalNumber":517,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400518,6,'逻辑判断','甲：“杭州山美水美人更美。” 乙：“你的话不对，我同桌就是杭州人，怎么就美了?” 以下哪项与上述对话方式最为相似：','[{"label":"A","content":"甲：“现已查实，你的受贿金额总共为五万元，你认罪吗?” 乙：“有人受贿几十万也没事，我认什么罪?”"},{"label":"B","content":"甲：“你在提意见的时候，容易情绪激动，希望今后注意。” 乙：“难道我连给别人提意见的权利也没有了?”"},{"label":"C","content":"甲：“我认为人们都没有什么信仰可言。我深信这种说法。” 乙：“你不是正在信仰‘没有信仰的信仰’吗?”"},{"label":"D","content":"甲：“你们通宵达旦、吵吵嚷嚷地打麻将，影响别人休息。” 乙：“影响别人，又不影响你。”"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":518,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400519,6,'逻辑判断','S 校是一所普通高校，近三年来，学校针对即将毕业的学生开展了一系列就业指导 课程，结果发现和前几年相比，学生的就业率普遍提升了5%,而且大部分学生在就 职后很少跳槽，就业稳定性较高。因此，S 校认为，该校开展的就业指导课程能显 著提升本校本科毕业生的就业率及就业稳定性。 以下哪项如果为真，不能削弱上述结论：','[{"label":"A","content":"开设就业指导课后，S 校学生就业后的工资水平并没有显著提高"},{"label":"B","content":"那些选修了就业指导课的学生，在上学期间都参加了课外的社会实践"},{"label":"C","content":"近三年，S 校的研究生就业率比以往提高，本科生就业率下滑较多"},{"label":"D","content":"就业指导课大多传授的是制作简历与求职技巧，对学生实际工作指导有限"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":519,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400520,6,'逻辑判断','在一次聚会上，甲喜欢吃川菜，乙喜欢吃的都是川菜，丙喜欢吃所有川菜。锅包肉 不是川菜，但是麻婆豆腐是川菜。 根据上述条件推知，下列一定为真的是：','[{"label":"A","content":"甲喜欢吃麻婆豆腐"},{"label":"B","content":"乙喜欢吃麻婆豆腐"},{"label":"C","content":"乙不喜欢吃锅包肉"},{"label":"D","content":"丙不喜欢吃锅包肉 IG考 逻辑判断6000 练习题27"}]','C','。 25花生批注： 即“所有乙喜欢吃的都 是川菜”,“所有有些” 可翻译为“前推后”, “乙喜欢吃→川菜”, 逆否为“非川菜→ 乙 不喜欢吃”。 401 练习题27 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 题干给出两个相同的 研究发现：人较多的 与小动物接触(伴侣 动物)能改变心情、 减轻病症、感觉变好、 对环境更有安全感。','逻辑判断600题','进阶','published','{"globalNumber":520,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400521,6,'逻辑判断','科学家研究发现，人如果较多地与小动物接触便能改变心情，减轻精神和心理上存 在的病症。这就是始于上世纪70年代的、国际流行的“伴侣动物疗法”。人和伴侣 动物之间充满着独特的深情和友善。正是在这种情感中，人类因对小动物的关爱而 使自己的身心得到健康。纽约州立大学的研究发现，伴侣动物可直接使人的感觉变好， 对环境更有安全感。 以下各项如果为真，最能支持上述观点的是：','[{"label":"A","content":"许多患者与宠物相处几个月后，原先的如偏头痛等顽固性病症就会得到减轻"},{"label":"B","content":"在与动物的陪伴、接触中，患者需要分散部分注意力与动物进行交流、互动"},{"label":"C","content":"随着社会生活水平的提高，更多家庭开始养宠物并将其视为家庭的重要成员"},{"label":"D","content":"可爱的动物往往会和主人产生更好的互动效果，更易受到主人的喜爱"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":521,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400522,6,'逻辑判断','一间超市被盗，警察锁定5名犯罪嫌疑人。面对警察，这5名犯罪嫌疑人分别说了 如下一句话： 甲：“不是我偷的。” 乙：“甲说谎。” 丙：“我不知道。” 丁：“丙说谎。” 戊：“丙和丁都在说谎。” 请问：这五个人中有几个人说了谎话：','[{"label":"A","content":"1"},{"label":"B","content":"2"},{"label":"C","content":"3"},{"label":"D","content":"4"}]','C','【题型分类】分析类——真假分析 【 实战解析】根据上述信息可知， 甲乙矛盾，必有一真一假；丙丁 矛盾，必有一真一假② ,则戊为假(丙丁不能都说谎); 综上， 一共三人说谎，C 选项正确。','逻辑判断600题','进阶','published','{"globalNumber":522,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400523,6,'逻辑判断','细胞因为发生了基因突变，出现不受控制地增殖分化，最终发展成为恶性肿瘤。在 癌细胞表面存在着许多由突变基因编码的异常蛋白，按理说，这些异常蛋白应该被 机体免疫系统及时识别，并引发免疫反应将癌细胞一举清除。然而，由于肿瘤细胞 发展迅速、极善伪装，而且不断突变，面对凶猛机智的肿瘤细胞，原本强大的免疫 细胞也显得有些“力不从心”,甚至还会对一些肿瘤细胞“视而不见”。在肿瘤微 环境中形成的免疫抑制，更是让免疫系统陷入“瘫痪”。 根据上述信息，下列研究除哪项外，可能有助于研发有效的抗肿瘤药物：','[{"label":"A","content":"研究人员对每位患者的肿瘤细胞和健康细胞的DNA 进行测序，以鉴定出肿瘤特异 性突变，并确定相关的异常蛋白"},{"label":"B","content":"科学家利用免疫疗法，试图改造对肿瘤细胞“不上心”的免疫T 细胞，使其重返 战场"},{"label":"C","content":"科学家将恶性肿瘤患者和健康人的生活方式、个性特征进行对照研究，找出诱发 肿瘤发病的风险因素"},{"label":"D","content":"科学家利用小鼠进行试验，将提取的肿瘤异常蛋白作为疫苗注射入小鼠体内，激 发并增强其免疫反应"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":523,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400524,6,'逻辑判断','甲：己所不欲，勿施于人。 乙：我反对，己所欲，则施于人。 以下哪句与上述对话方式最为相似：','[{"label":"A","content":"甲：人非草木，孰能无情?乙：我反对，草木无情，但人有情。"},{"label":"B","content":"甲：人不犯我，我不犯人。乙：我反对。人若犯我，我就犯人。"},{"label":"C","content":"甲：人无远虑，必有近忧。乙：我反对，人有远虑，亦有近忧。"},{"label":"D","content":"甲：不在其位，不谋其政。乙：我反对，在其位，则行其政。"}]','B','。 此类题目一定注意细 节，“谋其政”和“行 其政”不同。','逻辑判断600题','进阶','published','{"globalNumber":524,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400525,6,'逻辑判断','某学校学生中，所有的理科生都是男生，并非所有的理科生都不是北方人。 根据上述条件，可以推出：','[{"label":"A","content":"有的北方人是男生"},{"label":"B","content":"有的北方人是女生"},{"label":"C","content":"有的男生不是理科生"},{"label":"D","content":"有的北方人不是理科生"}]','A','。 ⑩花生批注： 不所有=有些不，即 有些理科生(不不) 是北方人。 逻辑判断600','逻辑判断600题','进阶','published','{"globalNumber":525,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400526,6,'逻辑判断','一次数学测验结束以后，同学们纷纷猜测班上的第一名是谁。 老师神秘地说是A、B、C、D、E、F六位同学中的一个。 甲说：“第一名要么是A, 要么是C” 乙说：“第一名肯定不是D” 丙说：“第一名不可能是B和 E” 丁说：“第一名如果不是D, 就是F” 老师回答说只有一个同学猜对了。可以推出：','[{"label":"A","content":"甲对了"},{"label":"B","content":"乙对了"},{"label":"C","content":"丙对了"},{"label":"D","content":"丁对了"}]','B','。 ⑪花生批注： 判断规则为“前件为 假，命题为真”。','逻辑判断600题','进阶','published','{"globalNumber":526,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400527,6,'逻辑判断','最近有一位科学家提出新观点：地球板块运动开始的时间不会晚于35亿年前。他的 依据是：板块运动必然会让自然界深色的镁铁质岩石转变成浅色的长英质岩石。而 在35亿年前，地球已经有浅色的长英质岩石出现了。 以下各项如果为真，最能质疑这位专家观点的是：','[{"label":"A","content":"颜色浅的长英质岩石本质上是颜色深的镁铁质岩石“再生”而来的，而在数十亿 年前，镁铁质岩石在地球上占有绝对的数量优势地位"},{"label":"B","content":"以全球各地35亿年前的沉积层样品分析，其中含有长英质岩石颗粒的不足一半"},{"label":"C","content":"长英质岩石在自然界中的占比比镁铁质岩石高出很多似乎只有板块运动这一解释， 但早期的板块构造运动很可能是时断时续的，局部范围的"},{"label":"D","content":"35 亿年前地球火山密布，火山爆发释放的岩浆会把镁铁质岩石深深埋在地下， 这些镁铁质岩石会被熔化，进而转变成长英质岩石，但板块运动不是火山爆发的 唯一原因"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":527,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400528,6,'逻辑判断','教育部出台“双减”政策后，某市教育部门对中小学课外补习制定了具体规定：针 对义务教育阶段的学科类补习只能在工作日晚上9点之前进行，周末可以进行艺术 类补习。 根据上述陈述，以下哪项陈述的情况违反了该市教育部门的规定：','[{"label":"A","content":"四年级同学小明在周三放学之后参加了两个艺术类辅导班"},{"label":"B","content":"初三学生小红在工作日晚上九点之后仍在刻苦学习各学科知识"},{"label":"C","content":"某培训机构针对上班族推出英语口语培训班，吸引了许多学员"},{"label":"D","content":"某培训机构在国庆假期为小升初学生补上因疫情耽搁的数学课程"}]','D','。 ⑬花生批注： 虽然35亿年前地球有 长英质岩石出现，但 地球板块运动不是其 出现的唯一原因，所 以35亿年前不一定有 地球板块运动出现。 ⑭花生批注： 规定可翻译为： ①不是工作日晚九点 后→不能进行义务教 育阶段的学科类补习 (“只有才”翻译成“不 不”) ; ②周末可以进行艺术 类补习。 ⑮花生批注： 有同学认为既然规定 指出周末可以进行艺 术类补习，言外之意 就是其他时间不可以 进行艺术类补习。 但此题为逻辑题，从 逻辑角度A 选项与题 中规定并非矛盾，又 因为有完美的D选项， 只能将此选项向“不 违反规定”方向理解。 逻辑判断60 0 ⑯花生批注： 论据：心脏骤停导致心 源性猝死的高发街区， CPR的实施率偏低； 结论：针对这些街区 的居民推出CPR 培训 计划。 ⑪花生批注： 此题也可分类为对比 实验归因，题干中隐 含了“心源性猝死率 高是因为CPR 实施率 低”这一归因过程， 但此题未从他因角度 进行质疑； 而是通过指出地广人 稀无人实施救治，质 疑计划的有效性。 ⑱花生批注： 论据：人工智能给人 们提供工作和生活上 的便利； 结论：面向家庭日常 使用的人工智能机器 人(家庭机器人), 将成为下一个爆发式 增长的市场(下一个 风口)。','逻辑判断600题','进阶','published','{"globalNumber":528,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400529,6,'逻辑判断','当心脏发生“停工”时 ，很可能导致心源性猝死，而身边如果有同伴懂得心肺复苏 术(CPR) 并迅速实施，就有抢救的机会。美国某大学查阅过去三年的人口资料，发 现心脏骤停导致心源性猝死的高发街区，CPR的实施率通常偏低。为降低猝死发生率， 他们建议针对这些街区的居民推出一项CPR 培训计划。 以下哪项如果为真，最能严重影响这一计划的实际效果：','[{"label":"A","content":"心脏骤停主要发生在晚间，特别是吃晚饭的时候"},{"label":"B","content":"发生心源性猝死的老年人一般都有基础疾病在先"},{"label":"C","content":"CPR的学习并不只是理论学习，还需要反复地练习"},{"label":"D","content":"CPR 实施率低的社区通常是地广人稀的低密度社区"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":529,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400530,6,'逻辑判断','“小T 小 T, 请帮我开灯，小T 小T, 我心情不好，给我讲个笑话吧。小T 小T, 请 在月底提醒我，妈妈的生日快到了……“”如今，各式各样的智能机器人层出不穷， 人工智能通过语音识别和机器学习来模拟人的行为，给人们提供工作和生活上的便 利。多位专家预测，面向家庭日常使用的人工智能机器人，将超过服务于传统制造 业和物流业的机器人，成为下一个爆发式增长的市场。 以下选项如果为真，最能质疑专家预测的是：','[{"label":"A","content":"人工智能机器人的研发制造工序繁杂，生产周期较长，很难实现大规模量产"},{"label":"B","content":"人工智能机器人虽然层出不穷，但各品牌机器人的质量参差不齐，家庭用户评价 褒贬不一"},{"label":"C","content":"面向家庭的人工智能机器人看上去高端，但与实际需求落差大，若要“更像人类”, 则成本过高"},{"label":"D","content":"人工智能和社会伦理是否会产生冲突，能否大批量投入居家使用，尚待时间检验"}]','C','【题型分类】 一般质疑类——有论据有结论 【实战解析】论据结论见批注，分析选项： A 选项，指出人工智能机器人制造周期长，很难大规模量产，但本题 谈论的是家庭机器人是否会是下一个“风口”,讨论的话题不一致； B 选项，指出人工智能机器人质量参差不齐，但本题谈论的是家庭机 器人是否会是下一个“风口”,讨论的话题不一致； C 选 项 ，虽然人工智能给人们提供工作和生活上的便利，但是家庭机 器人与实际需求落差大，若要“更像人类”则成本过高，所以家庭机 器人不一定会成为下一个爆发式增长的市场，可以削弱⑨,当选； D 选 项 ，“尚待时间检验”属于无观点选项，不确定家庭机器人会不 会是下一个爆发式增长的市场； 综 上 ，C 选 项 为 正 确 答 案。','逻辑判断600题','进阶','published','{"globalNumber":530,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400531,6,'逻辑判断','“同情用药”指的是某些重症患者可以在不参加临床试验的情况下，使用尚未获批 上市的在研药物。在新冠肺炎疫情初期，提前使用抗疫药物的同情用药案例数有所 增加，效果良好。但是，同情用药的实施条件十分严格，大部分患者不具备用药资格。 对此，有专家建议，应该放宽同情用药的使用条件。 以下哪项如果为真，最能质疑上述专家建议的合理性：','[{"label":"A","content":"同情用药会破坏新药审批的程序和权威，这对患者和社会都有不可预料的后果"},{"label":"B","content":"即便“无药可救”的患者愿意使用未获批的在研药物，也不一定能够成功延长生命"},{"label":"C","content":"为了保护患者用药安全，大部分国家目前严禁未经过临床试验的药品上市"},{"label":"D","content":"目前，大部分常见疾病都已经有一些适用药物，这些疾病并不需要同情用药"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":531,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400532,6,'逻辑判断','某研究调查了数千名被试者的睡眠情况与健康状况，结果发现，从中年至老年(50 岁至70岁间)一直处于较短睡眠模式(即每晚睡眠时长少于6小时)的人，失智风 险会增加30%。研究者呼吁，中老年人适当增加睡眠时长，可以预防失智的发生。 以下陈述如果为真，哪项最能质疑研究者的观点：','[{"label":"A","content":"老年人每日睡眠时间过长不仅会有疲劳感，还会记忆力降低，精力不集中"},{"label":"B","content":"随着年龄的增加，身体的细胞也慢慢衰老，这就导致睡眠时间开始变短"},{"label":"C","content":"心血管代谢问题和精神疾患等都是失智的重要风险因素"},{"label":"D","content":"失智是一种因脑部疾病所导致的渐进性认知功能退化，跟睡眠时长无关"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":532,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400533,6,'逻辑判断','某班级统计上课迟到人数，四名同学对是否迟到说法如下： 王：我没有迟到。 吴：李和王至少有一人没有迟到。 李：我们中有人迟到。 刘：我们四人都没有迟到。 已知上述四人两人说真话、两人说假话，则以下哪项断定为真：','[{"label":"A","content":"说真话的是王和刘"},{"label":"B","content":"说真话的是王和吴"},{"label":"C","content":"说真话的是吴和李"},{"label":"D","content":"说真话的是吴和刘"}]','C','。 3花生批注： 对比实验归因题，正 确选项要回归实验， 和实验分组一致，脱 离实验的“他因”往 往是强干扰项。 ④花生批注： 两真两假题目常用方 法：找矛盾，用假设 法判断剩余二人。 25花生批注： “所有不”和“有些是” 矛盾。 ⑥花生批注： “李和王至少有一人 没有迟到”,可翻译为 “李或王”,或者或者， 一真则真。 7 花生批注： “特例”可推出“有些”。 8花生批注： 题干将孩子近视的原 因归于户外时间(眼 睛是否在明亮光线下), 实验过程并未详细介 绍。 29花生批注： 排除他因是对比实验 归因题的常见支持方 式。 ③花生批注： 类比支持“虽有但弱”, 在“最能支持”、“不 能支持”的题目中一 般都不是正确答案。 ③花生批注： 眼球发育不良可能造 成其他眼部疾病，例 如上睑下垂、眼球轻 度外斜、眼球转动受限、 视力减退等。 ③花生批注： 若附近学校孩子每天 在户外活动时间超过 80分钟，此选项则为 质疑项。','逻辑判断600题','进阶','published','{"globalNumber":533,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400534,6,'逻辑判断','近视的原因是什么? 某国的研究者跟踪了500多名8-9岁视力正常的儿童，五年后 发现，唯一和患近视相关的环境因素是儿童在户外的时间。而且，孩子的近视确实 和在户外的时长有关，无论孩子们在户外是在锻炼、野餐，还是只是在海滩上读书。 由此研究者认为，导致近视更重要的原因可能是眼睛是否处在明亮光线下，光照可 以保护眼睛。 以下各项如果为真，哪项最能支持以上观点：','[{"label":"A","content":"那些在户外待得更久的孩子并没有减少看书本、看屏幕或进行近距离学习的时间， 有些孩子在户外看书a 和电子屏的时间非常长"},{"label":"B","content":"与在一般室内光照环境下生长的鸡相比，处于与户外光照相当的高光照水平下的 鸡 ，实验诱发的近视发生减缓约60%,恒河猴中也发现了类似效应"},{"label":"C","content":"视网膜按照昼夜节律产生多巴胺，使得眼球可以从夜间视觉切换到白昼视觉。白 天室内昏暗的光照下，视网膜的周期会被扰乱，影响到眼球发育"},{"label":"D","content":"某学校要求孩子们每天共80分钟的课间时间全到户外去，不许留在室内。一年后， 8%的孩子被诊断为近视，而附近一所学校同龄孩子的近视率是18%"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":534,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400535,6,'逻辑判断','小张与小陈参加了考研复试，不久，小张得到以下消息： (1)他与小陈至少有一人被录取。 (2)学校可能不录取他。 (3)学校一定录取他。 (4)学校已经录取小陈。 若上述消息两条为真，两条为假，则以下哪项为真：','[{"label":"A","content":"学校既未录取小张，也未录取小陈"},{"label":"B","content":"学校既录取了小张，也录取了小陈"},{"label":"C","content":"学校未录取小张，已录取小陈"},{"label":"D","content":"学校已录取小张，未录取小陈"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":535,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400536,6,'逻辑判断','对所有考生进行了安全检查，没有发现违禁品携带者。 如果以上假设为假，则以下哪项一定为真： I. 或者有的考生没有进行安全检查，或者在考生中发现了违禁物品携带者 Ⅱ.虽然有的考生没有进行安全检查，但还是发现了违禁物品携带者 Ⅲ.如果对所有的考生进行了安全检查，则一定发现了违禁品携带者','[{"label":"A","content":"仅 I 和Ⅲ"},{"label":"B","content":"仅 I"},{"label":"C","content":"仅Ⅲ"},{"label":"D","content":"仅 I 和Ⅱ"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":536,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400537,6,'逻辑判断','信天翁属于夔形目，有着管状的鼻子，嗅觉灵敏，经常为了觅食在外海上长距离飞行。 那些漂浮在海上的塑料垃圾看起来并非美味，可信天翁为什么会吃下它们，并为此 付出沉重代价呢?研究人员认为原因在于：对于信天翁而言，这些塑料垃圾闻起来“很 好吃”。“美食信号”是一种名叫二甲基硫醚 ( DMS) 的化学物质，这种气味物质在 海洋浮游植物的作用下产生。 以下哪项如果为真，无法支持研究人员的观点：','[{"label":"A","content":"骧形目鸟类当中有一部分物种常聚集在海洋浮游植物丰盛的地方"},{"label":"B","content":"误食塑料垃圾会导致海鸟行动不便、消化道阻塞，健康慢性受损"},{"label":"C","content":"实验证明在海中浸泡三周后的塑料样品上都检测到了DMS成分"},{"label":"D","content":"对 DMS 气味敏感的骧形目鸟类可以探测到浓度极低的气味分子"}]','B','。 414','逻辑判断600题','进阶','published','{"globalNumber":537,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400538,6,'逻辑判断','高一女生进行800米跑步训练，跑步前，蒋、沈、韩三位老师分别对高一女生的跑 步成绩进行如下预测： 蒋老师：大家最近都没怎么锻炼，没有人能在3分钟内跑完全程； 沈老师：会有人在3分钟内跑完全程； 韩老师：陶或姜会在3分钟内跑完全程。 跑步结束后，只有一位老师的预测是正确的。 由此可以推出：','[{"label":"A","content":"没有人在3分钟内跑完全程"},{"label":"B","content":"所有人都在3分钟内跑完了全程"},{"label":"C","content":"姜在3分钟内跑完了全程"},{"label":"D","content":"陶没有在3分钟内跑完全程"}]','D','。 ④②花生批注： 常见的矛盾关系有三 种： A与非A(A 且B 与非 A或非B、A或B与非 A且非B); 所有和有些不，有些 和所有不； A→B和A 且非B。','逻辑判断600题','进阶','published','{"globalNumber":538,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400539,6,'逻辑判断','在某大学的一个班级里： I. 所有的人都不吃早餐。 II. 没有一个人不吃早餐。 Ⅲ.该班的小李不吃早餐。 假设以上三句话只有一句为真，能够必然推出：','[{"label":"A","content":"该班的小李不吃早餐"},{"label":"B","content":"该班的小李吃早餐"},{"label":"C","content":"该班所有人都吃早餐"},{"label":"D","content":"该班有的人吃早餐"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":539,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400540,6,'逻辑判断','截至2019年末，全国60岁以上的老年人超2.5亿，其中农村老人占1.3亿。估计 未来可能还有近10%的农村人口会转移到城市居住，但仍有4亿多的农村人口。根 据预测，到2028年的时候，农村老年人口的比重或将突破农村人口的30%。由此可见， 我国农村的老龄化水平要高于城市，农村面临着更为严重的老龄化问题。 以下各项如果为真，除哪项外均能支持以上论述：','[{"label":"A","content":"农村的年轻人越来越多地向城市转移并改变其户籍性质"},{"label":"B","content":"截至2019年末，我国农村人口在总人口中的占比不足50%"},{"label":"C","content":"未来，我国将采取更有力的措施积极应对农村人口老龄化"},{"label":"D","content":"农村转移到城市居住的人口中，六十岁以上的老人占比不到30% 练习题28"}]','C','。 逻辑判断 练习题28 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数','逻辑判断600题','进阶','published','{"globalNumber":540,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400541,6,'逻辑判断','将东西两位戏剧大师的生平经历、文学造诣及身后影响作对比，是一个有趣的话题， 有专家认为，将汤显祖称作“东方的莎士比亚”有很大的问题，因为无论是就人格 的魅力，还是就文本美感而言，汤显祖都是不逊于莎士比亚的。 以下哪项最可能是上述专家观点所包含的假设：','[{"label":"A","content":"汤显祖的人格魅力及其文本的美感均高于莎士比亚"},{"label":"B","content":"汤显祖在西方的影响要大于莎士比亚在东方的影响"},{"label":"C","content":"汤显祖和莎士比亚都不愿意别人用他人的名字来称呼自己"},{"label":"D","content":"“东方的威尼斯”是逊色于真正的威尼斯的"}]','D','【题型分类】前提假设类——断点搭桥 【实战解析】论据和结论见批注。论据和结论是两个联系并不紧密的 话题，需要搭桥将“不逊于”和“东方的”连接； 可以将论据看作P,结论看作Q,需要的连接为“P →Q”⑤。即需要“如 果汤显祖不逊于莎士比亚，就不能将汤显祖称作‘东方的莎士比亚’”, 逆否为“若称呼‘东方的莎士比亚’,则其是逊色于真正的莎士比亚的”; 观察选项，只有D选项类似此说法⑨,将“不逊于”与“东方的”相连接， 其逻辑关系如下： “东方的某某”是逊色于真正的某某的，汤显祖不逊色于莎士比亚， 所以不能将汤显祖称为“东方的莎士比亚”⑤ ①花生批注： 论据：汤显祖都是不 逊于莎士比亚的； 结论：将汤显祖称作 “东方的莎士比亚” 有很大的问题。 ②花生批注： A、B 、C选 项 ，均无 法将“不逊于”与“东 方的”搭桥连接，不 是隐含的前提。 ③花生批注： 例如：“明天有雨， 所以要带伞”的隐含 假设是“下雨就要带 伞 ”。 ④花生批注： D选项存在类比推理， “东方的威尼斯”是 逊色于真正的威尼斯 的，说明“东方的某某” 可能是逊色于真正的 某某，即“东方的莎 士比亚”是逊色于真 正莎士比亚的。 ⑤花生批注： 例如：中国梅西是逊 色于真正梅西的。 ⑥花生批注： 结论：部分人对“乌 鸦保洁员”能否起到 作用表示怀疑，即他 们认为“乌鸦保洁员” 可能起不到作用。 ⑦花生批注： 虽然乌鸦让游客产生 了更多垃圾，但乌鸦 有更强的保洁功效， 不仅将产生的更多垃 圾清理，还清理了之 前有的垃圾，那么乌 鸦还是有保洁作用。 ⑧花生批注： 此题，A、B 、C、D选 项均有支持力度，但A、 C 、D选项只说到乌鸦 带来的负面作用，未提 及正面作用； 只有B 选项明确指出， 乌鸦几乎没有保洁作 用。 ⑨花生批注： 指赵某说的是错的， 即钱某的意思就是赵 某的意思的矛盾式； 常见矛盾关系有三种： A 与 非A(A 或 B 与 非A 且非 B 、A且 B 与非A 或非B); 所有和有些不、有些 和所有不； A→B 与A 且非B。','逻辑判断600题','进阶','published','{"globalNumber":541,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400542,6,'逻辑判断','法国某公园准备“聘请”一批乌鸦作为“保洁员”。但部分人也对这些“乌鸦保洁员” 能否起到作用表示怀疑。 以下各项如果为真，最能支持这部分人的怀疑的是：','[{"label":"A","content":"“乌鸦保洁员”可能引起人们的好奇，导致公园游客剧增，从而产生更多的垃圾"},{"label":"B","content":"经实验，受训的“乌鸦保洁员”每天只能拾捡极其有限的重量轻、体积小的垃圾， 对公园的保洁作用几乎为零"},{"label":"C","content":"据调查统计，为了亲眼目睹“乌鸦保洁员”如何拾捡垃圾，大部分游客有故意乱 扔大量垃圾的倾向"},{"label":"D","content":"哪怕是经过训练的乌鸦，也依然保留着乱衔树枝、小石头的本能，而且饲养乌鸦 本身也会产生垃圾"}]','B','⑧','逻辑判断600题','进阶','published','{"globalNumber":542,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400543,6,'逻辑判断','赵某：如果明天能准时下班，我们就去吃火锅。 钱某：我不同意。 据此，可以推出钱某的意思是：','[{"label":"A","content":"明天能准时下班，赵某和钱某一起去吃火锅"},{"label":"B","content":"明天能准时下班，但钱某不会和赵某一起去吃火锅"},{"label":"C","content":"明天不能准时下班，赵某和钱某仍一起去吃火锅"},{"label":"D","content":"明天不能准时下班，钱某没有和赵某一起去吃火锅"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":543,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400544,6,'逻辑判断','据报道，国际上有不少科学家声称，在新西兰周围发现了一块名为“西兰洲”的新大陆， 它符合大洲认定标准的全部要求，是世界第八大洲，相信在不久的将来，各国的地 理课本将会被改写。 得出“各国的地理课本将会被改写”的结论必须基于的前提是：','[{"label":"A","content":"各国地理课本会因为“大陆”“大洲”等相关知识内容变化而改写"},{"label":"B","content":"认定大洲的标准具有权威性，并且在课本发行前不会改变"},{"label":"C","content":"各国地理课本目前没有关于“世界第八大洲”的任何内容"},{"label":"D","content":"各国地理课本本身都有关于“大陆”“大洲”等的内容"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":544,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400545,6,'逻辑判断','某金库发生了失窃案。公安机关侦查确定，这是一起典型的内盗案，可以断定金库 管理员甲乙丙丁中至少有一人是作案者。侦查人员对四人进行了询问，四人的回答 如下： 甲：“如果乙不是窃贼，我也不是窃贼。” 乙：“我不是窃贼，丙是窃贼。” 丙：“甲或者乙是窃贼。” 丁：“乙或者丙是窃贼。” 后来事实表明，他们四个人中只有一个人说了真话。 根据以上陈述，以下哪项一定为假：','[{"label":"A","content":"甲说的是真话"},{"label":"B","content":"乙不是窃贼"},{"label":"C","content":"丙说的是假话"},{"label":"D","content":"丁说的是真话"}]','D','【题型分类】分析类---真假分析 【实战解析】本题无明显矛盾关系，可采用假设法： 优先对最多信息“乙”进行假设，假设乙是窃贼，则丙和丁都说真话 ， 根据“只有一真”得出乙不是窃贼，可排除B选项； 假设丙是窃贼，则乙和丁都说真话，根据“只有一真”得出丙不是窃贼； 乙和丙都不是窃贼，可以得出丁一定说假话，故D 选项一定为假。','逻辑判断600题','进阶','published','{"globalNumber":545,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400546,6,'逻辑判断','奇虾是一类已经灭绝的大型无脊椎海洋动物，是目前已知最庞大的寒武纪动物。化 石表明这种动物口器有十几排牙齿，直径有25厘米，粪便化石长10厘米，粗5厘米。 由此推测，奇虾体长可能超过2米。 以下哪项如果为真，最能支持上述推测：','[{"label":"A","content":"寒武纪时期，海洋虾类食物充足"},{"label":"B","content":"25 厘米直径的巨口奇虾可掠食当时的任何大型生物"},{"label":"C","content":"对于大型无脊椎动物而言，牙齿越多身体越长"},{"label":"D","content":"寒武纪时期的海洋虾类，其牙齿和体长有比较固定的构成比例"}]','C','。 ⑮花生批注： 切记：此类题目“以 我为主”,寻找想要 答案，不要被错误选 项干扰。 ⑯花生批注： 除主体错误外，D 选 项还存在不明确的问 题，牙齿和体长有固 定比例，但成正比、 反比未明确说明。','逻辑判断600题','进阶','published','{"globalNumber":546,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400547,6,'逻辑判断','木星是气态巨行星，也是太阳系中最大的行星，质量是太阳系中其他七大行星质量 总和的2.5倍。观测发现，围绕木星的70多颗卫星大部分由水冰构成。因此，木星 的大气层里应含有相当数量的水。 下列哪项如果为真，最能支持以上论述：','[{"label":"A","content":"经过若干亿年之后，卫星可能慢慢地跌落到行星上"},{"label":"B","content":"星际空间的水，很多是以气态形式存在的"},{"label":"C","content":"天王星也是气态巨行星，已经证实它含有大量水冰"},{"label":"D","content":"卫星和它所环绕的行星是在同一时期由相同的气体和灰尘所形成的"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":547,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400548,6,'逻辑判断','一项实验让两组人员观察20张图像后，A组服用咖啡因药丸，B组服用安慰剂药丸。 24小时后，再向两组人员展示20张图像，其中包含若干之前的图像，结果显示，A 组人员能更快速、更准确地辨认出之前的图像。因此，该实验表明，喝咖啡可以增 强记忆。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"B 组人员平均年龄比A组大15岁"},{"label":"B","content":"大部分图像都非常复杂，难以记住"},{"label":"C","content":"咖啡因在人体内作用最多持续8小时"},{"label":"D","content":"服用的咖啡因药丸剂量大于一杯咖啡"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":548,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400549,6,'逻辑判断','柏木都可以用来造船，这块木头不能用来造船，所以这块木头不是柏木。 以下哪项的推理结构与上述推理的形式最为类似：','[{"label":"A","content":"食肉动物都吃肉，羊吃草，所以羊不是食肉动物"},{"label":"B","content":"跑鞋都是有鞋钉的，皮鞋不是跑鞋，所以皮鞋没有鞋钉"},{"label":"C","content":"白洋淀的渔民都会划船，小赵不会划船，所以小赵不是白洋淀的"},{"label":"D","content":"跑步爱好者都能跑十公里，小胖跑不完十公里，所以小胖不是跑步爱好者"}]','D','。 2花生批注： 例如：药物最多作用8 小时，24小时后身体 好转了，不能说药物 无效。 ②花生批注： D 选项与题干推理形 式完全一致，其他选 项 一定注意细节，例 如A 选项的“吃肉” 和“吃草”,C 选项的“白 洋淀的渔民”和“白 洋淀的 ”。 423 423','逻辑判断600题','进阶','published','{"globalNumber":549,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400550,6,'逻辑判断','华为推出的P30 系列，其四摄一度成为安卓旗舰手机的标杆。除了屏幕技术的革新 和竞争，近年来，智能手机厂商们都致力在摄像头硬件、拍摄性能、算法以及其他 与镜头相关的技术上努力，加大研发，务求将手机拍摄从满足日常拍摄，走进半专业， 甚至专业领域。也正因为智能手机的这些优点，越来越多的人放弃购买数码相机。 据此，研究员张楠预计，再过若干年，制造数码相机的工厂最终会倒闭。 以下哪项如果为真，最能削弱张楠的结论：','[{"label":"A","content":"因为拍照功能好的智能手机价格较为昂贵，一些消费者不会购买"},{"label":"B","content":"虽然数码相机功能单一，用习惯的人不愿意用智能手机拍照"},{"label":"C","content":"大多数数码相机制造厂不仅制造数码相机也制造智能手机零件"},{"label":"D","content":"许多智能手机拍照时会抖动，令许多人感到麻烦"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":550,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400551,6,'逻辑判断','某汽车企业在传统车型的基础上新增了自动上锁装置，能保证汽车和车内财产的安 全性。因此，这款自动上锁车型的销售量将大大高于传统车型。 以下哪项如果为真，最能对上述推理提出质疑：','[{"label":"A","content":"传统车型中有一些最常用的功能并没有在新车型中体现"},{"label":"B","content":"新车型使用者与传统车型使用者的生活环境不同"},{"label":"C","content":"无论是装有自动上锁的新车型还是传统车型，使用习惯都是因人而异的"},{"label":"D","content":"该企业生产的这款自动上锁装置获得了专利权，是目前市面上其他汽车所不具备的"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":551,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400552,6,'逻辑判断','有经济学者不赞成政府对低收入人群的直接救助，主张政府对大企业家和富人采取 优惠的财政和税收政策，认为大企业家和富人的投资与消费活动会促进经济发展， 增加穷人的就业机会，将财富从社会上层传递到社会底层。 如果以下各项为真，最能削弱上述理论的观点是：','[{"label":"A","content":"政府对大企业家和富人采取优惠的财政和税收政策，导致因贫富差距拉大而引发 不确定的社会矛盾"},{"label":"B","content":"打破收入分配方面的平均主义，鼓励一部分人先富起来，但具体实施这一政策存 在不可预见的风险"},{"label":"C","content":"高收入者的消费需求达到饱和后，人的“自私性”将抑制投资需求，社会投资规 模也不再继续增长"},{"label":"D","content":"政府的财政和税收政策应该优惠穷人，提高穷人购买力同样会增加有效消费需求 促使经济持续发展"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":552,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400553,6,'逻辑判断','某研究小组进行了一项研究，他们让参与者进行一段时间的学习，之后部分参与者 被要求进行5分钟低强度的有氧运动，另一部分不做任何运动。研究人员发现，在 学习之后进行有氧运动的人比在学习之后不运动的人能够记住更多的信息。他们据 此推测，在学习之后做一些有氧运动对于记忆力的提升有显著效果。 以下哪项如果为真，最能质疑上述推测：','[{"label":"A","content":"有氧运动的参与者都是女性而另一部分参与者都是男性"},{"label":"B","content":"有氧运动参与者的记忆力原本比另一部分参与者差很多"},{"label":"C","content":"有氧运动的参与者多为年轻人而另一部分参与者多为中年人"},{"label":"D","content":"高强度的有氧运动对记忆力的提升不如低强度的有氧运动显著"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":553,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400554,6,'逻辑判断','因为受到极端天气等季节性因素的影响，某省水果、蔬菜价格比平时上涨了二三倍， 这就大大提高了水果、蔬菜制品的成本，估计水果、蔬菜制品的价格将会大幅提升。 以下哪项如果是真的，最能削弱上述结论：','[{"label":"A","content":"去年该省水果、蔬菜的价格是历年最低的"},{"label":"B","content":"其他替代原料可以用来生产仿水果、蔬菜制品"},{"label":"C","content":"最近的极端天气并不如专家们估计的那么严重"},{"label":"D","content":"除了该省外，其他省份也可以提供水果、蔬菜 173 173"}]','D','。 28花生批注： 论据：果蔬价格比平 时上涨了二三倍； 结论：果蔬制品的价 格将会大幅提升。 ⑨花生批注： 注意：仿果蔬制品， 不是果蔬制品； 该选项改成“可以用 其他替代原料生产果 蔬制品”,可以质疑。','逻辑判断600题','进阶','published','{"globalNumber":554,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400555,6,'逻辑判断','电脑城中的某计算机销售商只有从批发商那批发到低于批发价的计算机散件，才能 低于市场价销售计算机而获利；除非该销售商的销售量很大，否则，就不能从批发 商那批到低于批发价的计算机散件；要想有更大的销售量，计算机销售商就要满足 消费者的特定需求或者拥有特定型号计算机的专售权。 如果上述命题为真，则以下哪项必定为真：','[{"label":"A","content":"如果该销售商没有以低于市场价的价格销售计算机而获利，则他一定没有满足消 费者的需求或者拥有特定型号计算机的专售权"},{"label":"B","content":"如果该销售商以低于市场价的价格销售计算机而获利，那么一定是从批发商那批 发到低于批发价的计算机散件"},{"label":"C","content":"如果该销售商从批发商那里批发到低于批发价的计算机散件，那么就会低于市场 价的价格销售计算机而获利"},{"label":"D","content":"如果该销售商能够满足消费者特定需求或者拥有特定计算机型号专售权，那么就 会有大的销售量"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":555,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400556,6,'逻辑判断','“泰山天下雄”,以下选项与上述推理方式最相近的是：','[{"label":"A","content":"我见青山多妩媚，料青山见我应如是"},{"label":"B","content":"笑别庐山远，何烦过虎溪"},{"label":"C","content":"上有天堂，下有苏杭"},{"label":"D","content":"自古华山一条路"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":556,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400557,6,'逻辑判断','鲨鱼一般都是肉食性的，但一些科学家称，他们在某海域发现了一种以植物作为食 物重要组成部分的窄头双髻鲨鱼。 以下各项如果为真，最能支持这些科学家们发现的是：','[{"label":"A","content":"研究人员分析其胃内食物发现，一些窄头双髻鲨鱼的食物组成中有一半是植物"},{"label":"B","content":"以海草占比90%的特制饲料人工喂养的窄头双髻鲨鱼，在为期3周实验时间内体 重均有增长"},{"label":"C","content":"研究发现窄头双髻鲨鱼的肠道里存在一种能对植物进行高效分解的酶，该种酶在 其他鲨鱼肠道里并不存在"},{"label":"D","content":"窄头双髻鲨鱼的血液中含有大量的非自身合成的某种营养物质，在自然界中，仅 海草含有少量的该营养物质"}]','D','。 ③花 生批注： 题干只有结论：窄头 双髻鲨鱼以植物作为 食物重要组成部分。 33花生批注： 需注意“食物重要组 成部分”,不仅“要吃”, 还要“多吃”。 ③花生批注： “一些”可以极端的 理解为“一个”,从 少数个例无法推得整 体情况。 35花生批注： C 选项可看作该鲨鱼 “能”吃植物的必要 条件，但其是否将植 物当做“食物重要组 成部分”,无从得知。 ③⑥花生批注： 该选项的程度词“大 量”、“少量”,与 题干的“重要”对应， 体现出“吃得多”, 完美选项。 ③花生批注： 村长说的并非事实，指 的是“村长说的和事实 是矛盾的”; 常见矛盾关系有三种： A与非A(A 或B 与非 A 且非B 、A且B 与非 A或非B); 所有和有些不、有些和 所有不； A→B 与 A 且非B。 38花生批注： (2)可翻译为“盗窃 保险柜→有专门技术”, 丙没有专门技术，丙不 能单独盗窃保险柜； 需要注意，丙可以和其 他人合伙作案。','逻辑判断600题','进阶','published','{"globalNumber":557,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400558,6,'逻辑判断','村长在一次美丽乡村动员大会结束后宣布：“此次提出的关于村里垃圾处理的方案 得到了一致认可，全体村民一致通过了该方案。”会后，小张就此事进行了调查， 发现村长说的并非事实。 如果小张的调查结果为真，以下哪项也必然为真：','[{"label":"A","content":"全体村民都不同意通过该方案"},{"label":"B","content":"部分村民同意通过该方案"},{"label":"C","content":"有些村民同意通过该方案，有些村民反对通过该方案"},{"label":"D","content":"有村民不同意通过该方案"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":558,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400559,6,'逻辑判断','春节期间王先生回老家陪父母过年，回到市里发现家中保险柜被盗。民警通过走访 调查，认定甲、乙、丙三人有重大嫌疑。经过侦查审讯，现已掌握以下线索： (1)甲、乙、丙至少有一人参与了此次盗窃 (2)盗窃保险柜需要经过专门的技术训练 (3)如果甲作案，那么乙就是同伙 (4) 丙并不掌握保险柜盗窃技术 根据以上事实，能够确定的是：','[{"label":"A","content":"甲参与了盗窃"},{"label":"B","content":"乙参与了盗窃"},{"label":"C","content":"丙参与了盗窃"},{"label":"D","content":"甲乙合伙盗窃"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":559,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400560,6,'逻辑判断','每晚睡觉前都泡个热水脚的人睡眠质量都不会差，小王每晚睡前都会泡个热水脚。 所以小王睡眠质量不会差。 下列选项与上述推理结构最相似的是：','[{"label":"A","content":"会做饭的人都不会洗衣服，小明不会做饭，所以小明会洗衣服"},{"label":"B","content":"打篮球打的好的人都是长得高的人，小光长得高，所以小光是篮球打得好的人"},{"label":"C","content":"成功的人都很讲诚信，小李不讲诚信，所以小李不是成功的人"},{"label":"D","content":"会武功的人都很讲武德，更何况是赵师傅这样的武学大师呢 练习题29"}]','D','。 练习题29 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 研究人员发现：果蝇 的同性恋行为不仅受 遗传因素影响，社会 因素也发挥了很大的 促进作用。 ②花生批注： A 、D选项，分析的是 果蝇异性恋的原因。','逻辑判断600题','进阶','published','{"globalNumber":560,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400561,6,'逻辑判断','人们已经知道：如果果蝇体内的w基因发挥作用，雄性果蝇就不会向雌性果蝇求爱， 转而追求同性。因此果蝇的同性恋行为被认为是由遗传因素决定的。最近，研究人 员培养出w基因发挥作用的雄性果蝇，然后利用这种果蝇进行了实验。他们发现， 果蝇的同性恋行为不仅受遗传因素影响，社会因素也发挥了很大的促进作用。 以下哪项如果为真，最能支持研究人员的发现：','[{"label":"A","content":"如果这种雄性果蝇羽化为成虫后，只要进行一天以上的集体饲养，雄性果蝇就开 始追逐其他雌性果蝇，显示出求爱行为；但如果这种果蝇羽化后是一只只隔离饲 养的，则不会出现此种行为"},{"label":"B","content":"如果这种雄性果蝇羽化后是一只只隔离饲养的，若干天后，果蝇就开始表现出对 其他雄性果蝇的求爱行为；如果这种雄性果蝇羽化为成虫后是集体饲养的，则不 会出现此种行为"},{"label":"C","content":"如果这种雄性果蝇羽化为成虫后，只要进行一天以上的集体饲养，雄性果蝇就开 始追逐其他雄性果蝇，显示出同性恋的求爱行为；但如果这种果蝇羽化后是一只 只隔离饲养的，则不会出现此种行为"},{"label":"D","content":"如果这种雄性果蝇羽化后是一只只隔离饲养的，若干天后，果蝇就开始表现出对 其他雌性果蝇的求爱行为；如果这种雄性果蝇羽化为成虫后是集体饲养的，则不 会出现此种行为"}]','C','。 隔 离 饲 养 出现追逐其他雌性果蝇 的求爱行为 ③花生批注： 切记：此类题目“以 我为主”,寻找想要 的答案，不要被错误 选项干扰。 ④花生批注： “A→B” 与“A 且非 B” 矛盾。 ⑤花生批注： 翻译为： (1) 赢得人民信任→ 党可以克服任何困难； (2)赢得人民信任 → 党可以无往而不胜； (3)得到人民支持 → 党可以克服任何困难； (4)得到人民支持 → 党可以无往而不胜。 需要注意：选项均只 涉及一半前件，一半 后件，所以不能翻译 成“赢得人民信任且 得到人民支持→党可 以克服任何困难且无 往而不胜。”','逻辑判断600题','进阶','published','{"globalNumber":561,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400562,6,'逻辑判断','“世上无难事，只怕有心人” 这句话如果为真，则否定了以下哪一项：','[{"label":"A","content":"张三虽然没有解决问题，但还是尽心尽力了"},{"label":"B","content":"张三没有用心，结果事情没有办好"},{"label":"C","content":"张三能力很强，这点事难不倒他，不用花心思就能解决"},{"label":"D","content":"这件事张三不可能办不好，除非他不用心"}]','A','【题型分类】分析类——真假分析 【实战解析】③题干可理解为“如果是有心人，世上就无难事”,此 命题为真，则其矛盾⑨为假，即“有心人且有难事”为假； 观察选项，A 选项可翻译为“张三是有心人且有难事”,与题干矛盾， 当选； 其他选项： B 选项，翻译为“张三不是有心人且有难事”,和题干并非矛盾； C 选项，翻译为“张三不是有心人且无难事”,和题干并非矛盾； D 选项，可理解为“除非张三不用心，否则能办好”,翻译为“张三 是有心人→世上无难事”,与题干逻辑一致。','逻辑判断600题','进阶','published','{"globalNumber":562,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400563,6,'逻辑判断','我们党的百年历史，就是一部践行党的初心使命的历史，就是一部党与人民心连心、 同呼吸、共命运的历史。历史充分证明，江山就是人民，人民就是江山，人心向背 关系党的生死存亡。赢得人民信任，得到人民支持，党就能够克服任何困难，就能 够无往而不胜。 根据以上陈述，可以得出以下哪项： 四海公煮 SIHAIGONGKAO','[{"label":"A","content":"只有赢得人民信任，党才能得到人民支持"},{"label":"B","content":"只有能够克服任何困难，党才能赢得人民信任"},{"label":"C","content":"如果得不到人民支持，党就不能无往而不胜"},{"label":"D","content":"如果不能赢得人民信任，党就不能克服任何困难"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":563,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400564,6,'逻辑判断','足迹化石虽然不能像实体化石那样保存生物完整的形态，但从足迹化石中，我们可 以分析出生物大概的形态特征和行为学特征。也就是说，当直接证据缺失的时候， 我们只能通过间接证据——足 迹化石来推测当时的环境，反推是哪些动物留下的足 迹，他们有没有复杂的动物行为等。因此，在前寒武纪到寒武纪的转折时期⑦,足 迹化石显得尤为重要。 上述结论的成立，还需基于以下哪一前提：','[{"label":"A","content":"目前发现的从前寒武纪到寒武纪转折时期的足迹化石比实体化石更多"},{"label":"B","content":"前寒武纪到寒武纪转折时期的足迹化石比实体化石更具有研究价值"},{"label":"C","content":"目前发现的前寒武纪到寒武纪转折时期的足迹化石比其他时期稀少"},{"label":"D","content":"在前寒武纪到寒武纪的转折时期，保留下来的动物实体化石十分稀少"}]','D','。 435 ⑩花生批注： 论据：学术水平突出 的教授(A)→ 受学生 爱戴( B), 学术水平 突出的教授(A)→ 注 重培养学生的专业基 础知识( C); 结论：有些深受学生 爱戴的教授( B) 不主 张只关注学术前言问 题 ( D )。 两句论据无联系，应 分别和选项搭配，推 出结论。 ⑪花生批注： 三段论应包含三种概 念，而且每个概念出 现两次； 论据“A→B”, 结论 “有些B 是D”, 需 要补充“A ”和“D”。 ⑫花生批注： 根据“所有”可以推 出“有些”,“所有 学术水平突出的教 授 都深受学生爱戴”可 以推出“有些学术水 平突出的教授都深受 学生爱戴”;根据“有 些A 是B” 可以推出 “有些B 是A”, “有 些学术水平突出的教 授都深受学生爱戴” 可以推出“有些深受 学生爱戴的教授学术 水平突出”。 ⑬花生批注： “所有”可以推出“有 些”。 ⑭花生批注： “A→C”+ “ 有些C 是D”, 推不出“有 些B是D”','逻辑判断600题','进阶','published','{"globalNumber":564,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400565,6,'逻辑判断','所有学术水平突出的教授都深受学生爱戴，而所有学术水平突出的教授都注重培养 学生的专业基础知识，因此，有些深受学生爱戴的教授不主张只关注学术前沿问题。 上述论证的成立需补充的前提是：','[{"label":"A","content":"只关注学术前沿问题的教授不受学生爱戴"},{"label":"B","content":"学术水平突出的教授不主张只关注学术前沿问题"},{"label":"C","content":"注重培养学生专业基础知识的教授都深受学生爱戴"},{"label":"D","content":"部分注重培养学生专业基础知识的教授不主张只关注学术前沿问题"}]','B','','逻辑判断600题','进阶','published','{"globalNumber":565,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400566,6,'逻辑判断','所有太原人都是山西人；所有太原人都喜欢吃面食；有些山西人喜欢旅游。 如果以上断定成立，那么下列哪项能够从中推出： I. 有些山西人不是太原人 Ⅱ.有些山西人不喜欢旅游 Ⅲ. 有些山西人喜欢吃面食','[{"label":"A","content":"仅仅 I"},{"label":"B","content":"仅仅Ⅱ"},{"label":"C","content":"仅仅Ⅲ"},{"label":"D","content":"仅仅 I 和Ⅲ"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":566,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400567,6,'逻辑判断','两份同样的细菌培养液中加入同一种细菌，一份培养液放在光照下，一份培养液放 在黑暗中。一周后，光照下的培养液中的细菌都死了，黑暗下的培养液中的细菌繁 殖了很多倍。因此，黑暗有利于此种细菌的生长和繁殖。 以下各项如果都为真，最能削弱上述推论的是：','[{"label":"A","content":"光照使得培养液的成分发生了变化，使得细菌无法在变化后的培养液中生长"},{"label":"B","content":"另一份同样的培养液放在黑暗环境中，一周后细菌的数量没有发生明显变化"},{"label":"C","content":"自然状态下，此种细菌一般生活在阴暗的环境中"},{"label":"D","content":"光照达到一定强度和时间时一般会杀死细菌"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":567,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400568,6,'逻辑判断','新入职教师因不熟悉学校教学工作的相关规章制度，导致了较高的教学事故率。以 S 中学为例，尽管新入职教师占该校教师总数不足5%,但是在因教学事故给予处分 的教师中，新入职教师占了25%。 以下各项如果为真，除哪项外均能削弱上述结论：','[{"label":"A","content":"与老教师相比，新入职教师在工作中还比较散漫"},{"label":"B","content":"新入职教师普遍认为学校的教学管理规定不合理"},{"label":"C","content":"新入职教师所教授的班级大多是平均分较低的班级"},{"label":"D","content":"新入职教师因忙于熟悉环境而没有对教学工作足够重视"}]','C','。 ②花生批注：归因：将女性司机的 交通死亡事故发生率 高归因于女性缺少开 车技巧。②花生批注：前文介绍了实验过程， 但未说明实验结果， 可以看作背景。题干只有结论：人们 可以根据相貌丑俊来 判断个体的智商高低。四海公煮 逻辑判断 ②花生批注： 归因：将女性司机的 交通死亡事故发生率 高归因于女性缺少开 车技巧。 ②花生批注： 前文介绍了实验过程， 但未说明实验结果， 可以看作背景。 题干只有结论：人们 可以根据相貌丑俊来 判断个体的智商高低。','逻辑判断600题','进阶','published','{"globalNumber":568,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400569,6,'逻辑判断','某媒体记者表示：由于女性往往缺少开车技巧，所以应给予女性驾驶执照附加限制。 尽管女性司机只占注册司机的30%,但是他们却是超过40%的交通死亡事故的肇事者。 下面每一项，如果正确都能削弱女性缺乏基本的开车技巧的论述，除了：','[{"label":"A","content":"与其他人开的车相比，女性一般开的车较旧，而且稳定性也差"},{"label":"B","content":"女性司机平均每年开车的距离超过其他司机的两倍"},{"label":"C","content":"女性司机引起的交通事故比其他人引起的交通事故严重"},{"label":"D","content":"女性开车时的乘客人数很有可能比一般的司机多"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":569,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400570,6,'逻辑判断','科研人员做了一项实验，将十多张穿着同样考究的小孩的肖像照展示给一个由医生 和教师所组成的评判小组，小组成员需根据肖像照对孩子们的聪明程度做判断，这 种主观判断的结果将与客观智力测验的结果相比对。最后，科研人员得出的结论为： 人们可以根据相貌丑俊来判断个体的智商高低。 以下哪项如果为真，最能削弱上述结论：','[{"label":"A","content":"好莱坞的知名影星中不乏名校毕业的高材生"},{"label":"B","content":"如果一个人仪表堂堂，我们可能错误地认为他一定非常聪慧"},{"label":"C","content":"根据社会同型交配法则，聪慧基因和美丽基因会不断优化结合"},{"label":"D","content":"漂亮的小孩能接受到更用心的教育，才智也可以得到更好的开发"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":570,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400571,6,'逻辑判断','宣称植物有意识、有感情的人，通常会引用美国人巴克斯特的实验。巴克斯特将一 台测谎仪连在一盆植物的叶子上。这台测谎仪的设计原理是人在撒谎时，由于紧张， 皮肤会出汗，导致皮肤电阻降低，通过测定皮肤电阻的变化可辨别人的情绪，进而 判断人是否在撒谎。巴克斯特报告说，实验中当主试想到“我要烧掉那片叶子”时， 测谎仪反应剧烈，指针猛然摆到了仪表的顶端并显示出连续的激烈波动，测谎仪绘 制出类似于人在极度恐惧时会出现的图形。巴克斯特由此宣称：植物是有感情的。 以下哪项如果为真，最能驳斥以上观点：','[{"label":"A","content":"即使是巴克斯特也不能稳定地重复该实验，而巴克斯特对实验成功与失败的解释 难以令人信服"},{"label":"B","content":"具有中枢神经系统的生物才有意识、有感情，植物没有任何神经系统"},{"label":"C","content":"巴克斯特所记录的测谎器曲线，可能是其他因素引起的，包括静电作用、房间里 的机械振动、湿度的变化等"},{"label":"D","content":"巴克斯特的实验设计不够科学，没有对照组，也不符合客观、双盲等科学实验的 必要条件"}]','B','【题型分类】 一般质疑类——严谨逻辑关系 【实战解析】题干通过介绍巴克斯特的实验，得出结论：植物是有 意识、有感情的。 分析选项： ②花生批注：此题选项给出“只有 才”的严谨逻辑关系， “只有才”可翻译成“不 不”。B 选项，可翻译为：没有中枢神经系统的生物→ 没有意识感情。植物 没有任何神经系统，因此植物不可能有意识、有感情。属于严谨逻辑 关系质疑②,可直接选择； ②花生批注： 此题选项给出“只有 才”的严谨逻辑关系， “只有才”可翻译成“不 不”。 其他选项： A 选项、C 选项、D 选项均指出实验存在的问题，“不能重复实验”、 “可能其他因素引起”、“不满足科学实验的必要条件”,虽然质疑 了实验结果的科学性，但没有直接推翻结论，不如B 选项力度强烈。','逻辑判断600题','进阶','published','{"globalNumber":571,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400572,6,'逻辑判断','某工厂的生产线会排放大量废弃物导致大气污染，为了迫使该工厂改变生产流程， 减少污染，当地居民决定对该厂销量最大的产品——荧光灯进行联合抵制。因为居 民们认为对销售量最大的产品进行抵制能够最大程度地降低该厂的利润。 以下哪项如果为真，最能质疑上述推论：','[{"label":"A","content":"联合抵制行动仅考虑产品的销售量，无法推断其相应的利润"},{"label":"B","content":"联合抵制行动没有考虑该工厂改变生产流程的可能途径等信息"},{"label":"C","content":"联合抵制行动没有涉及可以使得该工厂改变生产流程的其他方法"},{"label":"D","content":"居民通过联合抵制的方式，想要达到目的需要花费很长时间"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":572,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400573,6,'逻辑判断','可以端菜、扫地、唱歌跳舞，可以跟孩子做游戏、陪老人谈天说地……在本届机器 人世界杯上，各式各样的服务机器人成为最吸引眼球的明星。多位业界专家预测， 面向家庭和个人的服务机器人，将超越工业机器人，成为下一个爆发式增长的市场。 以下哪项为真最能质疑上述专家的预测：','[{"label":"A","content":"由于一些关键部件仍依赖进口导致有些国内的服务机器人的价格居高不下"},{"label":"B","content":"在我国目前服务机器人进入家庭还只是“看上去很美”,有的产品尚未量产"},{"label":"C","content":"目前的服务机器人技术行的，实现成本却太高； 方案成本低的，技术却不行"},{"label":"D","content":"机器人产业中中国的主要差距在硬件，而硬件差距对机器人性能影响很小 179 179"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":573,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400574,6,'逻辑判断','根据疫情防控要求，某会议要压缩规模。张、王、李、赵、牛、孙和陈7人只能选 派3人参会。其中，张、王、李3名博士生至多只能有1人参会，其他4名教授至 多只能有2人参会。另外，根据工作需要，还需满足：(1)若赵参会，则孙、张均 不参会；(2)若牛参会，则张、赵均参会。 根据以上陈述，可以得出下列项：','[{"label":"A","content":"孙参会"},{"label":"B","content":"赵不参会"},{"label":"C","content":"张不参会"},{"label":"D","content":"陈参会"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":574,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400575,6,'逻辑判断','某公司总经理竞选在即，员工小李跟同事预测：竞选结果或者是老张当选，或者是 老严当选。如果老张赢得总经理的职位，该公司的海外项目将受损；如果老严当选， 国内的产品开发项目将暂停。 根据员工小李的上述预测，可以得出以下哪项：','[{"label":"A","content":"该公司海外项目可能不会受损，国内的产品开发项目也不会暂停"},{"label":"B","content":"如果该公司海外项目受损，那么老张赢得了总经理的职位"},{"label":"C","content":"该公司海外项目将受损，或者国内开发项目将暂停"},{"label":"D","content":"如果该公司海外项目受损并且国内产品开发项目暂停，那么老张和老严均赢得了 总经理的职位"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":575,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400576,6,'逻辑判断','发展中国家的经济增长速度很快，但同时环境的污染也越来越严重，如果不能从大 气和水源两方面整治污染，国家经济增长再快，也不能达到国家富强、人民安居乐 业的目标。 由此不能推出的是：','[{"label":"A","content":"只有大气和水源这两方面的污染状况得到改善，才能达到国家富强、人民安居乐 业的目标"},{"label":"B","content":"如果大气和水源这两方面的污染状况得到改善，即使国家经济增长再慢，也能达 到国家富强、人民安居乐业的目标"},{"label":"C","content":"没有从大气和水源两方面整治污染，却能达到国家富强、人民安居乐业的目标， 这种情况是不能存在的"},{"label":"D","content":"如果达到国家富强、人民安居乐业的目标，说明一定从大气和水源两方面整治了 污染"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":576,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400577,6,'逻辑判断','食品安全的实现，必须有政府的有效管理。只有政府各部门之间的相互协调配合， 才能确保政府进行有效的管理。但是，如果没有健全的监督制约机制，是不可能实 现政府各部门之间协调配合的。 由此可以推出：','[{"label":"A","content":"要想健全监督制约机制，必须有政府的有效管理"},{"label":"B","content":"没有健全的监督制约机制，不可能实现食品安全"},{"label":"C","content":"有了政府各部门之间的相互协调配合，就能实现食品安全"},{"label":"D","content":"一个不能进行有效管理的政府，即是没有建立起健全的监督制约机制的政府"}]','B','【题型分类】推出类——等价推出 【实战解析】翻译和分析过程见批注，分析选项： B 选项，⑤的逆否命题，以“起点(非健全监督机制)”开始，可以推出； 其他选项： A 选项、C 选项是⑤的逆命题、D 选项是⑤的否命题，均无法推出。 33花生批注： 题干可翻译为： ① 食品安全的实现→ 政府的有效管理； ②政府的有效管理 → 各部门相互协调配合； ③非健全监督机制→ 非各部门相互协调配 合； 其逆否命题可得： ④各部门相互协调配 合→健全监督机制； 综上所述，可以将上 述命题串连起来： ⑤食品安全的实现 → 政府的有效管理 →各 部门相互协调配合 → 健全监督机制。','逻辑判断600题','进阶','published','{"globalNumber":577,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400578,6,'逻辑判断','在芳华小区的居民中，很多中老年住户都办了人身意外险，所有买了三居室以上住 房的居民都办了财产保险，而所有办了人身意外险的都没办理财产保险。 下列说法必定为真的是： ①有中老年住户买了三居室以上的住房 ②有中老年住户没办理财产保险 ③买了三居室以上住房的居民都没办理人身意外险','[{"label":"A","content":"①②和③"},{"label":"B","content":"仅①和②"},{"label":"C","content":"仅②和③"},{"label":"D","content":"仅 ②"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":578,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400579,6,'逻辑判断','单位拟派姜、陈、贾、丁、胡、武6人中的4人前往非洲。 已知： (1)若姜、贾并非都去，则胡、武皆不去； (2) 若陈、胡并非都去，则武去而贾不去。 根据以上信息，可以得出下列哪项：','[{"label":"A","content":"姜、陈均不去"},{"label":"B","content":"丁、武均不去"},{"label":"C","content":"贾、丁均不去"},{"label":"D","content":"陈、胡均不去"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":579,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400580,6,'逻辑判断','工厂对技术工人的学历情况进行了调查，发现过去五年间新进厂的技术工人学历层 次有大幅度提高。因此，工厂技术工人的素质整体有较大提升。 如果上述情况属实，下列哪项无法对结论起到支持：','[{"label":"A","content":"过去五年间的新进厂的技术工人现在仍在工厂上班"},{"label":"B","content":"素质高的技术工人生产的产品较少出现不合格的情况"},{"label":"C","content":"学历越高的人，素质也越高"},{"label":"D","content":"学历高的人会带动其他同事提高素质 练习题30"}]','B','。 447 练习题30 题目整体评价 平均正确率 平均错题数 测试结果 时间 正确数 错误数 ①花生批注： 题干按照“是否使用 新型特效药”进行分 组，将“今年一月流 感患者数量较去年同 期下降”这一既成事 实归因于“使用了新 型特效药”。 ②花生批注： 题干“流感患者数量 明显下降”,说明下 降数量“大”;选项“患 者使用少”,说明即 使有一部分患者使用， 也不会带来“明显下 降”的结果； 要重视“明显”“很少” 这些程度词。 ③花生批注： 论据：奶制品充足让 牧民摄入足够钙质； 结论：足够的钙质是 牧民体魄健壮的必不 可少。','逻辑判断600题','进阶','published','{"globalNumber":580,"sourceNumber":20,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400581,6,'逻辑判断','据统计，和去年相比，今年1月以来流感患者的数量有明显的下降。这得益于新型 特效药的发明和投入使用。 以下最能反驳上述结论的是：','[{"label":"A","content":"2 月份为流感的高发期"},{"label":"B","content":"流感患者很少到医院去治疗"},{"label":"C","content":"流感病毒具有抗药性"},{"label":"D","content":"新型特效药定价高，患者使用少"}]','D','【题型分类】归因类——对比实验归因 【实战解析】既成事实和原因分析见批注，分析选项： A 选项，时间与题干不一致，无关项； B 选项，“不去医院治疗”不代表“不吃药”,无法质疑； C 选项，“流感病毒具有抗药性”不代表“吃药没用”,无法质疑； D 选项，指出很 少②有患者使用新型特效药定价高，即今年1月流感 患者数量明显减少的原因不是新型特效药的使用，属于否定此因质疑； 综上，D 选项正确。','逻辑判断600题','进阶','published','{"globalNumber":581,"sourceNumber":1,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400582,6,'逻辑判断','正是因为有了充足的奶制品作为食物来源，生活在呼伦贝尔大草原的牧民才能摄入 足够的钙质。很明显，这种足够的钙质，对呼伦贝尔大草原的牧民拥有健壮的体魄 是必不可少的。 以下哪项情况如果存在，最能削弱上述断定：','[{"label":"A","content":"有的呼伦贝尔大草原的牧民不具有健壮的体魄，但从食物中摄入的钙质并不少"},{"label":"B","content":"有的呼伦贝尔大草原的牧民不具有健壮的体魄，他们从食物中不能摄入足够的钙质"},{"label":"C","content":"有的呼伦贝尔大草原的牧民有健壮的体魄，但没有充足的奶制品作为食物来源"},{"label":"D","content":"有的呼伦贝尔大草原的牧民没有健壮的体魄，但有充足的奶制品作为食物来源"}]','C','④。 ④花生批注： A、B、D选项分别为“非 A且B”、“非A且非B”、 “非A 且B” 。','逻辑判断600题','进阶','published','{"globalNumber":582,"sourceNumber":2,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400583,6,'逻辑判断','世界羽毛球锦标赛女子团体赛的决赛前，马来西亚的教练在排兵布阵，他的想法是： 如果2号队员的竞技状态好，并且伤势已经痊愈，那么让2号队员出场。只有2号 队员不能出场时才派4号队员出场。 如果决赛时4号队员出场，则以下哪项可以推出：','[{"label":"A","content":"2 号队员受伤了"},{"label":"B","content":"2 号队员或许竞技状态不好"},{"label":"C","content":"如果2号队员不出场，他就能痊愈"},{"label":"D","content":"如果2号队员伤已痊愈，那么他的竞技状态不好"}]','D','⑦。 ⑤花生批注： “A且B”的否定为“非 A 或非B”。 ⑥花生批注： 根据“否一推一”翻 译规则：“A 或B” 等 价于“非A →B”。 ⑦花生批注： B 选项因为有“或许” 表述，也正确，但不 如D 选项，D 选项是 因为逻辑可推出。 ⑧花生批注： 论据：夜总会里的年 轻人为摇滚乐表演鼓 掌但不观看爵士乐表 演； 结论：在20世纪50年 代的一段时间里，摇 滚乐把爵士乐永久地 赶出了舞台。 ⑨花生批注： 注意结论中的“永久” 二字，可针对其进行 质疑。 ⑩花生批注： 论据：今年A市的桃 子在挂果期出现旱情， 有人担心桃子价格会 上涨； 结论：该地桃子罐头 厂的生产成本增多。','逻辑判断600题','进阶','published','{"globalNumber":583,"sourceNumber":3,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400584,6,'逻辑判断','在20世纪50年代的一段时间里，摇滚乐把爵士乐永久地赶出了舞台。证据源于那 段时间年轻人的行为。在拥挤的夜总会里，他们热情地为摇滚乐表演鼓掌，但当爵 士乐开始时，他们就出去并且吃一些小吃，只有当爵士乐表演结束后才回来。 下列哪一个如果是正确的，对上面得出的结论做了一个合理的反对：','[{"label":"A","content":"爵士乐在20世纪30年代到20世纪50年代间越来越流行"},{"label":"B","content":"尽管20世纪50年代参加夜总会的一些年轻人确实试图听爵士乐，他们最终对其 讨厌"},{"label":"C","content":"在20世纪60年代，摇滚乐不仅为年轻人提供娱乐，而且也为社会演说助兴，使 之更加具有振奋人心的作用"},{"label":"D","content":"尽管到1960年，爵士乐表演不那么流行，但从那时起在中产阶级的职业人员中 对爵士乐的兴趣开始复苏"}]','D','【题型分类】 一般质疑类——有论据有结论 【实战解析】论据结论见批注。依次分析选项： A 选项，时间与题干不一致，无关项； B 选项，指出当时年轻人最终讨厌爵士乐，可以支持结论； C 选项，指出20世纪60年代； D 选项，虽然20世纪50年代年轻人不喜欢爵士乐，但60年代中产 阶级对爵士乐兴趣复苏，所以摇滚乐没有把爵士乐永久的赶出舞台⑨, 可以质疑； 综上，D 项当选。','逻辑判断600题','进阶','published','{"globalNumber":584,"sourceNumber":4,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400585,6,'逻辑判断','如果桃子在挂果期持续干旱缺水，桃子的收成就会受到影响。今年A 市的桃子在挂 果期出现旱情，因此有人担心桃子价格会上涨，从而使得该地桃子罐头厂的生产成 本增多。 以下最能削弱上述论证的是：','[{"label":"A","content":"今年桃子罐头的价格是历年最低的"},{"label":"B","content":"该地的旱情并没有预计的严重"},{"label":"C","content":"今年A市扩大了桃子的种植面积"},{"label":"D","content":"A市桃子罐头厂的原料供应全部来自外市"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":585,"sourceNumber":5,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400586,6,'逻辑判断','相比那些不参加冲浪运动的人，经常参加冲浪运动的人一般都健康些。可见，冲浪 运动能锻炼身体，增进身体健康。 以下哪项最有力地对上述论证提出了质疑：','[{"label":"A","content":"无论什么人参加冲浪运动都是为了锻炼身体，增进健康"},{"label":"B","content":"锻炼身体、增进健康有许多方式，例如，参加长跑、球类活动、游泳等都能锻炼 身体，增进健康"},{"label":"C","content":"冲浪是一项十分危险的运动，每年都有一些人在冲浪运动中受伤，甚至有些人的 伤势还很严重"},{"label":"D","content":"身体健康状况不好的人大多都不会参加具有一定危险性的冲浪运动"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":586,"sourceNumber":6,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400587,6,'逻辑判断','一般认为，工作时间越长的人积累的工作经验也就越多。但最近一家公司发现，工 作多年的老员工和毫无工作经验的新人在设计一套营销方案时并没有表现出明显的 差距。因此，认为一个人工作时间越久经验越丰富的看法是站不住脚的。 以下哪项如果为真，最能削弱上述论证：','[{"label":"A","content":"在设计营销方案时，依靠的主要是创新意识而不是经验"},{"label":"B","content":"设计营销方案并不需要太多的工作经验"},{"label":"C","content":"老员工比新人参与过更多的方案设计"},{"label":"D","content":"设计营销方案有利于员工个人工作经验的积累 183"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":587,"sourceNumber":7,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400588,6,'逻辑判断','某单位的所有设计师都是广东人，有的广东人喜欢打乒乓球，该单位的运营经理喜 欢打乒乓球。 由此可以推出：','[{"label":"A","content":"该单位的运营经理是广东人"},{"label":"B","content":"该单位所有的广东人都是设计师"},{"label":"C","content":"该单位的设计师都喜欢打乒乓球"},{"label":"D","content":"该单位的设计师可能都不喜欢打乒乓球"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":588,"sourceNumber":8,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400589,6,'逻辑判断','只有加大科技创新投入，集中精力研发高质量科学技术并投入市场化运用，想方设 法为创新松绑解套，才能在关键核心技术领域实现重大突破，为经济发展提供源源 不断的增长动力。 由此可以推出：','[{"label":"A","content":"如果不加大科技创新投入，就不能在关键核心技术领域实现重大突破"},{"label":"B","content":"如果未在关键核心技术领域实现重大突破，说明没有想方设法为创新松绑解套"},{"label":"C","content":"如果能够为经济发展提供源源不断的增长动力，就说明在关键核心技术领域实现 重大突破"},{"label":"D","content":"如果在关键核心技术领域实现重大突破，为经济发展提供源源不断的增长动力， 也有可能未加大科技创新投入"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":589,"sourceNumber":9,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400590,6,'逻辑判断','如果下雨，那么活动将延期。 以下哪项可由上述结论推出： I. 如果活动没延期，则一定没下雨。 Ⅱ.如果活动延期，那么一定下雨。 Ⅲ.除非下雨，否则活动不会延期','[{"label":"A","content":"I"},{"label":"B","content":"I 和Ⅱ"},{"label":"C","content":"I 和Ⅲ"},{"label":"D","content":"Ⅱ 和Ⅲ"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":590,"sourceNumber":10,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400591,6,'逻辑判断','在人口最稠密的城市中，警察人数占总人口的比例也是最大。这些城市中的“无目 击证人犯罪”的犯罪率也最低。看来，维持高比例的警察至少可达到有效地阻止此 类犯罪的效果。 下列哪项如果为真，最能有效的削弱上述推论：','[{"label":"A","content":"人口稠密的城市中，大多数罪犯并不是被警察抓获的"},{"label":"B","content":"无目击证人犯罪在所有犯罪中本来就只占很小的比例"},{"label":"C","content":"高人口密度本身使得犯罪现场无目击证人的可能性减少"},{"label":"D","content":"警察的工作态度和巡逻频率在各个城市是有很大差别的"}]','C','。 455 ②花生批注： A 且B 的否定为“非 A 或非B”。 “不能既获得出勤分 满分又获得奖励分”, 即“获得出勤分满分 且获得奖励分”的否 定 ，“不能获得出勤 分满分或不能获得奖 励分”。 ②花生批注： “A或B”的否定为“非 A 且非B”。','逻辑判断600题','进阶','published','{"globalNumber":591,"sourceNumber":11,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400592,6,'逻辑判断','某老师规定，在一个学期内，除非每节课都出勤，否则任何学生都不可能既获得出 勤分满分，又获得奖励分。 下列哪项与上述规定的意思最为接近：','[{"label":"A","content":"在一个学期内，任何学生如果所有课都不缺勤，必然既获得出勤分满分，又获得 奖励分"},{"label":"B","content":"在一个学期内，任何学生如果所有课都不缺勤，都有可能既获得出勤分满分，又 获得奖励分"},{"label":"C","content":"在一个学期内，任何学生如果所有课都不缺勤，仍有可能获得出勤分满分，或者 获得奖励分"},{"label":"D","content":"在一个学期内，任何学生如果有某节课缺勤，必然或者无法获得出勤分满分，或 者无法获得奖励分"}]','D','。','逻辑判断600题','进阶','published','{"globalNumber":592,"sourceNumber":12,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400593,6,'逻辑判断','班主任：我主张小红和小明两人中至少提拔一人当班长。 教导主任：我不同意。 以下哪项最能准确表述教导主任实际意思：','[{"label":"A","content":"小红和小明两人都不提拔"},{"label":"B","content":"小红和小明两人都提拔"},{"label":"C","content":"如果提拔小红，则不提拔小明"},{"label":"D","content":"如果提拔小明，则不提拔小红"}]','A','【题型分类】分析类——真假分析 【实战解析】班主任的主张可翻译为“小红当班长或者小明当班长”; 教导主任不同意，其主张为“小红不当班长且小明不当班长②”,答 案为A 选项。 四海公煮 逻 辑 判 断','逻辑判断600题','进阶','published','{"globalNumber":593,"sourceNumber":13,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400594,6,'逻辑判断','某单位拟选派本单位人员去外地出差，候选人有甲、乙、丙、丁、戊、己6人，工 作会上几位领导的意见如下：','[{"label":"A","content":"甲和乙至少要去一个"},{"label":"B","content":"如果丙不能去或丁不能去，那甲也不能去"},{"label":"C","content":"如果丙不能去，己也不能去"},{"label":"D","content":"只有戊去了，乙才能去 E、戊不能去 工作会后，所有领导的意见都被采纳。由此可推出："},{"label":"E","content":"乙去了"},{"label":"F","content":"甲没有去"},{"label":"G","content":"无法确定己去没去"},{"label":"H","content":"无法确定丙、丁去没去"}]','C','。 2花生批注： “只有才”可翻译为 “不不”。 3花生批注： “至少”可翻译为“或 者甲或者乙”,乙不去， 可推出甲要去。 ④花生批注： “A或B”的否定为“非 A且非B”。','逻辑判断600题','进阶','published','{"globalNumber":594,"sourceNumber":14,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400595,6,'逻辑判断','研究人员发现一颗距离地球仅16光年的行星上具有与地球相似的温度和气候条件， 因此很有可能在这颗行星上发现生命存在的迹象。 如果上述结论成立，需要下列哪项作为前提假设：','[{"label":"A","content":"该行星上的生命存在条件与地球上的类似"},{"label":"B","content":"该行星距离地球的距离越近越好"},{"label":"C","content":"研究人员还需经过长期的观测才能发现这颗行星上的生命迹象"},{"label":"D","content":"生物必须要在固定的温度和气候条件下才能存活"}]','A','。','逻辑判断600题','进阶','published','{"globalNumber":595,"sourceNumber":15,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400596,6,'逻辑判断','根据中国和美国政府机构专家组成的工作组测算，美国官方统计的对华贸易逆差被 高估了20%左右。更令人难以信服的是，美国政府引用的贸易数据只包括货物贸易， 并未反映服务贸易。如果算进去，所谓的“贸易不平衡论”就更立不住了。 上述结论建立在下列哪项假设的基础之上：','[{"label":"A","content":"美国对华服务贸易逆差巨大"},{"label":"B","content":"美国对华服务贸易存在高额顺差"},{"label":"C","content":"美国购买了中国很多的工业产品"},{"label":"D","content":"美国购买了中国很多的劳务服务"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":596,"sourceNumber":16,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400597,6,'逻辑判断','哺乳动物在衰老过程中，大脑中的小胶质细胞会转变为促炎表型，出现过度活化， 进而产生损害认知和运动功能的化学物质。这是为什么人到老年大脑功能会衰退的 原因之一。实验表明，多补充膳食纤维，可以平衡与年龄有关的肠道微生物群失调， 从而提高血液中丁酸盐的水平。研究人员据此建议老年人多吃富含膳食纤维的食物， 称这有助于他们延缓大脑功能衰退的进程。 下列哪项如果为真，最能支持上述研究人员建议：','[{"label":"A","content":"膳食纤维会促进肠道中有益细菌的生长，产生多种短链脂肪酸"},{"label":"B","content":"丁酸盐可以减轻大脑中的小胶质细胞的促炎表型，增强细胞抗炎能力"},{"label":"C","content":"多吃富含膳食纤维的食物需要增加牙齿的咀嚼，这增加了口腔的运动量"},{"label":"D","content":"老年人吸收功能降低，多吃富含膳食纤维的食物可以增加肠道蠕动"}]','B','。','逻辑判断600题','进阶','published','{"globalNumber":597,"sourceNumber":17,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400598,6,'逻辑判断','有些人正是因为吃了太多肉类和海鲜，畅饮了过多啤酒，导致尿酸水平升高，造成 尿酸盐在关节和肾脏部位沉积，才使他们患上痛风。因此，患上痛风，对于判断这 些患者是否吃了太多肉类和海鲜，畅饮了过多啤酒是一项必不可少的条件。 下列哪项如果为真，最能削弱上述断定：','[{"label":"A","content":"有些人吃了太多的肉类和海鲜，畅饮了过多的啤酒，经检验的确患有痛风"},{"label":"B","content":"有些人没有吃太多的肉类和海鲜，畅饮过多的啤酒，但是患有痛风"},{"label":"C","content":"有些人没有吃太多的肉类和海鲜，畅饮过多的啤酒，也未患有痛风"},{"label":"D","content":"有些人吃了太多的肉类和海鲜，畅饮了过多的啤酒，但是并未患有痛风 186 SK煮 . 逻辑判断"}]','D','【题型分类】 一般质疑类——严谨逻辑关系 【实战解析】题干结论为严谨逻辑关系，直接寻找“A 且非B” 选项， 即“吃太多海鲜和肉、畅饮过多啤酒且未患上痛风”,D 选 项 正 确','逻辑判断600题','进阶','published','{"globalNumber":598,"sourceNumber":18,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400599,6,'逻辑判断','现代生活中，人们更加注重身体健康。调查显示，选择多种方式进行运动的人往往 比只用一种方式运动的人身体更为健康。因此，选择多种方式运动更有利于身体健康。 下列哪项为真，最能反驳上述观点：','[{"label":"A","content":"采用多种方式运动的人普遍身体较好"},{"label":"B","content":"有些只选择一种运动方式的人比其他人身体更为健康"},{"label":"C","content":"有数据显示，人们只有在身体锻炼到初见效果后才会选择多种方式锻炼"},{"label":"D","content":"选择多种方式运动风险较大，对专业程度要求高"}]','C','。','逻辑判断600题','进阶','published','{"globalNumber":599,"sourceNumber":19,"pairingMode":"question-block"}');
INSERT INTO questions (id, category_id, type, stem, options_json, answer, explanation, source, difficulty, status, details_json) VALUES (400600,6,'逻辑判断','在一项考试成绩提升计划实施前，负责老师统计了参与该计划的、学业表现不佳的 学生每天花在网上的平均时间。他重新制定了这些学生的学习计划，要求他们每天 减少上网时间，并预测了遵守其要求的学生的考试成绩所可能的提升幅度。但是， 考试成绩评定的最终结果表明，这些学生的成绩提升幅度并没有达到预期水平。 下列哪项如果为真，最能解释上述现象：','[{"label":"A","content":"在计划结束前夕，参与计划的不少学生主动减少了比老师所要求的更多的上网时间"},{"label":"B","content":"根据重新制定的学习计划，所有的课后作业都需要通过在线学习平台来完成和提交"},{"label":"C","content":"参与计划的学生每天上网时间的减少不会对他们完成新的学习计划产生影响"},{"label":"D","content":"该负责老师成功预测过参与其他考试成绩提升计划的学生的成绩提升幅度"}]','B','。 462','逻辑判断600题','进阶','published','{"globalNumber":600,"sourceNumber":20,"pairingMode":"question-block"}');
